/* characters q09 (151 mục) — R2.6 bồi tiểu sử Lưu Kim Bưu */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q09"]=window.__LIBQ["tien-nghich"]["q09"]||{};window.__LIBQ["tien-nghich"]["q09"]["characters"]={"updatedAt":"2026-07-13","count":151,"chars":[{"id":"vuong-lam","name":"Vương Lâm","cn":"王林","aliases":["Tằng Ngưu","Lữ Tử Hạo","Hứa Mộc","Lăng Tiêu","Lữ Mục","Lữ đạo hữu","Lữ huynh","Lữ","Thiết Trụ","họ Lữ","tên họ Lữ"],"gioiTinh":"nam","canhGioiCaoNhat":"Tịch Niết sơ kỳ (sắp đạt Tịch Niết trung kỳ, @c1131)","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Cưỡng ép thái sơ lực trong Tàn Dạ Thần Thông phá Hắc Dạ của huyết long, tạo hào quang duy nhất trong màn đêm, đổi giá thiêu đốt nguyên lực, nguyên thần, thân thể nham thạch. Lao vào vết thương huyết long, thu khối tinh thể màu máu lớn (tâm huyết Cổ Thần) vào không gian trữ vật. Nguyên thần sắp tiêu tan, được lão già áo đen vỗ mi tâm truyền sức mạnh vô biên, phục hồi toàn diện bằng phương thức nghịch thiên. Ngộ ra bổn tôn Cổ Thần dù đạt ngũ tinh cũng không hoàn mỹ so với Thác Sâm (bát tinh Cổ Thần vương tộc). Chứng kiến Thác Sâm giao chiến lão già áo đen, cảm nhận uy lực kinh hồn. Không do dự bước vào cơn lốc xoáy mới theo lão già áo đen.","anchor":"mơ hồ biết được nơi cơn lốc xoáy này dẫn đến, chỉ sợ cũng là một khe không gian khác bên ngoài thân thể của Đồ Ti","bridge":true,"khoang":"@c1064"},{"chuong":"@c1065","importance":"normal","mucCt":"ky","tieuDe":"Bị thương nặng bởi thanh âm Cổ Thần","text":"Bị thanh âm thức tỉnh của Thác Sâm gây thương tổn nghiêm trọng, thân thể xuất hiện nhiều vết nứt, một vết xuyên ngực từ trước ra sau, mặt hiện màu đen do nguyên thần bị thương nặng, thân thể có dấu hiệu hóa nham thạch. Nhận ra tinh điểm thứ ba trên mi tâm Thác Sâm liên quan đến Khánh Không Luyện Tinh nhờ trí nhớ truyền thừa Cổ Thần, nhưng chỉ biết tên mà không biết phương pháp thi triển.","anchor":"hắn chỉ biết được tên, còn phương pháp thi triển cụ thể không có bên trong trí nhớ"},{"chuong":"@c1066","importance":"major","mucCt":"ky","tieuDe":"Phân thần hy sinh ngăn Diệt Thần Mâu, bổn tôn bỏ trốn khỏi Liên minh Tinh Vực","text":"Phân thần Vương Lâm quyết định lao ra trước Diệt Thần Mâu, thân thể sụp đổ hóa mảnh đá vụn, dùng tia nguyên thần phun thần niệm lên Diệt Thần Mâu nhằm ngăn cản, tranh thời gian cho lão già áo đen thoát qua vòng xoáy. Thác Sâm đánh tan nguyên thần yếu ớt của Vương Lâm, trước đó nói để lại tinh điểm thứ nhất cho hắn. Bổn tôn tỉnh dậy trên nguyệt tinh ngoài Chu Tước Tinh, thu nữ thi áo trắng vào khe trữ vật, phá trận pháp, thi triển Súc Địa Thành Thốn liên tục bỏ trốn. Xác định vĩnh viễn không thể quay về Liên minh Tinh Vực trừ phi đủ sức đối phó Thác Sâm. Chạy đến tinh cầu bỏ đi đã bố trí trận pháp từ trước khi gặp Thanh Long Thánh Hoàng.","anchor":"Lấy thần niệm của Vương Lâm ta, ngăn cản ngươi tiến lên"},{"mucCt":"ky","text":"Trên một tinh cầu hoang trong Liên Minh Tinh Vực, Vương Lâm một mình đi trong gió tuyết tới bình nguyên, quét sạch tuyết ngàn trượng lộ ra trận pháp truyền tống cực lớn. Hắn lấy nguyên thần hôn mê từ khe trữ vật làm vật dẫn, bấm quyết kích hoạt trận pháp tạo thông đạo tối đen. Trước khi bước vào, hắn quay đầu nhìn lại, cảm nhận hương vị quê nhà và hơi thở bằng hữu của Liên Minh Tinh Vực, nói rằng lần này đi không biết khi nào trở về, có thể vĩnh viễn không trở về được. Hắn cười dài rồi bước vào vòng xoáy truyền tống, rời Liên Minh Tinh Vực hướng tới Vân Hải Tinh Vực thuộc Phong Giới. Trận pháp sụp đổ sau khi dùng, tuyết lấp đầy mọi dấu vết.","anchor":"Lần này đi, không biết khi nào mới có thể trở về","bridge":true,"khoang":"@c1067"},{"mucCt":"ky","text":"Vương Lâm xuất hiện từ Truyền Tống Trận trong khu rừng phía Bắc đại lục Mạc La, chính thức rời Liên Minh Tinh Vực tới Vân Hải Tinh Vực. Tuyết Liên Minh trên người hòa với mưa Vân Hải. Thần thức chưởng môn Quy Nguyên Tông trong trạng thái Trạch Linh phát hiện vô số oan hồn vờn quanh hắn — những người hắn đã giết cả đời — kinh hãi tột độ. Một cái liếc mắt ngẩng đầu của hắn khiến lôi đình lui tán. Hắn hít một hơi thật sâu không khí Vân Hải rồi bước vào rừng sâu.","anchor":"Khi đi có tuyết đưa tiễn, khi đến lại có mưa chào đón… Có vẻ không tồi","bridge":true,"khoang":"@c1068"},{"mucCt":"ky","text":"Phân thân quyết định đứng vững tại Vân Hải thay vì trốn chạy Thác Sâm, chờ bổn tôn vượt tam tổn thất kiếp. Biến đổi tướng mạo thành thư sinh tầm thường tóc đen, giả danh họ Tằng. Cứu Lão Tam khỏi rắn độc cắn, được đại hán Vũ Đại cho ở nhờ tại Bắc Thủy Thôn. Sống một tháng với thân phận lang trung chữa bệnh và thợ khắc gỗ, hòa nhập thôn dân. Khi tu sĩ Triệu Ngọc ức hiếp thôn dân bắt đứng dưới mưa, bước ra khiến Triệu Ngọc sửng sốt bối rối, lập tức cho dân về. Kín đáo phóng hơi nóng xua hàn khí cho từng thôn dân. Cuối cùng với danh tính Tằng Ngưu được đại trưởng lão Lữ Yên Phi thu nhận làm môn hạ Quy Nguyên Tông.","anchor":"Trong bảy người được Lữ Yên Phi, phụ nữ duy nhất trong bốn đại trưởng lão lựa chọn, có một người, tên là Tằng Ngưu, từ Bắc Thủy Thôn","bridge":true,"khoang":"@c1069"},{"mucCt":"ky","text":"Giả dạng phàm nhân Tằng Ngưu, cùng hai thanh niên được đưa vào Quy Nguyên Tông. Tự xưng lang trung, hoàn toàn bình tĩnh trước thần thông khiến Tôn Vân kinh ngạc vì không thấy chút linh lực nào trên người hắn. Được giao ở khu vườn dược thảo Nam Uyển, nhận ra nhiều loại dược thảo đã tuyệt chủng ở cả Liên Minh lẫn La Thiên Tinh Vực. Đêm xuống tách bổn tôn khỏi phân thân — nửa thân dưới chỉ còn bộ xương đen xen tia đỏ, thương thế nặng hơn lúc ở Chu Tước Thánh Tông vì sức mạnh Cổ Thần còn lại không nhiều. Suy ngẫm về thật và giả, nắm được chút ý niệm mơ hồ về đạo. Kinh ngạc trước thuật luyện đan Vân Hải Tinh Vực có đan dược vượt Vấn Đỉnh, nảy ra giả thuyết có thể có đan dược trợ cảm ngộ ý cảnh. Phát hiện Tôn Vân đột phá Dương Thực thất bại, truyền âm một chữ Định ngăn nàng uống Nhập Tử Ly Hồn Đan.","anchor":"Thật và giả… Hiện giờ có lẽ ta đang bị vây ở giữa thật và giả…","bridge":true,"khoang":"@c1070"},{"mucCt":"vua","text":"Buổi sáng mưa cầm ô lên đỉnh núi Quy Nguyên Tông, gặp trưởng lão Lữ Yên Phi, xưng tên giả Tằng Ngưu và bình tĩnh lắng nghe nàng kể tâm sự về sư tôn bị hại, Tử Đạo Tông ép song tu. Quay về phòng, phân tích đặc điểm Vân Hải Tinh Vực và đặc biệt hứng thú với Man Thiên Đan — đan dược trợ giúp Vấn Đỉnh.","anchor":"Trong mắt Vương Lâm lộ ra vẻ hứng thú","bridge":true,"khoang":"@c1071"},{"mucCt":"ky","text":"Dùng Định Thân Thuật khống chế Tôn Vân mà nàng không hề hay biết, lấy viên Nhập Tử Ly Hồn Đan từ tay nàng phân tích bằng thần thức, phát hiện bên trong chứa tinh hồn con vượn bị phong ấn. Khi Tôn Vân nuốt đan sắp thất bại, điểm một chỉ vào thiên linh nàng, thần thức hóa thân ảnh áo trắng tóc bạc tiến vào tâm thần, chỉ một chỉ tùy ý đánh tan con vượn đen. Sau đó suy ngẫm nhận ra loại đan dược dùng hồn phách linh thú trợ cảm ngộ ý cảnh hoàn toàn khác biệt với hai giới Lôi Vũ, liên tưởng tới tinh hồn Mặc Trí từng đưa tại Chu Tước Thánh Tông.","anchor":"Không ngờ… trong Vân Hải Tinh Vực này lại có loại đan dược này tồn tại","bridge":true,"khoang":"@c1072"},{"mucCt":"ky","text":"Ở Quy Nguyên Tông mười ngày, ban ngày giả phàm nhân đọc mộc giản Điển Tịch Các về lịch sử Mạc La và Vân Hải Tinh Vực. Đêm đột nhập đạo quán bí mật treo giữa không trung trên tám cột đá, phá cấm chế trên giá di bảo. Nghiên cứu ngọc giản lão tổ Quy Nguyên Tông phần linh thú và luyện đan, chứng thực phỏng đoán về phương pháp luyện đan Vân Hải qua Ly Hồn Đan cấp tám (phế đan). Không lấy di bảo, quyết tâm tự mình dùng phương pháp luyện đan Vân Hải nâng cao tu vi. Tử Mục Mãng (Khuy Niết hậu kỳ) canh giữ đạo quán sợ hãi lùi nhường đường vì bốn ngày trước suýt bị hắn chém chết. Ánh mắt lạnh lùng khiến Tôn Vân run sợ nuốt lời khi đến trách móc. Cảm nhận biên giới phía tây đại lục Mạc La bị phá vỡ kết giới.","anchor":"Trước mắt cần phải tự mình dùng phương pháp luyện đan của Vân Hải để luyện hóa đan dược","bridge":true,"khoang":"@c1073"},{"mucCt":"ky","text":"Đứng trong đạo quán quan sát cầu vồng tứ đại trưởng lão bay đi, suy tính nếu Quy Nguyên Tông bị diệt sẽ ảnh hưởng đường tu, lẩm bẩm thật là phiền toái rồi bước vào gợn sóng biến mất. Xuất hiện chặn trước linh thú khổng lồ màu đen của Tử Đạo Tông, ra lệnh Tống Ngũ Đức rời đi vĩnh viễn. Bị thiếu tông chủ áo tím coi thường, phóng Sát Lục Khí tràn ngập trời đất khiến nước mưa đóng băng, thi triển tiên thuật Hoán Vũ khống chế toàn bộ nước mưa vạn trượng lao tấn công, dùng thần thông Định cố định thân thể Tống Ngũ Đức giữa không trung, rút Không Niết Kiếm chém một nhát xuyên tinh thể băng — giết Tống Ngũ Đức (Tịnh Niết Trung Kỳ) trong nháy mắt, thể xác vỡ bốn năm mảnh, nguyên thần tan rã. Sau đó đuổi theo thiếu tông chủ áo tím đang cưỡi linh thú chạy trốn, thân ảnh trắng in sâu trong mắt Lữ Yên Phi dưới cầu vồng buổi sáng.","anchor":"hắn chết không oan uổng, bất luận là Sát Lục Khí hay tiên thuật Hoán Vũ cũng đủ để cho một người có thể hoành hành trong tu chân giới","bridge":true,"khoang":"@c1074"},{"chuong":"@c1075","importance":"normal","mucCt":"ky","tieuDe":"Giết Lô Địch, thu đóa sen đen","text":"Giết Lô Địch (thiếu tông chủ Tử Đạo Tông) bằng một ngón tay điểm vào mi tâm, nguyên thần sụp đổ, thân thể phun máu tan rã. Thu lấy đóa sen đen bảo mệnh, túi trữ vật và linh thú đen của Lô Địch. Từ đầu tới cuối không lộ mặt, chỉ để lại bóng lưng tóc bạc trước mắt Quy Nguyên Tông. Sự uy hiếp của Tử Đạo Tông trong mắt hắn chỉ là trò đùa, còn không bằng một sợi lông trên người Thác Sâm.","anchor":"Bất luận là Chính Phẩm Lôi Tiên của La Thiên, người đứng đầu Chu Tước Thánh Tông ở Liên Minh Tinh Vực"},{"mucCt":"ky","text":"Lữ Yên Phi chủ động đến nhà gỗ, kể chuyện sư thúc tổ Lữ Tử Đạo để gián tiếp trao thân phận 'Lữ Tử Hạo' cho Vương Lâm ẩn thân trong Quy Nguyên Tông. Vương Lâm nhận ra nàng đã đoán mình là người tóc trắng giết Tống Ngũ Đức và Lô Địch, đánh giá cao sự thông minh kín đáo của nàng, so sánh với Liễu Mi, Hồng Điệp, Lý Mộ Uyển. Nghiên cứu hoa sen đen, phát hiện là thực vật thiên nhiên bị phong ấn trận pháp đơn giản, có thể tạo phòng hộ cực mạnh. Kiểm tra túi trữ vật Lô Địch, tìm thấy bình ngọc tím, cờ nhỏ vàng, cây hương to. Thần thức nhập vào cờ nhỏ vàng, phát hiện mấy trăm âm hồn nữ tử bị phong ấn cùng thú hồn hình rắn phát ra khí tức cực âm. Nhận ra đây là mảnh ghép cuối để Thiên Nghịch Châu viên mãn lần thứ hai.","anchor":"Thiên Nghịch châu ngũ hành viên mãn đã trở thành âm dương, năm xưa Bạch Vi ở nơi đó đã có được cực dương, chỉ còn thiếu cực âm, là Thiên Nghịch châu có thể viên mãn lần thứ hai!","bridge":true,"khoang":"@c1076"},{"mucCt":"ky","text":"Xem xét cờ nhỏ màu vàng thu được từ Lô Địch, phá toàn bộ trận pháp giam cầm âm hồn nữ tử bên trong, giải phóng hồn phách, phong ấn cực âm hồn lại trong cờ rồi cất vào khe trữ vật. Nhận định phương pháp nuôi cực âm bằng âm hồn nữ tử là sai lầm, nhớ lại Thiên Vận Tử năm xưa mượn thân thể Bạch Vi khiến cực âm đạt đỉnh chuyển thành cực dương mới là phương pháp đúng. Xem bình ngọc tím chứa ba viên đan dược phát tử quang, mỗi viên có hồn phách hung ác. Nhận ra cây hương to bằng cánh tay trẻ con chính là vật năm xưa tu sĩ Vân Hải dùng mê hoặc Văn Thú dẫn ra khỏi Tứ Thánh Tông. Học nhận biết dược thảo Vân Hải Tinh Vực từ Tôn Vân, hỏi về Vụ Trung Hoa — dược liệu cần thiết để luyện Ly Hồn Đan tầng sáu trở lên. Hái dược thảo từ vườn Tôn Vân, dùng Thiên địa chi hỏa từ mắt trái tạo hỏa cầu thay lò luyện, luyện đan dược tầng ba với thú hồn linh thú Lô Địch nhưng đan tạc lần đầu, ra hái thêm dược thảo luyện lại.","anchor":"Luyện đan, không nhất định phải có lò luyện!","bridge":true,"khoang":"@c1077"},{"mucCt":"ky","text":"Trong ba ngày luyện đan mười sáu lần, chỉ lần đầu và lần cuối thành công, luyện được một viên đan dược cấp ba. Nhận ra thuật luyện đan Vân Hải kết hợp Thú hồn dung hợp cần tự ngộ nhiều điều ngọc giản không ghi rõ. Tôn Vân nổi giận vì dược viên tâm huyết bị phá gần hết mà chỉ ra đan dược cấp ba, hét đòi trả dược thảo. Vương Lâm ném đan dược cho nàng rồi lẳng lặng rời đi. Phá tầng phòng hộ Mạc La đại lục, bay vào biển mây tinh cầu hướng đến Man Hoang đại lục để tìm dược thảo và mãnh thú. Thả hơn mười con Văn Thú ra, cưỡi Văn Thú vương xuyên sương mù ba ngày. Đặt chân lên Man Hoang, phát hiện thành trì phàm nhân đổ nát có vết máu khô trên tường, bị một bóng đen từ đống đổ nát lao ra tấn công với tốc độ cực nhanh.","anchor":"Thuật luyện đan của Vân Hải cùng Thú hồn dung hợp lại thì cần phải chú ý rất nhiều thứ, những điều này trên ngọc giản cũng không ghi lại rõ ràng","bridge":true,"khoang":"@c1078"},{"mucCt":"ky","text":"Đã ở Man Hoang đại lục bảy ngày, chém nhiều mãnh thú lấy linh hồn và dược thảo. Tiến lên đỉnh núi xanh đen cùng bầy Văn Thú hộ tống, đối đầu khỉ đen khổng lồ cấp năm. Dùng phi kiếm tạo kiếm trận mở đường máu, thu cây đại thụ tím có hai quả trắng đen kỳ dị vào khe trữ vật. Dùng khí sát lục đánh tan lốc xoáy của khỉ đen rồi đánh văng nó. Trong lúc chiến đấu nhớ lại cảnh lão giả hắc y Đệ Tam Bộ trên La Thiên vung tay ngăn chưởng Cổ Thần Thác Sâm, minh ngộ cảm giác không phải điều động mà là điều khiển nguyên lực thiên địa — cưỡng ép nguyên lực bốn phương hóa công kích toàn bạo. Tay trái điểm ba chỉ lên tay phải, đánh bật khỉ đen, ba khe nứt lan khắp toàn thân nó, máu phun như suối. Khỉ đen dưới nguy cơ đột phá lên cấp sáu, hiện thần thông Tụ hồn vào thân. Vương Lâm ấn tay ép linh hồn quay về thân, dùng Khống Linh Ấn thu phục khỉ đen làm linh thú, cưỡi nó phóng đi.","anchor":"hắn không phải dùng lực lượng của bản thân điều động nguyên lực thiên địa tiến vào, mà giống như đang điều khiển","bridge":true,"khoang":"@c1079"},{"chuong":"@c1080","importance":"bridge","mucCt":"vua","text":"Vương Lâm ngồi trên vai khỉ đen khổng lồ di chuyển trên phía bắc Man Hoang đại lục, bình thản thu dược thảo cây cỏ đỏ mà khỉ đen đoạt từ hang chim ưng. Hơn mười vạn mãnh thú truy kích phía sau nhưng hắn không hề can thiệp, chỉ vỗ nhẹ khen ngợi khỉ đen.","anchor":"Vương Lâm đang khoanh chân ngồi trên vai con khỉ giơ tay ra bắt được"},{"mucCt":"ky","text":"Ở lại Man Hoang đại lục vài ngày, lợi dụng con khỉ đen liên tục xông vào sào huyệt mãnh thú cướp đoạt dược thảo khắp đại lục, dán bùa vàng tăng tốc cho khỉ. Cất Văn Thú vào túi trữ vật vì tình cảnh không thích hợp. Lo Tử Đạo Tông sẽ diệt Quy Nguyên Tông khi vắng mặt, muốn quay về trấn giữ. Con khỉ đen dẫn hắn xông vào khu vực trung tâm đại lục, phát hiện trận pháp tám đầu lâu khổng lồ hấp thu tử hồn do Ngũ Độc Môn bày ra. Lão bà Ngũ Độc Môn (Tịnh Niết trung kỳ) hiểu lầm hắn là viện binh đối thủ, chủ động tấn công để độc chiếm ngọc giản và đan phương Niết Không Đan. Vương Lâm thi triển hắc long cuồng phong đáp trả, đối mặt ba luồng khí độc, thần thông Độc Linh Ẩn và linh thú rắn mào gà của lão bà.","anchor":"hắn dùng tay phải vỗ lên vai con khỉ","bridge":true,"khoang":"@c1081"},{"mucCt":"ky","text":"Dùng tiên thuật Hô Phong hóa năm Hắc Long dung hợp thành trường thương đen truy kích lão bà dùng độc. Thu nguyên lực thiên địa trong nghìn trượng vào đầu ngón tay phá hủy Ấn Độc và pho tượng hư ảo, tiếng nổ chấn động toàn Man Hoang đại lục. Thả Ngân Y Nữ Thi chiến đấu với con rắn đầu mào gà. Thi triển Định Thân Thuật trói lão bà khiến máu độc phản phệ thối rữa toàn thân, trường thương đen đâm xuyên ngực nổ tung, thu nguyên thần lão bà. Phong ấn tám đầu lâu trận pháp thành khô lâu xám nhỏ như nắm tay, giữ khả năng khôi phục bất cứ lúc nào. Tiến vào sơn cốc phát hiện nam tử trung niên Tịnh Niết hậu kỳ trúng kịch độc Ngũ Độc Môn, gật đầu đồng ý phóng nguyên lực cho hắn nhưng nguyên lực đột nhiên biến đổi khi gần ba tấc.","anchor":"đối với Vương Lâm thì chuyện giết người giống như ăn cơm bữa","bridge":true,"khoang":"@c1082"},{"mucCt":"ky","text":"Dùng thiết kiếm chém đứt đầu tên đàn ông trung niên Tịnh Niết hậu kỳ khi hắn định tự bạo. Phân tích hiện trường sơn cốc, xác định bốn thi thể đệ tử bị tên đàn ông giết chứ không phải chết vì độc, và lời hắn nói hết nguyên lực là dối trá. Suy luận đồ vật không trong túi trữ vật mà giấu trong xác đệ tử, dùng lửa từ mắt trái luyện hóa hài cốt, tìm được ngọc giản Phá Thiên Tông cấp tám và mảnh xương thú ghi đan phương Niết Không đan. Chấn động nhận ra đan dược này giúp nắm chắc một phần quy tắc hóa bản nguyên thành tu sĩ Đệ Tam Bộ, năm phần vượt suy kiếp đầu Thiên Nhân, tám phần tiến cảnh giới Nhập Thần. Phi tang hiện trường, phá một đầu lâu để lại mảnh vỡ cùng xác đệ tử chết vì độc, tạo giả tượng Độc Bà Tử độc chiếm đan phương bỏ trốn. Bắt giữ nguyên thần Độc Bà Tử không cho chết, thu Ngân Y Nữ Thi và bảy đầu lâu. Dùng Súc Địa Thành Thốn, bùa vàng, da thú tăng tốc rời Man Hoang đại lục vào tinh không, ngụy trang ngồi trên khỉ đen bình thản hướng về Quy Nguyên Tông trên Mạc La đại lục. Cuối chương phát hiện nhiều luồng cầu vồng đang tiến đến gần.","anchor":"Ăn vào đan dược này có thể nắm chắc một phần quy tắc hóa bản nguyên, trở thành tu sĩ Đệ Tam Bộ!","bridge":true,"khoang":"@c1083"},{"mucCt":"ky","text":"Vương Lâm cưỡi khỉ đen khổng lồ, tay cầm bản đồ tinh cầu, chủ động tán nguyên lực giả tu vi Khuy Niết trung kỳ. Khi nhóm Tiền Quý Chung lướt qua lần đầu, hắn không bị nghi ngờ. Sau khi Tiền Quý Chung nhận tin Thi Lạc Hình chết, theo nguyên tắc thà giết lầm không bỏ sót, ra lệnh tám đệ tử bắt Vương Lâm mang đến Man Hoang đại lục. Vương Lâm giả vẻ kinh hoàng cung kính hỏi lý do.","anchor":"nguyên lực trong cơ thể Vương Lâm vẫn tán ra bên ngoài, chỉ dám đặt tu vi ở mức Khuy Niết trung kỳ","bridge":true,"khoang":"@c1084"},{"mucCt":"ky","text":"Nhận ra quay về Man Hoang đại lục sẽ lộ thân phận vì khỉ đen khiến mãnh thú náo động, cộng với nghi vấn cái chết Thi Lạc Hình, Vương Lâm quyết ra tay giết sạch. Thi triển Hô Phong thuật hóa năm Hắc Long diệt năm đệ tử Dương Thực, dùng ngón tay điểm mi tâm giết một tu sĩ Tịnh Niết sơ kỳ, đánh ngực giết tên thứ hai, khỉ đen đập chết một tên — tám người đồng loạt tử vong trong nháy mắt. Bị thần thông hắc quang của Tiền Quý Chung phá tầng phòng hộ sát lục và phun máu, vẫn xông thẳng qua dùng mắt trái bùng lửa tạo biển lửa thiêu chết ba tên, dùng thanh quang chém chết thêm một tên, thi triển Hoán Vũ hóa năm tiểu kiếm xuyên qua năm tên cuối giết bốn, một nguyên thần chạy thoát. Phun Phong Tiên Ấn mười tám tầng địa ngục chặn trường thương đen của Tiền Quý Chung, bị phản chấn phun máu lần hai. Bị mưa kiếm bạch quang từ phất trần trắng xuyên đùi phải, nhờ khôi giáp đỏ máu mới sống sót. Phóng Hứa Lập Quốc truy sát nguyên thần chạy thoát, triệu Ngân Y Nữ Thi thu phục linh thú mất chủ. Điểm ngón tay lên Phong Tiên Ấn triệu linh hồn Hư Không Tử và Thiên Vận Tử, rút Thứ Không Niết (Thiết Kiếm) khiến tinh không chấn động, chuẩn bị quyết chiến Tiền Quý Chung.","anchor":"Hắn nhất định phải thắng mà cũng nhất định phải nhanh","bridge":true,"khoang":"@c1085"},{"mucCt":"ky","text":"Phóng linh hồn Hư Không Tử và Thiên Vận Tử ra quấn chân Tiền Quý Chung, thi triển 19 kiếm Thứ Không Niết chém nát thân thể đối phương thành 19 mảnh, tiêu hao sáu phần nguyên lực. Hóa Chu Tước hơn mười trượng bằng Cửu Huyền Biến truy kích nguyên thần Tiền Quý Chung. Dung nhập linh hồn Thiên Vận Tử vào chính cơ thể mình (Tát Đậu Thành Binh đạt cực hạn), dùng ý niệm làm vật dẫn triệu hoán Một ngón tay Thiên Vận Tử tiêu diệt nguyên thần Tiền Quý Chung. Linh hồn Thiên Vận Tử biến mất sau đòn này, Vương Lâm mất một chiến hồn cực mạnh. Bị thương nặng: đùi phải bị bạch quang xuyên, ngực bị sợi tơ trắng phất trần xuyên qua. Năm ngày sau thoát về Mạc La đại lục, trở lại dược viện Quy Nguyên Tông dưới danh tính Tằng Ngưu, trị thương ba ngày rút hết tàn dư sợi tơ trắng. Lấy ngọc giản và mảnh xương thú chiến lợi phẩm định nghiên cứu nhưng cảm ứng bản tôn sắp độ kiếp, lập tức chìm vào lòng đất phóng đi.","anchor":"Nếu có bản tôn ở đây thì cuộc chiến ngày hôm nay sẽ không gian khổ thế này, Tam Tổn Thất Kiếp… chẳng biết có thể thành công vượt qua hay không","bridge":true,"khoang":"@c1086"},{"mucCt":"ky","text":"Bản tôn Vương Lâm ngồi sâu dưới lòng đất Quy Nguyên Tông, toàn bộ máu thịt đã mất chỉ còn khung xương phủ lớp màng máu huyết Đồ Ti. Máu huyết Đồ Ti bị xương cốt hấp thu hết trong sáu ngày, Tổn Kiếp đầu tiên kết thúc. Khung xương phình lên ba trăm trượng. Cốt Kiếp bắt đầu: lực vô hình bóp nát xương cốt từ chân lên. Sau một tháng, chân phải vỡ hoàn toàn, chân trái từ đầu gối xuống thành tro bụi. Vương Lâm bùng lên ý niệm nghịch thiên, quyết kiên trì đợi đến khoảnh khắc cuối cùng mới phản kháng để khung xương ngưng tụ hoàn chỉnh. Phân thân ngồi hộ pháp, cùng chịu đau đớn. Chấn động từ lòng đất lan khắp Mạc La đại lục suốt một tháng, kéo nguyên lực trời đất và tinh không về, khiến mãnh thú cấp năm đến cấp bảy tụ tập bên ngoài.","anchor":"Phân thân vì nghịch tu, bản tôn vì nghịch tộc, Vương Lâm ta cả đời tu đạo chỉ có một chữ nghịch, nghịch thiên, nghịch kiếp, vàng muốn nghịch mệnh!","bridge":true,"khoang":"@c1087"},{"chuong":"@c1088","importance":"normal","mucCt":"ky","tieuDe":"Ngưng tụ thần cốt vượt cốt kiếp","text":"Bản tôn trong lòng đất bị cốt kiếp phá nát toàn bộ khung xương ba trăm trượng đến mảnh cuối cùng rồi tiêu tán hoàn toàn. Đúng khoảnh khắc tro cốt sắp biến mất, phân thân bất chấp phản phệ trọng thương thi triển Định Thân Thuật, chỉ tay hét \"Ngừng!\" khiến tro cốt ngừng tiêu tán. Tro cốt ngưng tụ ngược thành xương mới, hút sạch nguyên lực thiên địa toàn Mạc La đại lục, phá vỡ tầng phòng hộ đại lục hút thêm nguyên lực bên ngoài tinh không. Xương mới cứng rắn vượt xa trước nhờ vòng tuần hoàn tan vỡ — ngưng tụ liên tục với cốt kiếp, ngưng tụ được xương đầu lâu và nửa thân trên. Hồng quang lóe trong hốc mắt, gầm rống tuyên chiến với trời. Trước đó bản tôn dùng thần niệm đánh bật bốn tu sĩ Quy Nguyên Tông (Lý Hướng Đông, Lữ Yên Phỉ, hai lão già) hai lần, khiến cả bốn phun máu văng ra khỏi lòng đất.","anchor":"Ta thân là Cổ Thần dám khiêu chiến thiên,chỉ là một cốt kiếp, chẳng làm gì được ta!"},{"importance":"major","mucCt":"ky","chuong":"@c1089","tieuDe":"Cốt kiếp thành, nhục kiếp lâm, tàn sát mãnh thú","text":"Khung xương nửa dưới bản tôn ngưng tụ hoàn chỉnh, cốt kiếp tiêu tán. Nhục kiếp (Nhất Tổn Nhị Kiếp) lập tức hàng lâm, ngăn máu thịt tăng trưởng nhằm xóa bỏ sinh cơ. Phân thân mở túi trữ vật lấy ra nhiều giọt máu vương tộc Cổ Thần to như nắm tay, dung nhập vào khung xương giúp máu thịt tái sinh. Mùi máu Cổ Thần khiến đám hung thú ngoài tinh không phát cuồng đổ xô về Mạc La đại lục. Bản tôn thu nhỏ từ hơn ba trăm trượng về hình người bình thường, dung hợp với phân thân rồi phá đất xông lên. Dùng nắm đấm giết liên tiếp hơn trăm mãnh thú cấp năm đến cấp bảy, mỗi lần giết đều hấp thu sinh cơ giúp máu thịt tăng trưởng. Một đòn húc nổ tan Kiếm Sư Thú cấp tám dài hai trăm trượng thành sương máu, hấp thu luồng sinh cơ khổng lồ, đứng giữa bầu trời uy phong.","anchor":"Nhất Tổn Nhị Kiếp nhục kiếp hàng lâm một cách vô cùng lặng lẽ"},{"mucCt":"ky","text":"Một cước giết hung thú cấp tám, truy sát toàn bộ mãnh thú trong phạm vi hơn mười vạn dặm ngoài Mạc La đại lục trong một nén nhang, thu sinh cơ dung nhập bản tôn chống nhục kiếp. Ba ngày sau bản tôn vượt qua Nhất Tổn Nhị Kiếp (kiếp đầu tiên của Cổ Thần Tam Tổn Thất Kiếp), chính thức thành Cổ Thần Ngũ Tinh hoàn chỉnh, tinh điểm thứ sáu mơ hồ hình thành trên mi tâm, bản tôn bắt đầu diễn hóa Vọng Nguyệt. Đánh giá sau hợp thể có thể giết Toái Niết sơ kỳ dễ dàng nhưng so với Toái Niết trung kỳ và đại viên mãn còn chênh lệch quá lớn. Ra lệnh đưa phương pháp luyện đan cấp cao để nghiên cứu, chỉ giữ đan phương, trả lại toàn bộ đan dược.","anchor":"bên cạnh năm tinh điểm trên mi tâm của hắn lại xuất hiện một cái tinh điểm khác, nhưng tinh điểm này vẫn còn chưa được thành hình","bridge":true,"khoang":"@c1090"},{"mucCt":"ky","text":"Nghiên cứu đan phương Niết Không Đan trên mảnh xương thú, tra điển tịch Quy Nguyên Tông tìm được ba dược liệu quý hiếm gần tuyệt diệt: Tinh Biến Mộc, Long Tinh Thảo, Toái Diệt Hoa. Thi triển Sưu Hồn lên nguyên thần Độc Bà Tử, lấy toàn bộ ký ức bao gồm thuật luyện độc Ngũ Độc Môn, lai lịch ngọc giản chứa dấu ấn Tư Mã Mặc (đại đệ tử Phá Thiên Tông), và phương pháp luyện thú hồn biến dị. Thu nguyên thần suy yếu nhưng chưa chết vào túi trữ vật. Dùng thú hồn cấp 5 từ Man Hoang, thú hồn đệ tử Hoa Thanh Tông bị giết, và linh xà cấp 6 đỉnh phong của Độc Bà Tử để luyện Ly Hồn Đan, thất bại 3 lần mới luyện thành Ly Hồn Đan cấp 8. Thử nghiệm phương pháp luyện thú hồn biến dị tại động phủ trên dãy núi Mạc La đại lục, kết quả thú hồn cấp 5 thôn phệ lẫn nhau thành công. Tĩnh tọa 7 ngày rồi nuốt đan cấp 5 và cấp 6, tiến vào trạng thái cảm ngộ kỳ dị — hóa thân thành mãnh thú cảm ngộ quy tắc thiên địa. Tỉnh lại chỉ còn viên đan cấp 8 chưa nuốt, đưa ra nhận định triết lý: đan dược Vân Hải dùng thú hồn cho tu sĩ nhiều cơ hội truy tìm đạo, muốn sâu hơn cần dùng nhân hồn hoặc tồn tại vượt hơn loài thú.","anchor":"Tu vi của Vương Lâm lúc này là Tịnh Niết sơ kỳ, hắn vừa nuốt vào thì ý cảnh lập tức bùng lên những cơn sóng chấn động","bridge":true,"khoang":"@c1091"},{"mucCt":"ky","text":"Ẩn cư trong cấm địa khu vườn phía nam Quy Nguyên Tông, khí tức khủng khiếp bao phủ dược viên. Khi Trừu Hải (Tịnh Niết sơ kỳ, Ngũ Độc Môn) xâm nhập cấm địa, Vương Lâm phát ra một câu lạnh lùng rồi xuất chưởng đánh Trừu Hải phun máu, áo ngực vỡ nát lộ ra dấu bàn tay đen kịt khắc sâu vào ngực. Được Lữ Yến Phỉ gọi là sư thúc tổ trước mặt ba tông phái tinh vực cấp sáu.","anchor":"Kẻ nào đánh ngươi, kẻ đó nhận hậu quả!","bridge":true,"khoang":"@c1092"},{"mucCt":"ky","text":"Đánh Trừu Hải trọng thương bằng một chưởng, rút sinh cơ chuyển cho đệ tử Nguyên Anh Quy Nguyên Tông bị thương để chữa trị. Bước ra từ khu vườn phía nam, tự nhiên phát ra Ý Cảnh đạo khiến thiên địa hư ảo. Lần lượt uy hiếp Phùng Bội Sơn, Triệu Vũ, Trừu Hải, khiến cả ba tự vỗ ngực phun máu xin tội. Cho phép tiếp tục tìm kiếm nhưng ra lệnh tìm xong phải rời khỏi Mạc La đại lục. Sau đó suy tính: trên Man Hoang đại lục vẫn còn manh mối chưa xóa được, quyết tâm nâng tu vi. Xác định Phong Tiên Giới là sát chiêu chuẩn bị cho Thác Sâm. Đang mạo hiểm thử nghiệm phương pháp luyện thú từ ký ức Độc Bà Tử, bố trí thần thức cấm chế tại địa điểm luyện thú.","anchor":"Hắn đứng ở đâu thì nơi đó là đạo","bridge":true,"khoang":"@c1093"},{"mucCt":"ky","text":"Vương Lâm ngồi trước dược viện Quy Nguyên Tông, cự tuyệt cầu kiến và nghiên cứu viên đan dược cấp tám của Vân Hải tinh vực, nhận ra sơ hở của loại đan dược mượn thú hồn chứng đạo là phải nuốt liên tục rất nhiều mới lấy được ý cảnh cần thiết. Khi Lô Vân Tòng dùng ý cảnh dung nhập thiên địa qua từng bước chân để tạo uy áp, Vương Lâm chỉ nói một chữ “Ngồi” đã khiến toàn bộ thế công ý cảnh tan vỡ. Con đường đạo của hắn được tổng kết từ Sinh Tử Luân Hồi, Nhân Quả Tuần Hoàn, Nhân Quả Viên Mãn đến Chân Giả Ý Cảnh, khiến đạo niệm của Lô Vân Tòng không thể so sánh.","anchor":"Con đường tu đạo của Vương Lâm đã cảm ngộ Sinh Tử Luân Hồi năm trăm năm, sau chín trăm năm thì Sinh Tử Luân Hồi trở thành Nhân Quả Tuần Hoàn","bridge":true,"khoang":"@c1095"},{"mucCt":"ky","text":"Vương Lâm dùng uy áp đạo niệm khiến Lô Vân Tòng tiến thoái lưỡng nan, rồi đối đáp với Lý Thiến Mai về câu hỏi cái gì là thiên. Hắn vẽ hai vòng tròn để luận rằng thiên chỉ tồn tại vì người ta tin vào nó, thoát khỏi một vòng lại rơi vào vòng khác, nhân quả tuần hoàn không bến bờ. Đạo luận của hắn làm đạo niệm Lô Vân Tòng nứt vỡ và quét sạch bế tắc đạo tâm của Lý Thiến Mai. Sau đó hắn xưng tên giả Lữ Tử Hạo, nhận Cực Tài Đan bán thành phẩm cấp mười và nhìn thấu hai câu hỏi cùng lời của Lý Thiến Mai thực chất khác nghĩa, một về cực hạn đạo niệm và một về thiên ý.","anchor":"Mấy trăm năm trước ta đã bắt đầu suy nghĩ về đạo lý này, cho nên vì sao nhất định phải có thiên?","bridge":true,"khoang":"@c1096"},{"mucCt":"ky","text":"Vương Lâm luận đạo với Lý Thiến Mai và Lô Vân Tòng về vận mệnh, thiên ý và đạo, dùng mưa sinh rồi cuốn ngược về mây để minh họa kẻ thay đổi vận mệnh chính là thiên ý. Hắn trả lời câu hỏi thứ ba bằng ví dụ cá, lưới, sông và ngư ông, rồi sau khi nghe Lý Thiến Mai dẫn lời sư tôn thì kết luận hiện tại đạo là tư tưởng. Hắn từ chối trả Âm Tiên Phiên cho Lô Vân Tòng, biết vật này do chủ tông Tử Đạo Tông ban xuống và trăm năm sau phải dâng lại. Cuối chương, hắn nhắm mắt nghe tiếng sáo của Lý Thiến Mai, liên tưởng đến những tiếng đàn từng in sâu trong lòng mình.","anchor":"tiếng sáo bên tai và tiếng đàn trong lòng lượn lờ và giao thoa, mơ hồ không thể phân biệt rõ","bridge":true,"khoang":"@c1097"},{"chuong":"@c1098","importance":"normal","mucCt":"ky","tieuDe":"Hỏi bí mật cấp chín","text":"Vương Lâm cùng Lý Thiến Mai đi về Bồng Lai đại lục, chấp nhận chuyến đi vì muốn tìm bản đồ tinh cầu để di chuyển trong sương mù Vân Hải. Trên đường, hắn hỏi về tinh vực cấp chín và nghe Lý Thiến Mai tiết lộ bốn tông phái, nguồn gốc Yêu Tông, cuộc nổi loạn mãnh thú cùng tinh vực thần bí sau không gian đứt gãy. Sau khi đồng ý giữ bí mật, hắn suy tư về vị trí tinh vực thần bí ấy.","anchor":"Thế sự vô thường, nhưng nhất định phải có nguyên nhân. nếu lời nói của Lý Thiến Mai là thật, như vậy tinh vực thần bí kia sẽ ở nơi đâu."},{"mucCt":"ky","text":"Vương Lâm trò chuyện với Lý Thiến Mai về bí ẩn tinh vực cấp chín và lời hẹn tiễn biệt khi chiến tranh với mãnh thú nổ ra. Hắn nhớ lại lúc rời Mạc La đại lục, Lữ Yên Phỉ đứng tiễn và dặn đừng quên Quy Nguyên Tông. Hắn cùng Lý Thiến Mai đến Bồng Lai đại lục, vào khu chợ của Bảo Ngọc Tông, thấy cảnh giao dịch tiên ngọc với nguyên tinh và bình thản trước tu chân tinh vì từng quen thuộc với loại địa vực này. Cuối chương, hắn bị Dương Ngọc nhìn chằm chằm rồi lạnh lùng hỏi thân phận.","anchor":"quê hương nơi hắn được sinh ra chính là một tu chân tinh, nơi bái sư cũng là một tu chân tinh, thậm chí ở La Thiên hắn còn có một tu chân tinh thuộc về chính mình","bridge":true,"khoang":"@c1099"},{"chuong":"@c1100","importance":"normal","mucCt":"ky","tieuDe":"Trấn nhiếp Ma Tùng Đạo","anchor":"Tâm trí của Vương Lâm rõ ràng đã giống như yêu ma, khi Dương Ngọc vừa xuất hiện thì hắn đã biết được kẻ này nhìn thấy mình trước","text":"Vương Lâm giao dịch với Âu Dương Long để đặt cọc mua nguyên tinh và được lão cảnh báo về thân phận Dương Ngọc. Khi Dương Ngọc cùng hai đồng môn vây dò xét, hắn phế hai tu sĩ Tịnh Niết sơ kỳ bằng ngón tay hóa kiếm và ánh mắt song hư thực phối hợp chữ Đạo. Sau đó hắn dùng ý cảnh bước chân ngộ từ phương pháp của Lô Vân Tòng để ép Dương Ngọc phun máu, rơi vào ảo giác và phải cầu cứu sư thúc. Khi sư thúc Dương Ngọc hiện thân gọi hắn là Lữ đạo hữu, hắn chấp nhận ngồi đàm phán, đồng thời tự phân tích Ma Tùng Đạo có thể đang thử tu vi mình vì Triệu Vũ hoặc vì sơ hở trên Man Hoang đại lục."},{"chuong":"@c1101","importance":"normal","mucCt":"ky","tieuDe":"Gặp Ma Tùng Đạo, mua bản đồ tinh cầu, đến đấu giá tư nhân","text":"Dùng danh tính Lữ gặp hai trưởng lão Ma Tùng Đạo Đường Lệ Hải và Ngô Thanh, được mời làm trưởng lão ngoại sự nhưng không đáp ứng ngay, hẹn trả lời trước khi rời Bồng Lai. Mơ hồ nhận ra tu sĩ ẩn thân tại bàn góc nhưng không lộ ra. Tách Lý Thiến Mai rồi một mình tìm mua bản đồ tinh cầu ba ngày, mua được sáu tấm nhưng chưa thỏa mãn. Nhận ra manh mối trên Man Hoang đại lục đã có người nhìn ra nên càng gấp rút. Được mời đến gặp Âu Dương Long tại tòa thành trung tâm, đi vào đấu trường linh thú và đến trước buổi đấu giá tư nhân do sư thúc Âu Dương Long chủ trì. Khi Âu Dương Long hỏi sao biết thân phận mình, hắn chỉ mỉm cười không đáp.","anchor":"Xem ra manh mối trên Man Hoang đại lục đã có người nhìn ra"},{"mucCt":"ky","text":"Vương Lâm dùng thân phận Lăng Tiêu bước vào phòng đấu giá tư nhân dành cho tu sĩ Toái Niết, bình thản trước ánh mắt dò xét của những người trong phòng. Hắn dựa vào ghi chép của Quy Nguyên Tông để chọn mãnh thú Sí Vân và đặt cược một trăm khối tiên ngọc. Khi Thương Tùng Tử lấy ra bộ tàn giáp không ai hỏi mua, hắn xin mua rồi được tặng miễn phí, nhưng sự chú ý của hắn đặt vào chất liệu giống xương kỳ lạ hơn là thần thông tàn khuyết bên trên. Đến lúc lão già áo đen tay vuốt ưng lấy lông Chu Tước ra giao dịch, tâm thần hắn chấn động nhưng vẫn che giấu không để lộ manh mối.","anchor":"Vương Lâm nhìn chằm chằm vào lông chim màu đỏ, tâm thần hắn chấn động nhưng lại che giấu rất tốt không lộ ra bất kỳ manh mối nào","bridge":true,"khoang":"@c1102"},{"mucCt":"ky","text":"Vương Lâm dùng danh xưng Lữ đạo hữu tham gia tụ hội, mua bản đồ tinh cầu từ bà lão áo xanh bằng mười vạn tiên ngọc để bà hoàn tất giao dịch thú hồn. Hắn tranh lông vũ Chu Tước tới ba vạn tiên ngọc nhưng nhận ra Ngô Thanh cố ý nâng giá nên từ bỏ và giấu sát khí. Sau đó hắn đổi tiên ngọc lấy năm ngàn nguyên tinh từ Thương Tùng Tử, hỏi mua Hỗn Nguyên Đan không thành, nhận bản đồ tinh cầu thật cùng lời cảnh báo rồi rời thành về phía tây Bồng Lai đại lục, trong lòng định nếu Ngô Thanh đuổi theo thì sẽ giết lão.","anchor":"Năm ngàn nguyên tinh vẫn còn chưa đủ, nếu muốn đủ số lượng để tẩm bổ linh thú, muốn Văn thú có thể dùng phương pháp này để thăng cấp đủ bảo vệ ta thành công tiến vào Phong tiên giới thì nhất định phải có đủ nguyên tinh","bridge":true,"khoang":"@c1103"},{"mucCt":"ky","anchor":"hắn cũng không ngờ sau khi mất đi điều khiển thì dấu chưởng lại có uy lực kh*ng b* như vậy","text":"Vương Lâm chủ động rời Bồng Lai tiên cảnh và dừng lại ở bình nguyên biên giới đông tây để đối đầu Ngô Thanh, nhằm đánh một trận công khai khiến các tu sĩ Bồng Lai và Ma Tùng Đạo phải kiêng dè. Hắn một quyền phá ngọn núi do Ngô Thanh ngưng tụ, dùng thần thông ba chỉ học từ Lỗ Phu Tử điều động nguyên lực thiên địa trên phạm vi cực lớn phá tan Lực bạt thiên và nghiền nát bảo vật đối phương. Sau đó hắn thi triển Dịch Linh Ấn, giết chết Ngô Thanh tới mức thân thể nổ tung, nguyên thần tiêu tán, rồi đoạt toàn bộ đồ vật trong khe trữ vật chưa kịp đóng. Dấu chưởng mất kiểm soát tiếp tục xuyên qua khu chợ Bồng Lai, phá hủy nhiều khối đá và đánh tan Man Hoang đại lục, khiến toàn bộ lão quái trên Bồng Lai kinh hoàng. Cuối chương hắn bình tĩnh bước tới trước tu sĩ trung niên Ma Tùng Đạo và nói người này đã đến muộn.","bridge":true,"khoang":"@c1104"},{"mucCt":"ky","text":"Vương Lâm giữ phong thái lạnh lùng của đệ tử Thần Tông, khiến Trương Kỳ của Ma Tùng Đạo phải dâng đan dược và bảo vật bồi thường. Hắn trở về khách điếm, thu nhận lông vũ Chu Tước dung nhập vào mắt trái, nhận ra chỉ một chiếc lông vẫn chưa đủ để Chu Tước thức tỉnh lần thứ ba. Sau đó hắn nhận ngọc giản Man Hoang đại lục từ Đỗ Đức, nhận bản đồ tinh cầu và lời mời hợp tác của Thương Tùng Tử, đồng ý đi vào nơi bí ẩn với giá hai vạn nguyên tinh.","anchor":"Nếu Chu Tước có thể thức tình lần thứ ba thì thực lực của ta sẽ tăng mạnh… đáng tiếc là chỉ có một chiếc lông, thế này vẫn chưa đủ","bridge":true,"khoang":"@c1105"},{"chuong":"@c1106","importance":"normal","mucCt":"ky","tieuDe":"Đấu giá tiễn biệt","text":"Vương Lâm đến tham dự đấu giá trên Bồng Lai, được các tu sĩ cung kính vì uy danh giết Ngô Thanh. Hắn giao hai bảo vật bọc hắc quang cho Tào trưởng lão đem đấu giá để đổi nguyên tinh. Khi Lý Thiến Mai tới từ biệt và nói phải đi viện trợ Yêu Tông, hắn trầm mặc trước lời hỏi tiễn biệt của nàng. Hắn mua bức tranh sóng nước không ai dám tranh rồi tặng cho Lý Thiến Mai, sau đó nhìn nàng rời đi và tự hỏi về câu cá quay về nước, quên chuyện trên bờ.","anchor":"Không có bất kỳ kẻ nào dám tranh đoạt với Vương Lâm"},{"chuong":"@c1107","importance":"normal","mucCt":"ky","tieuDe":"Hứng thú Thần Tông","text":"Sau khi Lý Thiến Mai rời đi, Vương Lâm không động tâm mà hồi tưởng lại Lý Mộ Uyển, Liễu Mi cùng những vết thương tình cảm đã khiến trái tim hắn chết lặng. Trong buổi đấu giá, hắn mở cấm chế cho núi đá và Thần Ma Giáp, chỉ muốn nhận nguyên tinh nhưng bất ngờ khi Thần Ma Giáp bị nhận ra là vật liên quan đến Thần Tông. Từ đó hắn bắt đầu nảy sinh hứng thú nồng đậm với Thần Tông trong Vân Hải tinh vực.","anchor":"trong lòng hắn bắt đầu có sự hứng thú nồng đậm đối với Thần Tông trong Vân Hải tinh vực"},{"mucCt":"ky","text":"Vương Lâm nhận một vạn nguyên tinh đặt cọc và ngọc giản bản đồ tinh cầu từ Thương Tùng Tử sau khi bộ giáp được bán xong. Hắn gặp Lý Thiến Mai trong sương mù, từ chối vòng ngọc phòng hộ vì vật quá quý, nhận bức tranh nàng vẽ thêm rồi đáp lễ bằng cây bút bảo vật Tiên giới. Trên đường theo bản đồ, hắn tình cờ nhặt lại vòng ngọc bị ném đi, sau đó tới Man Hoang đại lục hội hợp nhóm Thương Tùng Tử và bị Vân Hồn Tử sai âm hồn tấn công thử. Trong lòng hắn nhận định Thương Tùng Tử dù cáo già vẫn không sánh được Thiên Vận Tử, nên bản thân không cần sợ lão.","anchor":"Vương Lâm còn dám đấu một trận với Thiên Vận Tử thì cớ gì phải sợ tên Thương Tùng Tử này","bridge":true,"khoang":"@c1108"},{"mucCt":"ky","text":"Vương Lâm bị Vân Hồn Tử dùng âm hồn thử tu vi, đánh trả một quyền nhưng chủ động giữ lại một phần lực nên lùi năm bước và không bộc lộ hết thực lực. Hắn tự xét nếu toàn lực phối hợp pháp bảo thì không thua Toái Niết trung kỳ, đồng thời cảnh giác Thương Tùng Tử và Vân Hồn Tử liên thủ. Khi nghe nhắc Hồi đan, hắn nhận ra đan dược này không phải trọng điểm thật của Thương Tùng Tử, rồi theo nhóm sáu người xuất phát sau khi được hứa ngoài nguyên tinh còn được chọn bảo vật.","anchor":"Tình cảnh vửa rồi thì có vẻ hắn đã xuất toàn lực những thực tế vẫn giữ lại một phần lực","bridge":true,"khoang":"@c1109"},{"mucCt":"ky","text":"Vương Lâm phân tích quan hệ trong đội ngũ trước khi vào vết nứt bảy màu, nhận ra Vân Hồn Tử là trợ lực then chốt của Thương Tùng Tử và quyết định chặt đi cánh tay này. Hắn dùng Thiết Kiếm phối hợp uy lực Thứ Không Niết Bảo tập kích Vân Hồn Tử, rồi thi triển Định Thân Thuật và lực lượng Cổ thần khiến đối phương bị chém mất tay phải, lệch khỏi vị trí truyền tống chung. Sau khi vào thế giới bảy màu, hắn thấy Vân Hồn Tử không có mặt nên biết nước cờ đã thành, đồng thời lạnh lùng phủ nhận trước chất vấn của Thương Tùng Tử và lão già họ Bàng.","anchor":"Cho nên mục đích của Vương Lâm cũng không phải mạo hiểm giết chết một tu sĩ Toái Niết trung kỳ, mà chỉ lợi dụng khoảnh khắc xuyên qua vết nứt, bắt buộc phải làm cho Vân Hồn tử bị thương rồi thay đổi vị trí.","bridge":true,"khoang":"@c1111"},{"mucCt":"vua","text":"Trong thế giới bảy màu, Vương Lâm quan sát quang mang bảy màu và nhận ra nơi này ẩn chứa quy tắc quỷ dị. Hắn phát hiện nhiều cấm chế cổ hư hỏng nhưng uy lực vẫn vượt cấm chế trong động phủ Thanh Lâm, kịp tỉnh lại khi bị mùi Hồi đan làm nguyên thần chấn động, rồi yêu cầu toàn bộ nguyên tinh trong sương mù trước khi áp sát Giao Long hóa sương để ra quyền.","anchor":"Ánh mắt Vương Lâm lấp lánh, trong nháy mắt thân thể đã tiến đến gần Giao Long","bridge":true,"khoang":"@c1112"},{"mucCt":"ky","anchor":"Lực lượng Cổ Thần vang vọng trong cơ thể Vương Lâm","text":"Trong trận vây giết Giao Long tại thế giới bảy màu, Vương Lâm không liều mạng tranh công mà tranh thủ sương mù chưa tan để thu hàng ngàn nguyên tinh. Khi Giao Long sắp thăng không và trở thành đại họa, hắn bộc phát lực lượng Cổ Thần, chụp đuôi kéo thân thể ngàn trượng quật xuống con đường hẹp khiến đầu mãnh thú vỡ tan. Sau trận, hắn lấy ngọc giản dưới bộ hài cốt, đưa Hồi đan cho Đoan Mộc, đọc thấy bí mật liên quan thế giới bảy màu rồi lập tức cảnh giác trước dị biến vô hình.","bridge":true,"khoang":"@c1113"},{"chuong":"@c1114","importance":"normal","mucCt":"ky","tieuDe":"Nhận lời vì nguyên tinh","text":"Vương Lâm nhìn thấy rõ Mê Thất Giả xuất hiện phía sau đoàn và giữ bất động khi đối phương đi qua. Sau khi Đoan Mộc bị mang đi, hắn chất vấn Thương Tùng Tử về việc số Mê Thất Giả dường như tăng theo mỗi lần lão vào đây. Dù nhận ra Thương Tùng Tử chưa nói hết mục tiêu thật, hắn vẫn đồng ý tiếp tục để đổi lấy nguyên tinh và quyền chọn vật trong động phủ Tư Mã Mặc. Cuối chương, nội dung ngọc giản bên bộ hài cốt vang lại trong đầu hắn, khiến hắn lặng lẽ nhìn thế giới bảy màu trước mặt.","anchor":"Vương Lâm đứng thẳng người lên nhìn Thương Tùng Tử, hắn bình tĩnh nói"},{"mucCt":"vua","text":"Vương Lâm vừa suy ngẫm câu trong ngọc giản vừa âm thầm đánh giá kinh nghiệm của Thương Tùng Tử và năng lực cấm chế của bà lão áo xanh. Sau khi Thương Tùng Tử mặc Thần Ma Giáp vẫn thất bại trước Cửu Bộ Phong Tiên Trận, hắn bình tĩnh đứng dậy chuẩn bị tự mình thử trận.","anchor":"Vương Lâm đang khoanh chân ngồi lại đứng thẳng lên rồi vỗ vỗ bụi đất bám trên quần áo","bridge":true,"khoang":"@c1115"},{"mucCt":"ky","text":"Vương Lâm chủ động nhận phá Cửu Bộ Phong Tiên Trận vì muốn dò xét mục tiêu thật khiến Thương Tùng Tử điên cuồng. Khi bước vào vách đá, hắn âm thầm đưa cấm chế vô hình vào trận pháp rồi dùng thân thể Cổ Thần chịu áp lực, cố ý phun máu và biểu hiện như bị ép đến cực hạn. Đến bước thứ mười, hắn khiến trận pháp tan vỡ, sau đó tiếp tục diễn vai trọng thương, không nuốt đan dược Thương Tùng Tử đưa mà dùng thuốc của mình rồi lấy cớ ở lại động phủ cũ chữa thương.","anchor":"Không ai chú ý tới, khi Vương Lâm tiến vào trong vách đá thì lợi dụng khoảnh khắc những con sóng rung động vang vọng để một luồng cấm chế vô hình trên tay phải dung nhập vào trong trận pháp.","bridge":true,"khoang":"@c1116"},{"mucCt":"ky","text":"Vương Lâm giả vờ bị thương để lão già họ Bàng lộ sát tâm, sau đó lập tức phản kích, đánh nổ thân thể đối phương và dùng Thiết kiếm chém nguyên thần làm hai. Hắn không diệt hẳn nguyên thần vì nghi Thương Tùng Tử có cách phát hiện cái chết của lão Bàng, nên ép mở không gian trữ vật, chặt đứt liên hệ chủ cũ,搜 ký ức rồi thu nguyên thần suy yếu vào túi trữ vật. Từ chiến lợi phẩm và ký ức, hắn lấy được lượng lớn tiên ngọc, nguyên tinh, địa đồ, khẩu quyết rời đi, phát hiện động phủ hiện tại chỉ là nơi Thương Tùng Tử chọn tạm, sau đó phá phong ấn chiếc nhẫn và rời động phủ lần theo cảm ứng Tán Ma khôi giáp.","anchor":"Ánh mắt Vương Lâm vẫn bình tĩnh như mặt nước, khoảnh khắc khi lão già họ Bàng tới gần, hai mắt hắn lập tức bùng ra hàn quang.","bridge":true,"khoang":"@c1117"},{"mucCt":"ky","text":"Vương Lâm lần theo dấu vết tới sơn cốc trước dãy núi, dùng cấm chế kiểm tra và nhận ra Mai Hoa Thập Bát Cấm do lão bà áo xanh mới bố trí. Hắn nhìn ra tầng Sinh Tử Cấm hút sinh cơ cỏ cây bên trong trận chưa hoàn thành, rồi không phá trận mà thêm ký hiệu Phá Diệt Tâm Cấm của mình để biến mai phục thành phản bẫy có thể khiến lão bà áo xanh hoặc Thương Tùng Tử trọng thương. Sau đó hắn nhớ lời Lý Nguyên về Tứ Đại Cấm Thuật, vượt dãy núi, cảm nhận Thương Tùng Tử ở sâu trong sương mù và tiếp tục truy tung.","anchor":"Ta không mở trận pháp này ra mà thêm những ký hiệu và cấm chế của mình vào trận pháp chưa hoàn thành này","bridge":true,"khoang":"@c1118"},{"mucCt":"vua","text":"Vương Lâm xuất hiện sau khi Thương Tùng Tử và cô gái áo xanh đã tiến vào lỗ hổng trên Tuế Nguyệt Cấm. Hắn không vội xông vào mà bố trí nhiều cấm chế bên ngoài rồi mới vượt qua lỗ hổng.","anchor":"Sau khi bố trí bên ngoài rất nhiều cấm chế","bridge":true,"khoang":"@c1119"},{"chuong":"@c1121","importance":"normal","mucCt":"ky","tieuDe":"Đoạt bình ngọc","text":"Vương Lâm đã giấu tâm thần khi tiến vào lỗ hổng, chờ thời cơ giữa cuộc giao chiến của Thương Tùng Tử và lão phụ nhân áo xanh. Hắn hiện thân như bóng trắng với tốc độ Toái Niết hậu kỳ, lướt qua hai bên, chụp lấy bình ngọc rồi lao ra khe nứt. Sau khi thoát ra, hắn vỗ cấm chế làm tấm màn khép nhanh hơn, dùng cấm chế đặt sẵn làm Thương Tùng Tử khựng lại, dán hai tấm phù để kéo giãn khoảng cách với lão phụ nhân, đánh tan đuôi bò cạp độc và nhận ra ngón tay khổng lồ là Thiên Vận Nhất Chỉ liên quan đến Thiên Vận Tử.","anchor":"Khoảnh khắc này có một bóng người màu trắng lóe lên, hình bóng này dùng tốc độ của tu sĩ Toái Niết hậu kỳ lướt qua người lão bà áo xanh rồi lướt qua Thương Tùng Tử."},{"chuong":"@c1122","importance":"normal","mucCt":"ky","tieuDe":"Tam Xoa Kích xuất thế","text":"Vương Lâm đoạt bình ngọc nhưng không thể cất vào không gian trữ vật nên dán hai tấm phù tăng tốc bỏ chạy trước Thiên Vận Nhất Chỉ và ba luồng Sinh Tử Cấm. Hắn hóa thân Cổ Thần hơn ba trăm trượng, dùng một quyền đánh tan Thiên Vận Nhất Chỉ rồi triệu Tam Xoa Kích đen từ khe nứt mặt đất, chém đứt và thôn phệ Sinh Tử Cấm. Sau khi cảnh cáo Thương Tùng Tử cùng lão phụ nhân áo xanh, hắn dụ lão phụ nhân vào sơn cốc đã bố trí cấm chế, điều khiển ngược vòng xoáy khói đen để vây bà ta, rồi chính diện nghênh chiến Thương Tùng Tử bằng Tam Xoa Kích.","anchor":"Vương Lâm đã trở thành một người khổng lồ trên ba trăm trượng"},{"chuong":"@c1123","importance":"normal","mucCt":"ky","tieuDe":"Huyết chiến Thương Tùng Tử","text":"Sau Nhất Tổn Nhị Kiếp, Vương Lâm được xác nhận là Cổ Thần chân chính nên có thể kích hoạt thần thông thôn phệ của Tam Xoa Kích, khiến kích hóa Hắc Long thôn phệ Sinh Tử Cấm và Tinh Kiếm. Trong trận chiến với Thương Tùng Tử, hắn lần lượt dùng Tam Xoa Kích, Hô Phong, Hoán Vũ, Phong Tiên Ấn, Diệt Thần Thương hư ảnh, chưởng ấn, Thiết Kiếm và Dịch Linh Ấn để chống lại các sát chiêu liên hoàn. Cuối trận hắn bị tia chớp đánh vào ngực, bị cây đinh bảy màu ghim vai phải, thân thể Cổ Thần thu nhỏ về bình thường rồi thu pháp bảo rút đi trong khi La Bàn khổng lồ vẫn truy kích.","anchor":"Dù tu vi của Vương Lâm không bằng Thiên Vận Tử, nhưng hắn lại là Cổ Thần."},{"chuong":"@c1124","importance":"normal","mucCt":"ky","tieuDe":"Phá La Bàn, hôn mê bất tỉnh","text":"Sau trận chiến với Thương Tùng Tử, trọng thương tái nhợt, thu gom Thiết kiếm gãy đôi, chiến hồn và vật giống nguyên anh huyết sắc của Thương Tùng Tử. Bị La Bàn khổng lồ liên tục truy kích phóng ký hiệu bảy màu, bị thương thêm phun máu tươi. Dồn toàn bộ lực Cổ Thần còn sót vào Tam Xoa Kích, kích hoạt giáp Chu Tước từ mắt trái tạo biển lửa, mắt phải phóng sấm sét tạo địa ngục lôi quang ngàn trượng, ngưng tụ thành ngọn núi sấm sét bao ngoài thân. Thi triển Cửu Huyền Biến phân thân chín rồi hợp nhất tăng khí tức, phóng thẳng lên phá nát La Bàn thành bốn năm mảnh. Sau đó miễn cưỡng giữ thần trí vào động phủ bỏ hoang, mở khe nứt trữ vật thả Ngân Y Nữ Thi và Hứa Lập Quốc ra hộ pháp rồi ngã hôn mê bất tỉnh.","anchor":"trong mắt Vương Lâm lộ ra vẻ điên cuồng, tính cách của hắn là vậy, càng nguy cấp, càng là núi lở trước mặt thì tâm thần càng tỉnh táo và điên cuông"},{"chuong":"@c1125","importance":"normal","mucCt":"ky","tieuDe":"Ép đinh bảy màu ra khỏi thân thể","text":"Tỉnh dậy sau hôn mê, phát hiện đinh bảy màu găm vào xương vai phải và nguyên thần, liên tục phá vỡ xương cốt, hấp thu sinh cơ. Tổng kết tình hình các đối thủ: Thương Tùng Tử chỉ nguyên thần thoát, lão bà áo xanh bị nhốt trận pháp có Phá Diệt Tâm Cấm, Vân Hồn Tử bị truyền tống đi, Trần Thiên Quân bỏ đi sớm chưa chắc đã chết. Cố tự rút đinh thất bại, hào quang bảy màu lan sang toàn bộ khung xương phải kèm luồng tức giận lạ xâm nhập tâm thần. Thu được bình ngọc chứa chất lỏng đen — mục tiêu thật sự của Thương Tùng Tử, suy đoán liên quan tu vi. Thu Hứa Lập Quốc và Ngân Y Nữ Thi vào trữ vật, rời động phủ. Dùng phương pháp liều mạng — lấy thân xác Cổ Thần chịu đòn trực diện từ ba mãnh thú ưng cấp 12, chuyển toàn bộ lực chấn động lên xương vai phải ép hào quang bảy màu ngưng tụ. Thân thể trọng thương gần tan vỡ nhưng cuối cùng ép được cây đinh bảy màu văng ra ngoài.","anchor":"Xác thị của Cổ Thần chỉ cần không chấn động quá mạnh thì đều có thể khôi phục trở lại trong khoảng thời gian cực ngắn"},{"importance":"normal","mucCt":"ky","chuong":"@c1126","tieuDe":"Dưỡng thương và kiểm kê chiến lợi phẩm, mở động phủ Tư Mã Mặc","text":"Sau khi chụp được cây đinh bảy màu, Vương Lâm lợi dụng lực phản chấn trốn vào đường ngầm trong núi, ba mãnh thú hình ưng không dám đuổi theo. Dưỡng thương hai ngày bằng lực Cổ Thần và đan dược, khôi phục hoàn toàn đến đỉnh phong. Kiểm kê chiến lợi phẩm: thu cây đinh bảy màu làm đòn sát thủ, đeo chiếc nhẫn chín tầng họ Bàng lên ngón cái tay trái phòng thân, phun nguyên khí tế luyện nguyên anh huyết sắc hình người của Thương Tùng Tử để xóa ký hiệu, rút Thủy Tinh Kiếm từ Tam Xoa Kích xác nhận phẩm cấp Thứ Không Niết Bảo. Nhận định thế giới bảy màu là vùng đất đầy bảo vật, cuộc chiến với Thương Tùng Tử thực chất là so sánh ai đoạt được nhiều pháp bảo hơn. Dựa theo ký ức Bàng Đức Tài tìm đến động phủ Tư Mã Mặc, phá tầng cấm chế hư ảo rồi dùng ngọc giản di vật Tư Mã Mặc mở Tuế Nguyệt Cấm tiến vào bên trong. Phát hiện sơn cốc trăm trượng có chín hang động cửa đá đóng kín, bộ hài cốt xương lộ sáng bảy màu ngồi tựa vách đá và ba ngọc giản. Đọc ngọc giản thứ nhất, biết được Tư Mã Mặc thuộc Vân Hải, từng cùng đồng môn khám phá khe nứt không gian bảy màu và phát hiện tồn tại đáng sợ cùng bí mật khổng lồ khiến tu chân giới khiếp sợ.","anchor":"Mất một đổi một, dù Thiết Kiếm đã bị gãy đôi nhưng lại nhận được cây đinh bảy màu sắc bén"},{"importance":"normal","mucCt":"ky","chuong":"@c1127","tieuDe":"Đọc ngọc giản Tư Mã Đặc, phát hiện hạt châu Thiên Nghịch","text":"Đọc ba khối ngọc giản của Tư Mã Đặc, biết toàn bộ quá trình vài trăm năm đồng môn Phá Thiên Tông trong thế giới bảy màu: lần lượt thành Mê Thất Giả, Minh Chí Giả, Nghịch Hành Giả; Tư Mã Đặc học Tuế Nguyệt Cấm bảo hộ sơn cốc, phát hiện hạt châu phong ấn Nghịch Hành Giả, bị cây đinh bảy màu đâm gây ý niệm điên cuồng, cuối cùng ý thức kéo dài nhìn thấy Chưởng Tôn. Liên hệ cây đinh bảy màu với sự điên cuồng của Thanh Thủy trước khi Tiên giới tan vỡ và tại Liên Minh Tu Chân. Suy luận thế giới bảy màu liên quan đến Thiên Vận Tử và Chưởng Tôn, nơi đây chính là khe nứt không gian Phá Thiên Tông phát hiện. Mở động phủ thứ nhất trên vách đá, tìm thấy mười hạt châu nổi lơ lửng, nhận ra chính là loại Thương Tùng Tử dùng triệu hoán thần thông Nghịch Hành Giả. Đảo thần thức xem kỹ, phát hiện trên hạt châu có chữ Thiên Nghịch, liên hệ trực tiếp đến Nghịch Thiên Châu.","anchor":"Vẻ mặt Vương Lâm trở nên kinh hoàng, hắn hít vào một hơi thật sâu rồi vô thức lui người ra phía sau vài bước"},{"chuong":"@c1128","importance":"normal","mucCt":"ky","tieuDe":"Đoạt đan dược và luyện hóa trong động phủ","text":"Nhận ra hạt châu tìm thấy là bản mô phỏng Thiên Nghịch do người xưa tế luyện nhằm tạo Tiên Nghịch, suy đoán kẻ chế tạo có lẽ cũng là Chưởng Tôn. Thu hơn mười mấy hạt châu phong ấn thần thông vào trữ vật, xem là sản phẩm thất bại. Nghi vấn thân phận Thương Tùng Tử vì thần thông cuối lão triệu hồi trận pháp thứ bảy Phong giới giống hệt hai người Ngoại giới năm xưa. Khám phá ba động phủ: động phủ thứ hai có lò luyện đan khổng lồ và dược liệu. Dùng trận pháp hình thoi chuyển hướng khí tức hủy diệt của trận bảo vệ trong động phủ thứ ba, chộp được ba bình đan dược mà không làm đan tan vỡ. Giám định ba bình: đan cấp mười một, Vụ Hồn Đan cấp mười hai, đan cấp mười ba có tiếng gầm vượt xa mãnh thú cấp mười hai khiến hắn tái mặt đóng nút. Bắt đầu luyện hóa lại đan cấp mười một trong lò vì bỏ thân Cổ Thần chỉ còn Tịnh Niết sơ kỳ, không nuốt trực tiếp được.","anchor":"Chỉ trong nháy mắt này Vương Lâm đã chộp được ba bình đan dược"},{"chuong":"@c1129","importance":"major","mucCt":"ky","tieuDe":"Chứng ngộ đạo niệm thật-giả","text":"Tại động phủ Tư Mã Đặc, bố trí cấm chế và thả Văn Thú ra cho thôn phệ thú hồn kèm vài vạn nguyên tinh để hồi phục. Luyện đan hai ngày từ thú hồn ra chất lỏng màu vàng thu vào ba bình. Uống lần lượt ba bình đan dược, dùng minh ngộ thiên địa của thú hồn làm đối chứng chứng minh đạo niệm bản thân, vứt bỏ đạo niệm sai lệch ra ngoài cơ thể. Ngộ ra thật và giả không cần tách biệt hoàn toàn — đây là thay đổi lần thứ hai của đạo niệm. Đạo niệm bùng ra bao phủ hơn phân nửa thế giới bảy màu, tạo vòng xoáy hút mọi ý cảnh, khiến Thương Tùng Tử không thể tiến lên, Mê Thất Giả, Minh Chí Giả, mãnh thú cấp mười hai đều tụ về nghe đạo. Trong lúc chứng ngộ, tâm thần mơ hồ xuất hiện âm thanh bí ẩn nói về bỏ đi đạo niệm sai lệch, dâng tặng Tu Chân Hành.","anchor":"Không có giả sao có hiện thực, không có thật tại sao có giả? Thật và giả không cần phải tách biệt ra hoàn toàn"},{"chuong":"@c1130","importance":"normal","mucCt":"ky","tieuDe":"Đạo niệm tán ra, tâm thần thoát thể quét khắp thế giới bảy màu","text":"Trong trạng thái minh ngộ sâu, Vương Lâm uống sạch ba viên đan dược cấp mười một, tiếp tục dùng đan dược cấp tám đến mười từ Bồng Lai đại lục bay qua khe nứt không gian. Đan dược đến gần tự tan vỡ, thú hồn bên trong bị cuốn vào vòng xoáy đạo niệm để đối chiếu. Đạo niệm hỗn tạp tản ra bao phủ toàn thế giới bảy màu, khiến Mê Thất Giả dần có thần thái, Minh Chí Giả có cảm giác thực chất, mãnh thú cấp mười hai mất hung tính, đạo tâm Thương Tùng Tử ầm ầm suy sụp. Tâm thần thoát khỏi cơ thể, quét qua sơn cốc gây chấn động khắp nơi. Tâm thần xuyên qua Tuế Nguyệt Cấm không bị ngăn cản, nhìn thấy lão bà áo xanh trong trận pháp Phá Diệt Cấm kết hợp Sinh Tử Cấm, đạo tâm hỗn loạn tướng mạo biến đổi liên tục. Phát hiện hai ngọn núi bí mật: ngọn thứ nhất chứa bia đá không chữ toát khí tức tang thương giống pháp khí, ngọn thứ hai có tượng đá khổng lồ với cửa đá ký hiệu tia chớp chứa kho thú hồn phong ấn từ cấp bảy đến cấp mười ba cùng thiếu nữ giống lão bà áo xanh đang thổ nạp. Trong không gian ẩn giấu ngọn núi thứ hai, phát hiện nửa bộ hài cốt bị hai cây đinh bảy màu ghim, trên xương khắc chữ dày đặc nội dung là dâng tặng Tu Chân Hành — chính là âm thanh từng vang vọng trong tâm thần hắn trước đây, gây chấn động mãnh liệt. Sau đó tâm thần lần đầu xuyên sương mù vào vùng sâu thế giới bảy màu, phóng qua ba thanh niên ba tộc (Thiên Lôi, Hỏa Tước, trăng lưỡi liềm) gây chấn động dữ dội cho cả ba.","anchor":"Tâm thần của Vương Lâm chậm rãi bùng ra, lấy sơn cốc làm trung tâm mà tản ra khắp bốn phía"},{"chuong":"@c1131","importance":"normal","mucCt":"ky","tieuDe":"Đối đầu lão già Toái Niết và truy sát Thương Tùng Tử","text":"Tâm thần thăm dò ngọn núi bí ẩn trong thế giới bảy màu, bị lão già tóc trắng tu vi Toái Niết hậu kỳ phóng thần thức hóa bàn tay khổng lồ tấn công. Triệu hồi toàn bộ đạo niệm đã vứt bỏ trong thế giới bảy màu ngưng tụ thành vòng xoáy phòng thủ, khiến lão già phải ngừng tay và cảnh cáo rồi lui về. Quay về thân thể, ngưng tụ đạo niệm thành khối tinh thạch đen có uy lực phá đạo tâm tu sĩ Toái Niết. Nhận ra nhờ kinh văn trên nửa bộ hài cốt mà ý cảnh đã đột phá, chỉ cần ngưng tụ một thời gian ngắn là đạt Tịch Niết trung kỳ. Truy sát Thương Tùng Tử, triệu hồi Cổ Thần Đại Đỉnh thi triển thần thông Đổi vị hoán đổi vị trí hai người, áp sát tung chưởng tấn công.","anchor":"chỉ cần một khoảng thời gian ngắn để ngưng tụ thì có thể đạt đến Tịnh Niết trung kỳ"},{"chuong":"@c1132","importance":"normal","mucCt":"ky","tieuDe":"Giết Thương Tùng Tử, lần đầu dùng đinh bảy màu","text":"Triệu hư ảnh Cổ Thần tung quyền phá sấm sét Thương Tùng Tử, dùng nguyên thần Thái Cổ Lôi Long hấp thu toàn bộ sấm sét đối phương rồi phản đòn. Lần đầu sử dụng cây đinh bảy màu ném xuyên huyết quang phòng ngự, ghim ngực Thương Tùng Tử khiến thân xác nổ thành sương máu, nguyên thần bị ghim. Thừa cơ dùng sưu hồn trích ký ức nguyên thần, đoạt sạch không gian trữ vật của lão. Thương Tùng Tử phát cuồng chết, hóa hạt huyết châu bay lên trời. Vương Lâm chụp huyết châu, Nghịch Thiên Châu trong nguyên thần tự phát phản ứng phát lực hút qua cánh tay phải, thu hồi cây đinh bảy màu trở lại. Qua ký ức sưu hồn, nắm được thông tin về tượng đá Thương Tùng Tử ngưng tụ thân, ba thanh niên ngoại giới, lão bà áo xanh có Sinh Tử Cấm, và Tuế Nguyệt Cấm của Tư Mã Mặc. Đạt thỏa thuận với Trần Thiên Quân: cho hắn dùng công pháp Dịch Thiên Tông thu nguyên tinh từ mãnh thú hóa sương, đổi lại mang hắn rời thế giới bảy màu, đưa ngọc giản truyền âm. Trở về động phủ bố trí trận pháp nguyên tinh, bắt đầu thổ nạp xung kích Tịnh Niết trung kỳ. Trong cung điện bí ẩn ở cấm địa Thái Cổ tinh vực, ngọc giản mang tên Thương Tùng Tử vỡ rồi nghịch chuyển tái ngưng tụ đổi tên thành Vương Lâm — linh hồn hắn bị thế lực bí ẩn nhắm đến.","anchor":"đây là lần đầu tiên hắn sử dụng đinh bảy màu"},{"chuong":"@c1133","importance":"normal","mucCt":"ky","tieuDe":"Đột phá Tịnh Niết trung kỳ và giải mã đạo tủy","text":"Trong động phủ Tư Mã Đặc ở sơn cốc thế giới bảy màu, hấp thu toàn bộ nguyên lực thiên địa, nguyên thần phóng to thôn phệ nguyên lực, đột phá thành công Tịnh Niết trung kỳ. Tự đánh giá nếu đạt Tịnh Niết đại viên mãn kết hợp thân thể Cổ Thần thì lão quái Toái Niết hậu kỳ cũng không phải đối thủ. Lấy bình ngọc cướp từ Thương Tùng Tử, nhờ ký ức đoạt được mà giải mã bản chất chất lỏng bên trong là đạo tủy — được tạo bằng cách dùng Mê Thất giả thôn đạo, Minh Chí giả nuôi đạo, dung nhập vào bia đá, rồi dùng kinh văn trên hài cốt chuyển hóa ép đạo ra khỏi hài cốt hóa thành huyết dịch. Uống đạo tủy sẽ có được đạo tâm chủ nhân hài cốt nhưng rơi vào ngủ say vô thời hạn. Suy đoán chủ nhân hài cốt kiếp trước uy danh hiển hách, mọi tồn tại trong thế giới bảy màu đều phục vụ cho cơ chế bia đá hấp thu cảm ngộ đạo, mãnh thú vừa đạt cấp mười ba liền bị giết hút đạo hồn. Khám phá động phủ thứ tư đến thứ tám: động phủ thứ tư trống rỗng; động phủ thứ năm có cấm chế Tuế Nguyệt Cấm, chứa bốn Mê Thất giả và ngọc giản; động phủ thứ sáu chứa ba Minh Chí giả bị phong ấn và ngọc giản; động phủ thứ bảy chứa lão già tóc hoa râm bị cấm chế dày đặc phong ấn, nghi là Nghịch Hành Giả; động phủ thứ tám chứa nửa bộ hài cốt phần dưới có kinh văn đen và lực hút tâm thần khổng bố. Nhận ra tất cả những người trong ba động phủ đều là đồng môn Tư Mã Đặc bị đưa về phong ấn cố cho thức tỉnh nhưng thất bại. Không cam lòng bỏ đi, tự bấm cấm chế phong tỏa tâm thần, rút Thủy Tinh Kiếm truyền tâm thần lên, tiến đến bên hài cốt đặt tay lên vết nứt sâu trên đùi phải dung nhập tâm thần vào bên trong cảm ngộ — khoảnh khắc thần thức đụng hài cốt, trong đầu nổ đùng lên một tiếng.","anchor":"Khoảnh khắc khi thần thức Vương Lâm đụng vào hài cốt thì trong đầu đột nhiên nổ đùng lên một tiếng"},{"chuong":"@c1134","importance":"normal","mucCt":"ky","tieuDe":"Chứng kiến ảo cảnh Chiến Tinh Dã bị giết, Chiến Tự Thiếp dung hợp","text":"Chạm vào nửa bộ hài cốt trong động phủ thứ tám, tâm thần bị cuốn vào ảo cảnh chứng kiến Chiến Tinh Dã bị kẻ tự xưng bản tôn dùng thần thông bảy màu Thiên Địa Thái Sơ phong ấn giết chết chỉ một chiêu. Được Thủy Tinh Kiếm tự động phóng tới cắt đứt liên kết cứu thoát khỏi ảo cảnh. Suy luận kẻ giết Chiến Tinh Dã sở hữu lực lượng thái sơ, thần thông bảy màu cùng loại Tàn Dạ nhưng vượt xa, có thể là Chưởng Tôn. Nhận ra mưu kế Thiên Đạo Kế: Chưởng Tôn tặng Chiến Tự Thiếp cho Chiến Tinh Dã tu luyện rồi giết lấy chiến hồn làm dẫn tìm xương cốt Chiến Lão Quỷ Không Kiếp, bức ra đạo tủy hai sư đồ. Lấy ba bức Chiến Tự Thiếp từ không gian trữ vật, kim quang từ hài cốt bùng ra nhập vào khiến ba bức dung hợp thành một, xuất hiện chữ chiến kim sắc hư ảo, thu Chiến Tự Thiếp hoàn chỉnh. Rời động phủ, để lại nguyên tinh cho hài cốt Tư Mã Mặc tại động phủ đầu tiên. Đi qua trận pháp phong ấn lão bà áo xanh đã bị mở, tiến vào sương mù nơi có nhiều Minh Chí Giả. Phóng đến tượng đá khổng lồ, từ ký ức Thương Tùng Tử hiểu được công pháp Bách Thế Huyết Nguyên Hóa Anh — triệu hồi Đệ Thất Linh của Phong giới, tạo chín nguyên anh mỗi cái tự ngưng tụ thần thông.","anchor":"Lão tổ Chiến gia, Chiến Tinh Dã!"},{"chuong":"@c1135","importance":"normal","mucCt":"ky","tieuDe":"Khuất phục sấm sét tượng đá bằng con đường nghịch thiên","text":"Vương Lâm từ chối con đường quy thuận thờ phụng tượng đá mà Thương Tùng Tử đã chọn, quyết dùng tôn nghiêm Cổ Thần và sức mạnh nghịch tu để bắt buộc sấm sét khuất phục. Hắn triệu hồi nguyên thần Thái Cổ Lôi Long thôn phệ con rồng sấm sét do tượng đá phóng ra, đồng thời huyễn hóa cánh tay Cổ Thần khổng lồ bóp nát rồng sấm sét. Lôi cầu trăm trượng bao phủ quanh hắn cuối cùng chịu khuất phục, hóa tia chớp phóng vào nguyên thần Lôi Long khiến nó trở nên khổng lồ, sấm sét mắt phải tăng mạnh gấp bội. Hắn dung hợp lôi quang trong mắt phải thành ký hiệu tia chớp đánh vào mi tâm tượng đá, khiến hai mắt tượng đá bùng hào quang mở ra ảo cảnh tinh không. Trong ảo cảnh là trận pháp lớn như tinh vực giam cầm Luyện Khí Sĩ và Tiên nhân, bên ngoài có đám người kỳ dị chế giễu, bên trong có chín luồng hào quang tàn sát gồm Khai Thiên Phủ và tia chớp. Hắn tuyên bố tộc của tượng đá đừng hòng cướp đoạt quyền điều khiển lôi quang trước mặt hắn.","anchor":"Cái Vương Lâm muốn chính là bắt buộc tia chớp trong tượng đá phải khuất phục, phải khuất phục dưới hắn"},{"chuong":"@c1136","importance":"major","mucCt":"ky","tieuDe":"Dung hợp chữ Chiến, nhận di ngôn Chiến Tinh Dã, nghênh chiến Ngoại giới","text":"Hấp thu tia chớp từ mắt tượng đá xuyên vào mắt phải, chấn động nội tâm khi chứng kiến cảnh Tiên nhân bị Ngoại giới giết trong trận pháp năm xưa. Phóng đến ngọn núi Tuế Nguyệt Cấm, dùng Phá Diệt Cấm định vị vết nứt cũ do Thương Tùng Tử và lão bà áo xanh tạo ra, dùng Thủy Tinh Kiếm phóng kiếm quang mang khí tức Thứ Không Niết và Tam Xoa Kích xé toạc cấm chế, tiến vào không gian kỳ dị. Tìm thấy tấm bia đá khổng lồ cùng nửa bộ hài cốt bị hai cây đinh bảy màu ghim chặt. Lấy chữ Chiến hư ảo từ không gian trữ vật, kim quang từ hài cốt phóng ra dung hợp vào chữ Chiến rồi nhập mi tâm. Nhận di ngôn Chiến Tinh Dã truyền qua chữ Chiến, ý cảnh bắt đầu dung nhập chiến ý. Ba thanh niên Ngoại giới tập kích, Vương Lâm xoay người lại với nụ cười chế giễu, tuyên bố sẵn sàng nghênh chiến.","anchor":"sinh làm người kiệt xuất, chết cũng phải hy sinh oanh liệt, ta là tu sĩ, sao phải ngại một trận chiến?"},{"chuong":"@c1137","importance":"normal","mucCt":"ky","tieuDe":"Diệt hai tu sĩ Ngoại giới, thu hồi quyền lôi-hỏa","text":"Vương Lâm đối mặt ba tu sĩ Ngoại giới, bùng chiến ý và hồi tưởng trận chiến năm xưa bên cạnh Vọng Nguyệt trong hư vô. Hắn dùng tốc độ tuyệt đối bước tới, vỗ chưởng chuyển kiếm chỉ liên tiếp bốn lần đánh nát ngực người Thiểm Lôi Tộc, rồi bùng Chân Giả ý cảnh đạp tan trái tim đối thủ. Hắn dùng ký hiệu tia chớp trong mắt phải thu hồi tư cách điều khiển sấm sét của Thiểm Lôi Tộc, tuyên bố tộc này từ nay không được tranh đoạt lôi quang trước mặt hắn. Tiếp đó hắn phóng biển lửa từ mắt trái bao phủ mấy trăm trượng, khiến ngọn lửa do chính người Hỏa Tước Tộc điều khiển phản bội thiêu đốt chủ nhân, thân hóa tro bụi. Hắn hiển lộ bộ giáp Chu Tước, Chu Tước thật (trắng) xuất hiện từ thân hắn thôn phệ hoàn toàn Tộc linh chim lửa đen. Cuối cùng hắn gọi người thứ ba (ký hiệu trăng lưỡi liềm) là nô tộc, nói ngày xưa tộc hắn dám tự xưng thiên đạo, khiến kẻ kia hồn bay phách tán.","anchor":"Từ nay về sau bộ tộc của ngươi đừng hòng cướp đoạt quyền lợi điều khiển lôi quang trước mặt ta"},{"mucCt":"ky","text":"Giao chiến với thanh niên Nguyệt Phệ tộc, dùng lực lượng Cổ Thần áp đảo hoàn toàn Lực Phản Nguyệt và cấm thuật Nguyệt Cấm. Khi đối phương triệu hồi hư ảnh Cổ Thần, kích hoạt Cổ Thần Tinh Điểm trên mi tâm, dùng ngôn ngữ Cổ Thần với tư cách vương tộc ra lệnh linh hồn Cổ Thần tiêu tán, chính thức xóa bỏ quy ước Thái Cổ che chở Nguyệt Phệ tộc. Tuyên bố từ nay Cổ Thần sẽ không che chở cho Nguyệt Phệ tộc nữa. Đá gãy xương cốt thanh niên Nguyệt Phệ, ghim hắn vào hai cây đinh bảy màu trên bộ hài cốt dưới bia đá, sưu hồn lấy ký ức rồi để hắn chết dần trong tra tấn như Chiến Tinh Dã năm xưa. Ngọn lửa Chu Tước trên người đạt độ cao mới, liên tục kéo lên Chu Tước Đệ Tam Biến.","anchor":"bọn ngươi là những kẻ bảo vệ cho bộ tộc đã phản lại Cổ Thần, nghe theo mệnh lệnh của vương tộc Cổ Thần Vương Lâm ta, bọn ngươi hãy tán đi","bridge":true,"khoang":"@c1138"},{"chuong":"@c1139","importance":"normal","mucCt":"ky","tieuDe":"Chu Tước thức tỉnh lần ba, phá hủy Tuế Nguyệt cấm","text":"Chu Tước bạch sắc hót tiếng kinh thiên động địa rồi lao vào mắt trái Vương Lâm, ngọn lửa mắt trái chuyển từ đỏ thẫm sang trắng — đây là lần thức tỉnh thứ ba, cực kỳ hiếm từ viễn cổ trở về trước. Người ba lần thức tỉnh là linh hồn ngọn lửa thiên địa, có thần thông hiệu lệnh tất cả lửa. Toàn thân bùng ra biển lửa trắng uy lực hủy thiên diệt địa, Thần Ma Giáp không chịu nổi nhiệt hóa chất lỏng bị Vương Lâm hấp thu vào cơ thể. Thanh niên Nguyệt Phệ tộc bị tiêu diệt hoàn toàn, thân hóa nước máu, xương vỡ vụn chỉ còn hai khúc trên hai cây đinh bảy màu. Ngọn lửa trắng hủy diệt toàn bộ ngọn núi trong cấm chế, thiêu cháy mọi thú hồn dưới cấp mười hai khiến đạo niệm chúng dung nhập lửa trở thành vật Vương Lâm điều khiển. Tấm màn Tuế Nguyệt cấm bị xé rách, hóa hỏa cầu rồi sụp đổ hoàn toàn. Hắc khí bùng ra từ thân Vương Lâm cũng bị lửa đánh tan. Hệ quả xóa quy ước Thái Cổ lan tới cấm địa Nguyệt Phệ tộc khiến chín pho tượng Cổ Thần đồng loạt nứt vỡ sụp đổ.","anchor":"Chu Tước lầ tồn tại điều khiển tất cả lửa trong thiên địa"},{"chuong":"@c1140","importance":"normal","mucCt":"ky","tieuDe":"Chu Tước thức tỉnh lần ba — dục hỏa trọng sinh","text":"Thân thể Cổ Thần nứt nẻ khô khốc do khí nóng vô tận bùng ra từ bên trong, ngưng tụ nhanh hơn giải phóng, nguy cơ bị thiêu chết. Vương Lâm quyết định nghịch thiên: phong tỏa thất khiếu và toàn thân, giữ trọn ngọn lửa bên trong thay vì phát tiết ra ngoài. Ngọn lửa đạt đỉnh phong nổ tung, chuyển từ bạch sắc sang lam sắc, uy lực vượt xa lửa trắng, có thể đốt cháy nguyên thần và thân thể tu sĩ Toái Niết. Chu Tước lam sắc ra đời, Vương Lâm từ từ bước ra khỏi biển lửa xanh, hoàn thành dục hỏa trọng sinh. Biển lửa ngập tràn khắp thế giới bảy màu, phá hủy toàn bộ trận pháp cấm chế, xua tan sương mù dãy núi hình vòng cung lần đầu tiên sau rất nhiều năm. Mãnh thú hệ hỏa viên mãn (mãng xà) trước khinh thường lửa trắng, nay bị lửa lam thiêu chết hóa thành ý niệm dung hợp vào lửa.","anchor":"Tính cách Vương Lâm ẩn giấu sự kiên định và liều mạng, trong lòng lại có ý niệm nghịch thiên"},{"importance":"normal","chuong":"@c1141","mucCt":"ky","tieuDe":"Xác nhận ba Chân Giả ý cảnh, tấn công lão già tóc trắng","text":"Bước ra từ lửa lam sắc trong thế giới bảy màu, xác nhận Hoả, Lôi, Chiến đều đã thành Chân Giả ý cảnh, chỉ thiếu cơ hội dung hợp để tiến tu vi, không còn đối thủ dưới Thiên Nhân Suy Kiếp. Nói câu về loại đạo đắc đạo rồi điểm chỉ tấn công lão già tóc trắng. Chu Tước lam sắc tạo biển lửa vạn trượng, phá vỡ la bàn, đánh tan kiếm khí bảy màu và khí sát lục của Nghịch Hành Giả. Bị hơn mười Nghịch Hành Giả do lão già triệu tập đồng loạt tấn công.","anchor":"Hỏa, Lôi, Chiến đều đã trở thành Chân Giả ý cảnh của ta"},{"chuong":"@c1142","importance":"normal","mucCt":"ky","tieuDe":"Chu Tước lần ba — Phong ấn — Hai Dịch Linh Ấn đối đầu","text":"Đối mặt lão già tóc trắng (Toái Niết hậu kỳ), vứt bỏ Sinh Tử Ý Cảnh, dung hợp cảm ngộ lửa thay đạo cảnh, kích hoạt trạng thái Chu Tước thức tỉnh lần ba — ký hiệu lửa lam hiện trên mi tâm, Chu Tước lam sắc dung nhập mi tâm như nguyên thần, ngoài thân hiện bộ giáp Chu Tước lam sắc. Hiệu lệnh toàn bộ lửa lam trong thế giới bảy màu ngưng tụ về mình, biển lửa quét sạch thần thông đối phương, phá hủy chín khúc xương thú bảo hộ của lão già. Bị lão già thi triển Phong Thần thuật phong ấn đồ đằng ngọn lửa trên mi tâm, biển lửa lam tiêu tán. Bình tĩnh chuyển sang kích hoạt ký hiệu Thiểm Lôi tộc ở mắt phải, triệu tập sấm sét khắp thế giới bảy màu tạo thành địa ngục sấm sét. Khi lão già thi triển Dịch Linh Ấn hấp thu nguyên lực thiên địa, nhận ra ngay và cũng thi triển Dịch Linh Ấn đáp trả — hai bàn tay khổng lồ đồng thời xuất hiện khiến mặt đất nứt vỡ, phóng thẳng vào nhau.","anchor":"Khoảnh khắc này ta vứt bỏ Sinh Tử Ý Cảnh, để ngọn lửa bao phủ tâm thần, dung hợp cảm ngộ ngọn lửa để thay thế cho đạo cảnh"},{"chuong":"@c1143","importance":"normal","mucCt":"ky","tieuDe":"Kích hoạt Chiến Ý cảnh, đối đầu Tán Đạo thuật","text":"Dùng Dịch Linh Ấn giả (ẩn sấm sét và khí tức Cổ Thần) đối kháng bản thật của lão già tóc trắng, hai ấn va chạm xé đôi thế giới bảy màu, bị phản kích phun máu. Bị lão già tóc trắng thi triển Phong Thần thuật lần hai phong ấn ký hiệu Thiểm Lôi trên mi tâm. Bất đắc dĩ kích hoạt Chiến Ý cảnh truyền thừa từ Chiến Tinh Dã, mi tâm hiện chữ chiến kim quang, hóa thân chiến thần dùng thuần thể thuật cận chiến áp đảo lão già tóc trắng. Cuối cùng bị hào quang vàng Tán Đạo thuật bao phủ, thắng bại chưa phân.","anchor":"trên mi tâm Vương Lâm lại xuất hiện một chữ chiến"},{"chuong":"@c1144","importance":"normal","mucCt":"ky","tieuDe":"Bị đạo thuật xâm nhập ký ức, hóa thân Thiết Trụ","text":"Bị đạo thuật của lão già tóc trắng (Phong Diệt tộc) xâm nhập ký ức linh hồn, rơi vào ảo cảnh bản nguyên. Thế giới bảy màu biến mất, Vương Lâm hóa thành thiếu niên nông thôn tên Thiết Trụ đang đọc sách thánh hiền, coi toàn bộ cuộc đời tu tiên hơn nghìn năm chỉ là giấc mộng kỳ quái. Trong ảo cảnh gặp lại phụ thân, mẫu thân, Tứ Thúc đến báo tin Hằng Nhạc Phái tuyển đệ tử — tái hiện chính xác ký ức thưở đầu. Nghe nhắc Hằng Nhạc Phái, ký ức ập về: khảo nghiệm thất bại, rơi vực nhặt Nghịch Thiên Châu kèm tiếng thét kinh hoàng Thiên Nghịch, bị Đằng Lệ truy đuổi, thề diệt Đằng gia tóc bạc trắng trong một đêm, lĩnh ngộ lực lượng Cực. Xuyên suốt ảo cảnh bên tai vang giọng nói bí ẩn cực kỳ kinh hoàng khi nhận ra Thiên Nghịch và Cực đều ở trên một người. Cuối cùng tiếng kinh hoàng khiến bầu trời tan vỡ, ảo cảnh sụp đổ, thế giới quay về hào quang bảy màu.","anchor":"Trong giấc mộng này giống như ta đã trở thành tiên nhân… đã trải qua hơn một nghìn năm"},{"chuong":"@c1145","importance":"normal","mucCt":"ky","tieuDe":"Phá phong ấn Phong Thiên thuật, giết tu sĩ Toái Niết hậu kỳ","text":"Tỉnh khỏi Đạo thuật ép nhớ ký ức đau thương trong thế giới bảy màu, thề trả thù kẻ gây ra. Dùng chỉ kiếm phá nát thân xác lão già tóc trắng (Toái Niết hậu kỳ), truy kích nguyên thần. Trong cơn phẫn nộ, cưỡng chế phá tan phong ấn Phong Thiên thuật trên mắt trái — giải phóng lửa lam, rồi phá phong ấn trên mắt phải — giải phóng sấm sét. Lửa lam và sấm sét ngưng tụ thành cột lôi hỏa xuyên trời, tiêu diệt hoàn toàn nguyên thần lão già tóc trắng. Sau đó cảm nhận chữ Chiến trong cơ thể kích động trước thứ tồn tại trong ngọn núi sâu nhất thế giới bảy màu, chậm rãi tiến tới cửa động đỉnh núi — vị trí cao nhất thế giới bảy màu.","anchor":"ký hiệu phong ấn của Phong Thiên thuật bên trên xuất hiện dấu hiệu run rẩy"},{"chuong":"@c1146","importance":"normal","mucCt":"ky","tieuDe":"Rơi vào Sát Ngục, linh hồn bị hút vào cây hoa đỏ kết Đạo quả","text":"Bước vào cửa động trong thế giới bảy màu, toàn bộ hào quang bảy màu bị hút vào cơ thể, cảm giác điên cuồng giống Thanh Thủy năm xưa chiếm lĩnh tâm thần, rơi vào Sát Ngục mất hoàn toàn ý thức chỉ còn ý niệm giết chóc. Toàn bộ thế giới bảy màu mất hết ánh sáng chìm vào bóng tối. Linh hồn và nguyên thần hóa hồng quang thoát khỏi thân xác, phóng vào cửa động xuyên qua nham thạch. Bị lực hút cuốn vào cây hoa màu đỏ máu ở trung tâm tinh không bảy cây hoa, hoàn toàn tiêu tán bên trong cây hoa. Hài cốt trong cây hoa cùng linh hồn hóa thành chất lỏng đỏ nuôi Đạo quả. Trải qua chín mươi tám năm, Đạo quả đỏ máu ngưng tụ hoàn thành — cây hoa đầu tiên trong bảy cây kết quả.","anchor":"Vương Lâm đã mất đi tâm thần, mất đi ý thức, mất đi tất cả ký ức"},{"chuong":"@c1147","importance":"major","mucCt":"ky","tieuDe":"Thức tỉnh nhờ hạt châu Tiên Nghịch","text":"Sau 99 năm hôn mê trong thế giới bảy màu, thân thể Cổ Thần không thối rữa nhưng phủ đầy bụi. Trong Đạo quả cây bảy màu, thần thức hắn hấp thu lực lượng kỳ dị tạo ra hạt châu Tiên Nghịch. Sự xuất hiện của hạt châu khiến Vương Lâm thức tỉnh. Người nuôi hoa không phát hiện biến đổi này. Nhiều người (Lữ Yên Phi, Lô Vân Tòng, Lý Thiến Mai, Mộc Băng Mi, Thác Sâm) đều đang nhắc nhớ hoặc tìm kiếm hắn.","anchor":"Vương Lâm thức tỉnh vì hạt châu Tiên Nghịch xuất hiện"},{"importance":"bridge","mucCt":"vua","chuong":"@c1148","tieuDe":"Bị Thác Sâm truy tìm khắp Tứ Đại tinh vực","text":"Thác Sâm quét thần niệm khắp Tứ Đại tinh vực không tìm thấy khí tức của Vương Lâm, suy luận hắn đang ở Thái Cổ Tinh Thần và quyết tâm phá Phong Giới đại trận để truy sát.","anchor":"hắn đã tìm khắp Tứ Đại giới mà không phát hiện bất kỳ khí tức nào của Vương Lâm"},{"chuong":"@c1149","importance":"bridge","mucCt":"vua","text":"Khí tức bị Thác Sâm cảm nhận từ trong trận pháp Phong giới, trở thành mục tiêu thôn phệ để Thác Sâm thành Cổ Thần Bát Tinh chính thức.","anchor":"Chỉ cần ta lao ra ngoài và tìm được Vương Lâm để thôn phệ thì dù có hy sinh nhiều bao nhiêu cũng đáng"},{"chuong":"@c1150","importance":"normal","mucCt":"ky","tieuDe":"Hấp thu Đạo quả, đột phá Tịnh Niết hậu kỳ đại viên mãn","text":"Ý thức Vương Lâm tái sinh trong trạng thái mơ hồ bên trong Đạo quả cây hoa đỏ thẫm. Hấp thu toàn bộ đạo niệm về hỏa đạo, lôi đạo, chiến đạo từ vô số người tu qua các thời đại viễn cổ, thượng cổ, tiên giới, Tứ Đại Giới. Sáu yếu tố lôi, hỏa, chiến, thật giả, sinh tử, nhân quả dung hợp tạo thành quy tắc mới chưa từng có — đạo riêng của Vương Lâm. Đột phá từ Tịnh Niết trung kỳ lên Tịnh Niết hậu kỳ, rồi trực tiếp đạt Tịnh Niết hậu kỳ đại viên mãn, tiếp cận rất gần Toái Niết. Tuyên bố bản thân là chủ nhân chứ không phải nô lệ của Thiên Nghịch, yêu cầu cùng phân chia lợi ích. Lần đầu tiên phối hợp cùng Thiên Nghịch cướp đoạt lực lượng thiên địa.","anchor":"Ta là chủ chứ không phải là nô lệ của Thiên Nghịch!"},{"chuong":"@c1151","importance":"major","mucCt":"ky","tieuDe":"Đột phá Tịnh Niết đại viên mãn, quy tắc Chiến hình thành","text":"Nguyên thần bước ra từ cửa Thiên Nghịch tại Phong Giới, bình tĩnh để Thiên Nghịch tự diệt phân thân lão già áo đen bước thứ ba mà không hề ra tay. Thiên Nghịch co rút cuốn nguyên thần phá khai tinh vực vào hư vô biến mất. Trở về thân xác tại Thất Thải Giới sau trăm năm ngủ say, đột phá từ Tịnh Niết hậu kỳ lên Tịnh Niết đại viên mãn, khí tức tiếp tục tăng hướng Toái Niết sơ kỳ. Lửa mắt trái và thiểm điện mắt phải hóa hai dấu ấn dung hợp thành quy tắc mới chứa chữ Chiến, rơi vào mi tâm hợp nhất với đạo thật giả, thu nhỏ thành tinh điểm giống Cổ Thần Chi Tinh. Chủ động xuất vô số cấm chế phong ấn tu vi Toái Niết vì chưa hoàn toàn hiểu quy tắc mới, giữ ở Tịnh Niết đại viên mãn. Tự đánh giá có thể thắng Toái Niết hậu kỳ, quyết định tới Phong Tiên Giới bắt Văn Thú rồi xông vào Thần Tông.","anchor":"Tinh điểm này bất kề nhìn như thế nào dường như rất tương tự với Cổ Thần Chi Tinh"},{"chuong":"@c1152","importance":"normal","mucCt":"ky","tieuDe":"Tỉnh dậy sau 99 năm, thu phục Vân Hồn Tử","text":"Tỉnh dậy sau chín mươi chín năm ngủ say trong Thất Thải Giới, khí tức cường đại vượt bậc so với trước. Dùng uy áp cực mạnh gồm ngọn lửa lam, lôi đình, chiến ý và cảm giác con mắt thứ ba trên mi tâm trấn áp Vân Hồn Tử. Phóng ấn ký thao túng sinh tử vào mi tâm Vân Hồn Tử, thu làm nô bộc. Bay tới sơn cốc Tư Mã Mặc, thấy Văn Thú suy yếu thiếu nguyên tinh chưa lột xác xong, đau lòng đổ hết nguyên tinh ra cho Văn Thú hấp thụ. Sai Vân Hồn Tử mời Trần Thiên Quân, nhận túi nguyên tinh từ Trần Thiên Quân, hứa sẽ đưa hắn rời Thất Thải Giới.","anchor":"Chờ ta, ta sẽ đưa ngươi rời khỏi đây!"},{"chuong":"@c1153","importance":"normal","mucCt":"ky","tieuDe":"Đoạt Tuế Nguyệt cấm chế, hồn phách Thiên Vận Tử hấp thụ sương bảy màu, bị tồn tại thần bí chặn","text":"Dùng nguyên tinh từ túi trữ vật Trần Thiên Quân nuôi Văn Thú lột xác thành công sau trăm năm, thu Văn Thú lại coi là đòn sát thủ. Thu dọn toàn bộ vật phẩm động phủ kể cả lò luyện đan lớn. Dùng một quyền phá Tuế Nguyệt cấm chế trên động phủ thứ sáu và thứ bảy, đoạt ngọc giản ghi chép Tuế Nguyệt cấm chế (một trong tứ đại cấm chế), ghi nhớ toàn bộ rồi bóp nát ngọc giản để độc chiếm. Khám phá động phủ thứ chín: phá núi đá bằng hai quyền, phát hiện bộ xương hươu cắm đoản kiếm trong sương mù bảy màu vĩnh hằng. Dung hợp với hồn phách Thiên Vận Tử trong Phong Tiên Ấn, dẫn toàn bộ sương bảy màu vào cho hồn phách hấp thụ — trong quá trình đó thấy ảo ảnh Thiên Vận Tử thật sự có xác thịt. Rút đoản kiếm phong ấn từ bộ xương hươu (xương hóa tro), thu lại chưa giải phong ấn. Dẫn đoàn rời sơn cốc, dùng ấn quyết từ ký ức Thương Tùng Tử mở khe không gian tại biên giới Thất Thải Giới, nhưng bị tồn tại thần bí trong cơn lốc xoáy chặn lại — đòi đạo quả.","anchor":"Nuốt lấy đạo quả của bổn tôn, chẳng lẽ cứ như vậy mà rời khỏi sao?"},{"mucCt":"ky","text":"Đứng vững trước uy áp hủy thiên diệt địa nhờ quy tắc ý cảnh vờn quanh thân, không dung hòa với trời đất. Tung một quyền triệu hoán trăm vạn lôi đình đánh lên trời, hô hào ba người cùng chiến đấu tìm đường sống. Triệu Tam Xoa Kích từ tinh điểm mi tâm, dùng chiến ý cùng sức Cổ Thần quét ngang phá mở lỗ hổng trong cơn lốc xoáy. Giằng co với cơn lốc xoáy giật lại một nửa nguyên thần Trần Thiên Quân, phần kia bị nuốt mất. Phát hiện toàn bộ Thất Thải giới chính là lòng bàn tay khổng lồ đang nắm lại. Mi tâm hiện sáu tinh điểm Cổ Thần xoay nhanh cùng một quy tắc chi tinh do ý cảnh hóa thành, trông như thất tinh Cổ Thần. Cầm Tam Xoa Kích lao thẳng xuống đối đầu bàn tay.","anchor":"cả người giống như là một pho tượng chiến tiên, lao thẳng xuống phía dưới","bridge":true,"khoang":"@c1154"},{"mucCt":"ky","text":"Quyết chiến thay vì bỏ chạy trước bàn tay khổng lồ Thất Thải giới đang nắm lại bóp nát. Kích hoạt quy tắc chi tinh vượt cực hạn triệu hồi bảy con hắc long tấn công ngón tay út. Thi triển Hoán Vũ biến hóa mới lần đầu: mưa rơi, đóng băng rồi nổ băng tạo lực công kích vượt xa đóng băng đơn thuần. Mở Phong Tiên Ấn phóng toàn bộ chiến hồn (trừ Thiên Vận Tử) tự bạo tấn công. Thi triển Sơn Băng hiện năm ngọn núi lửa khổng lồ. Giải phóng toàn bộ Sát Lục Khí ngưng tụ thành Sát Lục Kiếm đỏ như máu đâm vào ngón tay út. Phá được nửa đầu ngón tay út nhưng phun máu, hào quang phòng hộ vỡ vụn, chiếc nhẫn chín tầng phong ấn của Bàng Đức vỡ nát hoàn toàn. Lao tiếp tới ngón tay trỏ, rút Thủy Tinh Kiếm bậc Không Niết phun máu kích hoạt rồi hạ lệnh tự hủy, lực nổ khiến ngón trỏ dừng lại. Lập tức rút chiếc búa xanh bậc Không Niết thứ hai từ túi trữ vật Thương Tùng Tử.","anchor":"hai mắt Vương Lâm lộ ra chiến ý","bridge":true,"khoang":"@c1155"},{"chuong":"@c1156","importance":"normal","mucCt":"ky","tieuDe":"Liều mạng phá ba ngón tay, hình thành quy tắc mới","text":"Vương Lâm phá phong ấn hai pháp bảo Không Niết (chiếc búa và Thủy Tinh Kiếm đã vỡ), giải phóng sức hủy diệt tấn công ngón trỏ bàn tay ngoại giới. Hai pháp bảo Không Niết tan vỡ, lực xung kích khiến thân thể Vân Hồn Tử vỡ nát, chỉ còn nguyên thần thê thảm thoát ra. Vương Lâm liều mạng triệu Cổ Thần đại đỉnh ra thực thể va chạm trực diện ngón trỏ, đại đỉnh sụp đổ vỡ vụn tạo gió lốc mảnh vụn phá hủy hoàn toàn ngón trỏ. Thu lấy nguyên thần gần tử vong của Vân Hồn Tử, trở thành người duy nhất còn sống trong Thất Thải giới. Ngón trỏ dù bị phá lại tự khôi phục với tốc độ cực nhanh, ba ngón còn lại đồng loạt tấn công. Ném Tam Xoa Kích hóa hắc quang cản ngón vô danh, bản thân lao thẳng đến ngón giữa. Kích hoạt quy tắc chi tinh trên mi tâm, toàn thân bùng cháy lửa lam kết hợp lôi đình, gào thét bất khuất khi bị ngón giữa đè xuống. Sức mạnh đạo quả đã hấp thu phong ấn trước đây bùng phát, dung hợp với lôi hỏa và chiến ý cảnh hình thành quy tắc mới chỉ thuộc về duy nhất Vương Lâm, tạo gợn sóng vặn vẹo như tuế nguyệt trùng điệp bao phủ ngón giữa. Ngược dòng nâng ngón giữa lên và phá hủy hoàn toàn. Trọng thương cực nặng, máu nhuốm đỏ thân thể, quy tắc chi tinh trên mi tâm dần mờ nhạt, nhưng vẫn giậm đất bay lên lao đến ngón vô danh. Nhận ra đối phương là ngoại giới chưởng tôn Lam Mộng Đạo Tôn của Thái Cổ Tinh Thần Lam Ti Tộc, cười dài kinh thiên động địa trước sinh tử.","anchor":"Sinh ra là người bất khuất, chết đi cũng là quỷ anh hùng!"},{"mucCt":"ky","text":"Bị bàn tay Lam Mộng Đạo Tôn dồn vào tuyệt cảnh trong Thất Thải giới, lần đầu tiên sử dụng toái tinh — phá vỡ tinh điểm thứ sáu trên mi tâm, nhất thời đạt sức mạnh thất tinh vương tộc Cổ Thần, thân thể vọt lên hơn hai ngàn trượng. Dồn toàn lực vào một quyền phá nát ngón vô danh nhưng thân thể nhanh chóng thu nhỏ còn trăm trượng, suy yếu nghiêm trọng. Đối mặt ngón cái — đòn chí mạng, tuyệt vọng trối trăng nhắc tới cha mẹ, Tư Đồ Nam, Thanh Thủy, Uyển Nhi, Mộc Băng Mi, Vương Bình, Lý Thiến Mai. Lấy vòng tay màu lam từ không gian trữ vật đeo lên tay trái, lam quang tỏa ra khiến Lam Mộng Đạo Tôn nhận ra phúc hữu của con gái, lập tức buông tha. Không do dự dùng ấn quyết từ ký ức Thương Tùng Tử mở khe không gian thoát về Vân Hải tinh.","anchor":"sau khi tinh điểm thứ sáu bị vỡ, là một quyền không cam lòng sau gần hai ngàn năm tu đạo của Vương Lâm","bridge":true,"khoang":"@c1157"},{"chuong":"@c1158","importance":"major","mucCt":"ky","tieuDe":"Trở về Vân Hải tinh vực","text":"Vương Lâm vọt ra từ đại lục hoang dã sâu nhất ngũ giai tinh vực Vân Hải, sắc mặt tái nhợt, phun máu. Khe nứt trong đại lục không còn tỏa bảy màu nữa. Vòng ngọc trên cổ tay đã chuyển từ màu lam sang màu xanh. Hắn tuyên bố trở về và sẽ hành hạ Lưu Kim Bưu.","anchor":"Vương mỗ đã trở về! Lưu Kim Bưu, để xem ta hành hạ ngươi thế nào."},{"chuong":"@c1159","importance":"normal","mucCt":"ky","tieuDe":"Trở về Vân Hải, tổng kết được mất","text":"Trở về bát giai tinh vực Vân Hải sau trăm năm trong Thất Thải giới, ngồi trên đại lục hoang dã hồi tưởng và tổng kết. Tự xác nhận tu vi đã tiến nửa bước vào Toái Niết. Tổn thất lớn: Thủy Tinh Kiếm bị đánh nát, chiến phủ tan tành, Cổ Thần đại đỉnh tan tành, đệ lục tinh Cổ Thần vỡ nát, nhưng ý cảnh biến thành quy tắc chi tinh vẫn còn, thân thể Cổ Thần có thể khôi phục theo thời gian. Lục soát ký ức hai nguyên thần ấn ký ngọn lửa và tia chớp rồi hút vào chữa thương, biết thêm về Thái Cổ Tinh Thần và Thái Cổ ngũ tôn. Xử lý ba nguyên thần: đáp ứng đưa Trần Thiên Quân về Dịch Thú Tông, lục soát thiên linh lão phụ nhân áo xanh lấy Sinh Tử Cấm rồi thả, thu Vân Hồn Tử vào khe trữ vật. Phát hiện Thiên Nghịch châu phỏng chế hoạt động khi dung hợp chiến hồn Thiên Vận Tử trong Phong Tiên Ấn, có thể triệu hoán thần thông Nghịch Hành Giả, tăng mạnh khả năng phòng ngự. Quyết định ưu tiên đi Phong Tiên giới bắt đàn lớn Văn thú để tung hoành Vân Hải, bay xuyên tinh vực với tốc độ vượt âm thanh.","anchor":"Hiện giờ mình đã tiến nửa bước vào Toái Niết"},{"mucCt":"ky","text":"Phi hành tốc độ cực hạn xuyên tinh vực lục giai khiến hơn mười lão quái chấn động bám theo quan sát. Không có ngọc giản thông hành, tăng tốc lao thẳng vào đại trận phong tỏa thất giai tinh vực, phá tan hoàn toàn. Dù thương thế chưa lành, thi triển Dịch Linh Ấn tạo chưởng ấn khổng lồ bao phủ cả đại lục, quét bay bốn tu sĩ Toái Niết ngăn đường khiến bọn họ phun máu, đánh bay đại lục tông phái trăm trượng. Chưởng ấn tiếp tục lao về phía trước đánh xuyên một đại lục hoang dã phân làm đôi. Các tông phái thất giai trên đường thấy uy lực kinh hoàng, chủ động huy động toàn lực đẩy đại lục dời đi mấy ngàn trượng nhường đường. Sau gần mười ngày dùng Dịch Linh Ấn mở đường, tới được tinh vực bát giai — nơi có Phong Tiên giới.","anchor":"Vương Lâm do dù thương thế chưa lành nhưng bốn đạo thần thức của tu sĩ Toái Niết muốn lưu ha lại là không có khả năng","bridge":true,"khoang":"@c1160"},{"mucCt":"ky","text":"Sau hai mươi ngày phi hành liên tục, Dịch Linh Ấn đã đạt cực hạn hấp thu sức mạnh thiên địa, Vương Lâm chặt đứt sự hấp thu ba ngày trước. Thương thế dần khôi phục nhờ nuốt đan dược dọc đường. Bỏ qua con đường mơ hồ biết được từ thời ở Bồng Lai vì đường vòng quá xa và không chắc chắn, quyết định đi đường thẳng xông vào Loạn Thú Vụ Giới để tiến vào bát giai tinh vực. Dùng Dịch Linh Ấn mở đường khiến sương mù tự lui, dập tắt biển lửa con rết cấp mười một dễ dàng. Phân tích chiến thuật hiệp đồng của bầy rết: con gần nhất liều chết kiềm chế, vài con trợ chiến trì hoãn tốc độ để rết cấp mười hai kịp tới. Quyết định phản kích giết mãnh thú đuổi theo để tránh bại lộ vị trí, xoay người giơ tay phải cách không điểm về phía mãnh thú.","anchor":"sau khi Vương Lâm suy tính, liền bỏ qua phương án này, mà quyết định đi theo đường thẳng, kiên quyết xông vào trong Loạn Thú Vụ Giới","bridge":true,"khoang":"@c1161"},{"chuong":"@c1162","importance":"normal","mucCt":"ky","tieuDe":"Quy tắc lửa diệt rết, đại chiến rết lam tại biên giới","text":"Dùng quy tắc lửa (chu tước thức tỉnh lần ba dung nhập quy tắc thiên địa) diệt nhiều rết cấp 12 chỉ bằng một chỉ, đại khai sát giới quét sạch mãnh thú cản đường. Bốn ngày xuyên Loạn Thú Vụ Giới theo Dịch Linh Ấn mở đường máu, tiếp cận biên giới tầng tám tinh vực. Tại biên giới, đại chiến con rết lam nghìn trượng (đã thoát xác nhiều lần còn ba trăm trượng), triệu biển lửa lam thẫm ngưng tụ thành chu tước lam đối đầu, nổ nửa thân rết khiến nó bỏ chạy, chu tước lui về nhập thân. Trận chiến gây chấn động khiến khí tức cấp 13 từ sâu nhất Loạn Thú Vụ Giới quét ra áp chế tất cả, Vương Lâm cũng tâm thần chấn động.","anchor":"Chu tước của Vương Lâm lần thứ ba thức tỉnh, lại hóa thành lửa dung nhập vào trong quy tắc, trở thành một quy tắc mới trong thiên địa"},{"mucCt":"ky","text":"Rời Loạn Thú Vụ Giới, Vương Lâm bước vào bát giai tinh vực. Cảm nhận luồng khí tức cấp mười ba nên bỏ qua con rết không truy sát, ưu tiên đến Phong Tiên Giới. Thu liễm thân hình, giảm tốc, vòng tránh các tông phái trong sương mù nồng đậm, cẩn thận tiến tới. Sau gần một tháng kể từ khi rời tầng năm, hắn tới gần lối vào đã bị tàn phá của Phong Tiên Giới mà không ai hay biết. Xuất hiện từ sương mù với đầu tóc bạc trắng nổi bật, thu hút ánh mắt hơn mười tu sĩ đang chuẩn bị tiến vào.","anchor":"hắn đã cảm nhận được một luồng khí tức cấp mười ba, chính luồng khí tức này đã khiến hắn bỏ qua không truy sát con rết kia","bridge":true,"khoang":"@c1163"},{"mucCt":"ky","text":"Sau một tháng đường, Vương Lâm tới cái khe lối vào Phong Tiên Giới tại bát giai tinh vực. Tản thần thức vào khe, thoáng thấy thế giới tràn đầy ánh sáng vàng bị cuồng phong bao phủ, thần thức nhanh chóng bị nuốt tiêu tan. Từ chối lời mời hợp tác của Lý Nguyên Lôi. Khi hơn một trăm Văn Thú đỏ thẫm dữ tợn phun ra từ khe cùng sương đỏ, Vương Lâm cưỡi trên một Văn Thú đặc biệt toàn thân màu vàng nhạt tiến về phía trước. Toàn bộ Văn Thú đỏ thẫm lộ vẻ cung kính né tránh, vờn quanh hộ tống hắn tiến vào bên trong Phong Tiên Giới.","anchor":"Ở dưới thân thể hắn rõ ràng là một Văn Thú đặc biệt toàn thân màu vàng nhạt","bridge":true,"khoang":"@c1164"},{"chuong":"@c1165","importance":"normal","mucCt":"ky","tieuDe":"Tiến vào Phong Tiên Giới, thu phục đàn Văn Thú","text":"Vương Lâm tiến vào Phong Tiên Giới qua khe nứt mở ra. Triệu hồi Văn Thú Vương (đã lột xác thành màu vàng nhạt), dùng nó để thu phục hơn hai trăm Văn Thú đỏ bên trong. Cảm nhận cảnh tượng gió vô biên và tiên khí nồng đậm tràn ngập giới này. Đánh giá thực lực Văn Thú đỏ — mỗi con tương đương Khuy Niết tu sĩ, loại đỏ sẫm ngang Khuy Niết hậu kỳ — và phấn chấn vì đây mới chỉ là ngoại vi.","anchor":"mà theo hắn biết thì đây mới chỉ là ngoại vi của Phong Tiên Giới mà thôi"},{"mucCt":"ky","text":"Mất hai ngày bay vòng quanh ngoại vi Phong Tiên Giới thu hoạch Văn Thú và tiên ngọc. Dùng Văn Thú Vương phát tiếng rống triệu hồi, thu phục thêm gần nghìn Văn Thú đợt đầu, trong đó gần trăm Văn Thú đỏ thẫm thần phục. Đàn Văn Thú mấy vạn con bất ngờ xuất hiện, trong đó có Văn Thú lam khí tức ngang Tịch Niết và khoảng ba trăm Văn Thú trắng khí tức Toái Niết. Dùng hai nghìn Văn Thú vây quanh ẩn thân thoát khỏi đại đàn. Thắc mắc về nguồn gốc Văn Thú Vương lấy từ Chu Tước Tinh và sự chênh lệch thực lực với Văn Thú cùng cấp trong Phong Tiên Giới. Từ bỏ chiến thuật dụ dỗ ra ngoại vi, quyết định mang hai nghìn Văn Thú tiến sâu vào Phong Tiên Giới tùy cơ ứng biến.","anchor":"Phong Tiên Giới đối với người khác mà nói thì đúng là vùng đất sinh tử, nhưng đối với ta, nơi này lại là kho báu lớn nhất của cuộc đời ta","bridge":true,"khoang":"@c1166"},{"mucCt":"ky","text":"Ngày thứ năm trong Phong Tiên Giới, dùng uy áp Văn Thú Vương khuất phục một Văn Thú lam đơn độc cảnh giới Tịch Niết sơ kỳ, đọc ký ức nó bằng thần thức, biết phía trước có Văn Thú Vương khác. Nảy kế hoạch giết các Văn Thú Vương khác để Văn Thú Vương của mình hấp thụ, nhằm thao túng toàn bộ Văn Thú thuộc hạ. Phóng quy tắc chi tinh từ mi tâm in lên Văn Thú Vương, nguyên thần dung nhập vào điều khiển, phong ấn uy áp ngụy trang nó thành Văn Thú lam bình thường, giao thân xác cho gần hai nghìn Văn Thú bảo vệ. Điều khiển Văn Thú Vương tiến sâu, dọc đường gặp nhiều đàn Văn Thú lam hàng trăm con, có con ngang Tịch Niết hậu kỳ, không bị phát hiện. Nhận định nơi sâu hơn ngay cả tu sĩ thiên nhân suy kiếp cũng khó sống sót. Tìm đến dãy núi khổng lồ ở rìa mảnh vỡ đại lục — lãnh địa Văn Thú Vương khác, phát hiện hai con Văn Thú trắng bám trên vách núi.","anchor":"những Văn Thú Vương này chết, bị Văn Thú của ta hấp thụ, thì có thể hoàn toàn thao túng tất cả những Văn Thú của chúng","bridge":true,"khoang":"@c1167"},{"mucCt":"ky","text":"Nguyên thần Vương Lâm điều khiển Văn Thú Vương (đã biến lam) xâm nhập vùng đất Văn Thú màu lam, dùng xúc tu kết hợp quy tắc chi tinh hạ sát liên tiếp bốn con Văn Thú lam cùng đẳng cấp, hút sạch tinh hoa huyết dịch. Một trong hai con Văn Thú màu trắng (khí tức tương đương Toái Niết) chủ động tấn công, hai bên va chạm mấy chục lần đều bị thương. Văn Thú Vương quan sát đối thủ rồi học theo thần thông tách lông để đối công. Cuối cùng Văn Thú Vương màu tím (chúa thật của vùng này) xuất hiện từ trong dãy núi nứt toác, dừng mắt nhìn Văn Thú Vương rồi truyền ra tiếng kêu khẽ.","anchor":"quy tắc chi tinh mà nguyên thần Vương Lâm ngưng tụ trên thân thể của Văn Thú Vương lập tức lóe lên","bridge":true,"khoang":"@c1168"},{"chuong":"@c1169","importance":"normal","mucCt":"ky","tieuDe":"Hạ sát Văn Thú Vương, Văn Thú tiến hóa thành tân Vương","text":"Cho Văn Thú giả vờ thần phục tiếng kêu vương giả của Văn Thú Vương màu tím (Toái Niết trung kỳ), tiếp cận gần rồi bất ngờ tấn công. Nguyên thần hiện ra, dùng cuồng phong cuốn bay hai Văn Thú trắng hộ vệ, liên tục điểm bốn chỉ lên lưng bàn tay trái tạo bốn dấu ấn quy tắc chi tinh hợp thành quy tắc thủ, in thủ ấn lên mi tâm Văn Thú Vương màu tím khiến nó trọng thương nặng trong ba hơi thở. Văn Thú tỏa lam quang rồi kim quang, phát tiếng kêu vương giả khiến toàn bộ đàn Văn Thú kính sợ ngừng chiến. Thi triển Định Thân Thuật dẫn động tiên lực vô tận của Phong Tiên Giới khóa chặt Văn Thú Vương màu tím, để Văn Thú dùng xúc tu hấp thụ toàn bộ tinh hoa đối phương, hoàn tất kế hoạch — Văn Thú Vương mới chính thức ra đời.","anchor":"Tất cả, toàn bộ đều phụ thuộc vào một chữ Nhanh! Nhanh!"}],"tuViMoc":[{"chuong":"@c1087","canhGioi":"Cổ Thần ngũ tinh — đang chịu Nhất Tổn Lưỡng Kiếp (Cốt Kiếp)","text":"Vương Lâm là Cổ Thần ngũ tinh đầu tiên trong ký ức Đồ Ti gặp Tổn Kiếp, điều không có tiền lệ. Tổn Kiếp đầu tiên (mất máu thịt) hoàn thành nhờ máu huyết Đồ Ti. Đang chịu Cốt Kiếp — xương cốt bị phá hủy dần từ chân.","importance":"major"},{"chuong":"@c1089","canhGioi":"Nhục kiếp (Nhất Tổn Nhị Kiếp)","text":"Cốt kiếp tiêu tán hoàn toàn, khung xương bản tôn ngưng tụ hoàn chỉnh. Nhục kiếp lập tức hàng lâm, ngăn cản máu thịt tăng trưởng nhằm xóa bỏ sinh cơ. Vương Lâm dùng máu Cổ Thần và sinh cơ mãnh thú để đối phó.","importance":"major"},{"chuong":"@c1090","canhGioi":"Cổ Thần Ngũ Tinh (hoàn chỉnh)","text":"Bản tôn vượt qua Nhất Tổn Nhị Kiếp (nhục kiếp), kiếp đầu tiên của Cổ Thần Tam Tổn Thất Kiếp. Chính thức thành Cổ Thần hoàn chỉnh (trước đây không hoàn chỉnh), tinh điểm thứ sáu mơ hồ hình thành. Khi Lục Tinh hoàn thành sẽ có thể diễn hóa Vọng Nguyệt từ cơ thể.","importance":"major"},{"chuong":"@c1095","canhGioi":"Chân Giả Ý Cảnh","text":"Mốc thuộc hệ ý cảnh, không phải tu vi chính: con đường đạo của Vương Lâm được tổng kết đã chuyển hóa qua Sinh Tử Luân Hồi, Nhân Quả Tuần Hoàn, Nhân Quả Viên Mãn rồi đến Chân Giả Ý Cảnh.","importance":"major"},{"chuong":"@c1123","canhGioi":"Cổ Thần chân chính","text":"Research xác nhận sau Nhất Tổn Nhị Kiếp, máu huyết và xương cốt của Vương Lâm đã ngưng tụ, trở thành Cổ Thần chân chính; đây là nền tảng để hắn mở thần thông thôn phệ của Tam Xoa Kích.","importance":"major"},{"chuong":"@c1131","canhGioi":"Tịch Niết trung kỳ (sắp đạt)","text":"Nhờ nhìn kinh văn trên nửa bộ hài cốt mà ý cảnh có đột phá, chỉ cần ngưng tụ một thời gian ngắn là đạt Tịch Niết trung kỳ.","importance":"minor"},{"chuong":"@c1132","canhGioi":"Tịnh Niết trung kỳ (đang xung kích)","text":"Bố trí trận pháp nguyên tinh quanh thân, bắt đầu thổ nạp nguyên lực thiên địa hướng đến Tịnh Niết trung kỳ.","importance":"minor"},{"chuong":"@c1136","canhGioi":"Ý cảnh dung nhập chiến ý","text":"Chữ Chiến hư ảo dung hợp kim quang hài cốt Chiến Tinh Dã nhập vào mi tâm, ý cảnh bắt đầu dung nhập chiến ý, xuất hiện biến hóa kinh người. Thuộc hệ ý cảnh, không phải tu vi chính.","importance":"major"},{"chuong":"@c1139","canhGioi":"Chu Tước thức tỉnh lần thứ ba","text":"Chu Tước bạch sắc lao vào mắt trái, ngọn lửa chuyển từ đỏ thẫm sang trắng. Người ba lần thức tỉnh là linh hồn ngọn lửa thiên địa, có thần thông hiệu lệnh tất cả lửa — từ viễn cổ đến nay gần như không ai đạt được.","importance":"major"},{"chuong":"@c1150","canhGioi":"Tịnh Niết hậu kỳ đại viên mãn","text":"Dung hợp lôi-hỏa-chiến cùng thật giả, sinh tử, nhân quả tạo quy tắc mới. Đột phá liên tục từ Tịnh Niết trung kỳ lên hậu kỳ rồi đại viên mãn nhờ hấp thu Đạo quả cây hoa đỏ thẫm dưới sự che giấu của Thiên Nghịch. Tiếp cận rất gần Toái Niết nhưng cảm ngộ chưa hoàn toàn chuyển hóa, cần thời gian.","importance":"major"},{"chuong":"@c1151","canhGioi":"Tịnh Niết đại viên mãn","text":"Nguyên thần dung nhập thi thể tại Thất Thải Giới, khí tức từ Tịnh Niết hậu kỳ tăng vọt qua đại viên mãn, tiếp tục hướng Toái Niết sơ kỳ. Chủ động phong ấn tu vi Toái Niết, giữ ở Tịnh Niết đại viên mãn chỉ cách Toái Niết nửa bước.","importance":"minor"},{"chuong":"@c1157","canhGioi":"Thất Tinh Cổ Thần (nhất thời, toái tinh)","text":"Chủ động phá vỡ tinh điểm thứ sáu trên mi tâm bằng toái tinh, nhất thời đạt sức mạnh tương đương thất tinh vương tộc Cổ Thần. Đây là lần đầu tiên dùng toái tinh kể từ khi tự xưng Cổ Thần. Tinh điểm bị phá không hồi phục, sau đó thân thể suy yếu nghiêm trọng.","importance":"major"},{"chuong":"@c1159","canhGioi":"Nửa bước Toái Niết","text":"Tự xác nhận tu vi đã tiến nửa bước vào Toái Niết sau trăm năm lịch luyện trong Thất Thải giới, nâng cấp đáng kể so với Tịch Niết sơ kỳ trước đó.","importance":"major"}],"nhanMach":[{"ten":"Vũ Đại","tag":"an-nhan","quanHe":"Đại hán Bắc Thủy Thôn cho Vương Lâm ở nhờ","ghiChu":"@c1069"},{"ten":"Triệu Ngọc","tag":"khac","quanHe":"Tu sĩ Quy Nguyên Tông, bị Vương Lâm áp chế khi ức hiếp thôn dân","ghiChu":"@c1069"},{"ten":"Lữ Yên Phi","tag":"su-mon","quanHe":"Đại trưởng lão Quy Nguyên Tông, thu nhận Vương Lâm (Tằng Ngưu) làm môn hạ","ghiChu":"@c1069"},{"ten":"Tôn Vân","tag":"khac","quanHe":"Nhị đệ tử Lữ Yên Phi, người tiếp nhận và sắp xếp chỗ ở cho Vương Lâm tại Quy Nguyên Tông","ghiChu":"Vương Lâm truyền âm ngăn nàng uống đan dược nguy hiểm"},{"ten":"Lữ Yên Phi","tag":"khac","quanHe":"Chưởng môn đệ tử / cao thủ hàng đầu Quy Nguyên Tông nơi Vương Lâm ẩn cư","ghiChu":"Chưa gặp mặt trực tiếp, Vương Lâm ở dưới quyền quản lý gián tiếp của nàng"},{"ten":"Tống Ngũ Đức","tag":"doi-thu","quanHe":"Đối thủ bị giết","ghiChu":"Vương Lâm giết Tống Ngũ Đức (Tịnh Niết Trung Kỳ) trong nháy mắt bằng tổ hợp Sát Lục Khí + Hoán Vũ + Định + Không Niết Kiếm"},{"ten":"Thiếu tông chủ áo tím","tag":"doi-thu","quanHe":"Mục tiêu truy đuổi","ghiChu":"Thiếu tông chủ Tử Đạo Tông, sau khi Tống Ngũ Đức bị giết, bị Vương Lâm truy đuổi"},{"ten":"Lô Địch","tag":"doi-thu","quanHe":"Thiếu tông chủ Tử Đạo Tông, bị Vương Lâm giết bằng một ngón tay","ghiChu":"@c1075"},{"ten":"Lô Vân Tòng","tag":"doi-thu","quanHe":"Tông chủ Tử Đạo Tông, phụ thân Lô Địch — tiềm ẩn thù hận","ghiChu":"@c1075"},{"ten":"Lữ Yên Phi","tag":"dong-minh","quanHe":"Tông chủ Quy Nguyên Tông, chủ động tạo thân phận che giấu cho Vương Lâm","ghiChu":"Vương Lâm đánh giá cao sự thông minh kín đáo của nàng"},{"ten":"Độc Bà Tử","tag":"doi-thu","quanHe":"Đối thủ giao chiến","ghiChu":"Lão bà Ngũ Độc Môn hiểu lầm Vương Lâm là viện binh đối thủ, chủ động tấn công tại trung tâm Man Hoang đại lục."},{"ten":"Tiền Quý Chung","tag":"doi-thu","quanHe":"Trưởng lão Hoa Thanh Tông, ra lệnh bắt Vương Lâm","ghiChu":"@c1084"},{"ten":"Lý Thiến Mai","tag":"doi-thu","quanHe":"Đối thủ tiềm tàng","ghiChu":"Nữ tu sĩ Toái Niết hậu kỳ Phá Thiên Tông nhận lệnh truy tìm kẻ đoạt ngọc giản Tư Mã Mặc — chính là Vương Lâm"},{"ten":"Tư Mã Mặc","tag":"khac","quanHe":"Gián tiếp — thu được ngọc giản chứa dấu ấn của Tư Mã Mặc, có thể dùng làm lệnh bài nhập môn Phá Thiên Tông"},{"ten":"Trừu Hải","tag":"doi-thu","quanHe":"Đệ tử hạch tâm Ngũ Độc Môn xâm nhập cấm địa, bị Vương Lâm đánh trọng thương","ghiChu":"@c1092"},{"ten":"Phùng Bội Sơn","tag":"doi-thu","quanHe":"Đệ tử hạch tâm Đạo Pháp Môn, chỉ huy nhóm truy tìm xâm nhập Mạc La đại lục","ghiChu":"@c1092"},{"ten":"Triệu Vũ","tag":"doi-thu","quanHe":"Đệ tử Ma Tùng Đạo, cùng nhóm xâm nhập Mạc La đại lục","ghiChu":"@c1092"},{"ten":"Lý Thiến Mai","tag":"khac","quanHe":"người muốn hỏi đạo","ghiChu":"Sau khi chứng kiến Vương Lâm phá ý cảnh của Lô Vân Tòng, nàng muốn hỏi hắn ba câu."},{"ten":"Lý Thiến Mai","tag":"dong-minh","quanHe":"Bạn đồng hành tạm thời trên đường tới Bồng Lai","ghiChu":"Nàng kể cho Vương Lâm nhiều bí mật về tinh vực cấp chín và dặn hắn giữ kín."},{"ten":"Dương Ngọc","tag":"doi-thu","quanHe":"Bị Dương Ngọc chất vấn lạnh lùng tại khu chợ Bồng Lai.","ghiChu":"Gặp lần đầu trong lúc đi cùng Lý Thiến Mai."},{"ten":"Âu Dương Long","tag":"dong-minh","quanHe":"Giao dịch nguyên tinh và được đối phương coi như bằng hữu.","ghiChu":"Lần đầu tiếp xúc tại khu chợ."},{"ten":"Sư thúc Dương Ngọc","tag":"doi-thu","quanHe":"Được đối phương hiện thân xin lỗi và mời đàm phán.","ghiChu":"Lão gọi hắn là Lữ đạo hữu."},{"ten":"Đường Lệ Hải","tag":"khac","quanHe":"Trưởng lão Ma Tùng Đạo gặp mặt và dò xét hắn trong lời mời làm trưởng lão ngoại sự.","ghiChu":"Quan hệ mới phát sinh tại Bồng Lai."},{"ten":"Ngô Thanh","tag":"khac","quanHe":"Trưởng lão Ma Tùng Đạo hỏi thẳng hắn về việc gia nhập làm trưởng lão ngoại sự.","ghiChu":"Quan hệ mới phát sinh tại Bồng Lai."},{"ten":"Nam tử trung niên bí ẩn","tag":"khac","quanHe":"Tu sĩ Ma Tùng Đạo ẩn thân quan sát hắn và đánh giá hắn cực kỳ nguy hiểm.","ghiChu":"Quan hệ mới phát sinh tại Bồng Lai."},{"ten":"Nam tử lưng hùm vai gấu","tag":"khac","quanHe":"Đệ tử Âu Dương Long tới mời và dẫn đường cho hắn.","ghiChu":"Quan hệ mới phát sinh tại Bồng Lai."},{"ten":"Bà lão áo xanh","tag":"dong-minh","quanHe":"Người tặng bản đồ tinh cầu thật và cảnh báo về Ngô Thanh","ghiChu":"Gặp sau buổi tụ hội @c1103"},{"ten":"Ngô Thanh","tag":"doi-thu","quanHe":"Địch thủ bị giết","ghiChu":"Ngô Thanh truy sát Vương Lâm nhưng bị Vương Lâm dùng Dịch Linh Ấn giết chết tại Bồng Lai.","gap":"@c1104"},{"ten":"Thương Tùng Tử","tag":"doi-thu","quanHe":"Kẻ tính kế","ghiChu":"Thương Tùng Tử cố ý mời Ngô Thanh tới Bồng Lai để mượn tay giết Vương Lâm rồi đoạt nguyên tinh.","gap":"@c1104"},{"ten":"Trương Kỳ","tag":"doi-thu","quanHe":"Đại diện Ma Tùng Đạo đến cầu hòa và bồi thường cho việc Ngô Thanh gây họa.","ghiChu":"Gặp tại Bồng Lai đại lục @c1105"},{"ten":"Đỗ Đức","tag":"dong-minh","quanHe":"Tán tu đến kết giao, cung cấp nguồn gốc lông vũ Chu Tước và ngọc giản Man Hoang đại lục.","ghiChu":"Bái phỏng ở khách điếm @c1105"},{"ten":"Tào trưởng lão","tag":"khac","quanHe":"Người tiếp đón và nhận bảo vật đấu giá","ghiChu":"Tào trưởng lão đại diện Bảo Ngọc Tông tiếp đãi Vương Lâm và xử lý hai bảo vật hắn gửi đấu giá."},{"ten":"Vân Hồn Tử","tag":"doi-thu","quanHe":"Bị Vân Hồn Tử khinh thường và sai âm hồn tấn công thử tại Man Hoang đại lục.","ghiChu":"Gặp trong nhóm do Thương Tùng Tử triệu tập @c1108"},{"ten":"Giao Long hóa sương cấp mười hai","tag":"doi-thu","quanHe":"Đối thủ trong trận vây công tại con đường hẹp có Hồi đan.","ghiChu":"Vương Lâm áp sát và đánh quyền vào thân Giao Long."},{"ten":"Người áo xám","tag":"khac","quanHe":"chạm mặt nguy hiểm","ghiChu":"Vương Lâm là người nhìn thấy rõ Mê Thất Giả xuất hiện và đi qua đoàn trong thế giới bảy màu."},{"ten":"Trần Thiên Quân","tag":"dong-minh","quanHe":"đồng hành tạm thời","ghiChu":"Cùng nhóm tiến vào thế giới bảy màu trước khi Trần Thiên Quân rút lui."},{"ten":"Lão già họ Bàng","tag":"doi-thu","quanHe":"Kẻ ở lại giám sát rồi trở mặt ám sát, bị Vương Lâm phản sát và giữ nguyên thần.","ghiChu":"Quan hệ đối địch bộc lộ tại @c1117"},{"ten":"Bàng Đức","tag":"doi-thu","quanHe":"Bị Thương Tùng Tử cho rằng sẽ bị Bàng Đức sưu hồn để lấy Dịch Linh Ấn.","ghiChu":"Quan hệ đối địch được nhắc qua tính toán của Thương Tùng Tử ở sâu trong sương mù."},{"ten":"Minh Chí Giả","tag":"khac","quanHe":"Gặp dấu hiệu tồn tại qua âm thanh và hư ảnh trong sương mù.","ghiChu":"Minh Chí Giả liên hệ trực tiếp tới bí mật Đạo Kinh trong thế giới bảy màu."},{"ten":"Lão phụ nhân áo xanh","tag":"doi-thu","quanHe":"Bị truy sát sau khi đoạt bình ngọc","ghiChu":"Lão phụ nhân dùng hư ảnh bò cạp độc và Sinh Tử Cấm truy kích Vương Lâm trong thế giới bảy màu."},{"ten":"Lý Thiến Mai","tag":"dong-hanh","quanHe":"người chứng kiến","ghiChu":"Lý Thiến Mai quan sát Vương Lâm ra tay và chấn động trước tâm trí của hắn.","gap":"@c1100"},{"ten":"Âu Dương Long","tag":"khac","quanHe":"người mời tới buổi đấu giá tư nhân","ghiChu":"Âu Dương Long dẫn Vương Lâm vào tòa thành trung tâm, qua trường đấu thú tới nơi đấu giá tư nhân."},{"ten":"Thanh niên áo vàng","tag":"doi-thu","quanHe":"người đấu giá Thần Ma Giáp với khách mua phía Vương Lâm","ghiChu":"Thanh niên Bí Lạc Tông đẩy giá Thần Ma Giáp lên cao, khiến vật của Vương Lâm có khả năng đổi được nhiều nguyên tinh."},{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Cường giả bí ẩn Ngoại giới, Tư Mã Đặc nhìn thấy khi ý thức kéo dài; Vương Lâm kinh hoàng khi đọc tên này","ghiChu":"@c1127"},{"ten":"Vũ Tôn","tag":"khac","quanHe":"Tồn tại cực kỳ hùng mạnh ở Ngoại giới, Vương Lâm biết từ động phủ Tiên Đế Thanh Lâm","ghiChu":"@c1127"},{"ten":"Lão già tóc trắng (ngọn núi thế giới bảy màu)","tag":"doi-thu","quanHe":"Đối đầu rồi lui bước","ghiChu":"Lão già Toái Niết hậu kỳ tấn công tâm thần Vương Lâm, sau thấy đạo niệm mạnh thì cảnh cáo rồi lui (@c1131)"},{"ten":"Chiến Tinh Dã","tag":"khac","quanHe":"Lão tổ Chiến gia La Thiên, Vương Lâm chứng kiến ảo cảnh hắn bị giết và thừa hưởng Chiến Tự Thiếp hoàn chỉnh","ghiChu":"@c1134"},{"ten":"Chiến Lão Quỷ","tag":"khac","quanHe":"Sư phụ Chiến Tinh Dã, chủ nhân gốc của Chiến Tự Thiếp, Vương Lâm suy đoán lão già trong Chiến Tự Thiếp chính là Chiến Lão Quỷ","ghiChu":"@c1134"},{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Kẻ bày mưu Thiên Đạo Kế giết Chiến Tinh Dã, Vương Lâm suy đoán hắn là Chưởng Tôn sở hữu lực lượng thái sơ","ghiChu":"@c1134"},{"ten":"Chiến Tinh Dã","tag":"an-nhan","quanHe":"Người truyền thừa chiến ý và di ngôn qua chữ Chiến hư ảo","ghiChu":"Nhận di ngôn và chiến ý của Chiến Tinh Dã khi chữ Chiến dung hợp kim quang hài cốt nhập mi tâm @c1136"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Ngoại giới chưởng tôn thi triển bàn tay năm ngón tấn công Thất Thải giới, đối thủ sinh tử","ghiChu":"Lam Mộng Đạo Tôn tuyên bố nếu Vương Lâm sống sót sẽ không giết"},{"ten":"Lưu Kim Bưu","tag":"doi-thu","quanHe":"Đối thủ / mục tiêu","ghiChu":"Vương Lâm tuyên bố trở về sẽ hành hạ Lưu Kim Bưu"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Tâm huyết Cổ Thần","moTa":"Khối tinh thể màu máu lớn lấy từ bên trong cơ thể huyết long, trước đó bị Thác Sâm đoạt hết, Vương Lâm bất ngờ thu được.","trangThai":"dang-co","nguon":"@c1064"}],"linhThao":[],"khac":[]},"diem":[{"text":"Đoạt xá thân Mã Lương sau khi tự nổ thân thể thoát khỏi tuyệt cảnh, mở ra giai đoạn tu đạo mới tại Hỏa Phần quốc","chuong":"@c0103"},{"text":"Dung hợp bổn tôn và phân thân thành một thể thống nhất, thức tỉnh tam tinh Cổ Thần vương tộc","chuong":"@c0365"},{"text":"Vượt Nhất Tổn Nhị Kiếp (cốt kiếp và nhục kiếp), trở thành Cổ Thần ngũ tinh hoàn chỉnh — Cổ Thần chân chính","chuong":"@c1090"},{"text":"Đạt Toái Niết đại viên mãn trên phương diện lôi tu sau khi luyện hóa sấm sét bất diệt và thôn phệ Từ Hợp lôi","chuong":"@c1282"},{"text":"Tu thành Cửu Huyền đệ nhất biến, chín hỏa nguyên dung hợp thành hư hỏa Chu Tước biến dị","chuong":"@c1017"},{"text":"Đạt thất tinh Cổ Thần vương tộc tại cổ mộ, manh nha tinh điểm thứ tám, cắt đứt truyền thừa Đồ Ti tự xưng Đạo Cổ","chuong":"@c1385"}]},"nguon":["@c1064","@c1065","@c1066","@c1067","@c1068","@c1069","@c1070","@c1071","@c1072","@c1073","@c1074","@c1075","@c1076","@c1077","@c1078","@c1079","@c1080","@c1081","@c1082","@c1083","@c1084","@c1085","@c1086","@c1087","@c1088","@c1089","@c1090","@c1091","@c1092","@c1093","@c1095","@c1096","@c1097","@c1098","@c1099","@c1100","@c1101","@c1102","@c1103","@c1104","@c1105","@c1106","@c1107","@c1108","@c1109","@c1110","@c1111","@c1112","@c1113","@c1114","@c1115","@c1116","@c1117","@c1118","@c1119","@c1121","@c1122","@c1123","@c1124","@c1125","@c1126","@c1127","@c1128","@c1129","@c1130","@c1131","@c1132","@c1133","@c1134","@c1135","@c1136","@c1137","@c1138","@c1139","@c1140","@c1141","@c1142","@c1143","@c1144","@c1145","@c1146","@c1147","@c1148","@c1149","@c1150","@c1151","@c1152","@c1153","@c1154","@c1155","@c1156","@c1157","@c1158","@c1159","@c1160","@c1161","@c1162","@c1163","@c1164","@c1165","@c1166","@c1167","@c1168","@c1169"],"theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gia-mao"}],"tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh vươn lên nhờ ý chí khổ tu và quyết tâm sinh tử; Thâm trầm mưu trí, giỏi bố trí hậu thủ, nhìn thấu cạm bẫy và tính toán trước nước cờ của đối thủ; Quyết đoán tàn nhẫn với kẻ thù, không ngại đại khai sát giới khi cần thiết; Trọng ân oán nhân quả, không quên","vaiTro":"Nhân vật chính — tu sĩ ma đạo kiêm Cổ Thần thất tinh vương tộc, chủ nhân Nghịch Thiên Châu","blurb":"Vương Lâm là thiếu niên tư chất kém từ Thạch Thôn, nhờ Nghịch Thiên Châu, ý chí khổ tu và vô số lần sinh tử mà bước vào con đường tu tiên nhuốm ma đạo — trải qua diệt tộc, đoạt xá thân Mã Lương, ngộ Thần Thức Cực Cảnh, nhận truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, rồi liên tiếp đột phá qua Anh Biến, Vấn Đỉnh, Âm Hư, Dương Thực, Khuy Niết, Tịnh Niết và Toái Niết. Hắn thức tỉnh Cổ Thần ngũ tinh vương tộc rồi vượt Nhất Tổn Nhị Kiếp trở thành Cổ Thần chân chính, cảm ngộ năm đạo bản nguyên, đạt Toái Niết đại viên mãn trên phương diện lôi tu, tu thành Cửu Huyền đệ nhất biến cùng hư"},{"id":"thac-sam","name":"Thác Sâm","cn":"拓森","aliases":["Đồ Ti"],"gioiTinh":"nam","canhGioiCaoNhat":"Cổ Thần Thất Tinh","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Xuất hiện trên cột đá bên trong cơn lốc xoáy, tóc đỏ mắt đỏ thẫm tràn sát khí, cuồng ngạo đỉnh thiên. Khinh miệt Viêm Lôi Tử là rác rưởi, Bát Vương Thi Âm Tông ngay cả rác rưởi cũng không bằng. Giao chiến lão già áo đen: quyền thứ nhất xé hư vô thành hai nửa, quyền thứ hai phá tan toàn bộ thế giới băng. Tuyên bố bộ tộc Cổ Thần không tu quy tắc, quy tắc là thứ bộ tộc ta muốn phá vỡ. Nhìn Vương Lâm rồi thân thể tiêu tan biến mất vào hư vô.","anchor":"Dù sao, hắn cũng là Đồ Ti","bridge":true,"khoang":"@c1064"},{"chuong":"@c1065","importance":"major","mucCt":"ky","tieuDe":"Thức tỉnh trong khe không gian","text":"Thác Sâm thức tỉnh từ giấc ngủ vĩnh hằng trong khe không gian, thân thể to bằng mấy tu chân tinh, tám tinh điểm trên mi tâm lần lượt sáng lên ba cái. Tự xưng danh Cổ Thần Thác Sâm. Vung tay quét chết một tu sĩ Toái Niết Sơ Kỳ tu đạo vạn năm dễ dàng như đuổi côn trùng, hút nguyên lực qua vết nứt trên cánh tay. Bị lão già áo đen đánh văng cánh tay một lần và lưu thủ ấn đen, nhưng nhanh chóng đứng dậy phản công, vung song chưởng tấn công mãnh liệt. Tinh điểm thứ ba mơ hồ giấu một vật bên trong, gọi Khánh Không Luyện Tinh là rác rưởi.","anchor":"Ta là Cổ Thần, Thác Sâm"},{"chuong":"@c1066","importance":"major","mucCt":"ky","tieuDe":"Triệu hồi Diệt Thần Mâu tàn sát, đánh tan phân thần Vương Lâm","text":"Khinh miệt mọi người như kiến, tuyên bố nuốt Lỗ phu tử làm tinh điểm thứ năm. Tinh điểm thứ năm hóa hắc động tấn công Lỗ phu tử, bị Vô Cực Tử trong tinh điểm thứ tư bùng tinh quang ngăn lại. Triệu hồi Diệt Thần Mâu — vũ khí vương tộc Cổ Thần — cự mâu to như tinh cầu, ném về phía lão già áo đen. Dư uy Diệt Thần Mâu xuyên vòng xoáy giết sáu trong Bát Vương, khiến Viêm Lôi Tử hai chân nổ tung. Đánh tan nguyên thần phân thần Vương Lâm, nói để lại tinh điểm thứ nhất Cổ Thần cho Vương Lâm.","anchor":"Tinh điểm thứ nhất của Cổ Thần, ta để lại cho ngươi"},{"importance":"bridge","mucCt":"gon","chuong":"@c1069","tieuDe":"Bị Vương Lâm coi là mối đe dọa phải tránh","text":"Vương Lâm nhận định Thác Sâm có thể phá tường ngăn cách hai giới, tinh không không có chỗ ẩn thân, quyết định đứng vững tại Vân Hải thay vì trốn chạy.","anchor":"với tu vi của Thác Sâm, để để phá vỡ bức tường ngăn cách hai giới, dường như giữa trời đất tinh không này, không có chỗ cho hắn có thể ẩn thân"},{"chuong":"@c1079","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhớ lại trong hồi ức: cảnh lão giả hắc y Đệ Tam Bộ trên La Thiên vung tay ngăn một chưởng Cổ Thần của Thác Sâm, trở thành nguồn minh ngộ cho thần thông điều khiển nguyên lực.","anchor":"một chưởng thần thông rõ ràng là Đệ Tam Bộ của lão nhân hắc y"},{"chuong":"@c1147","importance":"normal","mucCt":"ky","tieuDe":"Thức tỉnh, quét ngang Liên Minh tinh vực","text":"Thức tỉnh sau trăm năm, phá trận pháp bay ra khỏi Chu Tước Tinh. Nhảy vào chiến trường giết hơn vạn tu sĩ La Thiên rồi bỏ đi. Dùng lực lượng Cổ Thần phối hợp tinh điểm mi tâm đánh Thanh Long Thánh Hoàng trọng thương nặng, phá tan tinh vực Tứ Thánh Tông. Phất tay dập tắt ngọn lửa muôn đời bất diệt của Chu Tước Thánh Tông. Đến Côn Hư phong ấn lão già bên trong lên mi tâm, dùng Diệt Thần Mâu phá hủy thánh địa Côn Hư. Đánh Mộc Băng Mi tan thân, lưu ký hiệu trên nguyên thần nàng. Giết vô số người Thi Âm Tông vì không tìm được Vương Lâm. Định phá phong ấn Vũ Tiên giới nhưng được Thanh Nông thuyết phục bỏ đi. Mang theo nhiều Luyện Khí Sĩ thượng cổ rời Liên Minh tinh vực, gầm rống tìm Vương Lâm.","anchor":"Vương Lâm, rốt cuộc ngươi đang ở đâu?"},{"importance":"normal","mucCt":"ky","chuong":"@c1148","tieuDe":"Thức tỉnh truy tìm Vương Lâm, đánh vào Phong Giới đại trận","text":"Thức tỉnh trên tinh cầu hoang tại La Thiên tinh vực, mi tâm lộ tám tinh điểm (bốn sáng rực, bốn đen kịt). Dùng thần niệm quét khắp Vũ giới, Lôi giới, Thiểm giới đều không tìm thấy khí tức Vương Lâm. Gầm rống kinh thiên gây đại họa khắp La Thiên — mãnh thú nổ tung, tu sĩ chết hoặc trọng thương, tinh cầu hoang tan vỡ. Xuyên qua Vân Hải tinh vực bằng vòng xoáy khổng lồ, quét thần niệm thổi bay sương mù, giao phong thần niệm với vài cường giả cấp chín. Biết Vương Lâm chưa chết vì không cảm nhận ký ức truyền thừa tiêu tán, suy luận hắn đang ở Thái Cổ Tinh Thần. Phá nứt tinh không Vân Hải rồi đến vùng hư vô ngoài Tứ Đại giới, tìm thấy Phong Giới đại trận. Xuất quyền lần một bị phản lực đánh bật lui, lần hai trận run rẩy nhưng không vỡ. Trận pháp kích hoạt Trận linh — trường thương trắng bùng sét đánh trúng, bị phá nhưng ngưng tụ lại mạnh hơn, lưới điện khóa chặt thân. Tiếp đó trận pháp ngưng tụ đoản kiếm lam với kiếm khí và khí tức âm hàn phóng tới.","anchor":"Dù ngươi trốn ở Thái Cổ Tinh Thần thì bản thần cũng phải thôn phệ ngươi bằng được"},{"mucCt":"ky","text":"Triệu Diệt Thần Mâu và Loan đao đối đầu các khí linh trận pháp Phong giới Nội giới, lần lượt chống lại Ngũ Linh, Lục Linh. Bị Lục Linh (xe bắn đá khổng lồ) bức lui lần đầu, nhận ra phải thôn phệ Vương Lâm thành Cổ Thần Bát Tinh mới đủ sức. Phóng ba tinh điểm chứa khí tức bản nguyên tu sĩ Đệ Tam Bộ hóa lưu tinh, dung nhập bản thân vào lưu tinh xông trận, bị Thất Linh (nha bổng hắc khí) đánh khạc máu lần đầu. Bát Linh xuất hiện: cây búa khổng lồ mang Phụ Tổ Vương Khí, kinh hoàng nhận ra vũ khí Cổ Thần cấp Phụ Tổ Vương lại thành linh khí trận pháp. Bất chấp liên tục phun máu, thi triển Mặc Lưu Phân Thần Thuật tạo sương mù đen khiến búa do dự dừng lại, cho nổ tung lưu tinh tạo khe nứt đầu tiên trên trận pháp từ xưa chưa ai phá được, xông ra ngoài thành công. Trả giá nặng: một trong ba tinh điểm tan vỡ. Cảm nhận khí tức Vương Lâm đang ở Thái Cổ Tinh Thần, tuyên bố sẽ tìm thôn phệ.","anchor":"Vương Lâm, bản thần đã đến rồi. Lúc này ta xem ngươi còn chạy đi đâu được nữa!","bridge":true,"khoang":"@c1149"},{"chuong":"@c1151","importance":"normal","mucCt":"vua","tieuDe":"Tức giận trút giận lên tinh vực Thái Cổ","text":"Trong Thái Cổ Tinh Thần, không thể cảm ứng khí tức Vương Lâm dù đã phá trận pháp và hút chết tu sĩ bước thứ ba. Tức giận rống lên trời, lao tới tinh vực có người Thái Cổ cư trú để trút giận, thề sẽ tìm nuốt Vương Lâm.","anchor":"Vương Lâm đáng chết, bổn thần sớm muộn cũng có ngày tìm được ngươi"},{"chuong":"@c1152","importance":"normal","mucCt":"gon","text":"Vương Lâm cảnh giác nhận định Thác Sâm chắc đã rời khỏi Thất Thải Giới trong suốt gần 100 năm qua.","anchor":"Thác Sâm, chắc đã đi ra rồi!"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão giả áo đen","tag":"doi-thu","quanHe":"Đối thủ giao chiến","ghiChu":"Lão già áo đen bước ra đối đầu trực tiếp với Thác Sâm trong khe không gian"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Lộ diện là kẻ đứng đầu huyết hải, bị phong ấn mấy vạn năm trong Cổ Thần Chi Địa; thực chất là ma vật do oán niệm Cổ Thần Đồ Ti ngưng tụ","chuong":"@c0163"},{"text":"Trao Hỗn Nguyên khu thú quyển và cực phẩm linh thạch cho Vương Lâm để nhờ phá phong ấn, thừa kế lực lượng truyền thừa bát tinh Cổ Thần Đồ Ti","chuong":"@c0170"},{"text":"Phá phong ấn, hóa huyết hải thành huyết long vạn trượng xông vào hư vô, thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ","chuong":"@c1060"},{"text":"Thức tỉnh sau trăm năm, phá trận pháp bay khỏi Chu Tước Tinh, quét ngang Liên Minh tinh vực tàn phá nhiều thế lực và truy tìm Vương Lâm","chuong":"@c1147"},{"text":"Đại chiến Vương Lâm và Nguyệt Tộc, bị chém mất ngón trỏ; cho nổ tinh điểm toái tinh phá vây ba cao thủ Viễn Cổ Tinh Thần","chuong":"@c1239"},{"text":"Quỳ gối nhận truyền thừa Đồ Ti từ Vương Lâm, lần đầu bỏ xưng bổn thần và nói hai chữ đa tạ, rơi vào hoang mang bản ngã","chuong":"@c1386"}]},"nguon":["@c1064","@c1065","@c1066","@c1069","@c1079","@c1147","@c1148","@c1149","@c1151","@c1152"],"vaiTro":"Phản diện trọng yếu — Cổ Ma Đồ Ti, ma vật chủ huyết hải bị phong ấn trong Cổ Thần Chi Địa","tinhCach":"Xảo trá, dùng cực phẩm linh thạch và Hỗn Nguyên khu thú quyển làm mồi nhử để mưu cầu phá phong ấn; tàn nhẫn, khinh miệt chúng sinh như kiến và tàn sát hàng loạt tu sĩ không chớp mắt; cuồng ngạo đỉnh thiên, coi mọi thế lực đều không đáng kể; chấp niệm sâu nặng, liên tục khắc tên Vương Lâm và thề truy","blurb":"Thác Sâm là nam tử tóc đỏ như máu, kẻ đứng đầu huyết hải, thực chất là ma vật do oán niệm của Cổ Thần Đồ Ti chết ngưng tụ — tức Cổ Ma Đồ Ti — bị phong ấn mấy vạn năm trên thạch chùy giữa Cổ Thần Chi Địa. Hắn dùng bảo vật dụ dỗ Vương Lâm phá phong ấn, thừa kế lực lượng truyền thừa bát tinh của Cổ Thần Đồ Ti, triệu hoán Diệt Thần Mâu và thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ, phá phong ấn bay khỏi Chu Tước Tinh quét ngang Liên Minh tinh vực, truy tìm Vương Lâm xuyên suốt nhiều tinh vực. Cuối cùng trong cổ mộ, sau trận chiến định mệnh với Vương Lâm, Thác Sâm lần đầu bỏ xưng bổn thần"},{"id":"lao-gia-ao-den","name":"Lão giả áo đen","aliases":["Lỗ phu tử"],"gioiTinh":"nam","canhGioiCaoNhat":"Không Niết","trangThai":"tu-vong","tabs":{"kinhLich":[{"mucCt":"ky","text":"Lần đầu chú ý Vương Lâm khi thấy hào quang Tàn Dạ xuất hiện trong màn đêm, trong sự xúc động đã nghĩ thông suốt. Bước một bước tới bên huyết long, chỉ một ngón tay khiến huyết long kịch chấn gào rít lui về phía sau. Túm Vương Lâm ra khỏi cơ thể huyết long, vỗ mi tâm truyền sức mạnh vô biên phục hồi toàn diện bằng phương thức nghịch thiên. Khen Vương Lâm thông minh, nhìn thấu hắn dùng phân thân để tìm hiểu sức mạnh Cổ Thần. Nhận ra Thác Sâm là linh hồn Cổ Thần vương tộc. Chỉ tay phá cơn lốc xoáy lộ Thác Sâm, giao chiến bằng sụp đổ hư vô và hàng loạt núi băng. Bình tĩnh bước vào cơn lốc xoáy mới, nói tiếp theo mới là sức mạnh thật sự của Cổ Thần. Tu vi được Thác Sâm xác nhận là Không Niết.","anchor":"tu vi của ngươi đã đạt tới Không Niết, hiểu được quy tắc, vậy thì đã sao","bridge":true,"khoang":"@c1064"},{"mucCt":"ky","text":"Bước một bước vượt vô số khoảng cách, đối đầu cánh tay Cổ Thần, đánh văng cánh tay Thác Sâm và lưu lại thủ ấn màu đen. Nhận xét chỉ Không Niết mới giao chiến được vương tộc bát tinh Cổ Thần, và Thác Sâm chênh lệch trời đất so với bát tinh tầm thường mà lão từng tham gia giết. Lui bảy bước mặt tái nhợt nhưng chiến ý tràn ngập, tung tầng tầng thần thông chống lại song chưởng Thác Sâm nhưng chỉ khiến tạm dừng. Cuối cùng quát gọi Vô Cực Tử hiện ra, đe dọa không tuân thủ lời hứa năm đó, nhắc đến ước định năm xưa.","anchor":"chỉ có Không Niết mới có thể giao chiến với vương tộc bát tinh Cổ Thần","bridge":true,"khoang":"@c1065"},{"chuong":"@c1066","importance":"normal","mucCt":"ky","tieuDe":"Dùng kiếm gãy chống Thác Sâm, thoát qua vòng xoáy cứu Viêm Lôi Tử","text":"Bị Thác Sâm nhắm làm tinh điểm thứ năm. Rút thanh kiếm gãy chỉ còn một nửa, phun máu kích hoạt, xuyên thấu chân phải Thác Sâm nhưng bị tu sĩ xương khô tinh điểm thứ ba dùng hai ngón tay kẹp đổi hướng. Triệu hồi lại kiếm gãy chống Diệt Thần Mâu nhưng kiếm hóa hư vô. Nhờ khoảnh khắc Vương Lâm hy sinh cản Diệt Thần Mâu mà kịp nhảy vào vòng xoáy thoát đi, sau đó quay lại ôm Viêm Lôi Tử cứu đi.","anchor":"Lỗ phu tử, lão phu không có quên lời ước định"},{"mucCt":"vua","text":"Phân thân bước thứ ba lao tới cửa Thiên Nghịch bị ánh sáng thiêu đốt tiêu tán, tưởng chủ nhân Phong Giới sống lại. Nhận ra Vương Lâm là chủ nhân thứ hai của Phong Giới, liều tấn công bằng sương mù đen và ba phân thân nhưng bị cánh tay khổng lồ từ Thiên Nghịch quét sạch và tóm diệt bản thể, cười khổ thừa nhận bản thể không ở đây rồi tiêu tan.","anchor":"Nếu bản thể tới đây thì cũng có thể liều một phen, nhưng lúc này…","bridge":true,"khoang":"@c1151"}],"tuViMoc":[{"chuong":"@c1064","canhGioi":"Không Niết","text":"Thác Sâm xác nhận tu vi lão già áo đen đã đạt tới Không Niết, hiểu được quy tắc.","importance":"major"}],"nhanMach":[{"ten":"Vô Cực Tử","tag":"khac","quanHe":"Có ước định năm xưa","ghiChu":"Gọi tên Vô Cực Tử trong khe không gian, nhắc ước định và đe dọa không tuân thủ lời hứa nếu đối phương không hiện ra"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Tu vi đạt tới Không Niết, được Thác Sâm xác nhận","chuong":"@c1064"},{"text":"Xuất hiện từ hư vô, một ngón tay điểm xuyên sọ giết chết thượng cổ tu sĩ áo đỏ","chuong":"@c1059"},{"text":"Thi triển thần thông Súc Thốn Thành Không, biến chỗ đứng thành thiên địa co rút cả thế giới","chuong":"@c1062"},{"text":"Bước một bước vượt vô số khoảng cách, đánh văng cánh tay Cổ Thần của Thác Sâm và lưu lại thủ ấn","chuong":"@c1065"},{"text":"Dùng kiếm gãy chống Thác Sâm, thoát qua vòng xoáy cứu Viêm Lôi Tử","chuong":"@c1066"},{"text":"Phân thân bước thứ ba lao tới cửa Thiên Nghịch bị ánh sáng thiêu đốt tiêu tán","chuong":"@c1151"}]},"nguon":["@c1064","@c1065","@c1066","@c1151"],"vaiTro":"Đại năng bí ẩn của Liên Minh, tu vi vượt xa Khuy Niết","tinhCach":"Bình tĩnh thâm trầm khó lường; thận trọng quan sát trước khi ra tay; ra tay dứt khoát tàn nhẫn; suy tư sâu về ý đồ đối thủ","blurb":"Lão giả áo đen là đại năng bí ẩn cư ở tây bộ Liên Minh tinh vực, tu vi đã đạt tới Không Niết với thần thông di chuyển vượt xa khoảng cách thông thường. Lão có thể một ngón tay giết chết thượng cổ tu sĩ, thi triển thần thông Súc Thốn Thành Không co rút cả thế giới, và từng dùng kiếm gãy chống Thác Sâm để cứu Viêm Lôi Tử. Về sau phân thân của lão bị ánh sáng thiêu đốt tiêu tán trước cửa Thiên Nghịch."},{"id":"viem-loi-tu","name":"Viêm Lôi Tử","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1064","importance":"bridge","mucCt":"gon","text":"Tiếp xúc ánh mắt Thác Sâm, tâm thần chấn động sắc mặt tái nhợt, bị gọi là rác rưởi.","anchor":"Viêm Lôi Tử miệng đắng lưỡi khô, sắc mặt tái nhợt không còn chút máu"},{"chuong":"@c1065","importance":"bridge","mucCt":"gon","text":"Sắc mặt tái nhợt trước thân hình Cổ Thần Thác Sâm, dâng lên cảm giác bất lực rất hiếm thấy.","anchor":"Với tu vi của hắn, trong lòng dâng lên một cảm giác bất lực rất hiếm thấy"},{"chuong":"@c1066","importance":"normal","mucCt":"vua","tieuDe":"Trọng thương nặng bởi dư uy Diệt Thần Mâu, được Lỗ phu tử cứu","text":"Nhảy vào vòng xoáy bị dư uy Diệt Thần Mâu truyền tới: phun máu tươi, hai chân nổ tung hóa sương máu, nguyên thần bị xung kích. Oán hận Thác Sâm chỉ sau Trọng Huyền Tử. Được lão già áo đen ôm đi cứu thoát.","anchor":"Đối với Thác Sâm này hắn rất hận, chỉ sau có Trọng Huyền Tử năm đó"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Chủ trì nghi thức Phong Tiên: phong Hứa Mộc làm Chính phẩm Lôi tiên, ban Thiên Hổ kỳ và phong Hứa Đình","chuong":"@c0826"},{"text":"Hiến tinh huyết nguyên thần phát động mở thông đạo tới Liên Minh Tinh Vực, khởi đầu đại chiến","chuong":"@c0828"},{"text":"Bộc lộ tu vi thật vượt Toái Niết hậu kỳ trong trận giao chiến với Cực Hiền Thiên ở phía Bắc Liên Minh","chuong":"@c0864"},{"text":"Giao chiến kinh thiên động địa với Võ Đông Thiện trong màn sương đen giữa tinh không","chuong":"@c0871"},{"text":"Giao chiến một ngày với thượng cổ tu sĩ áo đỏ chưa phân thắng bại, dùng hạt châu bốc cháy hóa biển lửa","chuong":"@c1059"},{"text":"Trọng thương nặng bởi dư uy Diệt Thần Mâu: hai chân nổ tung, nguyên thần lung lay, được Lỗ phu tử cứu","chuong":"@c1066"}]},"nguon":["@c1064","@c1065","@c1066"],"vaiTro":"Điện chủ Lôi Tiên Điện — chỉ huy cấp cao La Thiên trong đại chiến với Tu Chân Liên Minh","tinhCach":"trọng dụng nhân tài, sẵn sàng bỏ qua tổn thất để chiêu nạp cao thủ; quyết đoán trong đại cục, dám hiến tinh huyết nguyên thần mở thông đạo; bình tĩnh trước chất vấn và biến cố bất ngờ; mang mối thù truyền kiếp với Tu Chân Liên Minh, không chịu dừng tay khi chiến sự chưa ngã ngũ","blurb":"Viêm Lôi Tử là Điện chủ Lôi Tiên Điện, một trong những nhân vật chỉ huy then chốt của La Thiên trong cuộc đại chiến với Tu Chân Liên Minh. Ông chủ trì toàn bộ nghi thức Phong Tiên, phong Hứa Mộc làm Chính phẩm Lôi tiên, phát động mở thông đạo tới Liên Minh Tinh Vực bằng cách hiến tinh huyết nguyên thần, rồi trực tiếp giao chiến với các đại tu sĩ hàng đầu như Cực Hiền Thiên, Võ Đông Thiện và thượng cổ tu sĩ áo đỏ. Sở hữu tu vi vượt Toái Niết hậu kỳ, Viêm Lôi Tử thống lĩnh đại quân La Thiên trên nhiều mặt trận và liên tục được Vương Lâm dùng làm thước đo khi đánh giá tu vi kẻ địch."},{"id":"huyet-long","name":"Huyết long","gioiTinh":"khac","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1064","importance":"bridge","mucCt":"gon","text":"Thi triển Hắc Dạ thần thông bao trùm hư vô, bị lão già áo đen chỉ một ngón tay khiến kịch chấn gào rít lui về phía sau, bị Vương Lâm lao vào vết thương đoạt tâm huyết Cổ Thần.","anchor":"dưới Hắc Dạ thần Thông của nó, tu sĩ này chưa kịp tới gần chắc chắn sẽ bỏ mạng"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1064"]},{"id":"do-ti","name":"Đồ Ti","cn":"屠戲","aliases":["Cổ thần Đồ Ti","Thác Sâm"],"gioiTinh":"nam","trangThai":"khong-ro","tabs":{"kinhLich":[{"mucCt":"vua","text":"Bên trong khe không gian, thân thể to bằng mấy tu chân tinh hợp lại, ngón tay khẽ động, nắm tay lại. Đôi mắt đã nhắm từ rất lâu lần đầu tiên chậm rãi mở ra.","anchor":"hai mắt đã khép lại từ rất lâu, từ lúc nhắm lại năm đó, lúc này lần đầu tiên chậm rãi mở ra","bridge":true,"khoang":"@c1064"},{"chuong":"@c1087","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Ký ức Đồ Ti cung cấp kiến thức về Tam Tổn Thất Kiếp cho Vương Lâm; máu huyết Đồ Ti bị bản tôn Vương Lâm hấp thu giúp vượt Tổn Kiếp đầu tiên.","anchor":"Vương Lâm đoạt được máu huyết của Đồ Ti, lúc này mới có lực để đánh cuộc một lần"},{"chuong":"@c1123","importance":"bridge","mucCt":"vua","text":"Đồ Ti được nhắc trong lai lịch Tam Xoa Kích: năm xưa lão luyện chế vũ khí có thần thông thôn phệ vạn vật, nhưng vì Mặc Lưu Phân Thần Thuật thất bại nên món vũ khí này bị lãng quên.","anchor":"năm xưa sau khi Cổ Thần Đồ Ti luyện chế vũ khí cảm thấy cực kỳ thõa mãn"},{"importance":"bridge","mucCt":"gon","chuong":"@c1148","tieuDe":"Thác Sâm nhớ Đồ Ti đến từ nơi không có Phong giới trận","text":"Thác Sâm mơ hồ nhớ ra Đồ Ti đã đến từ nơi không có Phong giới trận, tức Thái Cổ Tinh Thần.","anchor":"hắn vẫn mơ hồ nhớ ra Đồ Ti đã đến từ nơi nào"},{"chuong":"@c1149","importance":"bridge","mucCt":"gon","text":"Được Thác Sâm nhắc đến: Mặc Lưu Phân Thần Thuật là thuật Đồ Ti còn chưa triệt để hoàn thành.","anchor":"sử dụng Mặc Lưu Phân Thần Thuật mà trước đó Đồ Ti còn chưa triệt để hoàn thành"},{"chuong":"@c1156","importance":"bridge","mucCt":"gon","text":"Được nhắc là người tự mình tế luyện ra Cổ Thần đại đỉnh, một trong hai bảo vật Cổ Thần mà Vương Lâm sở hữu.","anchor":"Cổ Thần đại đỉnh là một trong hai bảo vật của Cổ Thần mà Vương Lâm có được, là do Đồ Ti tự mình tế luyện ra"},{"chuong":"@c1166","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc tới khi liên hệ ký ức của Đồ Ti về Văn Thú màu tím, tự hỏi Văn Thú tím trong Phong Tiên Giới tương đương trình độ nào.","anchor":"Văn Thú ở nơi này không biết nếu đạt tới màu tím giống như trong ký ức của Đồ Ti, thì sẽ tương đương với trình độ nào"},{"chuong":"@c1167","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhớ lại: năm đó ngay cả Đồ Ti cũng phải chật vật bỏ chạy khi đối mặt Văn Thú trong Phong Tiên Giới.","anchor":"Khó trách năm đó ngay cả Đồ Ti cũng phải chật vật mà bỏ chạy"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Phân thân xuất hiện sau khi Vương Lâm vượt ba trăm trượng cuối trong mười ba năm thử luyện, công nhận Vương Lâm là người lĩnh ngộ và truyền lại ký ức cùng truyền thừa Cổ Thần vương tộc","chuong":"@c0160"},{"text":"Được La Trần xác nhận đã chết; La Trần nhận ra Diệt Thần Mâu và xác nhận truyền thừa của Vương Lâm đến từ Đồ Ti","chuong":"@c0882"},{"text":"Thân thể khổng lồ tồn tại bên trong khe không gian, từng có biểu hiện ngón tay khẽ động và đôi mắt mở ra","chuong":"@c1064"},{"text":"Năm xưa tự mình luyện chế Tam Xoa Kích có thần thông thôn phệ vạn vật và tế luyện ra Cổ Thần Đỉnh, để lại Mặc Lưu Phân Thần Thuật chưa triệt để hoàn thành","chuong":"@c1123"},{"text":"Thân thể vương tộc bát tinh Cổ Thần tồn tại từ vạn cổ, đã bị Thác Sâm chiếm đoạt","chuong":"@c1383"},{"text":"Hư ảnh Đồ Ti tan vỡ khi Vương Lâm vượt qua giới hạn bát tinh; Vương Lâm tuyên bố truyền thừa của Đồ Ti hơn ngàn năm nay được trả về, không còn là truyền thừa giả của lão","chuong":"@c1385"}]},"nguon":["@c1064","@c1087","@c1123","@c1148","@c1149","@c1156","@c1166","@c1167"],"vaiTro":"Cổ thần chủ Cấm Sơn — nguồn truyền thừa Cổ Thần vương tộc của Vương Lâm","tinhCach":"Thận trọng, chọn lọc kỹ càng người kế thừa; kiêu hãnh mang khí phách đặc trưng của Cổ Thần; đơn độc khai phá, tự lực cánh sinh","blurb":"Đồ Ti là Cổ thần vương tộc bát tinh đến từ Thái Cổ Tinh Thần — nơi không tồn tại Phong giới trận — và là người đơn độc mở ra không gian Cổ Thần Chi Địa, lấy Cấm Sơn làm nơi đặt truyền thừa. Sau mười ba năm thử luyện, phân thân của lão công nhận Vương Lâm là người lĩnh ngộ, truyền lại ký ức và truyền thừa Cổ Thần mang tính vương tộc, dù phần ký ức ấy chưa trọn vẹn và còn bị phong ấn. Bản thân Đồ Ti đã được La Trần xác nhận là đã chết, thân thể khổng lồ tồn tại bên trong khe không gian và sau đó bị Thác Sâm chiếm đoạt; di sản của lão — từ ký ức, Cổ Thần Đỉnh, Tam Xoa Kích đến Mặc Lưu Phân Thần T"},{"id":"vo-cuc-tu","name":"Vô Cực Tử","cn":"","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1065","importance":"bridge","mucCt":"gon","text":"Được lão già áo đen gọi tên trong khe không gian, nhắc ước định năm xưa và đe dọa nếu không hiện ra sẽ không tuân thủ lời hứa.","anchor":"Vô Cực Tử. Lúc này nếu ngươi còn không hiện ra, đừng trách lão phu không tuân thủ lời hứa năm đó"},{"chuong":"@c1066","importance":"major","mucCt":"ky","tieuDe":"Lộ quá khứ tham sức mạnh Cổ Thần, dung hợp thành một thể bị giam","text":"Đã dung hợp thành một thể với Cổ Thần trong tinh điểm thứ tư, nửa người dưới hòa vào mặt đất, thân héo rũ như xương khô. Thú nhận năm xưa tham lam sức mạnh vương tộc Cổ Thần muốn đột phá Không Niết Sơ Kỳ nên rơi vào cảnh bị giam. Nói lời tang thương kêu Lỗ phu tử rời đi, cắn răng bùng tinh quang ngăn tinh điểm thứ năm nuốt Lỗ phu tử, phun máu tươi.","anchor":"năm đó đã sai quá rồi, không nên tham lam sức mạnh của vương tộc Cổ Thần này, muốn đột phá Không Niết Sơ Kỳ"}],"nhanMach":[{"ten":"Lão giả áo đen","tag":"khac","quanHe":"Có ước định năm xưa","ghiChu":"Lão già áo đen gọi tên, nhắc lời hứa và ước định"}],"tuViMoc":[],"diem":[{"text":"Từng tham sức mạnh Cổ Thần, dung hợp thành một thể và bị giam trong tinh điểm thứ tư trên mi tâm","chuong":"@c1066"},{"text":"Bị hắc y lão giả nhiều lần nhắc tên cùng ước định năm xưa, khiêu khích vì không chịu hiện thân","chuong":"@c1020"},{"text":"Thay đổi nhìn nhận về Lữ Tử Hạo, không còn coi là vãn bối mà là người cùng thế hệ","chuong":"@c1183"},{"text":"Bùng uy áp Thiên Nhân Suy Kiếp đối đầu Vương Lâm: ánh mắt hóa kiếm quang, sấm sét phải tránh, mưa ngừng giữa trời","chuong":"@c1188"},{"text":"Khuất nhục chấp nhận ý chỉ Thần Tông hủy bỏ đại hội phân tông cấp tám","chuong":"@c1196"},{"text":"Tham gia vây công Vương Lâm cùng sáu trưởng lão nhưng bị một kiếm trấn áp, không dám ngăn cản","chuong":"@c1218"}]},"nguon":["@c1065","@c1066"],"vaiTro":"Đại nhân vật bí ẩn của Quy Nguyên Tông, gắn với sức mạnh Cổ Thần","blurb":"Vô Cực Tử là nhân vật bí ẩn từng tham sức mạnh Cổ Thần nên bị dung hợp làm một thể và giam trong tinh điểm thứ tư trên mi tâm, nhiều lần bị hắc y lão giả nhắc tên cùng ước định năm xưa. Về sau hắn lộ diện gắn với các sự kiện của Quy Nguyên Tông, đánh giá cao và nâng đỡ nhân tài như Lữ Tử Hạo, đồng thời bùng uy áp Thiên Nhân Suy Kiếp đối đầu Vương Lâm. Dù mang uy thế lớn, hắn vẫn phải khuất nhục chấp nhận ý chỉ Thần Tông hủy bỏ đại hội phân tông và cuối cùng bị Vương Lâm một kiếm trấn áp.","tinhCach":"Thâm trầm bí ẩn, lâu không chịu hiện thân; trọng đại cục, biết nhẫn nhịn khuất nhục; uy áp cường đại; công tâm nhìn nhận và nâng đỡ người tài"},{"id":"bat-vuong-thi-am-tong","name":"Bát vương (Thi Âm Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thi Âm Tông","trangThai":"gan-bo"}],"trangThai":"khong-ro","vaiTro":"Một trong tám Vương của Thi Âm Tông","tinhCach":"Khiếp sợ, cùng đường trước uy áp Cổ Thần","blurb":"Bát vương của Thi Âm Tông, có mặt trong khe không gian khi Cổ Thần Thác Sâm thức tỉnh. Trước uy áp của Cổ Thần, mặt không còn chút máu, muốn lui nhưng không có đường. Về sau, sáu trong tám Vương bị Diệt Thần Mâu tàn sát, chỉ hai người được Chủ Tôn cứu.","tabs":{"diem":[{"text":"Mặt không còn chút máu trước uy áp Cổ Thần Thác Sâm, muốn lui nhưng không có đường","chuong":"@c1065"},{"text":"Nằm trong tám Vương nhảy vào vòng xoáy, bị dư uy Diệt Thần Mâu tấn công khiến thân thể sụp đổ hóa khí âm hàn","chuong":"@c1066"},{"text":"Sáu trong tám Vương bị Diệt Thần Mâu tàn sát, chỉ hai người được Chủ Tôn cứu","chuong":"@c1066"}],"kinhLich":[{"chuong":"@c1065","importance":"bridge","mucCt":"gon","text":"Mặt không còn chút máu trước uy áp Cổ Thần Thác Sâm, muốn lui nhưng không có đường.","anchor":"Bát vương của Thi Âm Tông trên mặt không còn chút máu"},{"chuong":"@c1066","importance":"major","mucCt":"vua","tieuDe":"Sáu trong tám Vương bị Diệt Thần Mâu tàn sát, hai người được Chủ Tôn cứu","text":"Tám người nhảy vào vòng xoáy, bị dư uy Diệt Thần Mâu tấn công: thân thể sụp đổ hóa tám đạo khí âm hàn, năm đạo tiêu tan ngay, thêm một người chết trên đường chạy. Hai người còn lại suýt chết thì được hai cánh tay từ hắc khí kéo vào cứu thoát.","anchor":"Chủ Tôn!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1065","@c1066"]},{"id":"tu-si-xuong-kho","name":"Tu sĩ xương khô (tinh điểm thứ ba)","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Tu sĩ bị giam làm tinh điểm thứ ba trên mi tâm Cổ Thần Thác Sâm, hình dáng như bộ xương khô, mi tâm có ấn ký hình lưỡi liềm.","vaiTro":"Tu sĩ bị giam làm tinh điểm thứ ba của Thác Sâm","tinhCach":"Không rõ, chỉ hành động theo bản năng bảo vệ tinh điểm","tabs":{"diem":[{"text":"Bước ra từ tinh điểm thứ ba trên mi tâm Thác Sâm, dùng hai ngón tay kẹp thanh kiếm gãy, vỗ một cái khiến quy tắc trời đất biến đổi theo.","chuong":"@c1066"}],"kinhLich":[{"chuong":"@c1066","importance":"normal","mucCt":"vua","tieuDe":"Bước ra từ tinh điểm thứ ba ngăn chặn kiếm gãy Lỗ phu tử","text":"Từ tinh điểm thứ ba trên mi tâm Thác Sâm bước ra, mi tâm hiện ấn ký hình lưỡi liềm biến ảo. Dùng hai ngón tay kẹp thanh kiếm gãy của Lỗ phu tử, đổi hướng ném lên trời, động tác chứa quy tắc trời đất biến hóa theo hắn.","anchor":"mi tâm đang trống không bỗng có một ấn ký hình lưỡi liềm biến ảo hiện ra"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1066"]},{"id":"chuong-mon-quy-nguyen-tong","name":"Chưởng môn Quy Nguyên Tông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Dưới Toái Niết","trangThai":"tu-vong","blurb":"Vị chưởng môn đương nhiệm của Quy Nguyên Tông, phân tông thuộc Vân Hải Tinh Vực. Cả đời không bước được vào Toái Niết, bị hút tuổi thọ ở Linh Nguyên Tông tầng thứ tám. Trước khi chết thiêu đốt nguyên thần thi triển Trạch Linh tìm Bạn Linh Tử, phát hiện Vương Lâm cùng vô số oan hồn rồi kinh hãi quy tiên.","vaiTro":"Chưởng môn Quy Nguyên Tông, chết ngay khi xuất hiện, gián tiếp dẫn Quy Nguyên Tông tìm Vương Lâm","tinhCach":"Tận tụy với tông môn; không cam lòng trước kết cục; bình thản trước cái chết nhưng kinh hãi khi thấy Vương Lâm","tabs":{"diem":[{"text":"Cả đời không đạt Toái Niết, bị hút tuổi thọ ở Linh Nguyên Tông tầng thứ tám dẫn đến cái chết","chuong":"@c1068"},{"text":"Thiêu đốt nguyên thần thi triển Trạch Linh, phát hiện Vương Lâm với vô số oan hồn bao quanh, kinh hãi quy tiên chỉ kịp hét bốn chữ di ngôn","chuong":"@c1068"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1068","tieuDe":"Thiêu nguyên thần thi triển Trạch Linh và quy tiên","text":"Lão chưởng môn hấp hối trong đạo quán Quy Nguyên Tông giữa cơn mưa lớn, tiết lộ với bốn đệ tử rằng bản thân không đạt Toái Niết và bị hút tuổi thọ ở Linh Nguyên Tông tầng thứ tám. Lão giao rắn Ngũ Giai Tử Mục làm thú trấn tông, dặn đệ tử gánh vác tông môn và đưa Quy Nguyên Tông thoát khỏi vị trí cuối cùng trong cuộc so tài phân tông. Thiêu đốt nguyên thần thi triển Trạch Linh quét toàn đại lục Mạc La tìm Bạn Linh Tử nhưng thất bại. Đúng lúc sắp tan biến, phát hiện Vương Lâm xuất hiện từ Truyền Tống Trận phía Bắc, nhìn thấy vô số oan hồn quanh hắn, kinh hãi tột độ. Chỉ kịp hét hai lần bốn chữ di ngôn rồi nguyên thần sụp đổ, quy tiên.","anchor":"mang theo vẻ không cam lòng mãnh liệt, mang theo sự giãy giụa điên cuồng"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được phát hiện qua Trạch Linh, oan hồn bao quanh khiến lão kinh hãi đến chết","ghiChu":"@c1068"},{"ten":"Nữ đệ tử Quy Nguyên Tông","tag":"su-mon","quanHe":"Đệ tử thân truyền","ghiChu":"@c1068"},{"ten":"Nam tử trung niên đệ tử Quy Nguyên Tông","tag":"su-mon","quanHe":"Đệ tử thân truyền","ghiChu":"@c1068"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Trạch Linh","moTa":"Thần thông truyền thừa của Quy Nguyên Tông, thiêu đốt nguyên thần thi triển lần cuối đời","nguon":"@c1068"}],"linhThu":[{"ten":"Rắn Ngũ Giai Tử Mục","moTa":"Nuôi trong khe trữ vật, giao phó làm thú trấn tông trước khi chết","trangThai":"da-dung","nguon":"@c1068"}],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1068"]},{"id":"nu-de-tu-quy-nguyen-tong","name":"Nữ đệ tử Quy Nguyên Tông","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bốn đệ tử thân truyền của chưởng môn Quy Nguyên Tông, tướng mạo xinh đẹp tuyệt trần, cương nghị. Khóc thương sư tôn nhiều nhất trong bốn người.","vaiTro":"Đệ tử thân truyền Quy Nguyên Tông, kế thừa sau khi chưởng môn quy tiên","tinhCach":"Cương nghị; nặng tình sư đồ","tabs":{"diem":[{"text":"Tướng mạo xinh đẹp tuyệt trần, cương nghị, khóc thương sư tôn nhiều nhất trong bốn đệ tử","chuong":"@c1068"}],"kinhLich":[{"mucCt":"vua","text":"Quỳ trước sư tôn trong đạo quán Quy Nguyên Tông giữa cơn mưa, khóc thương nhiều nhất trong bốn đệ tử thân truyền. Chứng kiến sư tôn giao phó rắn Ngũ Giai Tử Mục, thi triển Trạch Linh rồi quy tiên.","anchor":"người này tướng mạo xinh đẹp tuyệt trần, ẩn chứa một vẻ cương nghị","bridge":true,"khoang":"@c1068"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng môn Quy Nguyên Tông","tag":"su-mon","quanHe":"Sư tôn, vừa quy tiên","ghiChu":"@c1068"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1068"]},{"id":"nam-tu-trung-nien-de-tu-quy-nguyen-tong","name":"Nam tử trung niên đệ tử Quy Nguyên Tông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bốn đệ tử thân truyền của chưởng môn Quy Nguyên Tông, bất bình về việc Chủ Tông trút giận lên Quy Nguyên Tông vì sự kiện Tử Đạo Tông.","vaiTro":"Đệ tử thân truyền Quy Nguyên Tông","tinhCach":"Bất bình trước bất công; trực tính","tabs":{"diem":[{"text":"Chất vấn sư tôn về việc Chủ Tông bất công trừng phạt Quy Nguyên Tông vì chuyện Tử Đạo Tông","chuong":"@c1068"}],"kinhLich":[{"mucCt":"vua","text":"Bất bình hỏi sư tôn tại sao Tử Đạo Tông bố trí trận pháp trên đại lục Mạc La mà Chủ Tông lại trút giận lên Quy Nguyên Tông. Chứng kiến sư tôn giao phó di mệnh rồi quy tiên.","anchor":"Tử Đạo Tông kia ở trên đại lục Mạc La của ta bố trí trận pháp, tại sao sau khi không trở về, Chủ Tông lại muốn trút giận lên đầu Quy Nguyên Tông ta","bridge":true,"khoang":"@c1068"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng môn Quy Nguyên Tông","tag":"su-mon","quanHe":"Sư tôn, vừa quy tiên","ghiChu":"@c1068"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1068"]},{"id":"vu-dai","name":"Vũ Đại","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Đại hán có danh vọng trong Bắc Thủy Thôn, người cứu mang Vương Lâm về từ rừng và cho ở nhờ.","vaiTro":"Thôn dân tốt bụng tại Bắc Thủy Thôn, ân nhân của Vương Lâm khi ẩn thân","tinhCach":"Hào sảng; trọng nghĩa khí; dám đứng lên xin tha cho trẻ nhỏ trước tu sĩ","tabs":{"diem":[{"text":"Phàm nhân hào sảng, coi Vương Lâm là bằng hữu dù mới gặp, dám xin tha trẻ nhỏ trước mặt tu sĩ","chuong":"@c1069"}],"kinhLich":[{"mucCt":"vua","text":"Mang Vương Lâm về thôn sau khi hắn cứu Lão Tam, cho ở nhờ và tổ chức tiệc rượu tiếp đón. Khi Triệu Ngọc bắt thôn dân đứng mưa, run giọng xin tha cho trẻ nhỏ nhưng bị quát.","anchor":"Ta không có học, không hiểu lễ nghĩa gì cả, chẳng qua gặp được trên đường, thì chính là bằng hữu","bridge":true,"khoang":"@c1069"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Coi là bằng hữu, cho ở nhờ tại nhà mình","ghiChu":"@c1069"}],"tuiDo":{}},"nguon":["@c1069"]},{"id":"trieu-ngoc","name":"Triệu Ngọc","cn":"赵玉","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Trúc Cơ","trangThai":"song","blurb":"Tu sĩ trẻ chưa đến 20 tuổi của Quy Nguyên Tông, tu vi Trúc Cơ, thái độ lạnh như băng. Bị Vương Lâm áp chế khi đến Bắc Thủy Thôn tuyển đệ tử.","vaiTro":"Đệ tử Quy Nguyên Tông đi tuyển người tại Bắc Thủy Thôn","tinhCach":"Lạnh lùng; kiêu ngạo với phàm nhân; nhưng biết sợ khi gặp kẻ mạnh","tabs":{"diem":[{"text":"Tu sĩ Trúc Cơ trẻ tuổi kiêu ngạo, bắt thôn dân đứng mưa nhưng sửng sốt mất hồn khi Vương Lâm bước ra","chuong":"@c1069"}],"kinhLich":[{"mucCt":"vua","text":"Đến Bắc Thủy Thôn tuyển đệ tử, bắt toàn bộ thôn dân đứng dưới mưa lạnh hơn một nén hương. Khi Vương Lâm bước ra, sửng sốt lộ vẻ bối rối rồi mất hồn, lập tức cho thôn dân về và đi theo sau Vương Lâm.","anchor":"nhưng lập tức hai mắt lộ ra vẻ bối rối, ánh mắt rời khỏi người Vương lâm","bridge":true,"khoang":"@c1069"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Phát hiện điều bất thường ở Vương Lâm khi đến tuyển người, bị áp chế","ghiChu":"@c1069"}],"tuiDo":{}},"nguon":["@c1069"]},{"id":"lu-yen-phi","name":"Lữ Yên Phi","cn":"吕燕菲","aliases":["Lữ Yến Phỉ","Lữ sư muội"],"gioiTinh":"nu","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Lữ Yên Phi là đại trưởng lão Quy Nguyên Tông, tu vi từ Khuy Niết Hậu Kỳ đại viên mãn đột phá Vấn Đỉnh nhờ Man Thiên Đan do sư tôn bất chấp hao phí tự luyện. Nàng bái sư từ năm mười ba tuổi, về sau thu nhận bảy môn hạ trong đó có Tằng Ngưu (Vương Lâm), cung kính trao cho hắn thân phận Lữ Tử Hạo làm sư thúc tổ Quy Nguyên Tông. Trải qua thời kỳ tông môn suy yếu, bị Tử Đạo Tông ức hiếp và biến cố tại đại hội Vô Cực Tông, nàng cắt quan hệ sư đồ rồi rời Quy Nguyên Tông gia nhập Vô Cực Tông, cuối cùng được Vương Lâm triệu tập dẫn toàn bộ đệ tử rút về Mạc La đại lục.","vaiTro":"Đại trưởng lão Quy Nguyên Tông — phụ nữ duy nhất trong bốn đại trưởng lão, sư phụ danh nghĩa của Vương Lâm","tinhCach":"Trọng ân nghĩa, khắc ghi di ngôn sư tôn và luôn nhớ ơn người giúp mình; kiên cường quyết liệt, thề chết không khuất phục kẻ thù; cung kính lễ độ trước Vương Lâm, tự nguyện nhường vị thế; trung thành gắn bó với tông môn, bảo vệ đệ tử không chùn bước","tabs":{"diem":[{"text":"Bái sư năm mười ba tuổi, Vấn Đỉnh thành công nhờ sư tôn bất chấp hao phí luyện Man Thiên Đan trợ giúp","chuong":"@c1071"},{"text":"Tuyển chọn bảy đệ tử toàn Mạc La, trong đó có Tằng Ngưu (Vương Lâm) từ Bắc Thủy Thôn","chuong":"@c1069"},{"text":"Mang sát khí nghênh chiến Tử Đạo Tông, thề dù chết cũng không khuất phục Lô Địch","chuong":"@c1074"},{"text":"Kể chuyện sư thúc tổ Lữ Tử Đạo để gián tiếp trao cho Vương Lâm thân phận Lữ Tử Hạo trong Quy Nguyên Tông","chuong":"@c1076"},{"text":"Cắt quan hệ sư đồ với Vương Lâm, rời Quy Nguyên Tông đến Vô Cực Tông","chuong":"@c1163"},{"text":"Được Vương Lâm giáng lâm bảo hộ tại đại hội Vô Cực Tông, khóc sung sướng rồi được đưa ra an toàn","chuong":"@c1184"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1069","tieuDe":"Thu nhận môn hạ đợt tuyển chọn","text":"Chọn bảy người trong đợt tuyển đệ tử toàn Mạc La, trong đó có Tằng Ngưu từ Bắc Thủy Thôn.","anchor":"Lữ Yên Phi, phụ nữ duy nhất trong bốn đại trưởng lão lựa chọn"},{"chuong":"@c1070","importance":"normal","mucCt":"ky","tieuDe":"Tông phái suy yếu, bị ép song tu","text":"Sư tôn tu vi Tịch Niết viên mãn đã quy tiên, Quy Nguyên Tông lâm vào thời kỳ suy yếu nhất. Ba vị sư bá không dám ra mặt bảo vệ. Nhiều tu sĩ đại thần thông dòm ngó nhan sắc của nàng, ép song tu. Lữ Yên Phi cầm ngọc giản màu tím liên quan tới Lô Địch, đầy nhẫn nhục nhưng sợ hậu quả nếu bóp nát. Sau khi Tôn Vân rời đi, nàng bùng sát khí thề dù chết cũng tuyệt không song tu với Lô Địch. Phân bốn thiếu niên phàm nhân cho đại đệ tử và tam đệ tử, yêu cầu phải được Tử Mục Mãng tán thành.","anchor":"Lô Địch, Lữ Yên Phi ta cho dù chết cũng quyết không cùng ngươi song tu!"},{"mucCt":"ky","text":"Mười ba tuổi bái sư, sư tôn bất chấp hao phí dược liệu tự luyện Man Thiên Đan giúp nàng Vấn Đỉnh thành công. Sư tôn dẫn nàng ba năm vào tinh vụ săn bắn bắt được con cáo đỏ sáu mắt làm bản mệnh linh thú. Sau khi sư tôn bị Tử Đạo Tông hại quy tiên, thiếu tông chủ Lô Địch gửi ngọc giản ép nàng song tu, đe dọa tâu Chủ Tông khai chiến với Quy Nguyên Tông. Ba sư huynh hèn nhát muốn hy sinh nàng nhưng nàng cho rằng theo Lô Địch cũng không bình an. Gặp phàm nhân Tằng Ngưu trên đỉnh núi, kinh ngạc trước sự bình tĩnh quỷ dị của hắn, đánh giá nếu hắn tu đạo sẽ có thành tựu. Cuối cùng mặt nàng lộ vẻ kiên định và sát khí.","anchor":"Tử Đạo Tông hại sư tôn, sau khi sư tôn quy tiên thiếu tông chủ lại gửi ngọc giản đến, muốn ta cùng hắn song tu","bridge":true,"khoang":"@c1071"},{"mucCt":"vua","text":"Được nhắc đến là sư tôn của Tôn Vân, người có đại ân với nàng. Bị thanh niên áo tím tuyên bố muốn biến thành thê thiếp lô đỉnh, Tống thúc khẳng định mười phần nắm chắc.","anchor":"Thiếu gia ta không những muốn Lữ Yên Phi trở thành thê thiếp lô đỉnh","bridge":true,"khoang":"@c1072"},{"chuong":"@c1073","importance":"bridge","mucCt":"gon","text":"Tự mình thi triển thần thông điều tra manh mối về nhóm phàm nhân phương bắc nhưng không kết quả.","anchor":"Thậm chí ngay cả sư tôn Lữ Yên Phi đối với việc này cũng rất coi trọng"},{"mucCt":"vua","text":"Mang sát khí và đau khổ lao ra nghênh chiến Tử Đạo Tông, thề dù chết cũng không theo Lô Địch. Cuối cùng chứng kiến thân ảnh trắng của Vương Lâm đuổi theo linh thú màu đen dưới cầu vồng, hình ảnh in sâu vào con ngươi.","anchor":"Lô Địch, Lữ Yên Phi ta dù có chết cũng không theo ngươi!","bridge":true,"khoang":"@c1074"},{"mucCt":"vua","text":"Tươi cười lần đầu kể từ khi sư tôn bị trọng thương. Nhắc lại di ngôn bốn chữ “Phía bắc, tóc bạc” của sư tôn khi quy tiên, xác nhận Vương Lâm là người trong lời dặn. Kiên định rằng vị tiền bối tóc bạc sẽ giúp lần nữa, không cần truy tìm. Hủy diệt cuốn tranh cổ trong túi trữ vật bằng ám lực. Cùng Tôn Vân đến khu vườn dược thảo.","anchor":"Lúc sư tôn quy tiên đã từng nói bốn chữ “Phía bắc, tóc bạc.”","bridge":true,"khoang":"@c1075"},{"mucCt":"vua","text":"Cùng đệ tử Tôn Vân đến nhà gỗ Vương Lâm, kể chuyện sư thúc tổ Lữ Tử Đạo để gián tiếp trao thân phận 'Lữ Tử Hạo' cho Vương Lâm ẩn thân trong tông môn. Đã đoán ra Vương Lâm là người tóc trắng giết Tống Ngũ Đức và Lô Địch.","anchor":"Lữ sư thúc tổ này, chính là tổ tiên của nhà họ Lữ ta","bridge":true,"khoang":"@c1076"},{"chuong":"@c1081","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc lại là nữ tu thông minh Quy Nguyên Tông đã cung kính tặng hắn thân phận.","anchor":"nữ tu Lữ Yên Phi thông minh của Quy Nguyên Tông cũng đã cung kính tặng cho mình một thân phận"},{"mucCt":"vua","text":"Đã ngăn cản ba trưởng lão khác thăm dò nguồn chấn động nhiều ngày, cho thấy nàng biết hoặc đoán được liên quan đến Vương Lâm. Cuối cùng Lý Hướng Đông kiên quyết, Lữ Yến Phỉ bất an nhưng gật đầu đồng ý.","anchor":"Lữ sư muội, mặc kệ vì sao trước đây ngươi ngăn cản ba người chúng ta tiến lên kiểm tra, nhưng hôm nay chúng ta nhất định phải đi nhìn xem","bridge":true,"khoang":"@c1087"},{"mucCt":"vua","text":"Theo Lý Hướng Đông xuống lòng đất, bị thần niệm Vương Lâm đánh chảy máu khóe miệng nhưng hai mắt sáng ngời vì xác nhận suy đoán. Sau khi bốn người bị đánh bật ra, nàng tiết lộ người dưới lòng đất chính là sư thúc tổ Lữ Tử Hạo đang tiềm tu, khiến ba người kia kinh hoảng.","anchor":"Đã bảo các người đừng đi! Cũng may sư thúc tổ tuy tức giận nhưng không muốn làm chúng ta bị thương nặng!","bridge":true,"khoang":"@c1088"},{"importance":"bridge","mucCt":"gon","chuong":"@c1089","tieuDe":"Chứng kiến Kiếm Sư Thú xuất hiện","text":"Chứng kiến cảnh chiến đấu, hít sâu một hơi khi Kiếm Sư Thú cấp tám xuất hiện, mặt lộ vẻ khẩn trương.","anchor":"Ngay cả Lữ Yến Phỉ cũng hít cào một hơi thật sâu, trên mặt hiện lên vẻ khẩn trương"},{"mucCt":"gon","text":"Đứng cùng Lý Hướng Đông đợi ngoài dược viện, cung kính tham kiến Vương Lâm rồi cáo lui.","anchor":"Trong lòng Tôn Vân lại càng cảm thấy căng thẳng, nàng đi theo phía sau Lữ Yến Phỉ","bridge":true,"khoang":"@c1090"},{"mucCt":"ky","text":"Dẫn đệ tử Quy Nguyên Tông nghênh đón ba tông phái tinh vực cấp sáu. Nổi sát khí dùng gió lạnh ngăn Trừu Hải bảo vệ Tôn Vân nhưng bị bảy dấu ấn lam phá vỡ. Bị Phùng Bội Sơn quát một tiếng chứa thần thông trấn áp, phải khựng lại. Bình tĩnh giải thích Ngư Tinh Thảo trên người Tôn Vân do sư thúc tổ mang về, gián tiếp hé lộ có cao nhân ẩn trong tông.","anchor":"Ngư Tinh độc thảo này do sư thúc tổ mang về!","bridge":true,"khoang":"@c1092"},{"chuong":"@c1096","importance":"bridge","mucCt":"gon","tieuDe":"Không dám vào vườn","text":"Lữ Yến Phỉ được nhắc trong bối cảnh đám người Quy Nguyên Tông không dám tự tiện bước vào khu vườn phía nam nếu không được gọi.","anchor":"Dù là đám người Lữ Yến Phỉ, nếu không được gọi cũng không dám xâm nhập."},{"chuong":"@c1099","importance":"bridge","mucCt":"gon","tieuDe":"Tiễn biệt Mạc La","text":"Trong hồi tưởng, Lữ Yên Phỉ đứng trên căn lầu ở Mạc La đại lục đưa tiễn Vương Lâm, dặn hắn đừng quên Quy Nguyên Tông nếu sau này có địa vị trong tông phái.","anchor":"Trăm năm sau nếu có thể trở thành chủ tông hay người của bất kỳ bộ phận tông phái nào, mong rằng tiền bối đừng quên, cũng đừng nên quên Quy Nguyên Tông"},{"chuong":"@c1107","importance":"bridge","mucCt":"gon","tieuDe":"Được hồi tưởng","text":"Lữ Yên Phi được nhắc trong dòng hồi tưởng của Vương Lâm về những cô gái từng đi qua đời hắn.","anchor":"Dù la Hồng Điệp trên La Thiên, Tây Tử Phượng, hoặc là Liễu Mi, Lữ Yên Phi"},{"chuong":"@c1147","importance":"normal","mucCt":"vua","tieuDe":"Lo lắng chờ Vương Lâm về dự đại hội chủ tông","text":"Trên Mạc La đại lục (Vân Hải tinh vực), nhẹ nhàng hỏi Vương Lâm ở đâu, lo lắng chỉ còn một năm nữa là đại hội chủ tông.","anchor":"Chỉ còn một năm nữa là đại hội chủ tông… người có thể về kịp không?"},{"importance":"normal","mucCt":"ky","chuong":"@c1163","tieuDe":"Cắt quan hệ sư đồ, rời Quy Nguyên Tông đến Vô Cực Tông","text":"Đứng trên ngọn núi Quy Nguyên Tông nơi xưa lần đầu nói chuyện với Vương Lâm, Lữ Yên Phi đã chờ đợi thân ảnh hắn suốt trăm năm mà không thấy. Cuộc so tài phân tông sắp diễn ra, truyền tống trận chủ tông Vô Cực Tông đã mở. Nàng kiên quyết tuyên bố với Tôn Vân rằng sau chuyến đi này hai người không còn là sư đồ nữa, khen tư chất Tôn Vân sẽ trở thành đệ tử chủ chốt ở bất kỳ phân tông nào. Cùng ba sư huynh bước vào truyền tống trận hướng về chủ tông Vô Cực Tông ở bát giai tinh vực. Rơi lệ, bi cảm rằng khi Vương Lâm trở về thì Quy Nguyên Tông có lẽ không còn nữa.","anchor":"Có lẽ chờ tới khi ngươi trở về thì Quy Nguyên Tông.cũng không còn."}],"tuViMoc":[{"chuong":"@c1070","canhGioi":"Khuy Niết Hậu Kỳ đại viên mãn","text":"Tu vi được giới thiệu ở mức Khuy Niết Hậu Kỳ đại viên mãn khi xuất hiện.","importance":"major"},{"chuong":"@c1071","canhGioi":"Vấn Đỉnh","text":"Nhờ sư tôn luyện Man Thiên Đan trợ giúp mà Vấn Đỉnh thành công","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Thu nhận Tằng Ngưu (Vương Lâm giả danh) làm môn hạ","ghiChu":"@c1069"},{"ten":"Tôn Vân","tag":"su-mon","quanHe":"Nhị đệ tử","ghiChu":"Nữ tu thanh tú, nửa bước Âm Hư, lo lắng cho sư tôn"},{"ten":"Lô Địch","tag":"doi-thu","quanHe":"Kẻ ép song tu","ghiChu":"Lữ Yên Phi thề chết cũng không chịu"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Phàm nhân Tằng Ngưu mà nàng gặp trên đỉnh núi Quy Nguyên Tông","ghiChu":"Đánh giá hắn kiên định phi thường, nếu tu đạo sẽ có thành tựu"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân cứu Quy Nguyên Tông","ghiChu":"Thân ảnh trắng Vương Lâm đuổi linh thú in sâu vào con ngươi nàng"},{"ten":"Thiếu tông chủ áo tím","tag":"doi-thu","quanHe":"Kẻ đòi bắt nàng","ghiChu":"Thiếu tông chủ Tử Đạo Tông đòi bắt nàng hút nguyên âm"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ động tạo thân phận che giấu cho hắn, biết hắn là người giết Lô Địch"},{"ten":"Lữ Tử Đạo","tag":"ho-hang","quanHe":"Sư thúc tổ, tổ tiên nhà họ Lữ"},{"ten":"Lý Hướng Đông","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Quy Nguyên Tông","ghiChu":"Lý Hướng Đông kiên quyết yêu cầu đi kiểm tra, Lữ Yến Phỉ bất an nhưng đồng ý"},{"ten":"Trừu Hải","tag":"doi-thu","quanHe":"Đệ tử Ngũ Độc Môn, dùng gió lạnh ngăn nhưng bị phá","ghiChu":"@c1092"},{"ten":"Phùng Bội Sơn","tag":"doi-thu","quanHe":"Đệ tử hạch tâm Đạo Pháp Môn, trấn áp Lữ Yến Phỉ và toàn bộ Quy Nguyên Tông","ghiChu":"@c1092"},{"ten":"Triệu Vũ","tag":"doi-thu","quanHe":"Đệ tử Ma Tùng Đạo, gọi Lữ Yến Phỉ là tiểu mỹ nhân","ghiChu":"@c1092"}],"tuiDo":{}},"nguon":["@c1069","@c1070","@c1071","@c1072","@c1073","@c1074","@c1075","@c1076","@c1081","@c1087","@c1088","@c1089","@c1090","@c1092","@c1096","@c1099","@c1107","@c1147","@c1158","@c1163"]},{"id":"lao-tam-bac-thuy-thon","name":"Lão Tam","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Thôn dân Bắc Thủy Thôn bị rắn độc cắn trong rừng, được Vương Lâm cứu mạng.","vaiTro":"Thôn dân Bắc Thủy Thôn, người được Vương Lâm cứu sống","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Bị rắn độc cắn khi vào rừng, được Vương Lâm cứu mạng, là duyên cớ khiến Vương Lâm được thôn dân tiếp nhận","chuong":"@c1069"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1069","tieuDe":"Được Vương Lâm cứu khỏi rắn độc","text":"Bị rắn độc cắn trong rừng, được Vương Lâm cứu mạng.","anchor":"lão Tam nhà ta nói, nếu không có ngươi, hắn đã bị rắn độc cắn, không thể sống được"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Được Vương Lâm cứu khỏi rắn độc cắn","ghiChu":"@c1069"}],"tuiDo":{}},"nguon":["@c1069"]},{"id":"ton-van-thien-van-that-tu","name":"Tôn Vân","cn":"孙云","aliases":["Hứa Vân","Tôn Vân Sơn"],"gioiTinh":"nu","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Dương Thực (mở cửa, chưa chính thức đạt)","trangThai":"song","blurb":"Ngàn năm trước, Tôn Vân là kỳ tài Tử hệ vươn lên thay lão lục trở thành một trong Thiên Vận Thất tử tại Tử Vân Các, về sau bái Lữ Yên Phi làm sư tôn và gánh vác dược viên Nam Uyển của Quy Nguyên Tông. Ở cảnh giới nửa bước Âm Hư, nàng liều mạng nuốt Nhập Tử Ly Hồn Đan cực kỳ nguy hiểm để mở cửa cảnh Dương Thực hòng trợ giúp sư tôn, đồng thời nhiều lần xả thân nghênh chiến và bảo vệ đồng môn. Sau chuyến đi Vô Cực Tông, bị Lữ Yên Phi tuyên bố cắt quan hệ sư đồ, Tôn Vân rơi lệ và hiện mất tích.","vaiTro":"Kỳ tài Tử hệ — đệ tử Lữ Yên Phi, coi sóc dược viên Nam Uyển của Quy Nguyên Tông","tinhCach":"Tận tụy với sư môn, dốc sức bảo vệ dược viên tâm huyết; gan dạ liều lĩnh, dám nuốt đan dược cực hiểm và xông trận sống chết; giàu tình cảm, dễ xúc động trước nghĩa tình sư đồ","tabs":{"diem":[{"text":"Ngàn năm trước vươn lên thay lão lục, trở thành một trong Thiên Vận Thất tử của Tử Vân Các","chuong":"@c0453"},{"text":"Nuốt Nhập Tử Ly Hồn Đan cực kỳ nguy hiểm, hấp thu hồn lực vượn đen để mở cửa cảnh Dương Thực nhằm trợ giúp sư tôn Lữ Yên Phi","chuong":"@c1072"},{"text":"Liều sống chết bay theo trưởng lão nghênh chiến Tử Đạo Tông giữa mưa gió","chuong":"@c1074"},{"text":"Đau xót nổi giận khi dược viên tâm huyết nhiều năm bị phá hủy gần hết trong ba ngày","chuong":"@c1078"},{"text":"Bị sư tôn Lữ Yên Phi tuyên bố cắt quan hệ sư đồ sau chuyến đi Vô Cực Tông, rơi lệ","chuong":"@c1163"},{"text":"Cắn môi đến chảy máu khi Quy Nguyên Tông bị Lữ Anh Kiệt khiêu khích sỉ nhục, thể hiện lòng trung với sư môn","chuong":"@c1170"}],"kinhLich":[{"mucCt":"ky","text":"Dùng thần thông đám mây đưa Vương Lâm và hai thanh niên về khu vườn dược thảo Nam Uyển. Sắp xếp chỗ ở và truyền khẩu quyết luyện khí cho ba người. Ngạc nhiên trước sự bình tĩnh bất thường của Vương Lâm khi không có chút linh lực. Lo lắng cho sư tôn bị kẻ khác dòm ngó, liều mạng đột phá Dương Thực nhưng thất bại, phun máu, nguyên thần bị thương. Quyết định uống Nhập Tử Ly Hồn Đan nhưng bị Vương Lâm truyền âm một chữ Định ngăn lại.","anchor":"nhìn thế nào cũng không thấy được một chút linh lực, điều này làm cho nàng hết sức kinh ngạc","bridge":true,"khoang":"@c1070"},{"mucCt":"ky","text":"Nuốt viên Nhập Tử Ly Hồn Đan cực kỳ nguy hiểm vì muốn nhanh chóng đột phá trợ giúp sư tôn Lữ Yên Phi. Nguyên thần bị ngọn lửa thiêu đốt, con vượn đen mắt vàng xé rách nguyên thần, sắp thất bại thì được một thân ảnh áo trắng tóc bạc bí ẩn cứu bằng một chỉ kinh thiên động địa. Hấp thu hồn lực con vượn, mở cửa lớn tiến vào cảnh giới Dương Thực nhưng chưa chính thức đạt. Sau khi tỉnh, nhớ tới di ngôn sư tổ trước khi quy tiên — sau khi thi triển thần thông Trạch Linh chỉ nói 'Phía bắc… tóc trắng…' — lập tức bay đến tẩm cung sư tôn.","anchor":"Nếu không phải vì muốn tu vi nhanh chóng đột phá để có thể có được sức mạnh lớn nhấn trợ giúp cho sư tôn, nàng tuyệt đối sẽ không tùy tiện nuốt đan dược này","bridge":true,"khoang":"@c1072"},{"chuong":"@c1074","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Liều sống chết bay theo trưởng lão nghênh chiến Tử Đạo Tông, trong mưa gió nhớ lại hai thân ảnh của Vương Lâm chồng lên nhau.","anchor":"Một thân ảnh tóc đen gầy gò, tướng mạo không đẹp nhưng thủy chung bình tĩnh như nước"},{"chuong":"@c1075","importance":"bridge","mucCt":"vua","tieuDe":"Xác nhận Vương Lâm ẩn trong Quy Nguyên Tông","text":"Cùng Lữ Yên Phi đến khu vườn dược thảo, xác nhận với sư tôn rằng Vương Lâm đang ở chỗ này.","anchor":"Sư tôn, hắn, đang ở chỗ này."},{"importance":"bridge","mucCt":"gon","chuong":"@c1076","tieuDe":"Theo sư tôn gặp Vương Lâm","text":"Theo sư tôn Lữ Yên Phi đến nhà gỗ Vương Lâm, tâm lý khẩn trương, hoàn toàn không hiểu hàm ý lời sư tôn.","anchor":"Tôn Vân đối với lời nói của sư tôn hoàn toàn không hiểu gì"},{"mucCt":"ky","text":"Dùng trực giác nhận định Tằng Ngưu chính là người mặc áo trắng đã cứu nàng trước đó, dù hắn chưa thừa nhận. Dạy Vương Lâm nhận biết dược thảo Vân Hải Tinh Vực, giải thích về Ngưng Toái Thảo, Mặc Vân Chi và Vụ Trung Hoa. Rất đau lòng khi Vương Lâm hái dược thảo quý trong vườn — công sức của nàng và sư tôn. Khuyên hắn đến đan phòng ở Đông Uyển nhưng bị từ chối. Thiện cảm đối với Vương Lâm giảm đi phân nửa vì hắn tự đại không nghe lời.","anchor":"thiện cảm đối với Vương Lâm lúc trước giờ phút này cũng giảm đi phân nửa","bridge":true,"khoang":"@c1077"},{"chuong":"@c1078","importance":"bridge","mucCt":"vua","tieuDe":"Nổi giận vì dược viên bị phá hủy","text":"Đau xót nhìn dược viên tâm huyết nhiều năm gần như bị phá sạch trong ba ngày, cố kiềm lửa giận nhưng khi thấy chỉ luyện được đan dược cấp ba thì không nhịn nổi, hét đòi Tằng Ngưu trả dược thảo. Ngẩng đầu lên đã thấy phòng trống.","anchor":"Nhưng cuối cùng chỉ luyện chế ra một đan dược cấp ba, dù đan dược cấp ba cũng rất quý, rất cần thiết cho tu sĩ cảnh giới Dương Thực"},{"chuong":"@c1086","importance":"bridge","mucCt":"gon","text":"Đang đả tọa ngoài cửa dược viện, thấy Vương Lâm trở về liền nhận lại dược thảo, thở phào nhẹ nhõm.","anchor":"sợ Tằng Ngưu tiền bối mà bỏ đi thì sau này Tử Đạo Tông tiến đến mình sẽ là tội nhân thiên cổ"},{"mucCt":"gon","text":"Xác nhận với Lý Hướng Đông rằng dược thảo trong viện là sư thúc tổ mang về. Trong lòng căng thẳng khi ở gần Vương Lâm, theo Lữ Yến Phỉ rời đi.","anchor":"Trong lòng Tôn Vân lại càng cảm thấy căng thẳng, nàng đi theo phía sau Lữ Yến Phỉ","bridge":true,"khoang":"@c1090"},{"mucCt":"vua","text":"Phóng xuống đỡ đệ tử bị Trừu Hải đánh thương. Bị Trừu Hải phát hiện trên người có mùi Ngư Tinh Thảo — cỏ độc chỉ mọc ở sào huyệt mãnh thú cấp sáu — và truy vấn nguồn gốc.","anchor":"Bé gái, trên người ngươi sao lại có mùi vị Ngư Tinh Thảo?","bridge":true,"khoang":"@c1092"},{"importance":"normal","mucCt":"gon","chuong":"@c1163","tieuDe":"Bị sư tôn Lữ Yên Phi cắt quan hệ sư đồ","text":"Bị Lữ Yên Phi tuyên bố cắt quan hệ sư đồ sau chuyến đi tới Vô Cực Tông, Tôn Vân rơi lệ.","anchor":"Tư chất của ngươi rất tốt, chắc chắn ở bất kỳ một phân tông nào cũng sẽ trở thành đệ tử chủ chốt"}],"tuViMoc":[{"chuong":"@c1070","canhGioi":"Nửa bước Âm Hư","text":"Cảnh giới nửa bước Âm Hư khi xuất hiện, đột phá Dương Thực thất bại.","importance":"minor"},{"chuong":"@c1072","canhGioi":"Dương Thực (mở cửa, chưa chính thức đạt)","text":"Sau khi hấp thu hồn lực con vượn đen từ Nhập Tử Ly Hồn Đan, mở cửa lớn tiến vào cảnh giới Dương Thực nhưng còn cần thấu hiểu cảm ngộ mới chính thức đạt.","importance":"major"}],"nhanMach":[{"ten":"Lữ Yên Phi","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Lo lắng sư tôn bị kẻ khác dòm ngó ép song tu"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Phàm nhân mới tiếp nhận vào Quy Nguyên Tông","ghiChu":"Hắn truyền âm ngăn nàng uống Nhập Tử Ly Hồn Đan, lộ ra không phải phàm nhân"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân bí ẩn","ghiChu":"Bí mật cứu mạng khi nuốt đan sắp thất bại, nàng chỉ thấy thân ảnh áo trắng tóc bạc mà không biết danh tính"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Nhập Tử Ly Hồn Đan","trangThai":"dang-co","moTa":"Đan dược màu đen trợ đột phá, định uống nhưng bị Vương Lâm ngăn","nguon":"@c1070"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1070","@c1072","@c1074","@c1075","@c1076","@c1077","@c1078","@c1086","@c1090","@c1092","@c1163"]},{"id":"lo-dich","name":"Thiếu tông chủ áo tím","cn":"卢迪","aliases":["Thanh niên áo tím","Thiếu tông chủ Tử Đạo Tông","Thiếu tông chủ áo tím"],"gioiTinh":"nam","theLuc":[{"ten":"Tử Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Âm Hư","trangThai":"tu-vong","blurb":"Thiếu tông chủ Tử Đạo Tông, con của Lô Vân Tòng, tu vi Âm Hư. Hắn gửi ngọc giản màu tím ép Lữ Yên Phi song tu, đe dọa tâu Chủ Tông khai chiến với Quy Nguyên Tông nếu bị từ chối, nhưng bị nàng thề chết cự tuyệt. Khi đối mặt Vương Lâm, hắn sợ hãi cực điểm, đem thân phận thiếu tông chủ và tên cha ra dọa dẫm nhưng vô dụng, cuối cùng bỏ mạng; tàn hồn hiện ra từ ngọc giản bảo mệnh rồi tiêu tan trước mặt cha.","vaiTro":"Thiếu tông chủ Tử Đạo Tông — kẻ ép Lữ Yên Phi song tu","tinhCach":"Cưỡng ép, dâm dục; cậy quyền thế, hay đe dọa; hèn nhát khi lâm nguy (sợ hãi cực điểm, dọa dẫm vô dụng rồi bỏ chạy)","tabs":{"diem":[{"text":"Gửi ngọc giản tím ép Lữ Yên Phi song tu, đe dọa khai chiến với Quy Nguyên Tông nếu bị từ chối","chuong":"@c1071"},{"text":"Cưỡi linh thú khổng lồ màu đen cùng Tống Ngũ Đức","chuong":"@c1074"},{"text":"Tu vi Âm Hư khi xuất hiện","chuong":"@c1075"},{"text":"Sợ hãi cực điểm trước Vương Lâm, dọa dẫm bằng thân phận thiếu tông chủ và tên cha Lô Vân Tòng nhưng vô dụng","chuong":"@c1075"},{"text":"Bỏ mạng; tàn hồn hiện ra từ ngọc giản bảo mệnh vỡ rồi tiêu tan trước mặt cha Lô Vân Tòng","chuong":"@c1076"}],"kinhLich":[{"chuong":"@c1070","importance":"bridge","mucCt":"gon","text":"Được nhắc tên khi Lữ Yên Phi thề chết không song tu với hắn, ngọc giản tím liên quan tới việc ép buộc.","anchor":"Lô Địch, Lữ Yên Phi ta cho dù chết cũng quyết không cùng ngươi song tu!"},{"mucCt":"gon","text":"Gửi ngọc giản ép Lữ Yên Phi song tu, đe dọa tâu Chủ Tông khai chiến với Quy Nguyên Tông nếu bị từ chối.","anchor":"muốn ta cùng hắn song tu, nếu ta không đồng ý, sẽ thừa dịp sau khi sư tôn quy tiên","bridge":true,"khoang":"@c1071"},{"chuong":"@c1074","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được Lữ Yên Phi nhắc tên khi thề dù chết cũng không theo hắn. Cưỡi linh thú khổng lồ màu đen cùng Tống Ngũ Đức bay vào đại lục Mạc La, kiêu ngạo tuyên bố chiếm Quy Nguyên Tông, đòi bắt Lữ Yên Phi hút nguyên âm. Khi Tống Ngũ Đức bị Vương Lâm giết trong nháy mắt, kinh hoàng thét lên, cưỡi linh thú chạy trốn, bị Vương Lâm truy đuổi.","anchor":"Lô Địch, Lữ Yên Phi ta dù có chết cũng không theo ngươi!"},{"mucCt":"ky","text":"Sợ hãi cực điểm trước Vương Lâm, dọa dẫm bằng thân phận thiếu tông chủ và tên tuổi cha Lô Vân Tòng nhưng vô dụng. Lấy đóa sen đen bảo mệnh pháp bảo do phụ thân ban cho nhưng chưa kịp kích hoạt, Vương Lâm đã điểm ngón tay vào mi tâm, nguyên thần sụp đổ, thân thể phun máu tan rã mà chết. Đóa sen đen, túi trữ vật và linh thú đen đều bị Vương Lâm thu lấy.","anchor":"Ta là thiếu tông chủ của Tử Đạo Tông, nếu ngươi giết ta, cha ta là Lô Vân Tòng chắc chắn sẽ đồ sát toàn bộ đại lục Mạc La!","bridge":true,"khoang":"@c1075"},{"mucCt":"vua","text":"Đã chết ở chương trước. Tàn hồn hiện ra từ ngọc giản bảo mệnh vỡ với vẻ sợ hãi rồi tiêu tan trước mặt cha Lô Vân Tòng. Bị cha vạch trần tội mê nữ sắc, hấp thụ nguyên âm, hại nữ đệ tử nhiều tông phái.","anchor":"ánh mắt hắn lộ ra vẻ sợ hãi trước khi chết, tiêu tan ở trước mặt nam tử trung niên","bridge":true,"khoang":"@c1076"}],"tuViMoc":[{"chuong":"@c1075","canhGioi":"Âm Hư","text":"Tu vi Âm Hư khi xuất hiện (không có đột phá, đây là mốc xác lập).","importance":"minor"}],"nhanMach":[{"ten":"Lữ Yên Phi","tag":"khac","quanHe":"Đối tượng ép song tu","ghiChu":"Nàng thề chết từ chối"},{"ten":"Lô Vân Tòng","tag":"cha-me","quanHe":"Phụ thân, tông chủ Tử Đạo Tông, cho bảo mệnh pháp bảo đóa sen đen","ghiChu":"@c1075"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết mình bằng một ngón tay","ghiChu":"@c1075"},{"ten":"Tống Ngũ Đức","tag":"dong-minh","quanHe":"Hộ vệ đi cùng, cũng bị Vương Lâm giết trước đó","ghiChu":"@c1075"},{"ten":"Tống Ngũ Đức","tag":"dong-hanh","quanHe":"Hộ vệ","ghiChu":"Tống Ngũ Đức hộ tống thiếu tông chủ, bị giết trước mặt hắn"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết hộ vệ và truy đuổi","ghiChu":"Vương Lâm giết Tống Ngũ Đức rồi truy đuổi thiếu tông chủ"},{"ten":"Lữ Yên Phi","tag":"khac","quanHe":"Mục tiêu dâm dục","ghiChu":"Đòi bắt Lữ Yên Phi hút nguyên âm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1070","@c1071","@c1074","@c1075","@c1076"]},{"id":"dieu-bang-van","name":"Diêu Băng Vân","cn":"","aliases":["Mộng Vân","Tôn Vân"],"trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1071","tieuDe":"","text":"Vẫn đang trong phòng tĩnh tọa thổ nạp cố đột phá từ Âm Hư lên Dương Thực, không phát hiện Vương Lâm rời đi.","anchor":"Việc tu luyện của Tôn Vân vẫn chưa kết thúc, vẫn còn đang trong phòng yên lặng tĩnh tọa thổ nạp"}],"diem":[{"text":"Phụng Thiên Khung Lệnh của Diêu gia truy sát Vương Lâm, đồng thời vì quyết tâm cứu muội muội","chuong":"@c0774"},{"text":"Bị lốc xoáy trong não Vọng Nguyệt phun ra rồi bị xúc tu quấn hút sinh cơ, tự phong bế trong tầng băng","chuong":"@c0784"},{"text":"Bị Vương Lâm khống chế trong động phủ Hoàng Vân Sơn, trở thành nguồn nguyên lực cho hắn bế quan","chuong":"@c0791"},{"text":"Đạo niệm mở ra ký ức bị Diêu gia định sẵn làm linh hồn pháp bảo cùng muội muội Mộng Vân","chuong":"@c0795"},{"text":"Ý Cảnh bị Vương Lâm mượn để chứng đạo, lộ ra căn nguyên đạo tâm của nàng","chuong":"@c0797"},{"text":"Tĩnh tọa thổ nạp cố đột phá từ Âm Hư lên Dương Thực","chuong":"@c1071"}]},"nguon":["@c1071"],"vaiTro":"Tộc nhân đời thứ ba Diêu gia, sát thủ Hàn Phượng truy sát Vương Lâm","tinhCach":"kiên trì truy kích mục tiêu tới cùng; quyết tâm cứu muội; nhạy bén trong đấu pháp và truy tung; gánh chịu bi kịch gia tộc","blurb":"Diêu Băng Vân, còn được gọi là Hàn Phượng, là tộc nhân đời thứ ba Diêu gia ở La Thiên Đông Vực và từng phụng Thiên Khung Lệnh truy sát Vương Lâm suốt một chặng dài. Hành trình của nàng gắn với bi kịch bị lão tổ Diêu gia định sẵn làm khí hồn cùng muội muội Mộng Vân, và sau khi bị Vương Lâm khống chế thì trở thành nguồn nguyên lực cho hắn bế quan. Về sau đạo tâm của nàng được Vương Lâm mượn để chứng đạo, lộ ra căn nguyên tu luyện của chính nàng."},{"id":"thanh-nien-ao-tim","name":"Thanh niên áo tím","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Thanh niên tướng mạo anh tuấn nhưng toàn thân tà khí bạo ngược, cưỡi mãnh thú hình nòng nọc ở tầng năm Vân Hải Tinh Vực, tuyên bố muốn chiếm Lữ Yên Phi làm thê thiếp lô đỉnh và biến Quy Nguyên Tông thành tẩm cung.","vaiTro":"Kẻ thù nhắm vào Quy Nguyên Tông và Lữ Yên Phi","tinhCach":[{"text":"Ngạo mạn dâm tà, coi người khác như đồ vật, tự xưng thiếu gia"}],"tabs":{"diem":[{"text":"Tuyên bố muốn biến Lữ Yên Phi thành thê thiếp lô đỉnh và chiếm Quy Nguyên Tông làm tẩm cung, tà khí bao phủ toàn thân","chuong":"@c1072"}],"kinhLich":[{"mucCt":"vua","text":"Cưỡi mãnh thú hình nòng nọc khổng lồ ở tầng năm Vân Hải Tinh Vực gần đại lục Mạc La, tuyên bố muốn biến Lữ Yên Phi thành thê thiếp lô đỉnh và chiếm Quy Nguyên Tông làm tẩm cung.","anchor":"Thiếu gia ta không những muốn Lữ Yên Phi trở thành thê thiếp lô đỉnh, mà còn muốn Quy Nguyên Tông này trở thành tẩm cung của thiếu gia ta","bridge":true,"khoang":"@c1072"}],"tuViMoc":[],"nhanMach":[{"ten":"Tống thúc","tag":"khac","quanHe":"Lão giả theo hầu","ghiChu":"Cung kính hầu hạ, ánh mắt cưng chiều"},{"ten":"Lữ Yên Phi","tag":"khac","quanHe":"Mục tiêu chiếm đoạt","ghiChu":"Muốn biến thành thê thiếp lô đỉnh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1072"]},{"id":"tong-thuc","name":"Tống thúc","cn":"宋五德","aliases":["Tống thúc"],"gioiTinh":"nam","theLuc":[{"ten":"Tử Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết Trung Kỳ","trangThai":"tu-vong","blurb":"Lão giả theo hầu thanh niên áo tím, tự tin tuyên bố mười phần nắm chắc đối phó Quy Nguyên Tông vì sư tổ tông phái đã chết.","vaiTro":"Hộ vệ / trưởng bối theo hầu thanh niên áo tím","tinhCach":[{"text":"Bình thản tự tin, cưng chiều thanh niên áo tím"}],"tabs":{"diem":[{"text":"Khẳng định mười phần nắm chắc đối phó Quy Nguyên Tông sau khi sư tổ tông phái quy tiên","chuong":"@c1072"},{"text":"Tu vi Tịnh Niết Trung Kỳ, từng là bại tướng dưới tay lão tổ Quy Nguyên Tông năm xưa, đợi lão tổ quy tiên mới dám quay lại","chuong":"@c1074"},{"text":"Bị Vương Lâm giết trong nháy mắt bằng tổ hợp Sát Lục Khí + Hoán Vũ + Định + Không Niết Kiếm, hình thần câu diệt","chuong":"@c1074"}],"kinhLich":[{"mucCt":"vua","text":"Cung kính theo hầu thanh niên áo tím trên mãnh thú, bình thản tuyên bố nếu lão đạo kia (sư tổ Quy Nguyên Tông) chưa chết thì nửa phần nắm chắc cũng không có, nhưng hiện giờ là mười phần.","anchor":"Nếu lão đạo kia chưa chết, thì lão phu nửa phần nắm chắc cũng không có, nhưng lúc này, là mười phần","bridge":true,"khoang":"@c1072"},{"mucCt":"ky","text":"Cưỡi linh thú khổng lồ màu đen cùng thiếu tông chủ áo tím bay vào đại lục Mạc La, phóng cơn lốc cuốn sạch mưa và sấm sét thể hiện uy áp. Khi bị Vương Lâm chặn đường và ra lệnh rời đi vĩnh viễn, xin phép qua đường nhưng bị từ chối. Dùng tử phong chống đỡ Sát Lục Khí nhưng bất lực, bị tiên thuật Hoán Vũ khống chế nước mưa tấn công, bị thần thông Định cố định thân thể giữa không trung, nước mưa đóng thành tinh thể băng bao bọc. Cuối cùng bị Không Niết Kiếm chém một nhát — thể xác vỡ thành bốn năm mảnh, nguyên thần tan rã, hình thần câu diệt.","anchor":"thân thể đã bị vỡ thành bốn năm mảnh, ngay cả nguyên thần cũng vỡ tan","bridge":true,"khoang":"@c1074"},{"chuong":"@c1075","importance":"normal","mucCt":"gon","tieuDe":"Cái chết được nhắc lại","text":"Được nhắc lại đã bị Vương Lâm chém chết trong nháy mắt, nguyên thần tiêu tan giữa trời đất.","anchor":"Tống Ngũ Đức, chỉ trong nháy mắt đã bị thanh niên áo trắng này chém chết."},{"importance":"bridge","mucCt":"gon","chuong":"@c1076","tieuDe":"Được Lô Vân Tòng nhắc đến sau khi chết","text":"Lô Vân Tòng nhắc đến Tống Ngũ Đức là người chăm sóc Lô Địch từ nhỏ, đi cùng Lô Địch đến đại lục Mạc La và đã bị giết.","anchor":"Tông chủ, trước khi thiếu tông chủ đi, lão phu đã nghe Tống Ngũ Đức nói"}],"tuViMoc":[{"chuong":"@c1074","canhGioi":"Tịnh Niết Trung Kỳ","text":"Tu vi Tịnh Niết Trung Kỳ, được nhắc đến khi đối đầu Vương Lâm","importance":"major"}],"nhanMach":[{"ten":"Thanh niên áo tím","tag":"khac","quanHe":"Thiếu gia được hầu hạ","ghiChu":"Ánh mắt cưng chiều khi nhìn hắn"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết mình","ghiChu":"Bị Vương Lâm giết trong nháy mắt bằng tổ hợp tiên thuật và pháp bảo"},{"ten":"Thiếu tông chủ áo tím","tag":"dong-hanh","quanHe":"Người được hộ tống","ghiChu":"Hộ tống thiếu tông chủ Tử Đạo Tông xâm lược Quy Nguyên Tông"},{"ten":"Sư tổ Quy Nguyên Tông","tag":"doi-thu","quanHe":"Bại tướng năm xưa","ghiChu":"Từng thua lão tổ Quy Nguyên Tông, đợi lão tổ quy tiên mới dám quay lại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1072","@c1074","@c1075","@c1076"]},{"id":"su-to-quy-nguyen-tong","name":"Sư tổ Quy Nguyên Tông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"tu-vong","blurb":"Sư tổ đã quy tiên của Quy Nguyên Tông, trước khi chết thi triển thần thông Trạch Linh để lại di ngôn 'Phía bắc… tóc trắng…'.","vaiTro":"Sư tổ Quy Nguyên Tông, tiền bối đã mất","tinhCach":[],"tabs":{"diem":[{"text":"Trước khi quy tiên thi triển thần thông Trạch Linh tiên tri, chỉ để lại câu 'Phía bắc… tóc trắng…'","chuong":"@c1072"}],"kinhLich":[{"mucCt":"gon","text":"Trước khi quy tiên, thi triển thần thông Trạch Linh, chỉ nói 'Phía bắc… tóc trắng…'.","anchor":"Sư tổ trước khi quy tiên sau khi thi triển thần thông Trạch Linh, chỉ nói ra một câu","bridge":true,"khoang":"@c1072"}],"tuViMoc":[],"nhanMach":[{"ten":"Tôn Vân","tag":"su-mon","quanHe":"Đệ tử truyền thừa","ghiChu":"Tôn Vân nhớ lại di ngôn sư tổ"},{"ten":"Lữ Yên Phi","tag":"su-mon","quanHe":"Đệ tử (sư tôn của Tôn Vân)","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1072"]},{"id":"ton-van-son","name":"Tôn Vân Sơn","cn":"孙云","aliases":["Tôn Vân"],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Âm thầm điều tra ba mươi mốt phàm nhân từ phía bắc đến nhưng không thu hoạch gì. Đến phòng Vương Lâm trách hắn lười chăm dược thảo, nhưng khi đối mặt ánh mắt hắn thì theo bản năng nuốt lời, run sợ, nhận ra phong thái giống hệt người áo trắng hôm trước.","anchor":"bỗng nhiên khi đối mặt với ánh mắt Vương Lâm, lại theo bản năng nuốt xuống những lời sắp sửa nói","bridge":true,"khoang":"@c1073"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Chủ trì truyền tống trận khổng lồ của Huyền Uyên phái, ngăn em gái áo hồng đòi lên Đông Hải Yêu Linh","chuong":"@c0486"},{"text":"Cố đợi Vương Lâm để cùng đi Đông Hải Yêu Linh, dù than phiền phải lên đường theo lệnh gia phụ","chuong":"@c0487"},{"text":"Bị Tiên chủng vân xanh của lão tổ liên minh khống chế, kính sợ và xác nhận bản chất Tiên của Vương Lâm","chuong":"@c0576"},{"text":"Một trong bốn người được Vương Lâm cứu khỏi Minh vụ trùng và sấm sét","chuong":"@c0616"},{"text":"Âm thầm điều tra ba mươi mốt phàm nhân từ phía bắc nhưng không thu hoạch gì","chuong":"@c1073"}]},"nguon":["@c1073"],"vaiTro":"Thiếu tông chủ Huyền Uyên phái, chủ trì truyền tống trận đón Vương Lâm","tinhCach":"cẩn trọng, viện cớ tu vi để ngăn em gái phiêu lưu; nghe lời gia phụ dù bất đắc dĩ; kính sợ trước cường giả","blurb":"Tôn Vân Sơn là thiếu tông chủ Huyền Uyên phái, người chủ trì truyền tống trận đón Vương Lâm cùng đến Đông Hải Yêu Linh. Vì gia phụ bắt buộc, y phải lên đường dù biết nguy hiểm, và trong chuyến đi nhiều lần được Vương Lâm cứu giúp qua hiểm cảnh. Trải qua các biến cố, y dần kính sợ và nhận rõ bản chất phi thường của Vương Lâm."},{"id":"tu-muc-mang-quy-nguyen-tong","name":"Tử Mục Mãng (Quy Nguyên Tông)","cn":"紫目蟒","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Khuy Niết hậu kỳ","trangThai":"song","blurb":"Hộ tông linh thú Quy Nguyên Tông, rắn khổng lồ toàn thân tím, tu vi ngang Khuy Niết hậu kỳ, canh giữ đạo quán bí mật chứa di bảo lão tổ.","vaiTro":"Hộ tông linh thú canh giữ đạo quán bí mật Quy Nguyên Tông","tinhCach":"Hung hãn nhưng biết sợ kẻ mạnh hơn","tabs":{"diem":[{"text":"Rắn khổng lồ toàn thân tím, tu vi ngang Khuy Niết hậu kỳ, canh giữ di bảo lão tổ Quy Nguyên Tông.","chuong":"@c1073"}],"kinhLich":[{"mucCt":"gon","text":"Bốn ngày trước suýt bị Vương Lâm chém chết, giờ sợ hãi lùi lại nhường đường cho hắn vào xem di bảo.","anchor":"Con Tử Mục Mãng kia gầm nhẹ, những ánh mắt lộ ra vẻ sợ hãi, cuống quýt lùi về phía sau","bridge":true,"khoang":"@c1073"},{"chuong":"@c1074","importance":"bridge","mucCt":"gon","tieuDe":"","text":"E ngại Vương Lâm nên chui vào khe núi, khi Vương Lâm rời đi mới dám rống lên.","anchor":"giờ phút này vọt ra, hướng về chỗ Vương Lâm biết mất rống lên một trận"}],"tuViMoc":[{"chuong":"@c1073","canhGioi":"Khuy Niết hậu kỳ","text":"Tu vi ngang Khuy Niết hậu kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm suýt chém chết, sợ hãi nhường đường","ghiChu":"@c1073"}],"tuiDo":{}},"nguon":["@c1073","@c1074"]},{"id":"lao-gia-kiet-ngao","name":"Lão già kiệt ngạo","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"song","blurb":"Lão già vẻ mặt kiệt ngạo bí ẩn, cưỡi mãnh thú hình nòng nọc khổng lồ trăm trượng, tay phải có tử phong vờn quanh, phá vỡ tầng phòng hộ phía tây đại lục Mạc La xâm nhập vào bên trong.","vaiTro":"Nhân vật bí ẩn phá kết giới phía tây đại lục Mạc La","tinhCach":"Kiệt ngạo, bí ẩn","tabs":{"diem":[{"text":"Cưỡi mãnh thú hình nòng nọc trăm trượng toàn thân đen, tay phải có tử phong vờn quanh, phá vỡ kết giới phía tây đại lục Mạc La.","chuong":"@c1073"}],"kinhLich":[{"mucCt":"vua","text":"Cưỡi mãnh thú hình nòng nọc khổng lồ trăm trượng toàn thân đen, phá vỡ tầng phòng hộ phía tây đại lục Mạc La do hắc tháp phát ra, xâm nhập vào bên trong. Tay phải có tử phong vờn quanh.","anchor":"lão già vẻ mặt kiệt ngạo kia chậm rãi thu tay phải lại, ở trên tay phải của hắn có tử phong vờn quanh","bridge":true,"khoang":"@c1073"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1073"]},{"id":"ly-huong-dong","name":"Lý Hướng Đông","cn":"李向东","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nam tử trung niên, một trong tứ đại trưởng lão Quy Nguyên Tông, trú trên đỉnh Đông Uyển. Sau khi sư tôn quy tiên, ông quyết liều mạng nghênh chiến Tử Đạo Tông, rồi dấn thân điều tra mối nguy mãnh thú cấp cao xuất hiện bên ngoài tinh không Mạc La đại lục. Ông tận mắt chứng kiến sức mạnh kinh người của Vương Lâm và tin rằng Quy Nguyên Tông có thể xưng bá tinh vực.","vaiTro":"Trưởng lão Đông Uyển, một trong tứ đại trưởng lão Quy Nguyên Tông","tinhCach":"Trung nghĩa, đau đớn vì mất sư tôn nhưng không khuất phục; quyết liệt, sẵn sàng liều mạng; có trách nhiệm với tông môn và đại lục","tabs":{"diem":[{"text":"Đau khổ vì sư tôn quy tiên, hóa cầu vồng bay về phía tây liều mạng nghênh chiến Tử Đạo Tông","chuong":"@c1074"},{"text":"Phát hiện mãnh thú cấp bảy bên ngoài tinh không Mạc La đại lục, kiên quyết yêu cầu đi kiểm tra nguồn cơn","chuong":"@c1087"},{"text":"Không cam lòng rời đi trước nguy cơ hung thú cấp cao, dẫn đầu bốn người ứng phó","chuong":"@c1088"},{"text":"Kinh hoàng chứng kiến Vương Lâm một quyền đánh chết mãnh thú cấp sáu khi diệt Kiếm Sư Thú","chuong":"@c1089"},{"text":"Phấn chấn tin Quy Nguyên Tông có thể xưng bá tinh vực sau khi thấy Vương Lâm một cước giết hung thú cấp tám","chuong":"@c1090"},{"text":"Ôm quyền cung kính nghênh đón ba tông phái tinh vực cấp sáu","chuong":"@c1092"}],"kinhLich":[{"mucCt":"vua","text":"Sư tôn vừa quy tiên, đau khổ quyết liều mạng, hóa cầu vồng bay về phía tây nghênh chiến Tử Đạo Tông.","anchor":"Sư tôn vừa rời khỏi nhân thế, Tử Đạo Tông kia lại ngang ngược như vậy","bridge":true,"khoang":"@c1074"},{"mucCt":"vua","text":"Phát hiện mãnh thú cấp bảy xuất hiện bên ngoài tinh không Mạc La đại lục. Kiên quyết yêu cầu đi kiểm tra nguồn chấn động dù trước đó bị Lữ Yên Phỉ ngăn cản nhiều ngày.","anchor":"Lữ sư muội, mặc kệ vì sao trước đây ngươi ngăn cản ba người chúng ta tiến lên kiểm tra, nhưng hôm nay chúng ta nhất định phải đi nhìn xem","bridge":true,"khoang":"@c1087"},{"mucCt":"vua","text":"Bàn luận về nguy cơ hung thú cấp cao bị hấp dẫn tới Mạc La đại lục, không cam lòng rời đi, dẫn đầu bốn người xuyên đất tiến xuống sâu. Bị thần niệm Vương Lâm quét phun máu hai lần, xưng danh Quy Nguyên Tông nhưng chỉ nhận được chữ \"Cút!\", bị đánh xuyên đất văng ra ngoài.","anchor":"Nếu không nhìn thấy rõ ràng bên dưới có vật gì, ta không cam lòng.","bridge":true,"khoang":"@c1088"},{"importance":"bridge","mucCt":"vua","chuong":"@c1089","tieuDe":"Chứng kiến Vương Lâm diệt Kiếm Sư Thú","text":"Chứng kiến toàn bộ quá trình Vương Lâm tàn sát mãnh thú, kinh hoàng khi thấy mãnh thú cấp sáu bị một quyền đánh chết. Khi Kiếm Sư Thú cấp tám bị diệt, ngây dại đứng trống rỗng đầu óc.","anchor":"Cấp tám. Lý Hướng Đông trở nên ngây dại, trong đầu trống rỗng"},{"mucCt":"gon","text":"Chứng kiến Vương Lâm một cước giết hung thú cấp tám, phấn chấn tin Quy Nguyên Tông có thể xưng bá tinh vực cấp năm. Cung kính đợi ngoài dược viện tham kiến sư thúc tổ rồi cáo lui.","anchor":"Quy Nguyên Tông ta có tu sĩ đại thần thông kh*ng b* như vậy thì ngày xưng bá tinh vực cấp năm cũng còn không xa nữa","bridge":true,"khoang":"@c1090"},{"chuong":"@c1092","importance":"bridge","mucCt":"vua","text":"Ôm quyền cung kính nghênh đón ba tông phái tinh vực cấp sáu, nhận ra sức mạnh ba tông phái chiếm gần bốn phần tinh vực cấp sáu, cùng hai trưởng lão muốn ngăn cản nhưng bị Phùng Bội Sơn trấn áp.","anchor":"Ba tông phái vừa mới được đám người kia xưng danh đều hầu như chiếm gần bốn phần thế lực của tinh vực cấp sáu"}],"tuViMoc":[],"nhanMach":[{"ten":"Sư tổ Quy Nguyên Tông","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Sư tôn vừa quy tiên"},{"ten":"Lữ Yến Phỉ","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Quy Nguyên Tông","ghiChu":"Lữ Yên Phỉ từng ngăn cản Lý Hướng Đông thăm dò nguồn chấn động"}],"tuiDo":{}},"nguon":["@c1074","@c1087","@c1088","@c1089","@c1090","@c1092"]},{"id":"lo-van-tong","name":"Lô Vân Tòng","cn":"卢云从","aliases":["Tông chủ Tử Đạo Tông","Nam tử mặc tử kim bào"],"gioiTinh":"nam","theLuc":[{"ten":"Tử Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ, tu vi thấp hơn Lý Thiến Mai @c1095","trangThai":"song","blurb":"Lô Vân Tòng là Tông chủ Tử Đạo Tông ở tầng thứ năm Vân Hải Tinh Vực, phụ thân của Lô Địch. Ông từng dẫn hơn ba mươi đệ tử hạch tâm tiến về Mạc La đại lục để đối đầu Vương Lâm, nhưng sau khi nghe luận đạo thì phải ôm quyền cúi đầu kính phục. Trải trăm năm dẫn dắt Tử Đạo Tông phát triển mạnh, mơ hồ xếp đầu trong tinh vực cấp năm, dù cuối cùng cay đắng nhận ra khoảng cách tu vi với Vương Lâm quá lớn.","vaiTro":"Tông chủ Tử Đạo Tông tầng năm Vân Hải Tinh Vực, phụ thân Lô Địch","tinhCach":"Trọng đạo, đề cao thiên và đạo; biết người biết ta, kính phục kẻ mạnh hơn mình; kiêu ngạo chế giễu đối thủ yếu thế; kiên trì dẫn dắt tông phái","tabs":{"diem":[{"text":"Dẫn hơn ba mươi đệ tử hạch tâm cưỡi hổ thú tiến về Mạc La đại lục","chuong":"@c1094"},{"text":"Trả lời hai câu hỏi của Lý Thiến Mai về thiên và đạo trước khi đối đầu Vương Lâm","chuong":"@c1095"},{"text":"Nghe luận đạo của Vương Lâm mà kinh ngạc, phải ôm quyền cúi đầu kính phục","chuong":"@c1097"},{"text":"Trải trăm năm dẫn dắt Tử Đạo Tông phát triển, mơ hồ xếp đầu tinh vực cấp năm","chuong":"@c1147"},{"text":"Dẫn Tử Đạo Tông quét ngang đại hội phân tông cấp năm tại Vô Cực Tông, không có đối thủ","chuong":"@c1180"},{"text":"Cay đắng nhận ra khoảng cách tu vi với Vương Lâm quá lớn, mừng vì trăm năm trước không cố ra tay","chuong":"@c1191"}],"kinhLich":[{"mucCt":"vua","text":"Chưa trực tiếp xuất hiện. Được Lô Địch nhắc tên để dọa Vương Lâm, tuyên bố cha sẽ đồ sát toàn bộ đại lục Mạc La nếu con bị giết. Tuy nhiên lời dọa vô ích.","anchor":"Người này tư chất cực cao, cho dù là ở bên trong tầng thứ năm của tinh vực này, cũng là cực kỳ hiếm thấy, thanh danh hiển hách!","bridge":true,"khoang":"@c1075"},{"mucCt":"ky","text":"Đang ngoài tinh vụ cùng lão già áo tím thì ngọc giản bảo mệnh vỡ nát, tàn hồn Lô Địch hiện ra với vẻ sợ hãi rồi tiêu tan. Tuy gọi con là nghịch tử, thừa nhận Lô Địch mê nữ sắc hại nữ đệ tử nhiều tông phái hấp thụ nguyên âm, nhưng tuyên bố sẽ chôn Lữ Yên Phi cùng con và giết kẻ đã giết hắn. Nghe tin Lô Địch muốn lấy Thiên Âm Phiên ở Tử Vân Hải thì nổi giận dữ dội quát 'Nghịch tử!'.","anchor":"tên nghịch tử không nên người này, chết thì cũng đã chết rồi, từ nay về sau thế gian cũng bớt đi một mối họa","bridge":true,"khoang":"@c1076"},{"mucCt":"gon","text":"Được ba người Phùng Bội Sơn, Triệu Vũ, Trừu Hải nhắc đến: trên đường đi đã gặp người Tử Đạo Tông, mục tiêu nhắm vào Quy Nguyên Tông vì ân oán cá nhân.","anchor":"Tên Lô Vân Tòng này cũng không phải loại người đơn giản","bridge":true,"khoang":"@c1093"},{"mucCt":"ky","text":"Lô Vân Tòng dẫn hơn ba mươi đệ tử hạch tâm của Tử Đạo Tông cưỡi hổ thú tiến về Mạc La đại lục, mục tiêu là Quy Nguyên Tông. Hắn phân tích vụ đan phương và ngọc giản, kết luận Độc Bà Tử không thể là thủ phạm, mà có một tu sĩ thần bí thực lực rất cao đã giết Tiền Quý Chung rồi giá họa để chuyển hướng truy đuổi. Hắn tán thưởng đối phương tâm trí sâu xa, nói muốn kết giao và có dự cảm một ngày sẽ đối mặt. Khi Lý Thiến Mai chặn đường hỏi ba vấn đề, hắn trả lời vấn đề thứ nhất rằng thiên là nhà tù.","anchor":"Ta rất muốn có quan hệ với tên tu sĩ thần bí này. Ta có dự cảm sẽ có một ngày đối mặt với hắn.","bridge":true,"khoang":"@c1094"},{"mucCt":"ky","text":"Lô Vân Tòng trả lời hai câu hỏi của Lý Thiến Mai về thiên và đạo, rồi cùng nàng đến Mạc La đại lục để tìm tu sĩ thần bí đã đoạt đan phương và ngọc giản. Hắn dặn người tùy tùng ở lại để tránh gây hỗn loạn vì Tử Đạo Tông và Quy Nguyên Tông cùng chung một chủ tông. Khi gặp Vương Lâm, hắn dùng ý cảnh dung nhập từng bước chân vào thiên địa để tấn công đạo niệm, nhưng bị Vương Lâm chỉ một lời phá tan và bị khẳng định là không thể so sánh về đạo niệm.","anchor":"Dù đạo của Lô Vân Tòng có sâu sắc thế nào, dù đạo niệm có kiên định như thiên địa, thì cũng không thể nào so sánh với Vương Lâm được","bridge":true,"khoang":"@c1095"},{"mucCt":"ky","text":"Lô Vân Tòng đối diện uy áp đạo niệm của Vương Lâm thì tiến thoái lưỡng nan, cảm giác đạo của mình bị đối phương đùa giỡn. Khi nghe Vương Lâm luận thiên chỉ là lời bịa đặt, hắn không thể phản bác, đạo niệm cả đời xuất hiện vết nứt, sắc mặt tái nhợt và khạc máu. Cuối chương, hắn hiểu ra vì sao đáp án từng tưởng hoàn mỹ cho câu hỏi thứ hai của mình vẫn không đủ tư cách tiến tới câu hỏi thứ ba.","anchor":"Khoảnh khắc này đạo niệm hắn kiên trì theo đuổi cả đời đã xuất hiện vết nứt, hắn muốn phản bác lời nói của tên thanh niên áo trắng trước mặt nhưng lại không thể.","bridge":true,"khoang":"@c1096"},{"mucCt":"ky","text":"Lô Vân Tòng nghe luận đạo của Vương Lâm mà kinh ngạc, phải ôm quyền cúi đầu kính phục và sau đó cũng có chút tỉnh ngộ khi nghe Lý Thiến Mai nói đạo là tư tưởng. Khi lão già cưỡi mãnh hổ dẫn đệ tử hạch tâm xông vào Mạc La đại lục, hắn quát lui toàn bộ. Hắn xin Vương Lâm trả Âm Tiên Phiên, tiết lộ đó là vật do chủ tông ban xuống, nhưng bị từ chối. Cuối cùng hắn chấp nhận con trai chết dưới tay Vương Lâm như một phần tạo hóa, uống rượu rồi cáo từ rời đi.","anchor":"Con trai của ta quả thật đáng chết, có thể chết dưới tay người này cũng coi như là tạo hóa của hắn","bridge":true,"khoang":"@c1097"},{"chuong":"@c1100","importance":"normal","mucCt":"gon","tieuDe":"Ý cảnh được nhắc lại","anchor":"Ngày trước Lô Vân Tòng dùng khí thế của thiên địa để chèn ép Vương Lâm, lấy ý cảnh ép người nhưng lại phải vỡ tan trước mặt Vương Lâm","text":"Lô Vân Tòng được nhắc lại như người từng dùng khí thế thiên địa và ý cảnh ép Vương Lâm, khiến Vương Lâm về sau ngộ thành thần thông ý cảnh bước chân của riêng mình."},{"chuong":"@c1147","importance":"normal","mucCt":"vua","tieuDe":"Dẫn dắt Tử Đạo Tông phát triển, nhớ Vương Lâm","text":"Tông chủ Tử Đạo Tông, trải trăm năm dẫn dắt tông phái phát triển mạnh, mơ hồ xếp đầu trong tinh vực cấp năm tiến cấp sáu. Thường nhìn hư không nhớ đến Vương Lâm, thì thầm muốn gặp lại luận đàm.","anchor":"Lữ huynh, năm xưa cùng luận đàm với ngươi, Lô mỗ đã thu được rất nhiều lợi ích"}],"tuViMoc":[],"nhanMach":[{"ten":"Lô Địch","tag":"cha-me","quanHe":"Con trai, thiếu tông chủ Tử Đạo Tông (đã bị Vương Lâm giết, Lô Vân Tòng chưa biết)","ghiChu":"@c1075"},{"ten":"Tống Ngũ Đức","tag":"khac","quanHe":"Thuộc hạ tin cẩn, người chăm sóc Lô Địch từ nhỏ, đã chết"},{"ten":"Lữ Yên Phi","tag":"doi-thu","quanHe":"Mục tiêu trả thù, định chôn theo con trai"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết con (chưa biết danh tính cụ thể)"},{"ten":"Lão già áo tím (Tử Đạo Tông)","tag":"dong-minh","quanHe":"Thuộc hạ/đồng môn","ghiChu":"Xuất hiện chúc mừng tông chủ bắt thêm tinh hổ thú."},{"ten":"Lý Thiến Mai","tag":"khac","quanHe":"người chặn đường đặt vấn đề","ghiChu":"Lý Thiến Mai chặn đoàn Tử Đạo Tông và hỏi Lô Vân Tòng vấn đề về thiên."},{"ten":"Lão già tùy tùng Lô Vân Tòng","tag":"dong-minh","quanHe":"tùy tùng lâu năm","ghiChu":"Lão già theo Lô Vân Tòng nhiều năm và bẩm báo tiến độ hành trình."},{"ten":"Độc Bà Tử","tag":"khac","quanHe":"đối tượng phân tích","ghiChu":"Lô Vân Tòng cho rằng Độc Bà Tử bị tu sĩ thần bí giá họa."},{"ten":"Tiền Quý Chung","tag":"khac","quanHe":"người chết trong vụ án","ghiChu":"Lô Vân Tòng dùng cái chết của Tiền Quý Chung để chứng minh thủ phạm không phải Độc Bà Tử."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1075","@c1076","@c1093","@c1094","@c1095","@c1096","@c1097","@c1100","@c1147"]},{"id":"lao-gia-ao-tim-tu-dao-tong","name":"Lão già áo tím (Tử Đạo Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tử Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Lão già mặc áo tím thuộc Tử Đạo Tông, xuất hiện bên cạnh tông chủ Lô Vân Tòng chúc mừng việc bắt tinh hổ thú để luyện Hổ Cốt Hồn Đan.","vaiTro":"Thành viên Tử Đạo Tông, tùy tùng tông chủ","tinhCach":"Nịnh bợ; hào sảng","tabs":{"diem":[{"text":"Xuất hiện bên cạnh Lô Vân Tòng tại đại lục tím, ôm quyền chúc mừng tông chủ bắt được tinh hổ thú, nói Hổ Cốt Hồn Đan sắp luyện thành.","chuong":"@c1075"},{"text":"Tiết lộ Lô Địch muốn lấy Thiên Âm Phiên ở Tử Vân Hải để phong ấn hồn phách nữ tử","chuong":"@c1076"},{"text":"Xuất hiện bên Lô Vân Tòng sau khi tông chủ luyện hóa tinh hổ thú, chúc mừng Hổ Cốt Hồn Đan sắp thành.","chuong":"@c1075"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1076","tieuDe":"Bẩm báo tông chủ về Lô Địch","text":"Theo hầu tông chủ Lô Vân Tòng, bẩm báo Lô Địch đến đại lục Mạc La và tiết lộ Lô Địch muốn lấy Thiên Âm Phiên ở Tử Vân Hải.","anchor":"Tông chủ, trước khi thiếu tông chủ đi, lão phu đã nghe Tống Ngũ Đức nói"}],"tuViMoc":[],"nhanMach":[{"ten":"Lô Vân Tòng","tag":"cap-tren","quanHe":"Tông chủ Tử Đạo Tông","ghiChu":"@c1075"},{"ten":"Tông chủ Tử Đạo Tông","tag":"cap-tren","quanHe":"Tông chủ","ghiChu":"Bên cạnh chúc mừng @c1075"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1075","@c1076"]},{"id":"lu-tu-dao","name":"Lữ Tử Đạo","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"trangThai":"mat-tich","blurb":"Sư thúc tổ của Lữ Yên Phi, tổ tiên nhà họ Lữ. Người sùng đạo ẩn cư, cả đời chưa rời đại lục Mạc La trừ một lần mất tích, không ai từng gặp. Lữ Yên Phi dùng lai lịch nhân vật này để tạo thân phận cho Vương Lâm.","vaiTro":"Sư thúc tổ Quy Nguyên Tông, nhân vật được nhắc lại để tạo thân phận giả","tinhCach":"Sùng đạo; ẩn cư; bí ẩn","tabs":{"diem":[{"text":"Cả đời ẩn cư không ai gặp, một lần đi ra ngoài rồi mất tích — lai lịch được dùng để tạo thân phận Lữ Tử Hạo cho Vương Lâm","chuong":"@c1076"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1076","tieuDe":"Được Lữ Yên Phi nhắc đến","text":"Lữ Yên Phi kể lại lai lịch: người sùng đạo ẩn cư cả đời chưa rời đại lục Mạc La trừ một lần mất tích, dùng câu chuyện này tạo thân phận cho Vương Lâm.","anchor":"cả đời ngoài một lần đi ra ngoài rồi mất tích, còn chưa bao giờ đi ra khỏi đại lục Mạc La"}],"tuViMoc":[],"nhanMach":[{"ten":"Lữ Yên Phi","tag":"ho-hang","quanHe":"Hậu duệ nhà họ Lữ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1076"]},{"id":"ly-su-thuc-quy-nguyen-tong","name":"Lý sư thúc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Sư thúc trong Quy Nguyên Tông, có thuật luyện đan tuyệt luân, sở hữu ba cây Vụ Trung Hoa khô duy nhất trong tông.","vaiTro":"Đan sư bậc cao của Quy Nguyên Tông","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Thuật luyện đan tuyệt luân trong Quy Nguyên Tông, sở hữu ba cây Vụ Trung Hoa khô quý hiếm duy nhất trong tông.","chuong":"@c1077"}],"kinhLich":[{"chuong":"@c1077","importance":"bridge","mucCt":"gon","text":"Được Tôn Vân nhắc đến như sư thúc có thuật luyện đan tuyệt luân, sở hữu ba cây Vụ Trung Hoa khô duy nhất trong tông.","anchor":"Thuật luyện đan của Lý sư thúc, ở trong Quy Nguyên Tông có thể nói là tuyệt luân"}],"tuViMoc":[],"nhanMach":[{"ten":"Tôn Vân","tag":"su-mon","quanHe":"Đồng môn, Tôn Vân gọi là sư thúc","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Vụ Trung Hoa (khô)","moTa":"Ba cây hoa khô duy nhất trong Quy Nguyên Tông, dược liệu quý hiếm.","trangThai":"dang-co","nguon":"@c1077"}],"linhThao":[],"khac":[]}},"nguon":["@c1077"]},{"id":"van-thu","name":"Văn Thú","tabs":{"kinhLich":[{"chuong":"@c1078","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm thả ra trong tinh vụ, hơn mười con bay lượn vui sướng, Văn Thú vương cõng Vương Lâm bay ba ngày đến Man Hoang đại lục.","anchor":"Mười mấy con Văn Thú tản ra bay lượn khắp bốn phía phát ra những âm thanh vo ve, lộ ra vẻ vô cùng vui sướng"},{"chuong":"@c1079","importance":"bridge","mucCt":"gon","text":"Hơn mười Văn Thú hộ tống Vương Lâm ở Man Hoang đại lục, giao chiến tiêu diệt mãnh thú hình chim ưng rồi bay quanh khỉ đen mới thu phục.","anchor":"trên bầu trời hơn mười Văn Thú liên tục gào thét"},{"chuong":"@c1081","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm cất vào túi trữ vật vì tình cảnh không thích hợp.","anchor":"Văn Thú đã sớm bị Vương lâm bỏ vào trong túi trữ vật"},{"chuong":"@c1099","importance":"bridge","mucCt":"gon","tieuDe":"Chiếm Phong tiên giới","text":"Văn Thú được nhắc tới như nguyên nhân khiến Phong tiên giới bị chiếm giữ, làm Vân Hải tinh vực khó khai thác tiên ngọc.","anchor":"Phong tiên giới bị Văn Thú chiếm giữ, vì không thể tiến vào thì tất nhiên sẽ không lấy được Tiên ngọc"},{"chuong":"@c1103","importance":"bridge","mucCt":"gon","tieuDe":"Được chuẩn bị thăng cấp","text":"Văn thú được Vương Lâm dự định dùng nguyên tinh tẩm bổ để thăng cấp, nhằm đủ sức bảo vệ hắn tiến vào Phong Tiên giới.","anchor":"muốn Văn thú có thể dùng phương pháp này để thăng cấp đủ bảo vệ ta thành công tiến vào Phong tiên giới"},{"chuong":"@c1129","importance":"normal","mucCt":"vua","tieuDe":"Thôn phệ thú hồn hồi phục","text":"Được Vương Lâm thả ra khỏi không gian trữ vật, dáng vẻ cực kỳ dữ tợn, tâm thần tương thông với chủ nhân hiểu kế hoạch. Bị cuốn vào động phủ có cấm chế kèm nhiều thú hồn và vài vạn nguyên tinh, liên tục chém giết thôn phệ thú hồn đồng thời hấp thu nguyên lực từ trận pháp chuyển hóa nguyên tinh.","anchor":"bộ dạng của Văn Thú đã cực kỳ dữ tợn"},{"chuong":"@c1152","importance":"normal","mucCt":"vua","tieuDe":"Suy yếu chờ lột xác, được Vương Lâm đổ nguyên tinh","text":"Nằm trong động phủ thứ nhất sơn cốc Tư Mã Mặc, bên ngoài thân thể có vật hình quả trứng bao bọc, cực kỳ suy yếu do thiếu nguyên tinh chưa hoàn toàn lột xác. Khi thần thức Vương Lâm dò tới liền mở mắt vui mừng. Được Vương Lâm đổ hết nguyên tinh ra cho hấp thụ, bắt đầu tiếp tục lột xác.","anchor":"bên ngoài thân thể dường như có một vật hình quả trứng bao bọc"},{"chuong":"@c1153","importance":"major","mucCt":"ky","tieuDe":"Lột xác thành công, khí tức ngang Tịnh Niết","text":"Hoàn thành lột xác sau trăm năm tế luyện bằng lượng nguyên tinh khổng lồ: toàn thân chuyển màu vàng nhạt, kích cỡ thu nhỏ còn ba trượng, khí tức đạt ngang Tịnh Niết. Phá vỡ quả trứng bao phủ, hút khô quả trứng, hưng phấn vờn quanh Vương Lâm rồi bị thu lại. Vương Lâm coi là đòn sát thủ, chưa có đàn hoàn chỉnh sẽ không để người khác nhìn thấy.","anchor":"Văn Thú toàn thân màu vàng nhạt mang theo sự hứng khởi, vờn quanh bên người Vương Lâm"},{"chuong":"@c1164","importance":"normal","mucCt":"ky","tieuDe":"Đàn Văn Thú nghênh đón Vương Lâm vào Phong Tiên Giới","text":"Hơn một trăm con Văn Thú đỏ thẫm to trăm trượng cùng đám sương đỏ phun ra từ khe Phong Tiên Giới, dữ tợn hung ác, miệng phát tán tinh phong nồng đậm. Bị Tế Thiên Hương của nhóm tu sĩ cản lại. Khi Văn Thú vàng nhạt đặc biệt do Vương Lâm cưỡi xuất hiện, toàn bộ Văn Thú đỏ thẫm lập tức lộ vẻ cung kính né tránh, vờn quanh hộ tống rồi cùng quay về bên trong sương đỏ. Xác nhận Văn Thú chiếm cứ Phong Tiên Giới không thể thuần hóa bằng bất cứ phương pháp nào, Thần Tông từng phái tu sĩ đại thần thông vào đều thất bại không ai sống sót.","anchor":"những Văn Thú này không thể thuần hóa thành linh thú, bất kể là phương pháp gì, cũng không thể thành công"},{"chuong":"@c1165","importance":"normal","mucCt":"ky","tieuDe":"Thể hiện uy quyền Văn Thú Vương trong Phong Tiên Giới","text":"Được Vương Lâm triệu hồi bên trong Phong Tiên Giới, thể hiện hình thái sau lột xác: Văn Thú màu vàng nhạt. Tỏa uy lực tuyệt đối khiến hơn trăm Văn Thú đỏ tại khe nứt lao tới nghênh đón thần phục như đón vua. Hưng phấn ngửa mặt kêu dài, triệu tập thêm hơn trăm Văn Thú từ sương đỏ, tất cả run rẩy thần phục.","anchor":"có uy lực tuyệt đối, dường như theo đám người Lý Nguyên Lôi nhìn, thì những Văn Thú màu đỏ này quả thật đang tiếp đón vua của chúng"},{"chuong":"@c1166","importance":"bridge","mucCt":"gon","text":"Theo lệnh Vương Lâm phát tiếng rống triệu hồi bầy, tỏa uy áp vàng nhạt khuất phục gần nghìn Văn Thú đợt đầu nhưng bất lực trước đàn mấy vạn con, bộc lộ thực lực kém xa Văn Thú cùng cấp trong Phong Tiên Giới.","anchor":"Văn Thú của hắn cũng đã từng đạt tới màu tím, thậm chí bây giờ cũng đã đạt tới màu vàng, nhưng thực lực cũng còn kém rất xa Văn Thú trong Phong Tiên Giới này"},{"chuong":"@c1168","importance":"normal","mucCt":"vua","tieuDe":"Hạ sát bốn Văn Thú lam, giao chiến Văn Thú trắng","text":"Đã biến thành màu lam, xâm nhập vùng đất Văn Thú lam, dùng xúc tu hút tinh hoa hạ sát liên tiếp bốn Văn Thú lam cùng đẳng cấp. Giao chiến với Văn Thú màu trắng (khí tức Toái Niết), bị thương nhưng học được thần thông tách lông của đối thủ để đối công. Cuối chương bị Văn Thú Vương màu tím chú ý.","anchor":"trong cuộc đời nó, những lần chém giết đồng loại vẫn còn quá ít, dường như đang học hỏi"},{"chuong":"@c1169","importance":"normal","mucCt":"ky","tieuDe":"Tiến hóa thành Văn Thú Vương mới","text":"Giả vờ thần phục tiếng kêu vương giả của Văn Thú Vương màu tím, chậm rãi bay tới gần; nhờ đã lột xác thành màu vàng, khí tức thật sự bị ẩn giấu nên không bị phát hiện. Sau khi Vương Lâm đánh trọng thương Văn Thú Vương, toàn thân tỏa lam quang rồi bùng phát kim quang vạn dặm, ngửa mặt phát tiếng kêu vương giả khiến toàn bộ đàn Văn Thú kính sợ ngừng chiến. Lao tới dùng xúc tu đâm vào thân Văn Thú Vương màu tím hấp thụ toàn bộ tinh hoa, đối phương héo rũ rồi tiêu tan — Văn Thú Vương mới chính thức ra đời.","anchor":"Văn Thú Vương mới đã sinh ra rồi!"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Đột phá lên trung phẩm linh cấp (ngang Nguyên Anh hậu kỳ đại viên mãn) sau khi dung hợp Cực Quang Hỏa Tuyến","chuong":"@c0266"},{"text":"Được xác nhận là thú đến từ tinh không, hung tính vượt xa yêu thú tu chân giới, sống bằng cắn nuốt vạn vật","chuong":"@c0479"},{"text":"Hoàn thành lột xác sau trăm năm tế luyện bằng nguyên tinh, khí tức đạt ngang Tịnh Niết, toàn thân chuyển màu vàng nhạt","chuong":"@c1153"},{"text":"Hạ sát Văn Thú lam, chiến thắng Văn Thú Vương tím cũ và tiến hóa thành tân Văn Thú Vương xác lập vương quyền","chuong":"@c1169"},{"text":"Máu biến dị hóa vàng, hiện hình bóng Văn Vương vạn trượng, hút máu Văn Vương khổng lồ tại trung tâm Phong giới","chuong":"@c1178"},{"text":"Thống lĩnh hơn vạn Văn Thú theo lệnh Vương Lâm chinh chiến, hút máu mãnh thú cấp mười ba khiến tu vi tăng mạnh","chuong":"@c1228"}]},"nguon":["@c1078","@c1079","@c1081","@c1099","@c1103","@c1129","@c1152","@c1153","@c1164","@c1165","@c1166","@c1168","@c1169"],"gioiTinh":"khong-ro","trangThai":"song","canhGioiCaoNhat":"Tịnh Niết (khí tức)","cn":"蚊兽","vaiTro":"Linh thú tọa kỵ trung thành nhất của Vương Lâm — Văn Thú Vương đến từ tinh không","tinhCach":"Trung thành tuyệt đối với chủ nhân, sống chết không rời; hung mãnh hiếu chiến, sống bằng cắn nuốt hút máu vạn vật; nặng tình đồng tộc, liều mình cứu bầy dù mang trọng thương; cảnh giác nhạy bén, phản ứng cực nhanh trước nguy hiểm","blurb":"Văn Thú — thường được gọi là con muỗi khổng lồ — là hung thú đến từ tinh không với bản tính hung tàn vượt xa yêu thú tu chân giới, trở thành linh thú tọa kỵ trung thành nhất của Vương Lâm từ thuở hắn còn Ngưng Khí. Sau khi dung hợp Cực Quang Hỏa Tuyến đột phá lên trung phẩm linh cấp, nó trải qua trăm năm tế luyện bằng nguyên tinh để lột xác đạt khí tức ngang Tịnh Niết, rồi tại Phong Tiên Giới khuất phục gần nghìn đồng tộc, hạ sát Văn Thú lam, chiến thắng Văn Thú Vương tím và tiến hóa thành tân Văn Thú Vương thống lĩnh hơn vạn Văn Thú. Trong trận đối đầu Văn Vương khổng lồ tại trung tâm Phong g"},{"id":"khi-den-khong-lo","name":"Khỉ đen khổng lồ","cn":"","aliases":["Con khỉ đen"],"gioiTinh":"khong-ro","vaiTro":"Linh thú của Vương Lâm — hung thú cấp sáu ở Man Hoang đại lục","tinhCach":"Hung mãnh, dữ tợn; quy thuận và phục tùng sau khi bị thu phục","blurb":"Hung thú đứng đỉnh phong cấp năm ở Man Hoang đại lục, thân trăm trượng, mang lực lượng giống Cổ Thần. Bị Vương Lâm đánh trọng thương rồi thu phục bằng Khống Linh Ấn, đột phá lên cấp sáu và trở thành linh thú, được dùng để cướp đoạt dược thảo và dẫn dụ mãnh thú.","theLuc":[],"canhGioiCaoNhat":"Mãnh thú cấp sáu","trangThai":"song","tabs":{"diem":[{"text":"Đột phá từ cấp năm đứng đỉnh phong lên mãnh thú cấp sáu dưới nguy cơ","chuong":"@c1079"},{"text":"Ngồi khoanh chân trên đỉnh núi Man Hoang triệu tập mãnh thú tấn công Vương Lâm, bị đánh trọng thương","chuong":"@c1079"},{"text":"Chở Vương Lâm trên vai phá hang chim ưng đoạt dược thảo, quét chân hạ hắc ưng cấp năm giữa thủy triều","chuong":"@c1080"},{"text":"Bị Vương Lâm lợi dụng liên tục xông vào sào huyệt mãnh thú cướp đoạt dược thảo nhờ biết trước vị trí","chuong":"@c1081"},{"text":"Dẫn đàn mãnh thú vượt qua sơn cốc rồi phóng đi xa, hoàn thành nhiệm vụ dẫn dụ","chuong":"@c1082"},{"text":"Bị Vương Lâm gỡ bùa vàng thu vào túi trữ vật, sau được gọi ra để ngồi trên vai ngụy trang","chuong":"@c1083"}],"kinhLich":[{"mucCt":"vua","text":"Ngồi khoanh chân trên đỉnh núi Man Hoang, triệu tập mãnh thú tấn công Vương Lâm nhưng bị đánh trọng thương bởi thần thông điều khiển nguyên lực. Dưới nguy cơ đột phá lên cấp sáu, hiện thần thông Tụ hồn vào thân. Bị Vương Lâm ấn tay ép linh hồn quay về, dùng Khống Linh Ấn thu phục, gật đầu quy thuận trở thành linh thú.","anchor":"con khỉ đen khổng lồ trước mặt cũng chính là hung thú cấp năm","bridge":true,"khoang":"@c1079"},{"chuong":"@c1080","importance":"bridge","mucCt":"gon","text":"Chở Vương Lâm trên vai, phá hang chim ưng đoạt dược thảo, quét chân hạ hắc ưng cấp năm giữa thủy triều hơn mười vạn mãnh thú truy kích.","anchor":"Thân thể khổng lồ của nó phóng qua đỉnh núi vẽ ra một vòng tròn giống như nhảy dây"},{"mucCt":"ky","text":"Được Vương Lâm lợi dụng liên tục xông vào sào huyệt mãnh thú cướp đoạt dược thảo, biết trước vị trí thảo dược, nổi danh khắp Man Hoang đại lục vì thói cướp đoạt lâu ngày. Được dán bùa vàng tăng tốc, quay lại quậy phá đoàn thú rồi mới chạy, phải Vương Lâm vỗ vai mới chịu tiếp tục chạy. Dẫn cơn thủy triều mãnh thú xông vào khu vực trung tâm đại lục, xuyên qua các sơn cốc sương mù yên tĩnh bất thường.","anchor":"nó hình như đã biết trước những địa phương có thảo dược rồi","bridge":true,"khoang":"@c1081"},{"importance":"bridge","mucCt":"gon","chuong":"@c1082","tieuDe":"Dẫn mãnh thú vượt sơn cốc","text":"Dẫn đàn mãnh thú vượt qua sơn cốc rồi phóng đi xa, hoàn thành nhiệm vụ dẫn dụ.","anchor":"hóa thành một cái đầu lâu xám nhỏ như nắm tay, vẫn lơ lửng trên bầu trời không nhúc nhích"},{"chuong":"@c1083","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm gỡ bùa vàng rồi thu vào túi trữ vật, sau đó được gọi ra để Vương Lâm ngồi trên vai ngụy trang bình thường khi rời Man Hoang đại lục.","anchor":"Con khỉ đen vừa nhìn thấy Vương Lâm thì lập tức trở nên vui vẻ"}],"tuViMoc":[{"chuong":"@c1079","canhGioi":"Mãnh thú cấp sáu","text":"Đột phá từ cấp năm đứng đỉnh phong lên cấp sáu dưới nguy cơ sinh tử khi bị Vương Lâm đánh trọng thương, hiện thần thông Tụ hồn vào thân.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân","ghiChu":"Bị Vương Lâm thu phục bằng Khống Linh Ấn tại Man Hoang đại lục."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1079","@c1080","@c1081","@c1082","@c1083"]},{"id":"thi-lac-hinh","name":"Thi Lạc Hình","cn":"施洛形","aliases":["Đàn ông trung niên","Nam tử trung niên"],"gioiTinh":"nam","theLuc":[{"ten":"Hoa Thanh Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Thi Lạc Hình là đệ tử Hoa Thanh Tông (tông phái cấp sáu), tu vi Tịnh Niết hậu kỳ. Được tông môn bí mật cử dẫn mười chín đệ tử vào tinh vực cấp ba theo manh mối, hắn tìm được ngọc giản Phá Thiên Tông chứa bí phương Niết Không Đan, nhưng hành tung bại lộ dẫn đến bị truy đuổi và tử vong, khiến các tông phái phong tỏa Man Hoang đại lục.","vaiTro":"Đệ tử Hoa Thanh Tông — người tìm được ngọc giản Phá Thiên Tông","tinhCach":"Liều lĩnh dám mạo hiểm; có trách nhiệm dẫn dắt đệ tử; hành sự bí mật thận trọng","tabs":{"diem":[{"text":"Tự xưng tu vi đạt Tịnh Niết hậu kỳ","chuong":"@c1080"},{"text":"Lén dẫn mười chín đệ tử vào tinh vực cấp ba, tìm được ngọc giản Phá Thiên Tông","chuong":"@c1080"},{"text":"Được Hoa Thanh Tông bí mật cử tìm mảnh xương thú chứa phương pháp luyện Niết Không Đan","chuong":"@c1084"},{"text":"Cái chết của hắn khiến các tông phái phong tỏa Man Hoang đại lục","chuong":"@c1086"},{"text":"Hành động tại Hoa Thanh Tông bị thám tử Ngũ Độc Môn phát hiện manh mối","chuong":"@c1091"}],"kinhLich":[{"mucCt":"ky","text":"Thi Lạc Hình lén mang mười chín đệ tử vào tinh vực cấp ba theo manh mối, tìm được ngọc giản Phá Thiên Tông chứa phương pháp bào chế Niết Không Đan. Hành tung bại lộ, trên đường về bị vây công, mười lăm đệ tử tử trận, bản thân trúng kịch độc Ngũ Độc Môn. Bị lão bà Ngũ Độc Môn dùng trận pháp tám đầu lâu dẫn động tử hồn vây hãm trong sơn cốc trên Man Hoang đại lục. Đã truyền tin cầu viện Hoa Thanh Tông nhưng viện binh chưa tới. Lão bà tiết lộ gần như toàn bộ tông phái tinh vực cấp sáu đều đang truy đuổi.","anchor":"lão thân là đệ tử của Hoa Thanh Tông cấp sáu, tu vi đã đạt đến Tịnh Niết hậu kỳ","bridge":true,"khoang":"@c1080"},{"mucCt":"vua","text":"Được Hoa Thanh Tông bí mật cử dẫn 19 đệ tử đến tinh vực cấp ba tìm mảnh xương thú chứa phương pháp luyện Niết Không Đan. Thành công lấy được mảnh xương thú nhỏ và ngọc giản, nhưng trên đường về bị Ngũ Độc Môn đuổi giết. Thẻ sinh mệnh trong Tập Anh Các đã vỡ vụn, xác nhận tử vong.","anchor":"thẻ sinh mệnh của Thi Lạc Hình trong Tập Anh Các ở tông phái đã vỡ vụn","bridge":true,"khoang":"@c1084"},{"chuong":"@c1086","importance":"normal","mucCt":"gon","text":"Tin Thi Lạc Hình chết lan ra khắp tinh vực, cái chết của hắn khiến các tông phái phong tỏa Man Hoang đại lục.","anchor":"Ngay cả cái chết của Thi Lạc Hình cũng có liên quan rất lớn đến tên tu sĩ này"},{"chuong":"@c1091","importance":"bridge","mucCt":"gon","text":"Hành động của hắn tại Hoa Thanh Tông bị thám tử Ngũ Độc Môn phát hiện manh mối liên quan đến dấu tích nhóm Tư Mã Mặc.","anchor":"tin tức suy đoán có liên quan đến hành động của Thi Lạc Hình"}],"tuViMoc":[{"chuong":"@c1080","canhGioi":"Tịnh Niết hậu kỳ","text":"Tự xưng tu vi đã đạt Tịnh Niết hậu kỳ.","importance":"major"}],"nhanMach":[{"ten":"Độc Bà Tử","tag":"doi-thu","quanHe":"Đối thủ truy đuổi ngọc giản","ghiChu":"Lão bà Ngũ Độc Môn dùng trận pháp vây khốn, uy hiếp giao nộp ngọc giản"},{"ten":"Tiền Quý Chung","tag":"cap-tren","quanHe":"Trưởng lão Hoa Thanh Tông, dẫn đội cứu viện hắn","ghiChu":"@c1084"}],"tuiDo":{"phapBao":[{"ten":"Ngọc giản Phá Thiên Tông","trangThai":"dang-co","moTa":"Ngọc giản từ Phá Thiên Tông tinh vực cấp tám, chứa phương pháp bào chế Niết Không Đan","nguon":"@c1080"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1080","@c1083","@c1084","@c1086","@c1091"]},{"id":"doc-ba-tu","name":"Độc Bà Tử","cn":"毒婆子","aliases":["Lão bà Ngũ Độc Môn","Lão bà dùng độc"],"gioiTinh":"nu","theLuc":[{"ten":"Ngũ Độc Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Lão phụ nhân thuộc Ngũ Độc Môn (tông phái cấp sáu), tu vi Tịnh Niết trung kỳ với độc công vượt xa đồng cấp. Bố đại trận tám đầu lâu dẫn động tử hồn Man Hoang đại lục vây khốn Thi Lạc Hình để cướp ngọc giản Phá Thiên Tông, nhưng khi giao chiến với Vương Lâm thì bị bắt nguyên thần làm vật thế thân, sau đó bị Sưu Hồn lấy toàn bộ ký ức.","vaiTro":"Trưởng bối Ngũ Độc Môn, truy đuổi ngọc giản Phá Thiên Tông","tinhCach":"Dữ tợn; tham lam; tự tin vào sức mạnh trận pháp","tabs":{"diem":[{"text":"Tu vi Tịnh Niết trung kỳ, độc công vượt xa đồng cấp","chuong":"@c1081"},{"text":"Bố trận tám đầu lâu khổng lồ dẫn động tử hồn Man Hoang vây khốn Thi Lạc Hình","chuong":"@c1080"},{"text":"Giao chiến Vương Lâm, phóng ba luồng khí (mây đỏ, mưa đen, rắn đầu người)","chuong":"@c1082"},{"text":"Bị Vương Lâm bắt nguyên thần làm vật thế thân, cố ý không cho chết","chuong":"@c1083"},{"text":"Bị thi triển Sưu Hồn lấy toàn bộ ký ức","chuong":"@c1091"},{"text":"Bị ba tông phái cấp sáu (Ngũ Độc Môn, Ma Tùng Đạo, Đạo Pháp Môn) truy lùng gắt gao","chuong":"@c1092"}],"kinhLich":[{"mucCt":"vua","text":"Dùng tám đầu lâu khổng lồ bố trận pháp dẫn động tử hồn Man Hoang đại lục vây khốn Thi Lạc Hình trong sơn cốc. Uy hiếp giao nộp ngọc giản Phá Thiên Tông, tiết lộ gần như toàn bộ tông phái tinh vực cấp sáu đều đang truy đuổi.","anchor":"Thi đạo hữu, mười chín tên để tử của ngươi cũng chỉ còn lại bốn tên","bridge":true,"khoang":"@c1080"},{"mucCt":"ky","text":"Đứng trên đầu lâu điều khiển trận pháp tám đầu lâu hấp thu tử hồn bao vây sơn cốc tại trung tâm Man Hoang đại lục. Thấy con khỉ đen dẫn sóng mãnh thú tới, ngỡ Vương Lâm là viện binh Hoa Thanh Tông hoặc tông phái cấp sáu, chủ động tấn công để độc chiếm ngọc giản và phương pháp chế tạo Niết Không Đan. Thi triển ba luồng khí độc (mây đỏ chặn đòn, mưa nước đen kịch độc, tượng Độc Vương) cùng thần thông Độc Linh Ẩn và thả linh thú rắn đen mào gà.","anchor":"Mời độc vương hiện thân! Độc Linh Ẩn!","bridge":true,"khoang":"@c1081"},{"mucCt":"ky","text":"Giao chiến với Vương Lâm tại sơn cốc Man Hoang đại lục. Phóng ba luồng khí (đám mây đỏ, mưa đen, con rắn đầu mào gà) và Ấn Độc từ pho tượng hư ảo. Toàn thân biến đổi thành hình thái mãnh thú khi hoảng loạn. Cắn đầu lưỡi chuẩn bị phun máu độc nhưng bị Định Thân Thuật trói, máu độc phản phệ khiến thân thể thối rữa. Bị trường thương đen đâm xuyên ngực nổ tung, vỡ nát thành mưa máu, nguyên thần bị Vương Lâm thu.","anchor":"bà ta đã không còn là một tu sĩ, mà giống như một mãnh thú có thân hình con người","bridge":true,"khoang":"@c1082"},{"chuong":"@c1083","importance":"normal","mucCt":"vua","tieuDe":"Bị Vương Lâm bắt nguyên thần làm vật thế thân","text":"Nguyên thần bị Vương Lâm bắt giữ, cố ý không cho chết. Vương Lâm tạo hiện trường giả khiến các tông phái nghĩ bà lấy đan phương Niết Không đan rồi độc chiếm bỏ trốn, biến bà thành mục tiêu truy sát thay mình.","anchor":"Nguyên thần của Độc Bà Tử đã bị ta bắt, nhất định không để cho bà ta chết được"},{"chuong":"@c1091","importance":"normal","mucCt":"vua","tieuDe":"Bị Sưu Hồn lấy toàn bộ ký ức","text":"Nguyên thần bị Vương Lâm lấy ra, bị điểm ngón tay suy yếu dần rồi bị thi triển Sưu Hồn lấy toàn bộ ký ức gồm thuật luyện độc, chuyện đời, ký ức về đan phương và ngọc giản. Nguyên thần suy yếu nhưng chưa chết, bị thu lại vào túi trữ vật.","anchor":"đem nguyên thần Độc Bà Tử đang rất suy yếu nhưng chưa chết bỏ vào trong túi trữ vật"},{"chuong":"@c1092","importance":"bridge","mucCt":"gon","text":"Bị ba tông phái tinh vực cấp sáu (Ngũ Độc Môn, Ma Tùng Đạo, Đạo Pháp Môn) truy lùng gắt gao trên các tinh vực cấp năm, Ngũ Độc Môn đã phải trả giá rất lớn vì chuyện này.","anchor":"bắt buộc tất cả tông phái trên tinh vực cấp sáu cùng lên đường tìm kiếm một người"},{"chuong":"@c1094","importance":"bridge","mucCt":"gon","tieuDe":"Bị giá họa vụ án","text":"Độc Bà Tử bị Lô Vân Tòng nhắc tới như người bị tu sĩ thần bí giá họa trong vụ đan phương, khiến mục tiêu truy đuổi của tinh vực cấp sáu chuyển sang hắn và Ngũ Độc Môn.","anchor":"Với tu vi của Độc Bà Tử sao có lực ngăn cản tlh tự bạo?"}],"tuViMoc":[{"chuong":"@c1081","canhGioi":"Tịnh Niết trung kỳ","text":"Tu vi Tịnh Niết trung kỳ, độc công vượt xa đồng cấp.","importance":"major"}],"nhanMach":[{"ten":"Thi Lạc Hình","tag":"doi-thu","quanHe":"Mục tiêu cướp ngọc giản","ghiChu":"Dùng trận pháp vây khốn, uy hiếp giao nộp vật phẩm"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ giao chiến","ghiChu":"Hiểu lầm Vương Lâm là viện binh đối thủ, chủ động tấn công tại trung tâm Man Hoang đại lục."},{"ten":"Lô Vân Tòng","tag":"khac","quanHe":"người phân tích vụ giá họa","ghiChu":"Lô Vân Tòng cho rằng Độc Bà Tử không đủ khả năng làm thủ phạm thật sự."},{"ten":"Tiền Quý Chung","tag":"khac","quanHe":"liên quan vụ giá họa","ghiChu":"Cái chết của Tiền Quý Chung bị ấn định cho Độc Bà Tử và Ngũ Độc Môn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1080","@c1081","@c1082","@c1083","@c1091","@c1092","@c1094"]},{"id":"nam-tu-trung-nien-son-coc","name":"Nam tử trung niên (sơn cốc Man Hoang)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Tịnh Niết hậu kỳ","trangThai":"tu-vong","blurb":"Tu sĩ Tịnh Niết hậu kỳ trúng kịch độc Ngũ Độc Môn tại sơn cốc Man Hoang đại lục, bốn đệ tử đã chết vì bảo vệ hắn. Xin Vương Lâm giao ngọc giản và phương pháp luyện đan rồi cho cái chết thống khoái.","vaiTro":"Tu sĩ Tịnh Niết hậu kỳ trúng kịch độc, giao phó vật phẩm cho Vương Lâm","tinhCach":"Bình tĩnh đối diện cái chết; trọng tình nghĩa với đệ tử; thẳng thắn giao dịch","tabs":{"diem":[{"text":"Tu sĩ Tịnh Niết hậu kỳ trúng kịch độc Ngũ Độc Môn, không thể vận chuyển nguyên lực, nguyên thần đang dần tử vong, mi tâm lộ lỗ đen.","chuong":"@c1082"},{"text":"Bốn đệ tử đã chết vì bảo vệ hắn trước lão bà Ngũ Độc Môn, hắn xin được chết thống khoái thay vì bị sâu độc tra tấn.","chuong":"@c1082"}],"kinhLich":[{"mucCt":"ky","text":"Trúng kịch độc Ngũ Độc Môn tại sơn cốc, mi tâm lộ lỗ đen, không thể vận chuyển nguyên lực, nguyên thần đang dần tử vong. Bốn đệ tử đã chết vì bảo vệ hắn. Cảm ơn Vương Lâm cứu mạng rồi xin cho mượn nguyên lực mở túi trữ vật lấy ngọc giản và phương pháp luyện đan giao lại, đổi cái chết thống khoái. Khi Vương Lâm phóng nguyên lực đến gần ba tấc cơ thể hắn, nguyên lực đột nhiên biến đổi bất thường.","anchor":"Khi ta độc phát thì không thể vận chuyển nguyên lực trong cơ thể","bridge":true,"khoang":"@c1082"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người cứu hắn khỏi lão bà Ngũ Độc Môn, nhờ giao phó ngọc giản và phương pháp luyện đan","ghiChu":"@c1082"},{"ten":"Độc Bà Tử","tag":"doi-thu","quanHe":"Lão bà Ngũ Độc Môn hạ độc giết bốn đệ tử của hắn và hạ kịch độc lên hắn","ghiChu":"@c1082"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Ngọc giản và phương pháp luyện đan","trangThai":"mat","moTa":"Hai vật phẩm trong túi trữ vật, muốn giao cho Vương Lâm. Chưa rõ nội dung cụ thể, đáng giá đến mức gây chết người.","nguon":"@c1082"}]}},"nguon":["@c1082","@c1083"]},{"id":"ngan-y-luyen-thi","name":"Ngân Y Luyện Thi","cn":"银衣炼尸","aliases":["Ngân Y Nữ Thi"],"gioiTinh":"nu","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1082","tieuDe":"Chiến đấu bắt sống con rắn đầu mào gà","text":"Được Vương Lâm thả ra từ túi trữ vật, chiến đấu với con rắn nhỏ đầu mào gà rồi bắt sống nó.","anchor":"Ngân Y Nữ Thi lập tức phóng thẳng về phía con rắn nhỏ"},{"chuong":"@c1085","importance":"bridge","mucCt":"gon","text":"Xuất hiện từ túi trữ vật, không tham chiến mà đi thu phục linh thú mất chủ ở bốn phía.","anchor":"Ngân Y Nữ Thi lại xuất hiện"},{"chuong":"@c1124","importance":"bridge","mucCt":"vua","text":"Được thả ra hộ pháp Vương Lâm, hừ lạnh khiến Hứa Lập Quốc run rẩy, sau đó khoanh chân ngồi bên cạnh Vương Lâm với ánh mắt lộ vẻ mê man và dịu dàng.","anchor":"ánh mắt đảo qua mặt Vương Lâm mà bên trong lộ ra vẻ mê man và một chút dịu dàng"},{"chuong":"@c1125","importance":"normal","mucCt":"vua","tieuDe":"Thi triển và giải trừ Sinh Tử Cấm","text":"Mơ hồ nhớ lại điều gì đó, dựa trí nhớ đặt Sinh Tử Cấm lên cổng động phủ, phương pháp thành thạo hơn cả lão bà áo xanh. Khi Vương Lâm hỏi, thừa nhận có chút ký ức về Sinh Tử Cấm rồi vỗ một chưởng giải trừ cấm chế, sau đó bị thu vào không gian trữ vật.","anchor":"phương pháp cấm chế của nàng rõ ràng thành thạo hơn cả lão bà áo xanh"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Bị Vương Lâm gọi ra trong cung điện phong kín, tỉnh lại liền phản kháng bằng lốc xoáy mi tâm","chuong":"@c0931"},{"text":"Được xác nhận tu vi Tịnh Niết sơ kỳ, được gọi ra xử lý Vũ hậu độc hương và phá tan Hoa Linh","chuong":"@c0944"},{"text":"Lén hóa ngân quang nhảy vào Vũ Tiên Giới mà chính Vương Lâm cũng không phát hiện","chuong":"@c1040"},{"text":"Lần đầu mở miệng nói chuyện với giọng đứt quãng như mới học nói, kịp thời cứu nguy trận pháp","chuong":"@c1046"},{"text":"Dựa trí nhớ mơ hồ đặt Sinh Tử Cấm lên cổng động phủ, phương pháp thành thạo hơn cả lão bà từng dạy","chuong":"@c1125"},{"text":"Tự mở khe không gian trữ vật bước ra ngoài khống chế, bắt nuốt kim tuyến Lan Phi và cảnh báo hương hỏa là âm mưu","chuong":"@c1251"}]},"nguon":["@c1082","@c1085","@c1124","@c1125"],"trangThai":"song","canhGioiCaoNhat":"Kết Đan kỳ","vaiTro":"Luyện thi áo bạc bị Vương Lâm khống chế, hộ vệ thủy chung theo sát bảo vệ hắn","tinhCach":"phản kháng dữ dội lúc mới tỉnh; trầm mặc ít nói, giọng đứt quãng như mới học nói; trung thành bám sát bảo vệ chủ nhân; khí tức sắc bén, ra tay quyết đoán trong chiến đấu","blurb":"Ngân Y Luyện Thi là xác chết áo bạc do Vương Lâm khống chế, tu vi cao nhất đạt Tịnh Niết sơ kỳ. Từ chỗ tỉnh lại phản kháng bằng lốc xoáy mi tâm, nàng dần bị luyện hóa thành hộ vệ trung thành, theo sát Vương Lâm qua nhiều trận chiến và thậm chí lén hóa ngân quang theo hắn vào Vũ Tiên Giới. Sau nhiều năm im lặng, nàng lần đầu mở miệng nói với giọng đứt quãng, rồi dựa trí nhớ mơ hồ thi triển những cấm thuật như Sinh Tử Cấm thành thạo hơn cả người từng dạy, tới mức có lúc tự bước ra khỏi khống chế để hành động theo ý mình."},{"id":"tien-quy-chung","name":"Tiền Quý Chung","cn":"钱贵忠","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoa Thanh Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết @c1094","trangThai":"tu-vong","blurb":"Tiền Quý Chung là trưởng lão Hoa Thanh Tông, tu vi Toái Niết sơ kỳ, nổi danh hung ác trong tinh vực cấp sáu. Hắn cưỡi mãng xà hình rồng dẫn đệ tử hạch tâm bay về Man Hoang đại lục cứu viện Thi Lạc Hình, nhưng bị Vương Lâm chém nát thân thể thành 19 mảnh và tiêu diệt nguyên thần, chết hoàn toàn.","vaiTro":"Trưởng lão Hoa Thanh Tông, chỉ huy đội cứu viện Thi Lạc Hình","tinhCach":"Hung ác tàn nhẫn; quyết đoán, phản kích mạnh bạo khi bị công kích","tabs":{"diem":[{"text":"Trưởng lão Hoa Thanh Tông, tu vi Toái Niết sơ kỳ","chuong":"@c1084"},{"text":"Cưỡi mãng xà hình rồng dẫn đệ tử hạch tâm về Man Hoang cứu viện Thi Lạc Hình","chuong":"@c1084"},{"text":"Bùng phát tu vi, phản kích bằng thần thông hắc quang khi Vương Lâm tàn sát đệ tử","chuong":"@c1085"},{"text":"Bị 19 kiếm Thứ Không Niết chém nát thân thể thành 19 mảnh, nguyên thần bị tiêu diệt, chết hoàn toàn","chuong":"@c1086"},{"text":"Được Lô Vân Tòng xác nhận đã bị giết sau khi rời Man Hoang đại lục","chuong":"@c1094"}],"kinhLich":[{"mucCt":"ky","text":"Tiền Quý Chung cưỡi mãng xà hình rồng dẫn đệ tử hạch tâm bay về Man Hoang đại lục cứu viện Thi Lạc Hình. Giữa đường nhận ngọc giản truyền tin báo thẻ sinh mệnh Thi Lạc Hình trong Tập Anh Các đã vỡ vụn, xác nhận đại đệ tử đã chết. Hắn chấn động, theo nguyên tắc thà giết lầm không bỏ sót, hạ lệnh tám đệ tử bắt Vương Lâm mang đến Man Hoang đại lục.","anchor":"vẻ mặt Tiền Quý Chung lập tức trở nên âm trầm, hắn hung hăng bóp chặt ngọc giản","bridge":true,"khoang":"@c1084"},{"mucCt":"ky","text":"Khi Vương Lâm ra tay tàn sát đệ tử, quay đầu phản kích bằng thần thông hắc quang phá tầng phòng hộ sát lục của Vương Lâm. Triệu trường thương đen tấn công bị Phong Tiên Ấn chặn. Xé vết nứt hư không lấy phất trần trắng thi triển quy tắc thiên địa hóa bạch quang mưa kiếm xuyên đùi phải Vương Lâm. Khi thấy Vương Lâm rút Thứ Không Niết (Thiết Kiếm) khiến tinh không chấn động, tham vọng bùng lên, bùng phát tu vi Toái Niết chuẩn bị quyết chiến.","anchor":"Hai mắt Tiền Quý Chung trở nên ngưng trọng","bridge":true,"khoang":"@c1085"},{"chuong":"@c1086","importance":"major","mucCt":"ky","tieuDe":"Bị Vương Lâm tiêu diệt nguyên thần, chết hoàn toàn","text":"Bị 19 kiếm Thứ Không Niết chém nát thân thể thành 19 mảnh. Nguyên thần thoát ra từ thiên linh cuốn theo phất trần bỏ chạy. Suy đoán Vương Lâm biết chuyện Phá Thiên Tông và có thể là người từ Tụ tinh vực. Tự bạo hai tay nguyên thần, phất trần nổ tung hóa sợi tơ trắng tấn công Chu Tước nhưng không ngăn được. Hấp thu hồn Linh thú bản mệnh mãng xà để duy trì nguyên thần. Cuối cùng bị Một ngón tay Thiên Vận Tử điểm trúng nguyên thần, tan vỡ trong tuyệt vọng hóa thành tinh quang tiêu tán.","anchor":"Nguyên thần của Tiền Quý Chung tan vỡ trong tuyệt vọng rồi hóa thành từng điểm tinh quang tiêu tán trong tinh không"},{"mucCt":"vua","text":"Tiền Quý Chung của Hoa Thanh Tông được Lô Vân Tòng xác nhận đã bị giết sau khi rời Man Hoang đại lục. Lô Vân Tòng phân tích kẻ giết hắn không phải Độc Bà Tử mà là tu sĩ thần bí, rồi cái chết bị các thế lực cấp sáu ấn định cho Độc Bà Tử và Ngũ Độc Môn.","anchor":"Tiền Quý Chung của Hoa Thanh Tông lại bị giết sao?","bridge":true,"khoang":"@c1094"},{"chuong":"@c1124","importance":"bridge","mucCt":"gon","text":"Được xác nhận đã bị Hứa Lập Quốc giết chết, nhiệm vụ hoàn thành.","anchor":"Hứa Lập Quốc đã hoàn thành tốt đẹp nhiệm vụ g**t ch*t Tiền Quý Chung"}],"tuViMoc":[{"chuong":"@c1084","canhGioi":"Toái Niết sơ kỳ","text":"Tu vi được giới thiệu ở mức Toái Niết sơ kỳ.","importance":"major"},{"chuong":"@c1085","canhGioi":"Toái Niết","text":"Được giới thiệu ở cảnh giới Toái Niết, bùng phát tu vi khi chuẩn bị quyết chiến Vương Lâm.","importance":"major"}],"nhanMach":[{"ten":"Thi Lạc Hình","tag":"cap-tren","quanHe":"Đại đệ tử dưới quyền, được hắn cử đi tìm mảnh xương thú","ghiChu":"@c1084"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Tu sĩ lạ mặt bị hắn ra lệnh bắt giữ trên đường","ghiChu":"@c1084"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ sinh tử","ghiChu":"Vương Lâm tàn sát đồng môn, hai bên quyết chiến"},{"ten":"Lô Vân Tòng","tag":"khac","quanHe":"người xác nhận cái chết","ghiChu":"Lô Vân Tòng dùng cái chết của Tiền Quý Chung làm trọng điểm phân tích vụ án."},{"ten":"Độc Bà Tử","tag":"khac","quanHe":"người bị quy tội","ghiChu":"Cái chết của Tiền Quý Chung bị đẩy sang Độc Bà Tử và Ngũ Độc Môn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[{"ten":"Mãng xà hình rồng","moTa":"Linh thú cưỡi khổng lồ của Tiền Quý Chung","nguon":"@c1084"}],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1084","@c1085","@c1086","@c1094","@c1124"]},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","cn":"许立国","aliases":[],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1085","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm phóng ra từ túi trữ vật dưới dạng kiếm quang truy sát nguyên thần đệ tử hạch tâm chạy thoát.","anchor":"Không giết được hắn, ngươi sẽ chết!"},{"chuong":"@c1124","importance":"bridge","mucCt":"vua","text":"Được thả ra từ khe nứt trữ vật để hộ pháp Vương Lâm, định khoe công đã giết Tiền Quý Chung nhưng bị Ngân Y Nữ Thi hừ lạnh cảnh cáo, vội vàng nịnh nọt rồi đứng canh tự khen mình phong lưu anh tuấn.","anchor":"Hứa Lập Quốc liên tục than ngắn thở dài, trên mặt"},{"chuong":"@c1125","importance":"bridge","mucCt":"gon","text":"Chứng kiến Vương Lâm tự rạch vai rút đinh, thầm cảm thán sát tinh hung ác với cả chính mình, sau đó bị thu vào không gian trữ vật.","anchor":"Sát tinh quả nhiên là sát tinh, không những hung ác với kẻ khác mà cũng làm khổ cả chính mình"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc và ép luyện nguyên thần thành Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan","chuong":"@c0112"},{"text":"Liều mình cản đòn bảo vệ thân thể Vương Lâm trước người khổng lồ băng tuyết, chiến đấu đến kiệt sức","chuong":"@c0338"},{"text":"Được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ, trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm","chuong":"@c0596"},{"text":"Bị giam trong lốc xoáy lửa suốt ba năm, liên tục kháng cự khiến thực lực tăng mạnh, quét một kiếm tiêu diệt cả đàn quái thú","chuong":"@c01018"},{"text":"Được thả ra tại Thiểm Lôi Tộc, thu phục gần trăm tu sĩ gồm nhiều Kết Đan và Nguyên Anh, dựng ngai vàng xuất hành kiểu đế vương","chuong":"@c1256"},{"text":"Ẩn náu cùng Lưu Kim Bưu tại vùng đất Điên Lạc, biến hóa thành đại kiếm tạo lốc kiếm hộ vệ khi nguy cấp","chuong":"@c1337"}]},"nguon":["@c1085","@c1124","@c1125"],"canhGioiCaoNhat":"Kết Đan kỳ","gioiTinh":"nam","vaiTro":"Ma đầu bị Vương Lâm khống chế — kiếm hồn, kiếm linh đời thứ nhất của Vũ tiên kiếm","tinhCach":"Kiêu ngạo hay lải nhải, thường xuyên đòi đảo ngược thân phận chủ tớ; thực dụng biết tự bảo toàn, dao động giữa phản chủ và lập công tùy tình thế; si mê nữ sắc, dễ mất bình tĩnh trước mỹ nhân; bản tính nhát gan nhưng khi bị dồn ép có thể liều mạng","blurb":"Hứa Lập Quốc vốn là tu sĩ Nguyên Anh kỳ của Thiên Cương Tông, bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc và ép luyện nguyên thần thành Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan. Từ đó hắn trở thành ma đầu duy nhất được Vương Lâm giữ lại, lần lượt ẩn trong đám du hồn, nhập tiên kiếm làm kiếm hồn, rồi được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ mà trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm. Dù miệng liên tục đòi tự do và nhiều lần dao động ý phản chủ, Hứa Lập Quốc vẫn theo Vương Lâm xông pha vô số trận chiến — từng bị giam luyện trong lốc xoáy lửa ba năm khiến thực lực "},{"id":"thien-van-tu","name":"Thiên Vận Tử","cn":"天运子","aliases":["Thiên Vận"],"gioiTinh":"nam","tabs":{"kinhLich":[{"mucCt":"vua","text":"Linh hồn được Vương Lâm phóng ra chiến đấu điên cuồng bấm pháp đối kháng Tiền Quý Chung. Được Vương Lâm dung nhập vào thân thể (Tát Đậu Thành Binh cực hạn) làm vật dẫn triệu hoán Một ngón tay Thiên Vận Tử giết chết Tiền Quý Chung, sau đó linh hồn biến mất theo ngón tay.","anchor":"Một ngón tay của Thiên Vận Tử cũng biến mất theo","bridge":true,"khoang":"@c1086"},{"chuong":"@c1108","importance":"bridge","mucCt":"gon","tieuDe":"Được Vương Lâm so sánh","text":"Thiên Vận Tử được Vương Lâm dùng làm thước đo để nhận định tâm trí Thương Tùng Tử vẫn chưa đáng sợ bằng hắn.","anchor":"Nhưng dù kẻ này có tâm trí cao đến đâu cũng không thể sánh với Thiên Vận Tử"},{"chuong":"@c1121","importance":"bridge","mucCt":"vua","tieuDe":"Dấu vết Thiên Vận","text":"Thiên Vận Tử không trực tiếp hiện thân, nhưng Vương Lâm nhận ra ngón tay khổng lồ là Thiên Vận Nhất Chỉ và kết luận nơi này có liên quan đến ông.","anchor":"Thiên Vận Nhất Chỉ! Nơi đây rõ ràng có liên quan đến Thiên Vận Tử"},{"chuong":"@c1122","importance":"bridge","mucCt":"gon","tieuDe":"Thần thông được nhắc","text":"Tên Thiên Vận Tử được gắn với Thiên Vận Nhất Chỉ đang hàng lâm truy kích Vương Lâm trong thế giới bảy màu.","anchor":"ngẩng đầu nhìn lên nhìn Thiên Vận Nhất Chỉ đang từ trên bầu trời hàng lâm xuống"},{"chuong":"@c1123","importance":"normal","mucCt":"vua","tieuDe":"Chiến hồn bất thường","text":"Thiên Vận Tử được nhắc là người từng tìm được Tam Xoa Kích và có thể khiến nó phát ra uy lực vốn có, nhưng không mở được thần thông thôn phệ. Chiến hồn Thiên Vận Tử sau đó xuất hiện từ Phong Tiên Ấn trong trạng thái mê man, không còn bị Tát Đậu Thành Binh điều khiển để lao lên tấn công.","anchor":"Lúc này chiến hồn của Thiên Vận Tử cũng không bị thuật Tát Đậu Thành Binh điều khiển nữa"},{"chuong":"@c1125","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc: khi chiến hồn Thiên Vận Tử xuất hiện thì có ngón tay Thiên Vận lộ diện, Vương Lâm khẳng định nơi đây chắc chắn liên quan đến Thiên Vận Tử.","anchor":"Nơi đây chắc chắn phải có chút liên quan đến Thiên Vận Tử…"},{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1127","chuong":"@c1127","text":"Được nhắc: Vương Lâm suy luận thế giới bảy màu có liên quan đến Thiên Vận Tử.","anchor":"Thế giới bảy màu này có liên quan đến Thiên Vận Tử"},{"chuong":"@c1153","importance":"normal","mucCt":"ky","tieuDe":"Hồn phách hấp thụ sương bảy màu, xuất hiện ảo ảnh có xác thịt","text":"Hồn phách phân thân bị nhốt trong mười tám tầng địa ngục Phong Tiên Ấn lần đầu tự phát vùng vẫy muốn thoát ra khi gần sương bảy màu. Không chút do dự nhảy vào dung hợp cùng Vương Lâm. Điên cuồng hấp thụ toàn bộ sương mù bảy màu dẫn vào qua tay Vương Lâm. Sau hấp thụ ngồi khoanh chân thổ nạp, xuất hiện ảo ảnh Thiên Vận Tử thật sự có xác thịt bị nhốt bên trong phong ấn — không chỉ là hồn phách hai phân thân dung hợp.","anchor":"dường như thấy được một Thiên Vận Tử thật sự đang bị nhốt ở bên trong phong ấn, mà không phải là hồn phách hai phân thân dung hợp"},{"importance":"bridge","mucCt":"gon","chuong":"@c1155","text":"Duy nhất không xuất hiện khi Vương Lâm mở Phong Tiên Ấn phóng chiến hồn tự bạo tấn công ngón tay út.","anchor":"duy chỉ có Thiên Vận Tử là không xuất hiện"},{"chuong":"@c1156","importance":"bridge","mucCt":"gon","text":"Được nhắc trong hồi ức — cuộc chiến với Thiên Vận Tử ở vùng đất Yêu Linh là lần liều mạng đầu tiên trong đời Vương Lâm, lần này tại Thất Thải giới là lần thứ hai.","anchor":"những lúc liều mạng như thế này chỉ có một lần, đó chính là cuộc chiến coi Thiên Vận Tử ở vùng đất Yêu Linh"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Cưỡi tảng đá khổng lồ như sao băng ngang qua Chu Tước tinh, cứu Vương Lâm khỏi cảm ngộ thiên đạo luân hồi, lần đầu xuất hiện với tu vi ước lượng vượt Hóa Thần","chuong":"@c0241"},{"text":"Tổ chức đại thọ vạn năm trên Thiên Vận Tinh, giảng đạo phân tu đạo làm ba bước, thi triển Dẫn Tiên thuật cuốn hơn vạn đệ tử Đại La Kiếm Tông, nhận Vương Lâm làm đệ tử chân chính và mở tâm thần cho tự chọn thần thông","chuong":"@c0472"},{"text":"Được tiết lộ là thành viên Liên Minh Trưởng Lão Đoàn thần bí, uy vọng trên Thiên Vận Tinh nhờ thân phận này","chuong":"@c0871"},{"text":"Mở đạo phong ấn thứ nhất ở mi tâm, giải phóng tu vi Thiên Nhân nhất suy để quyết chiến với Vương Lâm","chuong":"@c1008"},{"text":"Xé hoàn toàn đạo phong ấn thứ hai, bùng nổ tu vi Thiên Nhân nhị suy trước áp lực của Mộng Hồi Viễn Cổ","chuong":"@c1012"},{"text":"Hồn phách bị Vương Lâm dung hợp hoàn toàn vào nguyên thần bằng Tát Đậu Thành Binh, từ đó trở thành công cụ thôi diễn tính toán thiên cơ cho Vương Lâm","chuong":"@c1197"}]},"trangThai":"khong-ro","nguon":["@c1086","@c1108","@c1121","@c1122","@c1123","@c1125","@c1127","@c1153","@c1155","@c1156"],"vaiTro":"Chưởng môn Thiên Vận Tông — sư tôn của Vương Lâm, thành viên Liên Minh Trưởng Lão Đoàn","tinhCach":"Toan tính sâu xa, bố cục hàng trăm năm và suy tính thiên cơ bằng la bàn đen trắng; uy nghi điềm tĩnh khi giảng đạo và chủ trì đại sự, thản nhiên trước biến cố; cứng rắn quyết liệt trước cường địch, sẵn sàng tự phá phong ấn đánh đổi tất cả; che giấu dã tâm dưới vẻ hòa ái với đệ tử, bản chất là kẻ lợi","blurb":"Thiên Vận Tử là chưởng môn Thiên Vận Tông kiêm thành viên Liên Minh Trưởng Lão Đoàn, đại cường giả tu vi thực tế vượt Hóa Thần với ba đạo phong ấn phong tỏa cảnh giới Thiên Nhân, sở hữu huyết tinh sát khí cực mạnh và thần thông bảy màu độc đáo. Ông từng cứu Vương Lâm khỏi cảm ngộ thiên đạo luân hồi, tổ chức đại thọ vạn năm giảng đạo ba bước, nhận Vương Lâm làm đệ tử chân chính và mở tâm thần cho tự chọn thần thông, nhưng đồng thời ngầm bố cục lên Vương Lâm qua lạc ấn và kế hoạch Đông Hải Yêu Linh kéo dài hàng trăm năm. Tới các mốc sau cùng, Thiên Vận Tử lần lượt mở hai đạo phong ấn giải phóng "},{"id":"hu-khong-tu","name":"Hư Không Tử","cn":"","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1086","importance":"bridge","mucCt":"vua","text":"Linh hồn được Vương Lâm phóng ra chiến đấu, xác nhận trước khi chết đã đạt Thiên Nhân Đệ Nhất Suy, ra tay sấm gió đối kháng trực tiếp thần thông Tiền Quý Chung.","anchor":"vì trước khi chết đã đạt đến Thiên Nhân Đệ Nhất Suy"},{"chuong":"@c1123","importance":"bridge","mucCt":"gon","text":"Hư Không Tử xuất hiện dưới dạng chiến hồn từ Phong Tiên Ấn và cùng các chiến hồn khác vây nguyên anh huyết sắc của Thương Tùng Tử.","anchor":"Bên trong Phong Tiên Ấn lập tức phóng ra hàng loạt chiến hồn, Hư Không Tử, Thiên Vận Tử, Ngô Thanh"},{"importance":"bridge","mucCt":"gon","chuong":"@c1155","text":"Hồn phách bên trong Phong Tiên Ấn, mang vẻ thê lương lao thẳng tới ngón tay út rồi tự bạo.","anchor":"bao gồm Hư Không Tử mang theo vẻ thê lương lao thẳng đến ngón tay út"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Xuất hiện trước hố đen Đông Hải Triều Tịch trong hình tượng lão giả áo choàng vàng, bộc lộ tu vi Toái Niết khiến Tôn Thiệp kinh sợ","chuong":"@c0938"},{"text":"Nhiều lần nảy sinh sát khí và trực tiếp truy sát Vương Lâm trong động phủ Tiên Đế, nhưng liên tục thất bại và bị trọng thương","chuong":"@c0983"},{"text":"Tu vi rơi từ Toái Niết xuống Tịnh Niết đỉnh sau trọng thương, tự bạo thân thể dẫn Thiên Nhân đệ nhất suy khiến nguyên thần huyễn hóa, rơi vào trạng thái điên cuồng","chuong":"@c0999"},{"text":"Bị lực Tàn Dạ giết chết trong tình trạng suy kiệt, hồn phách bị giam vào tầng mười tám Thập Bát Địa Ngục Phong Tiên Ấn","chuong":"@c1003"},{"text":"Được xác nhận bỏ mình sau trận chiến Tiên Đế động phủ, tin tức lan truyền khắp Liên Minh Tinh","chuong":"@c1015"},{"text":"Hồn phách bị Vương Lâm nhiều lần triệu ra từ Phong Tiên Ấn làm chiến hồn bằng thuật Tát Đậu Thành Binh","chuong":"@c1086"}]},"nguon":["@c1086","@c1123","@c1155"],"trangThai":"khong-ro @c1123","vaiTro":"Đại trưởng lão Tu Chân Liên Minh — cường giả Toái Niết tử trận tại động phủ Tiên Đế","tinhCach":"Thâm trầm mưu lược, kín đáo giấu sát khí và liên tục tính toán trừ khử mối nguy tiềm tàng; kiêu ngạo cậy mạnh nhưng phán đoán sai lầm liên tiếp trước Vương Lâm; cuồng sát mất kiểm soát khi tâm thần bị Thiên Nhân đệ nhất suy huyễn hóa chi phối","blurb":"Hư Không Tử là đại trưởng lão áo choàng vàng của Tu Chân Liên Minh, tu vi Toái Niết, theo nhóm cường giả tiến vào hố đen Đông Hải Triều Tịch rồi vào động phủ Tiên Đế. Trong động phủ, ông nhiều lần nảy sinh sát khí truy sát Vương Lâm nhưng đều thất bại, bị trọng thương rơi tu vi từ Toái Niết xuống Tịnh Niết đỉnh, rồi tự bạo thân thể dẫn Thiên Nhân đệ nhất suy khiến nguyên thần huyễn hóa và rơi vào trạng thái điên cuồng không thể tự chủ. Cuối cùng ông bị lực Tàn Dạ giết chết trong lúc suy kiệt, hồn phách bị giam vào tầng mười tám Thập Bát Địa Ngục Phong Tiên Ấn và nhiều lần bị Vương Lâm triệu ra"},{"id":"bach-pham","name":"Bạch Phàm","cn":"","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1086","importance":"bridge","mucCt":"gon","text":"Được nhắc gián tiếp: Vương Lâm sau trận chiến càng hiểu rõ hơn thần thông Tát Đậu Thành Binh của Bạch Phàm.","anchor":"Vương Lâm tạo hóa thì lại càng hiểu rõ đối với những thần thông của Bạch Phàm"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Đánh bại đồ đệ Thanh Thủy khi hắn nhập ma gây sát kiếp","chuong":"@c0746"},{"text":"Bố trí trận pháp trị thương trên chín phong ấn để cứu Thanh Thủy","chuong":"@c0747"},{"text":"Dùng thần thông Hô Phong trừng phạt Long Đạo Tử vì phạm tiên điều, đánh tan thân thể","chuong":"@c0768"},{"text":"Để lại truyền thừa ba thức thần thông Hô Phong, Hoán Vũ và Vãi Đậu Thành Binh","chuong":"@c0803"},{"text":"Xuất thân dân thời viễn cổ, chứng đạo cho Tiên Vực rồi trầm vào nhân gian giáo hóa vạn dân","chuong":"@c0886"},{"text":"Mỗi tiên thuật đều dùng thần thông cả đời cúng tế một pháp bảo, dung nhập quy tắc thiên đạo","chuong":"@c1047"}]},"nguon":["@c1086"],"vaiTro":"Tiên Đế thời viễn cổ, sư tôn của Thanh Thủy, chủ nhân truyền thừa Lục Thuật","tinhCach":"nghiêm minh với tiên điều, sẵn sàng trừng phạt kẻ phạm luật; trọng tình thầy trò; mang chí giáo hóa nhân gian sau khi chứng đạo","blurb":"Bạch Phàm là Tiên Đế thời viễn cổ, xuất thân dân thường, sau khi chứng đạo cho Tiên Vực thì trầm vào nhân gian giáo hóa vạn dân. Ông là sư tôn của Thanh Thủy, từng đánh bại đồ đệ này khi hắn nhập ma và bố trí trận pháp trị thương trên chín phong ấn để cứu hắn. Di sản của ông là hệ Lục Thuật cùng ba thần thông Hô Phong, Hoán Vũ và Vãi Đậu Thành Binh, mỗi tiên thuật đều đượcông dùng thần thông cả đời cúng tế một pháp bảo, dung nhập quy tắc thiên đạo."},{"id":"hai-lao-gia-quy-nguyen-tong","name":"Hai lão già Quy Nguyên Tông","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Quy Nguyên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Hai tu sĩ lão thành của Quy Nguyên Tông, cùng Lý Hướng Đông và Lữ Yến Phỉ xâm nhập lòng đất, bị thần niệm Vương Lâm đánh phun máu rút lui.","vaiTro":"Tu sĩ Quy Nguyên Tông đi cùng Lý Hướng Đông","tinhCach":"Cẩn trọng; lo lắng trước nguy cơ","tabs":{"diem":[{"text":"Lo lắng về vị trí Mạc La đại lục lộ ra ngoài tinh không và nguy cơ hung thú cấp cao","chuong":"@c1088"}],"kinhLich":[{"chuong":"@c1088","importance":"bridge","mucCt":"gon","text":"Theo Lý Hướng Đông xuống lòng đất, bị thần niệm Vương Lâm đánh phun máu, tái nhợt rút lui.","anchor":"ngay cả thân thể hai lão già phía sau cũng chấn động mạnh, vẻ mặt tái nhợt rồi phun ra máu tươi"},{"importance":"bridge","mucCt":"gon","chuong":"@c1089","tieuDe":"Chấn động trước uy lực Vương Lâm","text":"Kinh hoàng khi thấy mãnh thú cấp sáu bị một quyền đánh chết, cuối cùng trố mắt đứng như tượng khi Kiếm Sư Thú cấp tám bị diệt.","anchor":"hai lão già bên cạnh hắn hít vào một hơi thật sâu"}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Hướng Đông","tag":"dong-minh","quanHe":"Trưởng lão cùng tông, đi theo chỉ huy của hắn"}],"tuiDo":{}},"nguon":["@c1088","@c1089"]},{"id":"hung-thu-su-tu-cap-tam","name":"Hung thú sư tử cấp tám","gioiTinh":"khac","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Cấp tám (ngang Tịnh Niết viên mãn)","trangThai":"song","blurb":"Con sư tử khổng lồ toàn thân bao phủ gai sắc nhọn, hung thú cấp tám, đang phóng về phía Mạc La đại lục với vẻ tham lam.","vaiTro":"Hung thú ngoài tinh không tiến đến Mạc La đại lục","tinhCach":"Tham lam; hung dữ","tabs":{"diem":[{"text":"Hung thú cấp tám ngang Tịnh Niết viên mãn, toàn thân gai sắc nhọn, các mãnh thú khác đều nhường đường","chuong":"@c1088"}],"kinhLich":[{"chuong":"@c1088","importance":"bridge","mucCt":"gon","text":"Từ phương xa phóng về phía Mạc La đại lục, khí tức cấp tám bao phủ khắp bốn phía.","anchor":"Một luồng khí tức hung thú cấp tám bao phủ khắp bốn phía"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1088"]},{"id":"ly-thien-mai","name":"Lý Thiến Mai","cn":"李茜梅","aliases":["Lý Oánh Chi"],"gioiTinh":"nu","theLuc":[{"ten":"Phá Thiên Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết hậu kỳ @c1099","trangThai":"song","blurb":"Lý Thiến Mai (bí danh Lý Oánh Chi) là nữ tu sĩ tóc xanh lam truyền kỳ của Phá Thiên Tông thuộc Vân Hải tinh vực cấp chín, khởi tu từ năm tuổi và sau hơn 1200 năm đạt Toái Niết hậu kỳ. Trên hành trình hỏi đạo, nàng kết giao và dần sinh tình với Vương Lâm, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp quân lệnh đào ngũ, phi tinh trảm nguyệt xuyên tinh vực đến đại hội Vô Cực Tông tìm hắn, vì đó mà bị sư tôn Phá Thiên Tông đoạn tuyệt sư đồ. Nàng ẩn thân suốt mười năm bên tượng đá Vương Lâm trên đại lục hoang dã, hy sinh máu tươi và tinh huyết chăm sóc tượng đá đến kiệt qu","vaiTro":"Nữ tu sĩ truyền kỳ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ tình cảm của Vương Lâm","tinhCach":"Thiên phú tu luyện phi phàm, tốc độ đột phá cảnh giới hiếm có; ham hỏi đạo, trọng bản tâm, chủ động tìm người luận đạo; nặng tình kiên định, dám bất chấp sư mệnh và quân lệnh vì lời hứa; kiên nghị cô độc, một mình gánh chịu hậu quả không hối tiếc","tabs":{"diem":[{"text":"Thiên tài tu luyện truyền kỳ Vân Hải tinh vực: 5 tuổi khởi tu, hơn 1200 năm đạt Toái Niết hậu kỳ","chuong":"@c1090"},{"text":"Hỏi đạo Vương Lâm tại Bồng Lai, kết giao tri kỷ và dần nảy sinh tình cảm","chuong":"@c1096"},{"text":"Bất chấp quân lệnh rời chiến trường Yêu Tông, phi tinh trảm nguyệt xuyên tinh vực đến đại hội Vô Cực Tông tìm Vương Lâm","chuong":"@c1163"},{"text":"Bị sư tôn Phá Thiên Tông đoạn tuyệt sư đồ vì trái lệnh, một mình cô độc phóng đi trong tinh không","chuong":"@c1200"},{"text":"Ẩn thân mười năm bên tượng đá Vương Lâm trên đại lục hoang dã, hy sinh máu tươi và tinh huyết chăm sóc đến kiệt quệ","chuong":"@c1214"},{"text":"Tỉnh lại tại Lam Sơn sau trọng thương nhưng mất toàn bộ trí nhớ, dần khôi phục ký ức và quyết ý tìm lại Vương Lâm","chuong":"@c1284"}],"kinhLich":[{"mucCt":"ky","text":"Nữ tu sĩ tóc xanh lam, truyền kỳ Vân Hải tinh vực: 5 tuổi tu đạo, 7 tuổi Trúc Cơ, 19 Kết Đan, 26 Nguyên Anh, 37 Hóa Thần, 45 Anh Biến, 61 Vấn Đỉnh, trăm năm Âm Hư đỉnh phong, hơn 400 năm Khuy Niết đại viên mãn, 300 năm sau Tịnh Niết trung kỳ, 500 năm nữa thành Toái Niết. Hơn 1200 năm tu đạo đạt Toái Niết hậu kỳ, nhỏ tuổi nhất hàng ngũ Toái Niết Phá Thiên Tông. Nhận lệnh từ sư tổ (lão già tóc trắng trong pho tượng) đi tinh vực cấp năm truy tìm kẻ đoạt ngọc giản Tư Mã Mặc rồi mang cả người lẫn ngọc giản về.","anchor":"Nàng tên Lý Thiến Mai, chính là một truyền kỳ!","bridge":true,"khoang":"@c1090"},{"mucCt":"ky","text":"Lý Thiến Mai cưỡi Linh long lam sắc do sương xanh huyễn hóa, xuất hiện trước đoàn Tử Đạo Tông trên đường tới Mạc La đại lục. Nàng xưng Lô Vân Tòng là Lô huynh và nói muốn hỏi ba vấn đề, đồng thời tiết lộ trước đó nhiều nhân tài kiệt xuất không ai trả lời đúng để nàng hỏi tới vấn đề thứ hai. Nàng hỏi vấn đề thứ nhất là cái gì là thiên, sau khi Lô Vân Tòng đáp thiên là nhà tù thì tiếp tục hỏi vì sao, khẳng định vẫn thuộc vấn đề thứ nhất.","anchor":"Ba vấn đề của nàng cuối cùng chỉ có thể hỏi được một, không có bất kỳ người nào có thể để nàng hỏi đến vấn đề thứ hai","bridge":true,"khoang":"@c1094"},{"mucCt":"ky","text":"Lý Thiến Mai hỏi Lô Vân Tòng ba câu về thiên, đạo và nơi hắn đang đi, tán thưởng hai câu trả lời đầu nhưng hiểu rằng hắn vẫn dừng ở giới hạn câu thứ hai. Nàng đồng hành cùng hắn tới Mạc La đại lục, lắng nghe hắn phân tích tu sĩ thần bí đã đoạt đan phương và ngọc giản. Khi thấy Vương Lâm chỉ một lời phá tan ý cảnh của Lô Vân Tòng, nàng nhận ra người trước mắt vượt xa Lô Vân Tòng và mở lời muốn hỏi Vương Lâm ba câu.","anchor":"Vị huynh đài này, ta có ba câu hỏi, không biết có thể giải thích","bridge":true,"khoang":"@c1095"},{"chuong":"@c1096","importance":"normal","mucCt":"ky","tieuDe":"Hỏi đạo Vương Lâm","text":"Lý Thiến Mai tự giới thiệu là người Phá Thiên Tông, giải thích nàng và Lô Vân Tòng chỉ gặp nhau trên đường và không liên quan chuyện Tử Đạo Tông. Nàng hỏi Vương Lâm cái gì là thiên, nghe đạo luận thiên chỉ là lời bịa đặt và nhờ đó bế tắc tâm thần bị quét sạch hoàn toàn. Sau khi hỏi tục danh, nàng trao Cực Tài Đan bán thành phẩm cấp mười cho Vương Lâm rồi tiếp tục hỏi câu thứ hai cũng là cái gì là thiên, khiến Vương Lâm chỉ ra điểm khác biệt giữa đạo niệm và thiên ý.","anchor":"Lời nói của Vương Lâm giống như hóa thành những con sóng biển kinh hoàng, hóa thành hai bàn tay vô hình quét sạch tất cả mây đen đang bao phủ toàn bộ tâm thần Lý Thiến Mai."},{"mucCt":"ky","text":"Lý Thiến Mai đặt câu hỏi thứ ba về thiên, dẫn lời sư tôn rằng người là dế, đạo là sơn, ý là thiên, rồi nói đạo không phải lưới hay núi mà là tư tưởng tùy mỗi người cảm nhận. Nàng tâm phục đạo của Vương Lâm, trao ngọc giản ghi phương pháp luyện đan và đan dược bán thành phẩm chứa linh hồn mãnh thú cấp mười. Nàng tuyên bố từ nay không hỏi ba vấn đề ấy với ai nữa, thổi sáo trước lúc rời dược viện và quay đầu mỉm cười với Vương Lâm.","anchor":"Khoảnh khắc khi bước ra khỏi cổng nàng dừng chân xoay đầu lại rồi cười, một nụ cười cực kỳ tuyệt vời","bridge":true,"khoang":"@c1097"},{"chuong":"@c1098","importance":"normal","mucCt":"ky","tieuDe":"Tiết lộ tinh vực cấp chín","text":"Lý Thiến Mai cùng Vương Lâm đi về Bồng Lai, kể rằng nàng từng đến nơi này năm trăm năm trước và sử dụng truyền tống trận đặc biệt của sư môn để qua lại tinh vực cấp thấp. Khi Vương Lâm hỏi về tinh vực cấp chín, nàng nói rõ bốn tông phái gồm Thần Tông, Quỷ Tông, Yêu Tông và Phá Thiên Tông, đồng thời tiết lộ Yêu Tông vốn tách ra từ đệ tử Thần Tông phòng thủ không gian đứt gãy. Nàng còn nói Thần Tông đề bạt Quỷ Tông và Phá Thiên Tông để chuẩn bị cho cuộc nổi loạn mãnh thú lần hai, rồi dặn Vương Lâm không để lộ chuyện này.","anchor":"Vấn đề này cực kỳ quan trọng, mong Lữ huynh đừng để người khác biết."},{"chuong":"@c1099","importance":"normal","mucCt":"vua","tieuDe":"Vào chợ Bồng Lai","text":"Lý Thiến Mai kể cho Vương Lâm về cuộc chiến sắp xảy ra giữa Yêu Tông và mãnh thú tinh vực thần bí, đồng thời nhờ hắn đến tiễn biệt nếu ngày đó tới. Khi vào Bồng Lai, nàng đổi màu tóc để tránh bị nhận ra, bình luận Bảo Ngọc Tông chỉ có vẻ ngoài tiên gia, rồi lạnh nhạt cự tuyệt Dương Ngọc khi hắn tỏ ra thân mật.","anchor":"Hai chữ Thiến Mai không phải ngươi có thể mở miệng nói ra"},{"chuong":"@c1100","importance":"normal","mucCt":"gon","tieuDe":"Chấn động tâm trí","anchor":"Tâm trí của người này. còn đáng sợ hơn cả tu vi!","text":"Lý Thiến Mai quan sát Vương Lâm trực tiếp ra tay rồi chấn động nhận ra tâm trí và tính toán của hắn còn đáng sợ hơn cả tu vi."},{"chuong":"@c1101","importance":"bridge","mucCt":"gon","text":"Cùng Vương Lâm gặp hai trưởng lão Ma Tùng Đạo tại khách điếm rồi tách nhau.","anchor":"Lý Thiến Mai chỉ khẽ cười rồi gật đầu, hai người tách nhau ra"},{"mucCt":"vua","text":"Lý Thiến Mai đứng trên đỉnh núi phía đông Bồng Lai đại lục quan sát Vương Lâm từ xa. Nàng nhận ra Dịch Lịch Ấn thuộc hàng thần thông hạch tâm của Thần Tông, đồng thời chú ý một chưởng quái dị có thể điều khiển thiên địa nguyên lực và uẩn hàm ý nô dịch.","anchor":"người có thể thi triển thần thông Dịch Lịch Ấn chắc chắn sẽ là đệ tử hạch tâm của Thần Tông, sao lại đi ra ngoài đơn giản như vậy","bridge":true,"khoang":"@c1105"},{"chuong":"@c1106","importance":"major","mucCt":"ky","tieuDe":"Rời Bồng Lai","text":"Lý Thiến Mai ngồi cạnh Vương Lâm tại đấu giá và báo rằng sư tôn truyền tin, vết nứt chỗ Yêu Tôn xuất hiện thêm nhiều mãnh thú nên đệ tử tông phái cấp chín phải đi viện trợ. Nàng hỏi Vương Lâm sẽ tiễn mình thế nào, nhắc rằng trận với Ngô Thanh nàng đã không ra tay vì hắn. Sau khi nhận bức tranh sóng nước Vương Lâm tặng, nàng nhắn nếu tìm được người Phá Thiên Tông đang tìm thì hãy chuyển lời mời, rồi bay đi trong dáng vẻ tóc đen chuyển xanh.","anchor":"Nếu tìm được người mà Phá Thiên Tông muội đang tìm kiếm, thì huynh hãy nói cho hắn biết, Phá Thiên Tông xin mời"},{"chuong":"@c1107","importance":"normal","mucCt":"vua","tieuDe":"Xác nhận thân phận","text":"Khi rời đi, Lý Thiến Mai để mái tóc trở lại màu lam, dấu hiệu duy nhất của nàng trong Vân Hải. Hành động này công khai giúp chúng tu sĩ tin rằng Vương Lâm có thân phận đệ tử Thần Tông.","anchor":"Trong Vân Hải chỉ có một người có mái tóc màu lam, chỉ có một mình Lý Thiến Mai"},{"chuong":"@c1108","importance":"normal","mucCt":"ky","tieuDe":"Chia tay trong sương mù","text":"Lý Thiến Mai quay lại gặp Vương Lâm vì nhớ lời hắn hứa tiễn nàng, đồng thời nói thú loạn lần này rất nghiêm trọng và hai người có thể khó gặp lại. Nàng gỡ vòng ngọc xanh biếc trên tay tặng Vương Lâm làm bảo vật phòng hộ, nhưng khi bị từ chối thì ném nó vào sương mù. Nàng trao bức tranh đã vẽ thêm hai con cá sát cánh trên dòng sông khô, nhận cây bút bảo vật Tiên giới từ Vương Lâm rồi thổi sáo tiễn hắn rời đi.","anchor":"Sóng bên trên rất đẹp, chỉ thiếu một vài sinh khí, muội đã vẽ lên vài nét bút"},{"mucCt":"ky","text":"Trải trăm năm chiến đấu chém giết mãnh thú tại chiến trường vết nứt trong Yêu Tông (tinh vực cấp chín), là một trong bốn người được Yêu Tông xem trọng. Kiên quyết giữ cây bút kim sắc (pháp bảo Vương Lâm tặng), từng bị mười mãnh thú cấp 12 đánh trọng thương hôn mê, bút rơi, tỉnh dậy liều mình lấy lại. Ngẩng đầu nhìn phương xa nhớ Vương Lâm.","anchor":"Huynh bây giờ đang ở nơi nào… nháy mắt đã qua trăm năm rồi…","bridge":true,"khoang":"@c1147"},{"chuong":"@c1157","importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1157–@c1157","text":"Được Vương Lâm nhắc tên trong lời trối trăng, thừa nhận bà có tình với hắn.","anchor":"Một trong Thái Cổ ngũ tôn, Lam Mộng Đạo Tôn không ngờ đột nhiên lại có một khoảnh khắc không khống chế được tâm thần"},{"importance":"normal","mucCt":"ky","chuong":"@c1163","tieuDe":"Bất chấp cảnh cáo đào ngũ, rời chiến trường Yêu Tông","text":"Tại tầng thứ chín, chiến trường khe bên ngoài Yêu Tông, Lý Thiến Mai tóc lam lau máu thú trên kiếm sau trận thú triều. Vào đại điện sơn môn Yêu Tông kiên quyết thông báo phải rời đi ba tháng, bất chấp cảnh cáo sẽ bị coi là đào ngũ và sỉ nhục Phá Thiên Tông vì thú triều quy mô lớn hơn đang tới gần. Được thân ảnh mơ hồ nhượng bộ, đưa ngọc bội dùng truyền tống trận. Lý do: Vương Lâm biến mất trăm năm, nay hắn đã hứa trợ giúp Quy Nguyên Tông tham dự cuộc so tài phân tông, nàng tin hắn sẽ đến.","anchor":"Hắn biến mất đã trăm năm, lần này hắn hứa sẽ trợ giúp Quy Nguyên Tông tham dự đạo hữu của phân tông.hắn sẽ đến."}],"tuViMoc":[{"chuong":"@c1090","canhGioi":"Toái Niết hậu kỳ","text":"Hơn 1200 năm tu đạo đạt Toái Niết hậu kỳ. Lộ trình: 5 tuổi tu đạo, 7 tuổi Trúc Cơ, 19 Kết Đan, 26 Nguyên Anh, 37 Hóa Thần, 45 Anh Biến, 61 Vấn Đỉnh, trăm năm Âm Hư đỉnh phong, hơn 400 năm Khuy Niết đại viên mãn, 300 năm sau Tịnh Niết trung kỳ, 500 năm nữa Toái Niết.","importance":"major"}],"nhanMach":[{"ten":"Lão già tóc trắng (sư tổ Phá Thiên Tông)","tag":"su-mon","quanHe":"Sư tổ","ghiChu":"Giao lệnh truy tìm ngọc giản Tư Mã Mặc"},{"ten":"Lô Vân Tòng","tag":"khac","quanHe":"người được hỏi vấn đề","ghiChu":"Nàng chặn đường Lô Vân Tòng và nêu vấn đề thứ nhất về thiên."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người nàng muốn hỏi đạo","ghiChu":"Nàng chứng kiến Vương Lâm phá ý cảnh Lô Vân Tòng rồi muốn hỏi hắn ba câu."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Bạn đồng hành tạm thời trên đường tới Bồng Lai","ghiChu":"Nàng gọi hắn là Lữ huynh và kể cho hắn các bí mật quan trọng của tinh vực cấp chín."},{"ten":"Dương Ngọc","tag":"khac","quanHe":"Từng gặp và từng hỏi hắn một vấn đề, nhưng không hài lòng với câu trả lời; về sau lạnh nhạt cự tuyệt sự suồng sã của hắn.","ghiChu":"Dương Ngọc gọi tên nàng quá thân mật nên bị mắng."},{"ten":"Đường Lệ Hải","tag":"khac","quanHe":"Cùng có mặt trong buổi gặp Ma Tùng Đạo tại khách điếm Bồng Lai.","ghiChu":"Quan hệ mới phát sinh qua sự kiện gặp mặt."},{"ten":"Ngô Thanh","tag":"khac","quanHe":"Cùng có mặt trong buổi gặp Ma Tùng Đạo tại khách điếm Bồng Lai.","ghiChu":"Quan hệ mới phát sinh qua sự kiện gặp mặt."},{"ten":"Vương Lâm","tag":"dong-hanh","quanHe":"người được quan sát","ghiChu":"Lý Thiến Mai chứng kiến Vương Lâm ra tay và đánh giá cao tâm trí của hắn.","gap":"@c1100"}],"tuiDo":{}},"nguon":["@c1090","@c1094","@c1095","@c1096","@c1097","@c1098","@c1099","@c1100","@c1101","@c1105","@c1106","@c1107","@c1108","@c1147","@c1157","@c1163"]},{"id":"lao-gia-toc-trang-su-to-pha-thien-tong","name":"Lão già tóc trắng (sư tổ Phá Thiên Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Phá Thiên Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Sư tổ Phá Thiên Tông cấp chín, thân thể nhiều chỗ thối rữa, khoanh chân ngồi bên trong pho tượng tu sĩ khổng lồ trên tu chân tinh cấp chín. Là sư đệ của Tư Mã Mặc, hối hận về quyết định năm xưa của sư tôn.","vaiTro":"Sư tổ Phá Thiên Tông, đồng môn với Tư Mã Mặc","tinhCach":"Trầm mặc; mang nỗi hối hận về chuyện xưa","tabs":{"diem":[{"text":"Thân thể nhiều chỗ thối rữa, ẩn mình bên trong pho tượng tu sĩ khổng lồ trên tu chân tinh cấp chín.","chuong":"@c1090"},{"text":"Là sư đệ của Tư Mã Mặc, hối hận về quyết định năm xưa của sư tôn.","chuong":"@c1090"}],"kinhLich":[{"mucCt":"vua","text":"Ngồi khoanh chân trong pho tượng tu sĩ khổng lồ trên tu chân tinh cấp chín, thân thể nhiều chỗ thối rữa. Giao lệnh cho Lý Thiến Mai đi tinh vực cấp năm truy tìm kẻ đoạt ngọc giản Tư Mã Mặc, mang cả người lẫn ngọc giản về. Thở dài hồi ức, gọi Tư Mã sư huynh, cho rằng năm xưa sư tôn đã sai, hé lộ là sư đệ đồng môn của Tư Mã Mặc.","anchor":"Tư Mã sư huynh, có lẽ năm xưa sư tôn đã sai rồi","bridge":true,"khoang":"@c1090"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Mã Mặc","tag":"su-mon","quanHe":"Sư huynh (đồng môn)","ghiChu":"Gọi Tư Mã sư huynh, cùng sư tôn"},{"ten":"Lý Thiến Mai","tag":"su-mon","quanHe":"Đệ tử / hậu bối trong tông","ghiChu":"Giao lệnh truy tìm ngọc giản"}],"tuiDo":{}},"nguon":["@c1090"]},{"id":"tu-ma-mac","name":"Tư Mã Mặc","cn":"司马默","aliases":["Tư Mã Đặc"],"gioiTinh":"nam","theLuc":[{"ten":"Phá Thiên Tông","trangThai":"khong-ro"}],"trangThai":"tu-vong","blurb":"Tư Mã Mặc (bí danh Tư Mã Đặc) là đại đệ tử Phá Thiên Tông một vạn tám ngàn năm trước, xuất thân tinh vực Vân Hải và tinh thông luyện đan. Mười vạn tám ngàn năm trước hắn mang mảnh xương thú cùng một phần đệ tử rời tông môn rồi biến mất, để lại động phủ chứa ba khối ngọc giản ghi lại trải nghiệm nhiều năm trong thế giới bảy màu cùng các bình đan dược quý. Về sau Vương Lâm thu được ngọc giản luyện đan cùng di vật của hắn trong động phủ nơi Thất Thải Giới.","vaiTro":"Đại đệ tử Phá Thiên Tông, tinh thông luyện đan; chủ nhân động phủ và ngọc giản","tinhCach":"Trọng tình đồng môn — để lại di vật và đưa đồng môn về; am tường luyện đan; kiên trì tìm đường sinh tồn nơi hiểm địa","tabs":{"diem":[{"text":"Đại đệ tử Phá Thiên Tông một vạn tám ngàn năm trước, am hiểu luyện đan","chuong":"@c114"},{"text":"Mười vạn tám ngàn năm trước mang mảnh xương thú và một phần đệ tử rời tông môn rồi biến mất","chuong":"@c1091"},{"text":"Xuất thân tinh vực Vân Hải, cùng sư thúc và đồng môn tiến vào khe nứt không gian bảy màu","chuong":"@c1126"},{"text":"Để lại ba khối ngọc giản ghi lại toàn bộ trải nghiệm nhiều năm trong thế giới bảy màu","chuong":"@c1127"},{"text":"Chủ nhân ba bình đan dược quý, để lại cho đồng môn bằng trận pháp trong động phủ","chuong":"@c1128"},{"text":"Ở cảnh giới Toái Niết tìm được phương pháp thoát khỏi cây đinh bảy màu","chuong":"@c1206"}],"kinhLich":[{"mucCt":"vua","text":"10 vạn 8 ngàn năm trước, Tư Mã Mặc mang mảnh xương thú và một phần đệ tử rời Phá Thiên Tông rồi biến mất trong tinh vực. Chưởng môn Phá Thiên Tông để lại truyền thừa vài vạn năm: ai mang lệnh bài của Tư Mã Mặc trở về sẽ được thu làm đệ tử.","anchor":"Người này tên la Tư Mã Mặc, nếu không có chuyện gì xảy ra ngoài ý muốn thì hắn sẽ chính là chưởng môn đời kế tiếp","bridge":true,"khoang":"@c1091"},{"chuong":"@c1114","importance":"bridge","mucCt":"vua","tieuDe":"Động phủ được nhắc tới","text":"Tư Mã Mặc được Thương Tùng Tử nhắc là đại đệ tử Phá Thiên Tông một vạn tám ngàn năm trước, am hiểu luyện đan và là chủ nhân động phủ ở ranh giới ngoài trong thế giới bảy màu.","anchor":"hắn là đại đệ tử của Phá Thiên Tông một vạn tám ngàn năm trước"},{"chuong":"@c1116","importance":"bridge","mucCt":"gon","tieuDe":"Động phủ được nhắc","text":"Động phủ của Tư Mã Mặc được Thương Tùng Tử xác nhận nằm trong một sơn cốc phía trước bên trong dãy núi.","anchor":"Động phủ của Tư Mã Mặc cũng không phải nằm sau dãy núi mà nằm trong một sơn cốc trước mặt."},{"chuong":"@c1117","importance":"bridge","mucCt":"gon","tieuDe":"Động phủ thật bị hé lộ","text":"Tư Mã Mặc không xuất hiện, nhưng động phủ thật của hắn được Vương Lâm xác định không phải nơi hiện tại và vị trí thật đã lộ qua ký ức lão Bàng.","anchor":"-Nơi đây không phải động phủ của Tư Mã Mặc, nếu vậy thì của ai?"},{"importance":"normal","mucCt":"ky","chuong":"@c1126","tieuDe":"Tiết lộ bí mật khe nứt không gian bảy màu","text":"Ngọc giản thứ nhất trong động phủ tiết lộ: Tư Mã Mặc thuộc tinh vực Vân Hải, cùng sư thúc và đồng môn theo yêu cầu của một người bí ẩn tìm được khe nứt không gian tràn ngập ánh sáng bảy màu. Sư muội của hắn rất thích cầu vồng, hắn muốn mang ánh sáng cầu vồng về cho nàng. Tiến vào nơi sâu nhất, phát hiện tồn tại đáng sợ và biết được bí mật khổng lồ khiến toàn tu chân giới khiếp sợ, không chỉ Vân Hải mà cả La Thiên, Triệu Hà, Côn Nhai đều khó tưởng tượng. Tai họa ập xuống, bọn họ bị mắc kẹt không thể rời đi. Bộ hài cốt ngồi trong sơn cốc xương lộ sáng bảy màu chính là di thể của hắn.","anchor":"phát hiện ra tồn tại đáng sợ kia, biết được một cái bí ẩn khổng lồ có thể làm khiếp sợ tu chân giới"},{"importance":"normal","mucCt":"ky","chuong":"@c1127","tieuDe":"Ký ức vài trăm năm trong thế giới bảy màu qua ngọc giản","text":"Ba khối ngọc giản ghi lại toàn bộ trải nghiệm: ba năm đầu Nhị sư đệ và Lão Tam chết thành Mê Thất Giả. Năm thứ sáu tìm được ngọc giản ghi Tuế Nguyệt Cấm Chế, mày mò học. Năm thứ 11 sư thúc vào vị trí sâu nhất vì nghe âm thanh kêu gọi. Ba mươi năm sau Minh Chí Giả tấn công, sư thúc mang đi nhiều đồng môn. Hiểu rõ Tuế Nguyệt Cấm, cùng đồng môn bố trí đại cấm chế bảo hộ sơn cốc, Cửu sư đệ hy sinh tuổi thọ gia cố trận pháp. Sau một trăm năm mười ba đệ tử bị phá hủy thân thể, chỉ còn ba người: Tư Mã Đặc, Thập Lục sư đệ và Tứ sư thúc (đã thành Nghịch Hành Giả). Đi tìm cứu đồng môn từ đám Mê Thất Giả, Minh Chí Giả. Sau ba trăm năm phát hiện hạt châu phong ấn thần thông Nghịch Hành Giả, lần thứ tư vào cứu Tứ sư thúc nhưng thất bại, bị cây đinh bảy màu đâm vào cơ thể gây ý niệm điên cuồng. Đuổi Thập Lục sư đệ khỏi sơn cốc, đưa lệnh bài và đan phương thú cốt cho hắn. Phát hiện hạt châu do người tế luyện, dùng thần thông tự tạo thạch châu. Cuối cùng ý thức kéo dài đến tinh không kỳ dị, nhìn thấy Chưởng Tôn.","anchor":"Bộ hài cốt của người này không có bất kỳ dấu hiệu bị phá hoại"},{"chuong":"@c1128","importance":"bridge","mucCt":"gon","text":"Được xác định là chủ nhân di vật ba bình đan dược quý trong động phủ thứ ba, để lại cho đồng môn bằng trận pháp bảo vệ đặc biệt.","anchor":"Tư Mã Măc để lại đan dược cho đồng môn mà lại sử dụng phương pháp đó"},{"chuong":"@c1133","importance":"bridge","mucCt":"gon","text":"Được nhắc đến: động phủ là của Tư Mã Đặc, đã đưa đồng môn (Mê Thất giả, Minh Chí giả, nghi Nghịch Hành Giả) về phong ấn trong các động phủ cố cho thức tỉnh nhưng thất bại, để lại Tuế Nguyệt Cấm trong ngọc giản cho đồng môn tự giải phong ấn khi thức tỉnh.","anchor":"Ngày trước Tư Mã Đặc đã đưa bọn họ về phong ấn trong động phủ rồi cố gắng để bọn họ thức tình"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già tóc trắng (sư tổ Phá Thiên Tông)","tag":"su-mon","quanHe":"Sư đệ (đồng môn)","ghiChu":"Lão gọi Tư Mã sư huynh, cùng sư tôn"},{"ten":"Phá Thiên Tông chưởng môn","tag":"su-mon","quanHe":"Sư tôn — chưởng môn Phá Thiên Tông đời trước"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người tìm được động phủ và đọc di ngôn của hắn","ghiChu":""},{"ten":"Thập Lục sư đệ","tag":"su-mon","quanHe":"Đồng môn Phá Thiên Tông, một trong ba người sống sót cuối cùng, được Tư Mã Đặc đuổi đi kèm lệnh bài và đan phương thú cốt","ghiChu":"@c1127"},{"ten":"Tứ sư thúc","tag":"su-mon","quanHe":"Sư thúc trong Phá Thiên Tông, trở thành Nghịch Hành Giả đầu tiên","ghiChu":"@c1127"},{"ten":"Cửu sư đệ","tag":"su-mon","quanHe":"Đồng môn Phá Thiên Tông, hy sinh tuổi thọ gia cố trận pháp Tuế Nguyệt Cấm","ghiChu":"@c1127"},{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Người bí ẩn Tư Mã Đặc nhìn thấy khi ý thức kéo dài đến tinh không kỳ dị","ghiChu":"@c1127"}],"tuiDo":{}},"nguon":["@c1090","@c1091","@c1114","@c1116","@c1117","@c1126","@c1127","@c1128","@c1133"],"canhGioiCaoNhat":"Không rõ"},{"id":"truu-hai","name":"Trừu Hải","cn":"抽海","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ngũ Độc Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết sơ kỳ","trangThai":"song","blurb":"Đệ tử hạch tâm Ngũ Độc Môn, tu luyện lam độc, Tịnh Niết sơ kỳ. Dẫn đầu nhiệm vụ truy tìm phản đồ Độc Bà Tử trên các tinh vực cấp năm.","vaiTro":"Đệ tử hạch tâm Ngũ Độc Môn, kẻ xâm nhập Mạc La đại lục truy tìm Độc Bà Tử","tinhCach":["Ngạo mạn, khinh thường tông phái nhỏ","Hành sự tàn nhẫn, ra tay không thương tiếc"],"tabs":{"diem":[{"text":"Tu luyện lam độc đặc trưng Ngũ Độc Môn, mắt phải lóe lam quang, huyễn hóa bảy dấu ấn lam phòng ngự","chuong":"@c1092"},{"text":"Bị Vương Lâm đánh trọng thương bằng một chưởng, ngực lộ dấu bàn tay đen kịt khắc sâu","chuong":"@c1092"}],"kinhLich":[{"mucCt":"ky","text":"Cùng Triệu Vũ và Phùng Bội Sơn phá tầng phòng hộ Mạc La đại lục hạ xuống truy tìm Độc Bà Tử. Tại Quy Nguyên Tông, dùng lam quang quét kiểm tra rồi đánh trọng thương một đệ tử Nguyên Anh. Phát hiện trên người Tôn Vân có mùi Ngư Tinh Thảo, truy vấn nguồn gốc. Xâm nhập cấm địa khu vườn phía nam, bị Vương Lâm xuất chưởng đánh phun máu, áo ngực vỡ nát lộ ra dấu bàn tay đen kịt khắc sâu vào ngực.","anchor":"Một mảnh áo trước ngực thân thể vỡ nát, bên trong lộ ra đáu bàn tay đen kịt khắc vào rất sâu","bridge":true,"khoang":"@c1092"},{"mucCt":"vua","text":"Bị Vương Lâm đánh trọng thương bằng một chưởng đen kịt, sinh cơ bị rút sạch khiến thân thể héo rũ như hài cốt. Khi rời đi, nhận định tu vi đối phương ít nhất Toái Niết trung kỳ, khẳng định không phải độc công.","anchor":"Tu vi của vị tiền bối kia ít nhất cũng trên Toái Niết trung kỳ","bridge":true,"khoang":"@c1093"}],"tuViMoc":[{"chuong":"@c1092","canhGioi":"Tịnh Niết sơ kỳ","text":"Xuất hiện với tu vi Tịnh Niết sơ kỳ","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cao nhân ẩn cư tại Quy Nguyên Tông, đánh trọng thương Trừu Hải khi xâm nhập cấm địa","ghiChu":"@c1092"},{"ten":"Triệu Vũ","tag":"dong-hanh","quanHe":"Đệ tử Ma Tùng Đạo, cùng nhóm truy tìm Độc Bà Tử, thường châm chọc Trừu Hải","ghiChu":"@c1092"},{"ten":"Phùng Bội Sơn","tag":"dong-hanh","quanHe":"Đệ tử hạch tâm Đạo Pháp Môn, chỉ huy nhóm truy tìm","ghiChu":"@c1092"},{"ten":"Tôn Vân","tag":"khac","quanHe":"Đệ tử Quy Nguyên Tông bị Trừu Hải phát hiện mang mùi Ngư Tinh Thảo và truy vấn","ghiChu":"@c1092"},{"ten":"Lữ Yến Phỉ","tag":"doi-thu","quanHe":"Trưởng lão Quy Nguyên Tông, dùng gió lạnh ngăn Trừu Hải nhưng bị phá","ghiChu":"@c1092"},{"ten":"Độc Bà Tử","tag":"doi-thu","quanHe":"Phản đồ Ngũ Độc Môn, đối tượng Trừu Hải truy tìm","ghiChu":"@c1092"}],"tuiDo":{}},"nguon":["@c1092","@c1093"]},{"id":"trieu-vu","name":"Triệu Vũ","cn":"赵武","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ma Tùng Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Đệ tử Ma Tùng Đạo, giọng âm dương quái khí, mặt thoa son. Cùng Trừu Hải và Phùng Bội Sơn xâm nhập Mạc La đại lục truy tìm Độc Bà Tử.","vaiTro":"Đệ tử Ma Tùng Đạo, thành viên nhóm truy tìm Độc Bà Tử","tinhCach":["Giọng âm dương quái khí, hay châm chọc","Khinh thường tông phái nhỏ"],"tabs":{"diem":[{"text":"Mặt thoa son, giọng âm dương quái khí, liên tục châm chọc Trừu Hải và khinh thường Quy Nguyên Tông","chuong":"@c1092"},{"text":"Là đệ tử của Đường Lệ Hải.","chuong":"@c1101"},{"text":"Từng kể với Đường Lệ Hải rằng Vương Lâm có thần thông kinh người.","chuong":"@c1101"},{"text":"Từng kể với Đường Lệ Hải về thần thông của Vương Lâm.","chuong":"@c1101"}],"kinhLich":[{"mucCt":"vua","text":"Cùng Trừu Hải và Phùng Bội Sơn phá tầng phòng hộ Mạc La đại lục hạ xuống. Liên tục châm chọc Trừu Hải, khinh thường Quy Nguyên Tông, gọi Lữ Yến Phỉ là tiểu mỹ nhân. Nhướng mày nhìn về khu vườn phía nam khi quét thần thức.","anchor":"Triệu mỗ cũng muốn xem Ngũ Độc Môn của ngươi bây giờ có dám cùng Ma Tùng Đạo chúng ta khai chiến không","bridge":true,"khoang":"@c1092"},{"chuong":"@c1093","importance":"bridge","mucCt":"vua","text":"Kinh hãi trước tu vi Vương Lâm, tự vỗ ngực phun máu xin tội. Trên đường về nhận định may là chỉ đánh người bị thương chứ không giết, hả hê nghĩ Lô Vân Tòng sẽ gặp khối sắt ở Quy Nguyên Tông.","anchor":"Tu vi của sư thúc tổ Quy Nguyên Tông này rất cao, dù trên tinh vực cấp sáu của chúng ta người này cũng được rất nhiều tu sĩ coi trọng"},{"chuong":"@c1100","importance":"normal","mucCt":"gon","tieuDe":"Liên hệ Ma Tùng Đạo","anchor":"Tên Dương Ngọc này rõ ràng vì mình mà đến, đầu tiên là kẻ này có quan hệ với Ma Tùng Đạo, cũng chính là tông phái của tên Triệu Vũ trước đó đã đến Mạc La đại lục","text":"Triệu Vũ được Vương Lâm nhắc trong suy luận rằng Ma Tùng Đạo, tông phái của Triệu Vũ, có thể đang để Dương Ngọc thử tu vi hắn vì chuyện từng xảy ra trên Mạc La đại lục."},{"chuong":"@c1101","importance":"bridge","mucCt":"gon","text":"Được Đường Lệ Hải nhắc tên — trước đó đã kể cho Đường Lệ Hải nghe về thần thông kinh người của Vương Lâm.","anchor":"Đường mỗ nghe đệ tử Triệu Vũ nói Lữ đạo hữu thần thông kinh người"}],"tuViMoc":[],"nhanMach":[{"ten":"Trừu Hải","tag":"dong-hanh","quanHe":"Đệ tử Ngũ Độc Môn, cùng nhóm truy tìm, bị Triệu Vũ thường xuyên châm chọc","ghiChu":"@c1092"},{"ten":"Phùng Bội Sơn","tag":"dong-hanh","quanHe":"Đệ tử hạch tâm Đạo Pháp Môn, chỉ huy nhóm truy tìm","ghiChu":"@c1092"},{"ten":"Đường Lệ Hải","tag":"su-mon","quanHe":"Đệ tử của Đường Lệ Hải, từng báo lại chuyện thần thông của Vương Lâm.","ghiChu":"Quan hệ sư môn trong Ma Tùng Đạo."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người có thần thông kinh người mà Triệu Vũ từng kể cho Đường Lệ Hải.","ghiChu":"Được nhắc qua lời Đường Lệ Hải."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"nguyên nhân suy luận","ghiChu":"Vương Lâm nghi việc Ma Tùng Đạo thử mình có thể liên quan đến Triệu Vũ.","gap":"@c1100"},{"ten":"Dương Ngọc","tag":"su-mon","quanHe":"đồng môn Ma Tùng Đạo","ghiChu":"Dương Ngọc thuộc Ma Tùng Đạo, cùng tuyến thế lực với Triệu Vũ.","gap":"@c1100"},{"ten":"Dương Ngọc","tag":"dong-minh","quanHe":"đồng môn Ma Tùng Đạo","ghiChu":"Dương Ngọc thuộc Ma Tùng Đạo, cùng tông phái với Triệu Vũ."}],"tuiDo":{}},"nguon":["@c1092","@c1093","@c1100","@c1101"]},{"id":"phung-boi-son","name":"Phùng Bội Sơn","cn":"冯佩山","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Pháp Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết trung kỳ","trangThai":"song","blurb":"Đệ tử hạch tâm Đạo Pháp Môn — tông phái đệ nhất tinh vực cấp sáu, tu vi Tịnh Niết trung kỳ. Chỉ huy nhóm ba tông phái truy tìm Độc Bà Tử.","vaiTro":"Đệ tử hạch tâm Đạo Pháp Môn, chỉ huy nhóm truy tìm Độc Bà Tử trên Mạc La đại lục","tinhCach":["Uy nghiêm, quyết đoán","Hành sự mạnh tay, trấn áp bằng thần thông"],"tabs":{"diem":[{"text":"Tịnh Niết trung kỳ, thuộc tông phái đệ nhất tinh vực cấp sáu, chỉ huy cuộc truy tìm","chuong":"@c1092"},{"text":"Quát một tiếng chứa thần thông quy tắc thiên địa, trấn áp toàn bộ Quy Nguyên Tông","chuong":"@c1092"}],"kinhLich":[{"mucCt":"ky","text":"Dẫn nhóm ba tông phái phá tầng phòng hộ Mạc La đại lục truy tìm Độc Bà Tử. Sai phân tán đệ tử lục soát toàn bộ đại lục. Tại Quy Nguyên Tông, khi Lữ Yến Phỉ phản kháng, quát một tiếng kinh thiên động địa chứa thần thông quy tắc thiên địa, khiến toàn bộ đệ tử Quy Nguyên Tông miệng mũi trào máu, bốn cao thủ Lữ Yến Phỉ và Lý Hướng Đông cũng phải khựng lại không dám phản kháng thêm.","anchor":"Người Quy Nguyên Tông nếu quấy rối đến công việc tìm kiếm của chúng ta thì tự gánh chịu lấy hậu quả","bridge":true,"khoang":"@c1092"},{"mucCt":"ky","text":"Nhận ra Vương Lâm thi triển Ý Cảnh đạo, nhớ lại trong Đạo Pháp Môn chỉ đại trưởng lão mới có thần thông đạo tùy thân động. Tự vỗ ngực phun máu xin tiền bối bớt giận. Tìm kiếm khắp Mạc La đại lục không phát hiện gì, dẫn đám người rời đi. Phân tích: nếu liên quan Độc Bà Tử thì nhất định phải ẩn giấu, kết luận Vương Lâm chắc chắn là sư thúc tổ Quy Nguyên Tông. Nhắc đến Lô Vân Tòng nhắm vào Quy Nguyên Tông, nhận xét hắn không đơn giản, được đại trưởng lão coi trọng.","anchor":"đại trưởng lão cao nhất môn phái mới có được thần thông “đạo tùy thân động” thế này","bridge":true,"khoang":"@c1093"}],"tuViMoc":[{"chuong":"@c1092","canhGioi":"Tịnh Niết trung kỳ","text":"Xuất hiện với tu vi Tịnh Niết trung kỳ","importance":"major"}],"nhanMach":[{"ten":"Trừu Hải","tag":"dong-hanh","quanHe":"Đệ tử Ngũ Độc Môn, cùng nhóm truy tìm","ghiChu":"@c1092"},{"ten":"Triệu Vũ","tag":"dong-hanh","quanHe":"Đệ tử Ma Tùng Đạo, cùng nhóm truy tìm","ghiChu":"@c1092"},{"ten":"Lữ Yến Phỉ","tag":"doi-thu","quanHe":"Trưởng lão Quy Nguyên Tông, phản kháng nhưng bị Phùng Bội Sơn trấn áp","ghiChu":"@c1092"},{"ten":"Lý Hướng Đông","tag":"doi-thu","quanHe":"Tông chủ Quy Nguyên Tông, bị trấn áp","ghiChu":"@c1092"}],"tuiDo":{}},"nguon":["@c1092","@c1093"]},{"id":"chu-ton-thi-am-tong","name":"Chủ Tôn","cn":"","aliases":["Chủ Tôn Thi Âm Tông"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thi Âm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Chủ nhân của Thi Âm Tông, chỉ lộ diện qua hai cánh tay vươn ra từ hắc khí vòng xoáy để cứu hai Vương cuối cùng.","vaiTro":"Thủ lĩnh đứng sau Bát Vương Thi Âm Tông","tinhCach":[{"text":"Hành động nhanh, quyết đoán cứu thuộc hạ trong nguy cấp"}],"tabs":{"diem":[{"text":"Chỉ xuất hiện qua hai cánh tay từ hắc khí vòng xoáy, cứu hai Vương cuối cùng của Thi Âm Tông khỏi dư lực Diệt Thần Mâu.","chuong":"@c1066"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Bát Vương Thi Âm Tông","tag":"cap-tren","quanHe":"Chủ nhân của Bát Vương, được họ gọi là Chủ Tôn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1066"]},{"id":"tong-chu-tu-dao-tong","name":"Tông chủ Tử Đạo Tông","cn":"","aliases":["Nam tử tử kim bào"],"gioiTinh":"nam","theLuc":[{"ten":"Tử Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Tông chủ Tử Đạo Tông, nam tử trung niên mặc tử kim bào, ánh mắt âm trầm. Dùng tử quang hóa lò luyện đan bắt tinh hổ thú luyện Hổ Cốt Hồn Đan.","vaiTro":"Tông chủ Tử Đạo Tông","tinhCach":[{"text":"Ánh mắt sâu xa, lông mày lãnh đạm, vẻ âm trầm","chuong":"@c1075"}],"tabs":{"diem":[{"text":"Dùng tử quang hóa lò luyện đan bắt tinh hổ thú trăm trượng, đang luyện Hổ Cốt Hồn Đan.","chuong":"@c1075"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Lô Địch","tag":"cha-me","quanHe":"Con trai (nghi vấn, chương chưa xác nhận trực tiếp)","ghiChu":"Nếu là Lô Vân Tòng thì Lô Địch là con trai"},{"ten":"Lão già áo tím (Tử Đạo Tông)","tag":"khac","quanHe":"Thuộc hạ/trưởng lão","ghiChu":"Ôm quyền chúc mừng bên cạnh @c1075"}],"tuiDo":{"danDuoc":[{"ten":"Hổ Cốt Hồn Đan","trangThai":"dang-co","moTa":"Đang luyện, cần tinh hổ thú làm nguyên liệu, sắp thành.","nguon":"@c1075"}]}},"nguon":["@c1075"]},{"id":"lao-gia-tuy-tung-lo-van-tong","name":"Lão già tùy tùng Lô Vân Tòng","cn":"","aliases":["Lão già cưỡi mãnh hổ"],"gioiTinh":"nam","theLuc":[{"ten":"Tử Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1095","trangThai":"song","blurb":"Lão già đi theo sau Lô Vân Tòng trong chuyến Tử Đạo Tông tiến về Mạc La đại lục. Ông cung kính với tông chủ, nhận ra thân phận Lý Thiến Mai và chấn động trước phân tích của Lô Vân Tòng.","vaiTro":"tùy tùng của Lô Vân Tòng","tinhCach":[{"text":"cung kính và trung thành","chuong":"@c1094"},{"text":"hiểu biết về danh tiếng nhân vật trong Vân Hải","chuong":"@c1094"}],"tabs":{"diem":[{"text":"Đã theo Lô Vân Tòng nhiều năm, từ thời Tử Đạo Tông chưa nổi danh.","chuong":"@c1094"},{"text":"Nhận ra Lý Thiến Mai qua đặc điểm cô gái tóc xanh duy nhất trong Vân Hải.","chuong":"@c1094"},{"text":"Quan sát Lô Vân Tòng và Lý Thiến Mai, hy vọng hai người kết thành đạo lữ.","chuong":"@c1095"},{"text":"Nghe lệnh ở lại khi Lô Vân Tòng và Lý Thiến Mai tiến vào Mạc La đại lục.","chuong":"@c1095"}],"kinhLich":[{"mucCt":"gon","text":"Lão già tùy tùng bẩm báo tiến độ tới Mạc La đại lục, nghe Lô Vân Tòng phân tích vụ tu sĩ thần bí và nhận ra Lý Thiến Mai khi nàng xuất hiện chặn đường.","anchor":"trong Vân Hải tinh vực này chỉ có duy nhất một cô gái tóc xanh, đó là Lý Thiến Mai","bridge":true,"khoang":"@c1094"},{"chuong":"@c1095","importance":"bridge","mucCt":"gon","tieuDe":"Ở lại ngoài đại lục","text":"Lão đi theo Lô Vân Tòng, thầm mong tông chủ kết đạo lữ với Lý Thiến Mai rồi được dặn ở lại ngoài Mạc La đại lục.","anchor":"Có lẽ tông chủ và nàng ta sẽ. thật sự kết thành đạo lữ"},{"chuong":"@c1097","importance":"bridge","mucCt":"gon","tieuDe":"Bị quát lui","text":"Lão già cưỡi mãnh hổ vì lo lắng cho Lô Vân Tòng và Lý Thiến Mai nên dẫn hơn ba mươi đệ tử hạch tâm tiến vào Mạc La đại lục, nhưng bị Lô Vân Tòng quát lui.","anchor":"Lui ra! Không có lệnh của ta, không kể nào được tiến vào Mạc La đại lục nửa bước!"}],"tuViMoc":[],"nhanMach":[{"ten":"Lô Vân Tòng","tag":"dong-minh","quanHe":"tông chủ và người theo hầu","ghiChu":"Ông theo Lô Vân Tòng nhiều năm và cung kính bẩm báo hành trình."},{"ten":"Lý Thiến Mai","tag":"khac","quanHe":"người được nhận ra thân phận","ghiChu":"Ông nhận ra Lý Thiến Mai là cô gái tóc xanh duy nhất trong Vân Hải."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1094","@c1095","@c1097"]},{"id":"duong-ngoc","name":"Dương Ngọc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ma Tùng Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết trung kỳ @c1100","trangThai":"song","blurb":"Dương Ngọc là tu sĩ áo xanh có tướng mạo anh tuấn, dáng cao và khí chất kiêu ngạo. Hắn từng gặp Lý Thiến Mai, đến khu chợ Bồng Lai cùng hai tùy tùng và va chạm với Vương Lâm vì thái độ thân mật quá mức với nàng.","vaiTro":"Tu sĩ va chạm với Vương Lâm","tinhCach":[{"text":"Kiêu ngạo, dễ nổi giận khi bị cự tuyệt","chuong":"@c1099"},{"text":"Suồng sã với Lý Thiến Mai dù nàng giữ khoảng cách","chuong":"@c1099"}],"tabs":{"diem":[{"text":"Từng được Lý Thiến Mai hỏi một vấn đề nhưng câu trả lời của hắn không khiến nàng hài lòng.","chuong":"@c1099"},{"text":"Gặp lại Lý Thiến Mai tại khu chợ Bồng Lai và bị nàng mắng vì gọi tên quá thân mật.","chuong":"@c1099"},{"text":"Chuyển sự chú ý sang Vương Lâm và lạnh lùng hỏi thân phận hắn.","chuong":"@c1099"},{"text":"Là tu sĩ Tịnh Niết trung kỳ, tam đệ tử của chưởng môn Ma Tùng Đạo cấp sáu.","chuong":"@c1100"},{"text":"Cùng hai đồng môn vây quanh Vương Lâm để dò xét.","chuong":"@c1100"},{"text":"Bị ý cảnh bước chân của Vương Lâm đánh thẳng vào tâm thần, phun máu và rơi vào ảo giác.","chuong":"@c1100"},{"text":"Là tu sĩ Tịnh Niết trung kỳ và tam đệ tử của chưởng môn Ma Tùng Đạo cấp sáu.","chuong":"@c1100"},{"text":"Cùng hai đồng môn Tịnh Niết sơ kỳ vây quanh Vương Lâm để dò xét.","chuong":"@c1100"},{"text":"Bị Vương Lâm dùng ý cảnh bước chân ép vào ảo giác, phun máu và phải cầu cứu sư thúc.","chuong":"@c1100"},{"text":"Cùng hai tu sĩ Tịnh Niết sơ kỳ của Ma Tùng Đạo vây quanh Vương Lâm để dò xét.","chuong":"@c1100"},{"text":"Bị Vương Lâm dùng ý cảnh bước chân ép đến phun máu, rơi vào ảo giác thấy sư môn thân nhân chết thảm.","chuong":"@c1100"}],"kinhLich":[{"mucCt":"vua","text":"Dương Ngọc cùng hai tùy tùng xuất hiện ở khu chợ Bồng Lai, vui mừng nhận ra Lý Thiến Mai và gọi nàng bằng tên thân mật. Bị Lý Thiến Mai mắng, hắn nổi giận rồi chuyển sang nhìn Vương Lâm, lạnh lùng hỏi đối phương là ai.","anchor":"Cặp mày kiếm của Dương Ngọc dựng ngược lên","bridge":true,"khoang":"@c1099"},{"chuong":"@c1100","importance":"normal","mucCt":"ky","tieuDe":"Bị ý cảnh chế ngự","anchor":"Sư thúc cứu ta với!","text":"Dương Ngọc xuất hiện trong thân phận tu sĩ áo xanh, tam đệ tử của chưởng môn Ma Tùng Đạo cấp sáu, dẫn hai đồng môn Tịnh Niết sơ kỳ vây quanh Vương Lâm để dò xét. Sau khi hai đồng môn bị phế, hắn bị Vương Lâm dùng bước chân đồng bộ nhịp tim tạo áp lực lên tâm thần, rồi phun máu và rơi vào ảo giác thấy sư môn thân nhân chết thảm. Cuối cùng hắn hét lên cầu cứu sư thúc và được lão già tóc trắng mắt ưng điểm mi tâm giải ảo rồi hôn mê."}],"tuViMoc":[{"chuong":"@c1100","canhGioi":"Tịnh Niết trung kỳ","text":"Dương Ngọc xuất hiện với tu vi Tịnh Niết trung kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Lý Thiến Mai","tag":"khac","quanHe":"Từng gặp và từng trả lời một vấn đề của nàng, nhưng không khiến nàng thỏa mãn.","ghiChu":"Gặp lại ở khu chợ Bồng Lai thì bị nàng lạnh nhạt cự tuyệt."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Lạnh lùng chất vấn thân phận Vương Lâm khi thấy hắn đi cùng Lý Thiến Mai.","ghiChu":"Hai bên bắt đầu va chạm tại khu chợ."},{"ten":"Sư thúc Dương Ngọc","tag":"su-mon","quanHe":"Được sư thúc hiện thân cứu khỏi ảo giác.","ghiChu":"Dương Ngọc cầu cứu khi không chịu nổi ý cảnh."},{"ten":"Hai tu sĩ Tịnh Niết sơ kỳ","tag":"dong-minh","quanHe":"Đồng môn đi cùng hắn để vây dò xét Vương Lâm.","ghiChu":"Cả hai bị Vương Lâm phế bỏ."},{"ten":"Âu Dương Long","tag":"khac","quanHe":"Bị Âu Dương Long nhận ra thân phận và cảnh báo cho Vương Lâm.","ghiChu":"Âu Dương Long nói hắn là tam đệ tử chưởng môn Ma Tùng Đạo cấp sáu."},{"ten":"Triệu Vũ","tag":"su-mon","quanHe":"đồng môn Ma Tùng Đạo","ghiChu":"Dương Ngọc và Triệu Vũ cùng liên hệ với Ma Tùng Đạo, khiến Vương Lâm suy đoán việc dò xét có thể liên quan đến Triệu Vũ.","gap":"@c1100"},{"ten":"Triệu Vũ","tag":"dong-minh","quanHe":"đồng môn Ma Tùng Đạo","ghiChu":"Vương Lâm suy luận Dương Ngọc có quan hệ với Ma Tùng Đạo, cũng là tông phái của Triệu Vũ."}],"tuiDo":{}},"nguon":["@c1099","@c1100"]},{"id":"au-duong-long","name":"Âu Dương Long","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Bảo Ngọc Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Âu Dương Long là lão già bày quầy bán nguyên tinh trong khu chợ tu sĩ. Ông giao dịch với Vương Lâm, nhận tiên ngọc đặt cọc rồi dẫn hắn vào đấu giá tư nhân tại tòa thành trung tâm. Về sau ông tham gia đấu giá và quyết liệt tranh giành Thần Ma Giáp, đẩy giá lên tới ba vạn nguyên tinh.","vaiTro":"Người bán nguyên tinh kiêm dẫn khách trong khu chợ tu sĩ","tinhCach":"Nhiệt tình khi thấy lợi ích; quyết liệt tranh đấu trong đấu giá","tabs":{"diem":[{"text":"Bày quầy bán nguyên tinh, nhận tiên ngọc của Vương Lâm làm tiền đặt cọc","chuong":"@c1100"},{"text":"Dẫn Vương Lâm vào tòa thành trung tâm dự đấu giá tư nhân","chuong":"@c1101"},{"text":"Nhắc Vương Lâm về quy tắc không che giấu tướng mạo trước khi vào phòng đấu giá","chuong":"@c1102"},{"text":"Tham gia đấu giá và quyết liệt tranh Thần Ma Giáp, đẩy giá lên ba vạn nguyên tinh","chuong":"@c1107"}],"kinhLich":[{"chuong":"@c1100","importance":"normal","mucCt":"vua","tieuDe":"Giao dịch nguyên tinh","anchor":"Đạo hữu làm việc rất quyết đoán, lão phu là Âu Dương Long cũng coi như là một bằng hữu","text":"Âu Dương Long bày quầy bán một khối nguyên tinh và nhận túi trữ vật chứa tiên ngọc của Vương Lâm làm tiền đặt cọc. Trước khi rời đi, ông tự giới thiệu tên, hẹn ba ngày sau tìm Vương Lâm và truyền thần niệm cảnh báo về Dương Ngọc của Ma Tùng Đạo."},{"chuong":"@c1101","importance":"normal","mucCt":"vua","tieuDe":"Dẫn Vương Lâm vào đấu giá tư nhân","text":"Thái độ nhiệt tình hơn hẳn trước, dẫn Vương Lâm vào tòa thành trung tâm qua đấu trường linh thú đến buổi đấu giá tư nhân do sư thúc chủ trì. Hỏi VL vì sao biết thân phận mình khi không ai giới thiệu, VL chỉ mỉm cười không đáp.","anchor":"Sao đạo hữu biết được thân phận của tại hạ?"},{"chuong":"@c1102","importance":"bridge","mucCt":"vua","text":"Âu Dương Long nhắc Vương Lâm về quy tắc không che giấu tướng mạo, dẫn vào phòng đấu giá tư nhân rồi khom lưng phục vụ cạnh Thương Tùng Tử.","anchor":"Âu Dương Long đang khom lưng ở phía sau người lão rồi khẽ nói bên tai vài câu gì đó"},{"chuong":"@c1103","importance":"bridge","mucCt":"gon","tieuDe":"Dẫn rời căn lầu","text":"Âu Dương Long dẫn Vương Lâm rời khỏi căn lầu sau buổi tụ hội.","anchor":"Bản đồ tinh cầu trước đó chỉ là giả, đây mới là đồ thật"},{"chuong":"@c1107","importance":"normal","mucCt":"vua","tieuDe":"Tranh Thần Ma Giáp","text":"Âu Dương Long tham gia đấu giá núi đá rồi quyết liệt tranh Thần Ma Giáp, đẩy giá lên tới ba vạn nguyên tinh. Việc ra giá lớn khiến thanh niên áo vàng Bí Lạc Tông nhận ra xuất thân Bảo Ngọc Tông cấp năm của hắn và chất vấn nguồn gốc nguyên tinh.","anchor":"Ngươi chỉ là Bảo Ngọc Tông cấp năm trên Bồng Lai đại lục, đâu ra có nhiều nguyên tinh như vậy"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Giao dịch nguyên tinh và chủ động coi đối phương như bằng hữu.","ghiChu":"Ông nhận tiên ngọc đặt cọc rồi hẹn ba ngày sau tìm Vương Lâm."},{"ten":"Dương Ngọc","tag":"khac","quanHe":"Biết rõ thân phận Dương Ngọc và cảnh báo Vương Lâm.","ghiChu":"Dương Ngọc là tam đệ tử chưởng môn Ma Tùng Đạo cấp sáu."},{"ten":"Nam tử lưng hùm vai gấu","tag":"su-mon","quanHe":"Đệ tử được hắn phái đi mời Vương Lâm.","ghiChu":"Quan hệ sư đồ được nêu trong chương."},{"ten":"Thương Tùng Tử","tag":"su-mon","quanHe":"sư thúc","ghiChu":"Âu Dương Long đứng sau phục vụ và báo cáo với Thương Tùng Tử trong buổi tụ họp."},{"ten":"Thanh niên áo vàng","tag":"doi-thu","quanHe":"Đối thủ đấu giá","ghiChu":"Hai bên tranh đoạt Thần Ma Giáp trong buổi đấu giá, thanh niên áo vàng chất vấn nguồn gốc nguyên tinh của Âu Dương Long."},{"ten":"Vương Lâm","tag":"khac","quanHe":"khách được mời tới đấu giá","ghiChu":"Âu Dương Long dẫn Vương Lâm tới trường đấu thú và buổi đấu giá tư nhân."},{"ten":"Sư thúc Âu Dương Long","tag":"su-mon","quanHe":"Sư thúc, chủ trì buổi đấu giá tư nhân tại tòa thành trung tâm","ghiChu":"@c1101"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Khối nguyên tinh","loai":"nguyên liệu","trangThai":"dang-co","moTa":"Một khối nguyên tinh được bày bán, chỉ đổi bằng tiên ngọc.","nguon":"@c1100"}],"linhThao":[],"khac":[]}},"nguon":["@c1100","@c1101","@c1102","@c1103","@c1107","@c1108"]},{"id":"su-thuc-duong-ngoc","name":"Sư thúc Dương Ngọc","cn":"","aliases":["lão già tóc trắng mắt ưng"],"gioiTinh":"nam","theLuc":[{"ten":"Ma Tùng Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Sư thúc Dương Ngọc là tu sĩ bậc cao của Ma Tùng Đạo, đi theo bảo hộ đệ tử trong khu chợ. Khi Dương Ngọc cầu cứu, lão hiện thân, giải ảo giác rồi mềm mỏng mời Vương Lâm đàm phán.","vaiTro":"Tu sĩ bậc cao Ma Tùng Đạo","tinhCach":[{"text":"Ra tay nhanh gọn để cứu người trong tông môn","chuong":"@c1100"},{"text":"Biết hạ giọng xin lỗi và chuyển xung đột sang đàm phán","chuong":"@c1100"}],"tabs":{"diem":[{"text":"Hiện thân rất nhanh sau tiếng cầu cứu của Dương Ngọc.","chuong":"@c1100"},{"text":"Điểm mi tâm Dương Ngọc và một đệ tử khác để giải ảo giác, khiến họ hôn mê.","chuong":"@c1100"},{"text":"Gọi Vương Lâm là Lữ đạo hữu và mời ngồi nói chuyện bồi tội.","chuong":"@c1100"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Dương Ngọc","tag":"su-mon","quanHe":"Sư thúc trong Ma Tùng Đạo, hiện thân cứu Dương Ngọc khỏi ảo giác.","ghiChu":"Điểm mi tâm khiến Dương Ngọc hôn mê để giải ảo."},{"ten":"Hai tu sĩ Tịnh Niết sơ kỳ","tag":"su-mon","quanHe":"Cứu một đệ tử khỏi ảo giác bằng cách điểm mi tâm.","ghiChu":"Cùng thuộc Ma Tùng Đạo."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sau xung đột, chủ động xin lỗi và mời Vương Lâm đàm phán.","ghiChu":"Lão gọi Vương Lâm là Lữ đạo hữu."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1100"]},{"id":"hai-tu-si-tinh-niet-so-ky","name":"Hai tu sĩ Tịnh Niết sơ kỳ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ma Tùng Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết sơ kỳ @c1100","trangThai":"song","blurb":"Hai tu sĩ Tịnh Niết sơ kỳ là đồng môn đi cùng Dương Ngọc trong lần dò xét Vương Lâm. Họ lần lượt bị Vương Lâm phá thuật, đánh rơi vào ảo giác và phế bỏ.","vaiTro":"Đệ tử Ma Tùng Đạo đi theo Dương Ngọc","tinhCach":[{"text":"Phối hợp với Dương Ngọc để vây ép đối thủ","chuong":"@c1100"},{"text":"Ra tay trước nhưng nhanh chóng bị áp đảo","chuong":"@c1100"}],"tabs":{"diem":[{"text":"Một người thi triển huyễn hóa đóa hoa đỏ khổng lồ tấn công Vương Lâm.","chuong":"@c1100"},{"text":"Một người phóng phi kiếm nhưng bị ánh mắt song hư thực làm rơi vào ảo giác.","chuong":"@c1100"},{"text":"Cả hai bị Vương Lâm phế bỏ, sau đó được sư thúc Dương Ngọc điểm mi tâm cho hôn mê.","chuong":"@c1100"}],"kinhLich":[],"tuViMoc":[{"chuong":"@c1100","canhGioi":"Tịnh Niết sơ kỳ","text":"Hai đồng môn của Dương Ngọc xuất hiện với tu vi Tịnh Niết sơ kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Dương Ngọc","tag":"dong-minh","quanHe":"Đồng môn đi cùng Dương Ngọc để vây dò xét Vương Lâm.","ghiChu":"Cùng thuộc Ma Tùng Đạo."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Ra tay với Vương Lâm nhưng bị đối phương phế bỏ.","ghiChu":"Một người bị ngón tay hóa kiếm đánh trúng, một người bị ánh mắt song hư thực làm rơi vào ảo giác."},{"ten":"Sư thúc Dương Ngọc","tag":"su-mon","quanHe":"Được sư thúc Dương Ngọc điểm mi tâm cho hôn mê để giải ảo.","ghiChu":"Là đệ tử Ma Tùng Đạo được lão bảo hộ."}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm","loai":"pháp bảo","trangThai":"khong-ro","moTa":"Một tu sĩ Tịnh Niết sơ kỳ vung tay biến ảo ra phi kiếm khi tấn công Vương Lâm.","nguon":"@c1100"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1100"]},{"id":"duong-le-hai","name":"Đường Lệ Hải","cn":"唐丽海","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ma Tùng Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết sơ kỳ @c1101","trangThai":"song","blurb":"Đường Lệ Hải là trưởng lão cấp sáu của Ma Tùng Đạo trên Bồng Lai đại lục. Ông cùng Ngô Thanh tiếp xúc Vương Lâm, vừa mời chào vừa dò xét lai lịch và mức nguy hiểm của đối phương.","vaiTro":"Trưởng lão Ma Tùng Đạo","tinhCach":[{"text":"Nói năng vòng vo, có ý dò xét đối phương.","chuong":"@c1101"},{"text":"Cẩn trọng trước người có thần thông khó lường.","chuong":"@c1101"}],"tabs":{"diem":[{"text":"Là trưởng lão Ma Tùng Đạo cấp sáu, xuất hiện với y phục xanh và gương mặt đỏ như son.","chuong":"@c1101"},{"text":"Sau khi Vương Lâm rời đi, ông nhận xét đối phương là người cẩn thận đa nghi, cơ trí và ra tay độc ác.","chuong":"@c1101"},{"text":"Là trưởng lão Ma Tùng Đạo cấp sáu, tu vi Toái Niết sơ kỳ.","chuong":"@c1101"},{"text":"Đánh giá Vương Lâm là người quái lạ, đa nghi, cơ trí và nguy hiểm.","chuong":"@c1101"},{"text":"Sau khi gặp Vương Lâm, đánh giá đối phương quái lạ và nguy hiểm.","chuong":"@c1101"},{"text":"Nhận xét Vương Lâm: cẩn thận đa nghi, cơ trí phi phàm, ra tay độc ác","chuong":"@c1101"}],"kinhLich":[{"chuong":"@c1101","importance":"normal","mucCt":"vua","tieuDe":"Chiêu mộ Vương Lâm làm trưởng lão ngoại sự","text":"Cùng Ngô Thanh gặp Vương Lâm tại khách điếm, ban đầu vòng vo kết giao rồi mời hắn làm trưởng lão ngoại sự Ma Tùng Đạo. Sau khi VL rời đi, nhận xét hắn cẩn thận đa nghi, cơ trí phi phàm, ra tay độc ác.","anchor":"cẩn thận đa nghi, cơ trí phi phàm, ra tay độc ác"},{"mucCt":"vua","anchor":"Tiên sinh đã từng nói đừng nên trêu chọc tên kia, Ngô Thanh ơi Ngô Thanh, ngươi sao lại phải như thế","text":"Đường Lệ Hải phát hiện Ngô Thanh rời Bồng Lai truy sát Vương Lâm, nhớ lời tiên sinh từng dặn không nên trêu chọc người này nên chỉ thầm than mà không đi ngăn cản. Sau khi chứng kiến Dịch Linh Ấn, hắn mím chặt môi và hiểu rằng nếu bản thân đối diện Vương Lâm thì cũng không thể ung dung.","bridge":true,"khoang":"@c1104"}],"tuViMoc":[{"chuong":"@c1101","canhGioi":"Toái Niết sơ kỳ","text":"Xuất hiện với tu vi Toái Niết sơ kỳ khi gặp Vương Lâm tại Bồng Lai.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được ông đại diện Ma Tùng Đạo mời làm trưởng lão ngoại sự.","ghiChu":"Gặp tại khách điếm Bồng Lai."},{"ten":"Ngô Thanh","tag":"dong-minh","quanHe":"Đồng môn trưởng lão Ma Tùng Đạo, cùng tiếp xúc Vương Lâm.","ghiChu":"Cùng đại diện Ma Tùng Đạo trong buổi gặp."},{"ten":"Nam tử trung niên bí ẩn","tag":"cap-tren","quanHe":"Tu sĩ Ma Tùng Đạo có địa vị cao hơn, cùng bàn việc sau khi Vương Lâm rời đi.","ghiChu":"Đường Lệ Hải kính trọng ý kiến của người này."},{"ten":"Triệu Vũ","tag":"su-mon","quanHe":"Đệ tử từng báo lại cho ông về thần thông của Vương Lâm.","ghiChu":"Quan hệ sư môn trong Ma Tùng Đạo."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1101","@c1104"]},{"id":"ngo-thanh","name":"Ngô Thanh","cn":"吴清","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ma Tùng Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết sơ kỳ @c1101","trangThai":"song","blurb":"Ngô Thanh là trưởng lão Ma Tùng Đạo tu vi Toái Niết sơ kỳ, cùng Đường Lệ Hải chiêu mộ Vương Lâm tại Bồng Lai. Sau khi nhận ra và thăm dò Vương Lâm trong phòng đấu giá, ông truy sát hắn và chết dưới Dịch Linh Ấn, rồi bị Ma Tùng Đạo tuyên bố trục xuất để phủi sạch liên hệ. Về sau ông còn xuất hiện dưới dạng chiến hồn do Phong Tiên Ấn phóng ra.","vaiTro":"Trưởng lão Toái Niết sơ kỳ của Ma Tùng Đạo","tinhCach":"thẳng thắn, hỏi thẳng ý định người khác; thủ đoạn, cố ý nâng giá để thăm dò tài lực; tham lam, tiếc rẻ trước linh hồn hung thú cấp mười","tabs":{"diem":[{"text":"Trưởng lão Ma Tùng Đạo tu vi Toái Niết sơ kỳ, cùng Đường Lệ Hải chiêu mộ Vương Lâm","chuong":"@c101"},{"text":"Nhận ra Vương Lâm và cố ý nâng giá lông vũ Chu Tước từng năm ngàn tiên ngọc để thăm dò tài lực hắn","chuong":"@c1103"},{"text":"Truy sát Vương Lâm rời khu chợ Bồng Lai và chết dưới Dịch Linh Ấn","chuong":"@c1104"},{"text":"Sau khi chết bị Trương Kỳ tuyên bố trục xuất khỏi Ma Tùng Đạo để tông phái phủi sạch liên hệ","chuong":"@c105"},{"text":"Xuất hiện dưới dạng chiến hồn được Phong Tiên Ấn phóng ra, cùng Hư Không Tử và Thiên Vận Tử","chuong":"@c1123"}],"kinhLich":[{"chuong":"@c1101","importance":"normal","mucCt":"vua","tieuDe":"Cùng chiêu mộ Vương Lâm","text":"Cùng Đường Lệ Hải gặp Vương Lâm, hỏi thẳng hắn có muốn gia nhập Ma Tùng Đạo không. Sau khi VL rời đi, nhận xét tu vi của hắn rất quái lạ.","anchor":"Tu vi rất quái lạ!"},{"chuong":"@c1102","importance":"bridge","mucCt":"gon","text":"Ngô Thanh nhận ra Vương Lâm trong phòng đấu giá tư nhân, sau đó tiếc rẻ khi thấy linh hồn hung thú cấp mười hai chỉ mới nửa hóa sương.","anchor":"Ngô Thanh nhìn qua mãnh thú trong bọt khí rồi lắc đầu than nhẹ"},{"mucCt":"ky","text":"Ngô Thanh cố ý nâng giá lông vũ Chu Tước từng năm ngàn tiên ngọc để thăm dò tài lực Vương Lâm, khiến nhiều lão quái khó chịu. Khi Vương Lâm từ bỏ, lão lấy được lông vũ và nhận định đối phương có rất nhiều tiên ngọc. Sau khi Vương Lâm rời thành, lão lập tức phóng theo, mở đầu xung đột ngoài thành.","anchor":"Ngô Thanh phóng đi như tên bắn, lão đang đuổi theo Vương Lâm","bridge":true,"khoang":"@c1103"},{"chuong":"@c1104","importance":"normal","mucCt":"vua","tieuDe":"Chết dưới Dịch Linh Ấn","anchor":"Ngô Thanh trưởng lão của Ma Tùng Đạo, tu sĩ Toái Niết sơ kỳ cứ như vậy mà tiêu tán","text":"Ngô Thanh rời khu chợ Bồng Lai truy sát Vương Lâm, trước sau thi triển ngọn núi khổng lồ, Lực bạt thiên và nhiều bảo vật từ khe trữ vật nhưng đều bị phá tan. Khi Vương Lâm thi triển Dịch Linh Ấn, lão nhận ra thần thông này và tuyệt vọng bỏ chạy, cuối cùng thân thể nổ tung hóa thành sương máu, nguyên thần tiêu tán."},{"chuong":"@c1105","importance":"bridge","mucCt":"gon","tieuDe":"Bị trục xuất danh nghĩa","text":"Sau khi chết, Ngô Thanh bị Trương Kỳ tuyên bố đã bị trục xuất khỏi Ma Tùng Đạo để tông phái phủi sạch liên hệ với hành động của hắn.","anchor":"Hai người trước Ngô Thanh đã bị trục xuất khỏi Ma Tùng Đạo, tất cả lời nói và hành động của hắn đã không còn liên quan đến Ma Tùng Đạo nữa"},{"chuong":"@c1109","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc trong mật mưu","text":"Ngô Thanh được Thương Tùng Tử nhắc lại như bằng chứng khiến lão e ngại thực lực thật của Vương Lâm.","anchor":"Người này nếu đã có bản lĩnh giết Ngô Thanh"},{"chuong":"@c1111","importance":"bridge","mucCt":"gon","text":"Cái chết của Ngô Thanh được lão giả họ Bàng nhớ lại khi bị Vương Lâm cảnh cáo, khiến lão họ Bàng sợ hãi và hối hận vì đã lắm lời.","anchor":"Lão già họ Bàng chấn động tâm thần, lúc này nhớ lại cái chết của Ngô Thanh thì âm thầm hối hận mình lắm lời."},{"chuong":"@c1123","importance":"bridge","mucCt":"gon","text":"Ngô Thanh xuất hiện dưới dạng chiến hồn được Phong Tiên Ấn phóng ra, cùng Hư Không Tử và Thiên Vận Tử tham gia vây đánh nguyên anh huyết sắc.","anchor":"Bên trong Phong Tiên Ấn lập tức phóng ra hàng loạt chiến hồn, Hư Không Tử, Thiên Vận Tử, Ngô Thanh"}],"tuViMoc":[{"chuong":"@c1101","canhGioi":"Toái Niết sơ kỳ","text":"Xuất hiện với tu vi Toái Niết sơ kỳ trong buổi gặp Vương Lâm.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được ông hỏi thẳng về việc làm trưởng lão ngoại sự Ma Tùng Đạo.","ghiChu":"Gặp tại khách điếm Bồng Lai."},{"ten":"Đường Lệ Hải","tag":"dong-minh","quanHe":"Đồng môn trưởng lão Ma Tùng Đạo, cùng tiếp xúc Vương Lâm.","ghiChu":"Cùng đại diện Ma Tùng Đạo trong buổi gặp."},{"ten":"Nam tử trung niên bí ẩn","tag":"cap-tren","quanHe":"Tu sĩ Ma Tùng Đạo có địa vị cao hơn, cùng bàn việc sau khi Vương Lâm rời đi.","ghiChu":"Cùng thuộc Ma Tùng Đạo."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Địch thủ giết mình","ghiChu":"Ngô Thanh truy sát Vương Lâm nhưng bị Vương Lâm dùng Dịch Linh Ấn giết chết.","gap":"@c1104"},{"ten":"Thương Tùng Tử","tag":"khac","quanHe":"Bị lợi dụng","ghiChu":"Thương Tùng Tử cố ý mời Ngô Thanh đến Bồng Lai để mượn mâu thuẫn giữa Ma Tùng Đạo và Vương Lâm.","gap":"@c1104"},{"ten":"Trương Kỳ","tag":"khac","quanHe":"Bị Trương Kỳ cắt khỏi Ma Tùng Đạo trên danh nghĩa để tránh liên lụy.","ghiChu":"Bị tuyên bố trục xuất @c1105"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1101","@c1102","@c1103","@c1104","@c1105","@c1106","@c1109","@c1111","@c1123"]},{"id":"nam-tu-trung-nien-bi-an-ma-tung-dao","name":"Nam tử trung niên bí ẩn","cn":"","aliases":["Nam tử trung niên bí ẩn Ma Tùng Đạo"],"gioiTinh":"nam","theLuc":[{"ten":"Ma Tùng Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Cao hơn Toái Niết sơ kỳ của Đường Lệ Hải và Ngô Thanh @c1101","trangThai":"song","blurb":"Nam tử trung niên bí ẩn của Ma Tùng Đạo ẩn thân tại chiếc bàn không người trong khách điếm để quan sát Vương Lâm. Sau buổi gặp, ông hiện hình và khuyên Ma Tùng Đạo rút khỏi chuyện đan phương và ngọc giản vì cảm thấy Vương Lâm cực kỳ nguy hiểm.","vaiTro":"Tu sĩ cấp cao Ma Tùng Đạo","tinhCach":[{"text":"Thận trọng, đánh giá nguy cơ trước khi hành động.","chuong":"@c1101"},{"text":"Có nhãn lực cao, nhận ra Vương Lâm khiến mình bất an.","chuong":"@c1101"}],"tabs":{"diem":[{"text":"Ẩn thân tại chiếc bàn không người trong khách điếm để theo dõi buổi gặp với Vương Lâm.","chuong":"@c1101"},{"text":"Được Đường Lệ Hải và Ngô Thanh xem như người có địa vị cao hơn trong Ma Tùng Đạo.","chuong":"@c1101"},{"text":"Khuyên Ma Tùng Đạo rút khỏi chuyện đan phương và ngọc giản vì Vương Lâm quá nguy hiểm.","chuong":"@c1101"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng bị ông ẩn thân quan sát và đánh giá là cực kỳ nguy hiểm.","ghiChu":"Chưa trực tiếp giao thủ hay nói chuyện."},{"ten":"Đường Lệ Hải","tag":"dong-minh","quanHe":"Tu sĩ cùng Ma Tùng Đạo, bàn việc sau khi Vương Lâm rời đi.","ghiChu":"Có địa vị cao hơn Đường Lệ Hải."},{"ten":"Ngô Thanh","tag":"dong-minh","quanHe":"Tu sĩ cùng Ma Tùng Đạo, bàn việc sau khi Vương Lâm rời đi.","ghiChu":"Có địa vị cao hơn Ngô Thanh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1101"]},{"id":"nam-tu-lung-hum-vai-gau","name":"Nam tử lưng hùm vai gấu","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ @c1101","trangThai":"song","blurb":"Nam tử lưng hùm vai gấu là đệ tử của Âu Dương Long. Hắn tới mời Vương Lâm theo lệnh sư phụ và dẫn đường vào tòa thành trung tâm khu chợ Bồng Lai.","vaiTro":"Đệ tử của Âu Dương Long","tinhCach":[{"text":"Cung kính khi đối diện Vương Lâm.","chuong":"@c1101"},{"text":"Làm việc theo lệnh sư phụ.","chuong":"@c1101"}],"tabs":{"diem":[{"text":"Đến gặp Vương Lâm vào hoàng hôn ngày thứ ba để truyền lời mời của Âu Dương Long.","chuong":"@c1101"},{"text":"Dẫn Vương Lâm vào tòa thành trung tâm trong khu chợ Bồng Lai.","chuong":"@c1101"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Âu Dương Long","tag":"su-mon","quanHe":"Sư phụ của hắn, người sai hắn tới mời Vương Lâm.","ghiChu":"Quan hệ sư đồ."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được hắn truyền lời mời và dẫn đường.","ghiChu":"Gặp tại khu chợ Bồng Lai."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1101"]},{"id":"thuong-tung-tu","name":"Thương Tùng Tử","cn":"苍松子","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Bảo Ngọc Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết trung kỳ @c1123","trangThai":"tu-vong","blurb":"Thương Tùng Tử là lão giả tóc trắng áo bào màu tro, tu vi Toái Niết trung kỳ, sư thúc của Âu Dương Long và người chủ trì buổi đấu giá tư nhân tại khu chợ Bồng Lai. Ông dẫn đoàn tiến vào thế giới bảy màu để đoạt Đạo Kinh, nhiều lần đối đầu và mưu hại Vương Lâm bằng vạn phi kiếm cùng thuật Bách Thế Huyết Nguyên Hóa Anh. Cuối cùng ông bại vong dưới tay Vương Lâm, nguyên anh huyết sắc bị đoạt và tế luyện.","vaiTro":"Tu sĩ Toái Niết trung kỳ — chủ trì đấu giá, sư thúc Âu Dương Long","tinhCach":"Mưu tính xảo quyệt, quen mượn tay người khác và lợi dụng kẻ có giá trị;ham lam bảo vật, tranh đoạt quyết liệt; hành sự thận trọng, giàu kinh nghiệm dẫn đường trong thế giới bảy màu","tabs":{"diem":[{"text":"Tu sĩ Toái Niết trung kỳ, chủ trì buổi đấu giá tư nhân tại khu chợ Bồng Lai","chuong":"@c1102"},{"text":"Điều khiển hơn một vạn phi kiếm kim quang làm thủ đoạn công kích chủ lực, từng dùng chặn Giao Long và âm hồn Vân Hồn Tử","chuong":"@c1113"},{"text":"Dẫn đoàn nhiều lần tiến vào thế giới bảy màu, mục tiêu thật là đoạt Đạo Kinh trong vùng phong ấn","chuong":"@c1119"},{"text":"Tu luyện thuật Bách Thế Huyết Nguyên Hóa Anh, triệu hồi Nghịch Hành Giả cùng các thần thông trận pháp","chuong":"@c1134"},{"text":"Từng tái tạo thân thể hoàn chỉnh nhờ hấp thu sáng bảy màu và tia chớp trên tượng đá khổng lồ","chuong":"@c1129"},{"text":"Bại vong dưới tay Vương Lâm, nguyên anh huyết sắc bị bao bọc và tế luyện thành pháp bảo","chuong":"@c1132"}],"kinhLich":[{"mucCt":"vua","text":"Thương Tùng Tử ngồi vị trí chính trong phòng đấu giá tư nhân, nhận báo cáo từ Âu Dương Long rồi tuyên bố mở buổi tụ họp theo quy luật cũ. Ông lấy ra ba vật phẩm để giao dịch, bán Huyết Tinh Kiếm và Hỗn Nguyên Đan, đồng thời tặng bộ tàn giáp cho Vương Lâm khi không ai nhận ra lai lịch vật này.","anchor":"Hôm nay Thương Tùng Tử lão phu mở cuộc tụ họp mời một số bạn cũ thâm giao","bridge":true,"khoang":"@c1102"},{"mucCt":"vua","text":"Thương Tùng Tử thử mua thú hồn cấp mười hai nhưng bị từ chối, sau đó tỏ ý không vui với cách Ngô Thanh nâng giá và xin lỗi Vương Lâm. Lão đổi năm ngàn nguyên tinh lấy tiên ngọc của Vương Lâm, từ chối bán thêm Hỗn Nguyên Đan vì chỉ còn một hạt, rồi sau khi đối phương rời đi thì lộ ý đồ riêng với số nguyên tinh ấy.","anchor":"Nguyên tinh của Thương Tùng Tử ta cũng không phải dễ dàng mang đi như vậy","bridge":true,"khoang":"@c1103"},{"mucCt":"vua","anchor":"Hắn… hắn…hắn rốt cuộc là ai…","text":"Thương Tùng Tử ngồi trong chủ thành phía đông, cầm ngọc giản và thầm tính chuyện mượn Ngô Thanh giết Vương Lâm rồi đoạt nguyên tinh. Sau khi chứng kiến Dịch Linh Ấn giết Ngô Thanh và phá hoại Bồng Lai, lão bóp nát ngọc giản, tái nhợt run rẩy và hoảng sợ không biết Vương Lâm rốt cuộc là ai.","bridge":true,"khoang":"@c1104"},{"mucCt":"ky","text":"Thương Tùng Tử sau khi chứng kiến thanh thế của Vương Lâm đã chủ động bắt chuyện và cho người thu mua sạch bản đồ tinh cầu trong chợ để tặng hắn. Lão đưa ngọc giản về một nơi bí ẩn, đề nghị Vương Lâm hợp tác đi vào với thù lao một vạn nguyên tinh, cuối cùng chấp nhận mức hai vạn và giao trước một nửa. Sau khi rời đi, lão nghi ngờ thân phận đệ tử Thần Tông của Vương Lâm nhưng vẫn quyết định lợi dụng cơ hội vì đã chuẩn bị cho chuyện này suốt ngàn năm.","anchor":"Đệ tử Thần Tông lại thiếu nguyên tinh sao? Thân phận người này cực kỳ khả nghi","bridge":true,"khoang":"@c1105"},{"mucCt":"vua","text":"Thương Tùng Tử xuất hiện trong cuộc đấu giá, áp đảo thanh niên áo vàng Bí Lạc Tông và thắng bộ giáp ở mức sáu vạn nguyên tinh. Sau đó lão giao cho Vương Lâm tiền đặt cọc cùng ngọc giản bản đồ, rời Bồng Lai để tới Man Hoang đại lục chủ trì nhóm tu sĩ. Tại điểm hẹn, lão giải thích cần Vương Lâm vì Dịch Linh Ấn có thể giúp kế hoạch tăng thêm hai phần thành công.","anchor":"Người này có thể thi triển Dịch Linh Ấn, có hắn thì lão phu sẽ có thể nắm chắc thêm hai phần thành công","bridge":true,"khoang":"@c1108"},{"mucCt":"ky","text":"Thương Tùng Tử dùng mấy ngàn phi kiếm kim quang tạo màn kiếm ngăn âm hồn của Vân Hồn Tử, giữ Vương Lâm trong vai khách quý do mình mời. Lão bí mật nói với Vân Hồn Tử rằng e ngại Vương Lâm vì một tu sĩ Tịnh Niết có thể giết Ngô Thanh, nên nhờ Vân Hồn Tử tiếp tục dò xét trên đường. Sau đó lão tiết lộ nơi đến có Hồi đan bị Giao Long hóa sương cấp mười hai canh giữ, hứa cho Vương Lâm ngoài nguyên tinh còn được chọn bảo vật, rồi dẫn sáu người xuất phát.","anchor":"Người này nếu đã có bản lĩnh giết Ngô Thanh thì chắc chắn cũng không chênh lệch nhiều so với tu sĩ Toái Niết trung kỳ chúng ta","bridge":true,"khoang":"@c1109"},{"chuong":"@c1111","importance":"normal","tieuDe":"Nghi vấn Vân Hồn Tử","mucCt":"vua","text":"Thương Tùng Tử vào thế giới bảy màu cùng đội ngũ nhưng phát hiện Vân Hồn Tử không xuất hiện tại tế đàn. Lão nghi ngờ Vương Lâm có liên quan và chất vấn, nhưng sau khi nghe phản bác cùng lời chen vào của Đoan Mộc thì tạm nhận mình lỗ mãng.","anchor":"Chuyện này là lão phu lỗ mãng, Lữ đạo hữu đừng nên để bụng!"},{"mucCt":"ky","text":"Thương Tùng Tử dẫn đoàn người đi trong thế giới bảy màu, cảnh báo không tản thần thức quá xa và không bay quá cao vì ngay vòng ngoài đã có mãnh thú cấp mười hai. Lão giới thiệu nơi này có mãnh thú hóa sương, nguyên tinh và thi hài cổ nhân, đồng thời chỉ đường qua tế đàn, bình nguyên, núi sâu và các vùng nguy hiểm. Khi tới khu Hồi đan, lão tiết lộ viên đan nằm trước mặt Đoan Mộc nhưng có Giao Long hóa sương canh giữ, thừa nhận cần Hồi Đại Tự Tại của Đoan Mộc để mở đường, rồi trong trận chiến hóa ra mấy vạn phi kiếm công kích Giao Long.","anchor":"Đúng vậy, thần thông Hồi Đại Tự Tại của Đoan Mộc đạo hữu có thể trợ giúp rất nhiều đến hành trình của chúng ta","bridge":true,"khoang":"@c1112"},{"mucCt":"ky","anchor":"Trong mắt Thương Tùng Tử bùng lên vẻ sợ hãi, lão nhanh chóng truyền thần niệm ra ngoài","text":"Thương Tùng Tử điều khiển hơn một vạn phi kiếm công kích Giao Long và cùng nhóm tu sĩ ngăn nó thăng không. Sau khi chứng kiến Vương Lâm dùng lực Cổ Thần kéo rơi Giao Long, lão sinh lòng kiêng kị, rồi đưa đan dược hỗ trợ lão giả họ Bàng và đề nghị tiếp tục đi sâu. Cuối chương, khi dị biến xuất hiện, lão cùng Đoan Mộc dừng lại trước và hoảng sợ truyền thần niệm cảnh báo mọi người không được cử động.","bridge":true,"khoang":"@c1113"},{"mucCt":"ky","text":"Thương Tùng Tử lập tức cảnh báo đoàn người không được tản thần thức khi Mê Thất Giả tới gần. Sau khi Đoan Mộc bị mang đi, lão giải thích quy tắc tránh nguy hiểm, thừa nhận người áo xám từng là đạo hữu bị Mê Thất Giả mang đi, rồi đối mặt với nghi ngờ của Vương Lâm và Trần Thiên Quân. Để giữ nhóm tiếp tục đồng hành, lão tiết lộ động phủ Tư Mã Mặc ở ranh giới ngoài trong thế giới bảy màu và dùng nguyên tinh cùng quyền chọn vật để thuyết phục Vương Lâm. Sau đó lão dùng tiên ngọc dụ mãnh thú hóa sương, phối hợp với lão Bàng thu gần hai vạn nguyên tinh.","anchor":"Nhớ đừng tản thần thức ra!","bridge":true,"khoang":"@c1114"},{"mucCt":"ky","text":"Thương Tùng Tử dẫn đoàn người tới vách núi đường cụt nhờ bản đồ và kinh nghiệm từng nhiều lần tiến vào thế giới bảy màu, đồng thời giải thích trên đỉnh núi có bảy hung thú cấp mười hai nên không thể vượt qua bằng đường trên. Sau khi Triệu lão bà mở lộ trận pháp, lão mặc Thần Ma Giáp, dùng tu vi Toái Niết trung kỳ xông vào Cửu Bộ Phong Tiên Trận và cố bước tới bước thứ chín. Lão bị phản lực đánh bật, phun máu, rồi lộ vẻ điên cuồng không cam lòng và đe dọa nếu mình không vào được thì không ai được rời khỏi thế giới này.","anchor":"Ta vào không được thì đừng hòng có người nào ra khỏi thế giới này!","bridge":true,"khoang":"@c1115"},{"chuong":"@c1116","importance":"normal","mucCt":"ky","tieuDe":"Dò thương giữ người","text":"Thương Tùng Tử muốn lợi dụng thân thể đặc dị của Vương Lâm để phá trận, sau khi trận vỡ liền nhân lúc chộp lấy hắn để dùng nguyên lực và thần thức dò xét thương thế. Lão xác nhận Vương Lâm có vẻ trọng thương nhưng không ra tay trước mặt Triệu đạo hữu, rồi dẫn mọi người vào bên trong dãy núi đến khu động phủ cũ. Tại đó lão nhường vật phẩm cho Vương Lâm, lấy lý do an toàn để sắp đặt lão già họ Bàng ở lại bảo hộ hắn, còn mình cùng Triệu đạo hữu tiếp tục đi sâu đoạt bảo vật.","anchor":"Mục đích của Thương Tùng Tử là thử xem tên họ Lữ này có bị trọng thương hay không, nếu có được đáp án chính xác thì tất nhiên sẽ không tính toán cái tên trọng thương không còn lực uy h**p đến kẻ khác này nữa."},{"mucCt":"vua","text":"Thương Tùng Tử xem sự im lặng của Vương Lâm như đồng ý, giao lão Bàng ở lại bảo hộ rồi cùng lão bà áo xanh rời động phủ về phía dãy núi. Qua ký ức lão Bàng, Vương Lâm biết Thương Tùng Tử không dẫn hắn tới động phủ thật của Tư Mã Mặc mà chỉ tìm một nơi khác để đánh lạc hướng.","anchor":"Thương Tùng Tử nói xong thì quét mắt qualão bà áo xanh , hai người mở động phủ","bridge":true,"khoang":"@c1117"},{"mucCt":"ky","text":"Thương Tùng Tử mặc Thần Ma Giáp, đi cùng lão bà áo xanh trong vùng sương mù với thái độ cực kỳ thận trọng. Lão tính rằng Lữ đạo hữu đã chết và Bàng Đức có thể sưu hồn để thu được Dịch Linh Ấn của Thần Tông, rồi cùng lão bà áo xanh gặp pho tượng đá nam tử có dấu ấn tia chớp trên mi tâm. Khi âm thanh và hư ảnh quỷ dị xuất hiện, lão nhận ra Minh Chí Giả và giải thích họ là những kẻ có đạo cảnh nhưng không có Đạo Kinh, còn Đạo Kinh là vật nghe nói do máu huyết thiên địa tạo thành.","anchor":"Thương Tùng Tử mặc Thần Ma giáp trên người, vẻ mặt lão cực kỳ cẩn thận","bridge":true,"khoang":"@c1118"},{"chuong":"@c1119","importance":"normal","mucCt":"ky","tieuDe":"Canh bạc Đạo Kinh","text":"Thương Tùng Tử thừa nhận mục tiêu thật khi tiến vào vùng phong ấn là Đạo Kinh, còn linh hồn mãnh thú chỉ là thứ phụ. Lão dẫn lão bà áo xanh họ Triệu tới ngọn núi bị Tuế Nguyệt Cấm bao bọc, liên tiếp lấy Phá Cấm Trùy, khối gỗ đen, tinh thạch và ngọc bội Thứ Không Niết Bảo để đổi lấy cơ hội phá cấm. Khi lỗ hổng mười trượng mở ra, lão lập tức xông vào bên trong vùng phong ấn.","anchor":"Thứ lão phu thật sự nghĩ tới chính là Đạo Kinh"},{"mucCt":"ky","text":"Thương Tùng Tử dẫn Triệu đạo hữu tới ngọn núi trong khe nứt Tuế Nguyệt Cấm, dùng con lắc tia chớp mở cửa động phủ phong ấn thú hồn rồi lừa nàng vào trong và khép cửa đá nhốt lại. Lão lên đỉnh núi mở cầu vồng bảy màu vào không gian tấm bia, bỏ qua Đạo Kinh trên hài cốt vì biết nguy cơ trở thành Minh Chí Giả, rồi tập trung đoạt bình ngọc dưới trận pháp. Khi bình ngọc hút bạch khí, lão hy sinh hơn một ngàn nguyên thần bị phong ấn và dùng bốn tiểu kiếm kim quang phá trận để nhấc bình ngọc lên, sau đó bị người phụ nữ trung niên áo xanh và bà lão áo xanh họ Triệu hiện thân ngăn cản, khiến lão nhận ra Dương Tụ Âm Quy.","anchor":"Thương Tùng Tử biết rất rõ văn tự trên hài cốt chính là Đạo Kinh, nhưng lão cũng không muốn xem nó","bridge":true,"khoang":"@c1120"},{"chuong":"@c1121","importance":"normal","mucCt":"ky","tieuDe":"Mất tay mất bình","text":"Thương Tùng Tử giữ bình ngọc trong tay, lần lượt dùng vạn phi kiếm, nguyên anh hình người kỳ dị, bảy thanh trường kiếm và hạt châu Nghịch Hành Giả để đối đầu phe áo xanh. Khi bị lão phụ nhân áo xanh phục kích, tay trái của lão trúng kịch độc, sau đó bị dư chấn xé rời khiến bình ngọc văng ra và rơi vào tay Vương Lâm. Lão tiếp tục truy đuổi, đạp trúng cấm chế Vương Lâm bố trí, rồi lại ném hạt châu dẫn ánh sáng bảy màu hóa thành Thiên Vận Nhất Chỉ.","anchor":"Cánh tay trái của lão đã hoàn toàn nhiễm vào chất kịch độc, máu đã hóa thành nước vàng, ngay cả xương cốt cũng đã bị hòa tan."},{"mucCt":"ky","text":"Thương Tùng Tử cùng lão phụ nhân áo xanh truy kích Vương Lâm vì bình ngọc, chứng kiến thân Cổ Thần và Tam Xoa Kích nên chấn động nhưng vẫn không chịu bỏ cuộc do đã chuẩn bị ngàn năm. Lão tái ngưng tụ tay trái bằng sáng bảy màu, thận trọng không bước hẳn vào trận pháp, rồi quyết định nhân lúc lão phụ nhân bị vây để giết họ Lữ đoạt bình ngọc. Trong giao chiến, lão dùng vạn kim quang phi kiếm nhưng bị Tam Xoa Kích đánh bật, sau đó lấy ra kiếm trong suốt mang khí tức Thứ Không Niết Bảo để tấn công trực diện.","anchor":"Tâm thần Thương Tùng Tử chấn động, một lúc lâu sau vẫn không thể yên ổn trở lại","bridge":true,"khoang":"@c1122"},{"mucCt":"ky","text":"Thương Tùng Tử dùng Tinh Kiếm, kiếm khí, ba hạt châu triệu hồi Nghịch Hành Giả, nguyên anh huyết sắc, Huyết Nguyên Hóa Anh và cây đinh bảy màu để nhanh chóng vây giết Vương Lâm. Lão đánh Vương Lâm trọng thương bằng tia chớp và đinh bảy màu, nhưng cũng bị mũi Thiết Kiếm gãy xuyên ngực. Sau khi lưỡng bại câu thương, lão phun máu trọng thương và bỏ chạy về phía dãy núi.","anchor":"Một khi đã ra tay thì nhất định giết người, Thương Tùng Tử không tiế tiêu hao ba hạt châu","bridge":true,"khoang":"@c1123"},{"mucCt":"ky","text":"Ngồi chữa thương trên ký hiệu tia chớp nơi mi tâm bức tượng đá khổng lồ trong sương mù. Hồi tưởng tổn thất trận chiến: mất ba hạt châu, Thủy Tinh Kiếm, và đặc biệt chiếc đinh bảy màu — pháp bảo mạnh nhất, đòn sát thủ bảo mệnh — dùng ra mà không giết được đối phương, bản thân suýt chết. Tin La Bàn sẽ giết nốt Vương Lâm nhưng khi cảm ứng La Bàn bị cắt đứt, chấn động, lần đầu chính thức sinh ra sợ hãi với Vương Lâm. Tiết lộ vị trí trung tâm thật sự của thế giới bảy màu không phải nơi lão đang ở mà là một sơn cốc sâu hơn bao phủ sương mù.","anchor":"Lần đầu tiên trong lòng Thương Tùng Tử chính thức sinh ra cảm giác sợ hãi đối với Vương Lâm","bridge":true,"khoang":"@c1124"},{"chuong":"@c1125","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc lại: bị trọng thương, chỉ nguyên thần chạy thoát, bình ngọc chứa chất lỏng đen là mục tiêu cuối cùng của hắn khi vào thế giới bảy màu.","anchor":"phá vỡ thân thể trước khi Dịch Linh Ấn đánh xuống"},{"importance":"bridge","mucCt":"vua","chuong":"@c1126","tieuDe":"Bị tế luyện pháp bảo","text":"Nguyên anh huyết sắc hình người của Thương Tùng Tử bị Vương Lâm phun nguyên khí bao bọc, đặt vào nguyên thần tế luyện xóa ký hiệu. Vương Lâm đánh giá trận chiến tiếp theo thực chất là so tài đoạt bảo vật và đề thăng tu vi.","anchor":"Trận chiến sau này thực tế chỉ so sánh xem kẻ nào có thể đoạt được nhiều pháp bảo và đan dược hơn"},{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1127","chuong":"@c1127","text":"Được nhắc: Vương Lâm nhận ra hạt châu trong động phủ chính là loại Thương Tùng Tử dùng triệu hoán thần thông Nghịch Hành Giả.","anchor":"hắn lập tức nhận ra vật này đúng là những hạt châu mà Thương Tùng Tử lấy ra để triệu hoán thần thông của Nghịch Hành Giả"},{"chuong":"@c1128","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm nghi vấn thân phận vì thần thông cuối lão triệu hồi trận pháp thứ bảy Phong giới giống hệt hai người Ngoại giới năm xưa.","anchor":"thần thông cuối cùng lão già kia thi triển là triệu hồi ra trận pháp thứ bảy của Phong giới"},{"chuong":"@c1129","importance":"major","mucCt":"ky","tieuDe":"Tái tạo thân thể và bị đạo niệm chặn","text":"Nguyên thần trên tượng đá hấp thu sáng bảy màu và tia chớp, tái tạo thân thể hoàn chỉnh với da phát sáng bảy màu, mi tâm hiện ký hiệu tia chớp. Tuyên bố đã tiến lên một bước và thề báo thù. Dùng hạt châu từ không gian trữ vật, phun máu tươi lên triệu hồi Nghịch Hành Giả, biết được Vương Lâm ở động phủ Tư Mã Đặc. Phóng tới nhưng đến cách sơn cốc ngàn trượng đã hai ngày, bị vòng xoáy đạo niệm thật-giả của Vương Lâm chặn, phải khoanh chân bó tâm thần chống đỡ, không thể tiến lên.","anchor":"Lão đã đến đây được hai ngày nhưng không thể tiến lên phía trước"},{"mucCt":"vua","text":"Thương Tùng Tử vùng vẫy trong đau khổ, cố bảo vệ tâm thần trước cơn lốc đạo niệm của Vương Lâm bao phủ thế giới bảy màu. Khi tâm thần Vương Lâm quét qua, đạo tâm ầm ầm suy sụp, vẻ mặt tái nhợt, mắt lộ vẻ mờ mịt.","anchor":"dù là Thương Tùng Tử thì đạo tâm cũng ầm ầm suy sụp, vẻ mặt tái nhợt","bridge":true,"khoang":"@c1130"},{"mucCt":"ky","text":"Tiến vào vùng đạo niệm bên ngoài sơn cốc thì đạo tâm bị khuấy động, suýt tan vỡ tâm thần, tái mặt phóng đi. Phẫn nộ thừa nhận thất bại, oán hận cả Vương Lâm và lão bà họ Triệu đã tạo cơ hội cho Vương Lâm. Quyết định rời đi bằng con đường riêng chỉ mình biết, dự định phong kín hoàn toàn nơi này và phá hủy vết nứt bảy màu bên ngoài để mọi người bị vây khốn vĩnh viễn. Tiết lộ Bàng Đức Tài không hề biết phương pháp chính thức rời đi, chỉ biết những gì Thương Tùng Tử cố ý cho biết. Đang bỏ chạy thì bị Vương Lâm dùng Đổi vị truy kịp, bị tấn công.","anchor":"Khi lão phu rời khỏi sẽ phong kín hoàn toàn chỗ này, phá hủy vết nứt bảy màu bên ngoài để từ nay về sau các ngươi phải nằm lại nơi đây","bridge":true,"khoang":"@c1131"},{"chuong":"@c1132","importance":"normal","mucCt":"ky","tieuDe":"Bại vong dưới tay Vương Lâm","text":"Dùng nguyên anh huyết sắc và dấu hiệu tia chớp trên mi tâm phản kích Vương Lâm, nhưng sấm sét bị đối phương hấp thu toàn bộ. Bị cây đinh bảy màu xuyên thủng huyết quang phòng ngự ghim vào ngực, thân xác nổ thành sương máu, nguyên thần bị ghim đinh. Bị Vương Lâm sưu hồn trích ký ức, không gian trữ vật bị đoạt sạch. Phát cuồng, thân thể héo rũ tiêu tán hóa thành hạt huyết châu bay lên trời. Ngọc giản mang tên lão trong cung điện Thái Cổ tinh vực nổ vỡ, sau đó tái ngưng tụ đổi tên thành Vương Lâm — xác nhận chết.","anchor":"ngửa mặt lên trời rống giận, lúc này thân thể đột nhiên chấn động"},{"chuong":"@c1133","importance":"bridge","mucCt":"vua","text":"Được nhắc qua ký ức bị Vương Lâm đoạt: lão dự định mang đạo tủy đến ngọn núi sâu nhất thế giới bảy màu làm nơi ngủ say an toàn, nhưng không dám uống khi giao chiến với lão bà áo xanh.","anchor":"Những gì Thương Tùng Tử tính toán chính là cầm đạo tủy này tìm một địa phương tuyệt đối an toàn"},{"mucCt":"gon","text":"Qua ký ức được Vương Lâm đọc, tiết lộ công pháp tu luyện là thuật Bách Thế Huyết Nguyên Hóa Anh, triệu hồi Đệ Thất Linh của Phong giới, cảm ngộ từ tượng đá khổng lồ, tạo chín nguyên anh mỗi cái tự ngưng tụ thần thông. Trước trận với Vương Lâm đã bị lão bà áo xanh lấy mất một nguyên anh.","anchor":"công pháp tu luyện của lão chính là thuật Bách Thế Huyết Nguyên Hóa Anh, triệu hồi ra Đệ Thất Linh của Phong giới","bridge":true,"khoang":"@c1134"},{"chuong":"@c1135","importance":"bridge","mucCt":"vua","text":"Được nhắc lại: Thương Tùng Tử đã chọn con đường quy thuận, coi tượng đá là thần linh, dùng một vật huyết anh lưu lại cảm ngộ ký hiệu tia chớp trên mi tâm tượng đá với lực cảm ngộ gấp chín lần, nhận một bộ phận truyền thừa và có thể triệu hồi Đệ Thất Linh của Phong giới.","anchor":"Thương Tùng Tử đã dùng những lực lượng này hóa thành thần thông của chính mình, thậm chí còn có thể triệu hồi ra Đệ Thất Linh của Phong giới"}],"tuViMoc":[{"chuong":"@c1102","canhGioi":"Toái Niết trung kỳ","text":"Thương Tùng Tử được giới thiệu là tu sĩ Toái Niết trung kỳ trong buổi tụ họp tư nhân.","importance":"major"}],"nhanMach":[{"ten":"Âu Dương Long","tag":"su-mon","quanHe":"sư điệt","ghiChu":"Âu Dương Long gọi ông là sư thúc và phục vụ bên cạnh trong buổi tụ họp."},{"ten":"Vương Lâm","tag":"khac","quanHe":"khách tham dự","ghiChu":"Ông cho Vương Lâm tham dự tụ họp và tặng bộ tàn giáp cho hắn."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ bị tính kế","ghiChu":"Thương Tùng Tử muốn mượn tay Ngô Thanh giết Vương Lâm rồi đoạt nguyên tinh nhưng bị uy lực của Vương Lâm làm kinh hãi.","gap":"@c1104"},{"ten":"Ngô Thanh","tag":"khac","quanHe":"Quân cờ được mời đến","ghiChu":"Thương Tùng Tử cố ý mời Ngô Thanh tới Bồng Lai vì biết mâu thuẫn giữa Ngô Thanh và Vương Lâm.","gap":"@c1104"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Mời hợp tác đi vào nơi bí ẩn, vừa lợi dụng sức chiến đấu vừa nghi ngờ thân phận.","ghiChu":"Đạt thỏa thuận thù lao hai vạn nguyên tinh @c1105"},{"ten":"Thanh niên áo vàng","tag":"doi-thu","quanHe":"Đối đầu trong đấu giá bộ giáp và công khai uy hiếp đường về.","ghiChu":"Đối phương thuộc Bí Lạc Tông @c1108"},{"ten":"Bà lão áo xanh","tag":"dong-minh","quanHe":"Cùng tham gia nhóm, được Thương Tùng Tử hứa cho chọn trước ba vật sau khi thành công.","ghiChu":"Triệu đạo hữu @c1108"},{"ten":"Vân Hồn Tử","tag":"dong-minh","quanHe":"Một thành viên được chờ tới trong nhóm bí mật.","ghiChu":"Đến muộn vì gặp kẻ thù @c1108"},{"ten":"Đoan Mộc đồng tử","tag":"dong-minh","quanHe":"Mời tới theo bản đồ tinh cầu để tham gia chuyến đi.","ghiChu":"Đoan Mộc phàn nàn bản đồ khó tìm đường @c1109"},{"ten":"Trần Thiên Quân","tag":"dong-minh","quanHe":"Mời tham gia chuyến đi, thừa nhận thuật ẩn dấu của đối phương cao minh.","ghiChu":"Gặp tại Man Hoang đại lục @c1109"},{"ten":"Giao Long hóa sương cấp mười hai","tag":"doi-thu","quanHe":"Đối thủ canh giữ khu Hồi đan.","ghiChu":"Thương Tùng Tử dùng mấy vạn phi kiếm vây công nó."},{"ten":"Người áo xám","tag":"khac","quanHe":"biết lai lịch","ghiChu":"Thương Tùng Tử nói người áo xám từng là đạo hữu bị Mê Thất Giả mang đi trong lần đầu tới đây."},{"ten":"Minh Chí Giả","tag":"khac","quanHe":"Nhận ra và giải thích bản chất của Minh Chí Giả.","ghiChu":"Lời giải thích của lão mở ra tuyến Đạo Kinh trong vùng sương mù."},{"ten":"Bàng Đức","tag":"dong-minh","quanHe":"Trông đợi Bàng Đức sưu hồn Lữ đạo hữu để thu được Dịch Linh Ấn.","ghiChu":"Sự tính toán cho thấy hai người có chung lợi ích trong chuyến vào thế giới bảy màu."},{"ten":"Bà lão áo xanh","tag":"doi-thu","quanHe":"Bị lão lừa vào động phủ thú hồn và nhốt sau cửa đá.","ghiChu":"Quan hệ đối địch bộc lộ rõ khi tranh đoạt trong khu vực tấm bia."},{"ten":"Người phụ nữ trung niên áo xanh họ Triệu","tag":"doi-thu","quanHe":"Nàng hiện thân ngăn bốn tiểu kiếm khi lão đoạt bình ngọc.","ghiChu":"Dung mạo giống bà lão áo xanh họ Triệu, liên quan Dương Tụ Âm Quy."},{"ten":"Lão phụ nhân áo xanh","tag":"doi-thu","quanHe":"Bị phục kích và giao chiến","ghiChu":"Lão phụ nhân dùng độc, phong ấn nguyên anh hình người và đối kháng Nghịch Hành Giả của Thương Tùng Tử."},{"ten":"Lão bà áo xanh","tag":"doi-thu","quanHe":"Giao chiến trong tấm màn cấm chế","ghiChu":"Lão bà áo xanh dùng lực hút đoạt sinh cơ, buộc Thương Tùng Tử phản công bằng vạn phi kiếm và nguyên anh hình người."}],"tuiDo":{"phapBao":[{"ten":"Huyết Tinh Kiếm","loai":"phi kiếm","trangThai":"doi-ten","moTa":"Được Thương Tùng Tử lấy ra giao dịch và bán cho thiếu phụ áo hoa.","nguon":"@c1102"},{"ten":"Bộ tàn giáp","loai":"giáp / vật liệu","trangThai":"da-dung","moTa":"Được Thương Tùng Tử đưa ra để mọi người nhận định lai lịch, sau đó tặng cho Vương Lâm.","nguon":"@c1102"}],"danDuoc":[{"ten":"Hỗn Nguyên Đan","loai":"đan dược","trangThai":"da-dung","moTa":"Được Thương Tùng Tử bán cho thanh niên văn sĩ với giá năm vạn tiên ngọc.","nguon":"@c1102"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1102","@c1103","@c1104","@c1105","@c1108","@c1109","@c1110","@c1111","@c1112","@c1113","@c1114","@c1115","@c1116","@c1117","@c1118","@c1119","@c1120","@c1121","@c1122","@c1123","@c1124","@c1125","@c1126","@c1127","@c1128","@c1129","@c1130","@c1131","@c1132","@c1133","@c1134","@c1135"]},{"id":"thanh-nien-van-si-cam-quat-long","name":"Thanh niên văn sĩ cầm quạt lông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Toái Niết sơ kỳ @c1102","trangThai":"song","blurb":"Thanh niên văn sĩ cầm quạt lông là một tu sĩ Toái Niết sơ kỳ tham dự buổi tụ họp của Thương Tùng Tử. Hắn nhận ra giá trị của Hỗn Nguyên Đan và mua viên đan này với giá cao.","vaiTro":"Khách đấu giá Toái Niết","tinhCach":[{"text":"Quan sát nhanh và hứng thú trước người mới"},{"text":"Quyết đoán khi mua vật phẩm quý"}],"tabs":{"diem":[{"text":"Là một trong các tu sĩ Toái Niết sơ kỳ có mặt trong phòng đấu giá tư nhân.","chuong":"@c1102"},{"text":"Mua Hỗn Nguyên Đan sau khi nhận ra lai lịch đan dược.","chuong":"@c1102"}],"kinhLich":[{"mucCt":"gon","text":"Thanh niên văn sĩ cầm quạt lông tham dự buổi tụ họp của Thương Tùng Tử và mua Hỗn Nguyên Đan với giá năm vạn tiên ngọc.","anchor":"Hắn không nói nhiều mà trực tiếp đặt viên thuốc vào trong ngực của mình rồi hướng về Thương Tùng Tử khẽ gật đầu","bridge":true,"khoang":"@c1102"}],"tuViMoc":[{"chuong":"@c1102","canhGioi":"Toái Niết sơ kỳ","text":"Thanh niên văn sĩ được giới thiệu là tu sĩ Toái Niết sơ kỳ trong phòng đấu giá tư nhân.","importance":"major"}],"nhanMach":[{"ten":"Thương Tùng Tử","tag":"khac","quanHe":"người bán vật phẩm","ghiChu":"Hắn mua Hỗn Nguyên Đan từ Thương Tùng Tử."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Hỗn Nguyên Đan","loai":"đan dược","trangThai":"dang-co","moTa":"Viên đan dược đen được mua từ Thương Tùng Tử với giá năm vạn tiên ngọc.","nguon":"@c1102"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1102"]},{"id":"thieu-phu-ao-hoa","name":"Thiếu phụ áo hoa","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Toái Niết sơ kỳ @c1102","trangThai":"song","blurb":"Thiếu phụ áo hoa là nữ tu Toái Niết sơ kỳ tham dự buổi đấu giá tư nhân của Thương Tùng Tử. Nàng chú ý Huyết Tinh Kiếm, xem xét rồi mua vật này bằng truyền âm.","vaiTro":"Khách đấu giá Toái Niết","tinhCach":[{"text":"Dáng vẻ quyến rũ, uể oải"},{"text":"Hành động kín đáo khi giao dịch"}],"tabs":{"diem":[{"text":"Là một trong các tu sĩ Toái Niết sơ kỳ dự buổi tụ họp.","chuong":"@c1102"},{"text":"Triệu Huyết Tinh Kiếm xuống tay để xem xét và mua bằng truyền âm.","chuong":"@c1102"}],"kinhLich":[{"mucCt":"gon","text":"Thiếu phụ áo hoa xem xét Huyết Tinh Kiếm do Thương Tùng Tử đưa ra và mua thanh kiếm này bằng cách truyền âm.","anchor":"Thiếu phụ xinh đẹp mặc áo hoa vung tay phải lên, Huyết Tinh Kiếm lập tức bay thấp xuống tay","bridge":true,"khoang":"@c1102"}],"tuViMoc":[{"chuong":"@c1102","canhGioi":"Toái Niết sơ kỳ","text":"Thiếu phụ áo hoa được giới thiệu là tu sĩ Toái Niết sơ kỳ trong phòng đấu giá tư nhân.","importance":"major"}],"nhanMach":[{"ten":"Thương Tùng Tử","tag":"khac","quanHe":"người bán vật phẩm","ghiChu":"Nàng mua Huyết Tinh Kiếm từ Thương Tùng Tử."}],"tuiDo":{"phapBao":[{"ten":"Huyết Tinh Kiếm","loai":"phi kiếm","trangThai":"dang-co","moTa":"Thanh kiếm trong suốt có tơ máu, được nàng mua trong buổi tụ họp.","nguon":"@c1102"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1102"]},{"id":"lao-gia-mat-lo-nho-deo-nhan","name":"Lão già mặt lỗ nhỏ đeo nhẫn","cn":"","aliases":["Lão già mặt lỗ nhỏ"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Toái Niết sơ kỳ @c1102","trangThai":"song","blurb":"Lão già mặt lỗ nhỏ đeo nhẫn là một tu sĩ Toái Niết sơ kỳ có mặt trong phòng đấu giá tư nhân. Ông có tướng mạo kỳ dị, ánh mắt âm trầm và liên tục xoay nhẫn trên ngón trỏ.","vaiTro":"Khách đấu giá Toái Niết","tinhCach":[{"text":"Trầm mặc trong buổi tụ họp"},{"text":"Khí chất âm trầm"}],"tabs":{"diem":[{"text":"Là một trong các tu sĩ Toái Niết sơ kỳ dự buổi tụ họp.","chuong":"@c1102"},{"text":"Có tướng mạo mặt đầy lỗ nhỏ và thường xoay chiếc nhẫn trên tay.","chuong":"@c1102"}],"kinhLich":[],"tuViMoc":[{"chuong":"@c1102","canhGioi":"Toái Niết sơ kỳ","text":"Lão già mặt lỗ nhỏ đeo nhẫn được giới thiệu là tu sĩ Toái Niết sơ kỳ trong phòng đấu giá tư nhân.","importance":"major"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1102"]},{"id":"lao-gia-ao-den-tay-vuot-ung","name":"Lão già áo đen tay vuốt ưng","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Toái Niết sơ kỳ @c1102","trangThai":"song","blurb":"Lão già áo đen tay vuốt ưng là tu sĩ Toái Niết sơ kỳ tham dự buổi tụ họp của Thương Tùng Tử. Ông mang hai hạt châu, sau đó lấy ra lông Chu Tước và linh hồn hung thú cấp mười hai nửa hóa sương để giao dịch.","vaiTro":"Khách bán vật phẩm quý","tinhCach":[{"text":"Lạnh lùng, lời nói sắc bén"},{"text":"Nắm giữ vật phẩm hung hiểm hiếm thấy"}],"tabs":{"diem":[{"text":"Là tu sĩ Toái Niết sơ kỳ, tướng mạo khô gầy và tay trái như vuốt ưng.","chuong":"@c1102"},{"text":"Mang lông Chu Tước và linh hồn hung thú cấp mười hai nửa hóa sương ra giao dịch.","chuong":"@c1102"}],"kinhLich":[{"mucCt":"vua","text":"Lão già áo đen tay vuốt ưng tham dự buổi tụ họp của Thương Tùng Tử và nhận xét Hỗn Nguyên Đan chỉ một viên thì uy lực không đủ. Sau đó ông lấy ra lông Chu Tước cùng linh hồn hung thú cấp mười hai nửa hóa sương để giao dịch, đồng thời đáp lại lời tiếc rẻ của Ngô Thanh rằng nếu là mãnh thú hoàn toàn hóa sương thì ông đã không mang ra bán.","anchor":"Nếu thật sự là mãnh thú hóa sương, lão phu sao có thể lấy ra giao dịch","bridge":true,"khoang":"@c1102"}],"tuViMoc":[{"chuong":"@c1102","canhGioi":"Toái Niết sơ kỳ","text":"Lão già áo đen tay vuốt ưng được giới thiệu là tu sĩ Toái Niết sơ kỳ trong phòng đấu giá tư nhân.","importance":"major"}],"nhanMach":[{"ten":"Ngô Thanh","tag":"khac","quanHe":"người đối đáp trong giao dịch","ghiChu":"Ông phản bác lời tiếc rẻ của Ngô Thanh về linh hồn hung thú nửa hóa sương."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[{"ten":"Linh hồn hung thú cấp 12 nửa hóa sương","loai":"thú hồn","trangThai":"dang-co","moTa":"Linh hồn hung thú bị nhốt trong bọt khí, nửa trên hình rồng và nửa dưới hóa sương, được ông mang ra giao dịch.","nguon":"@c1102"}],"nguyenLieu":[{"ten":"Lông Chu Tước","loai":"linh vật","trangThai":"dang-co","moTa":"Sợi lông chim đỏ có ngọn lửa nồng đậm, được ông mang ra giao dịch.","nguon":"@c1102"}],"linhThao":[],"khac":[]}},"nguon":["@c1102"]},{"id":"ba-lao-toc-trang-ao-xanh","name":"Bà lão tóc trắng áo xanh","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Toái Niết sơ kỳ @c1102","trangThai":"song","blurb":"Bà lão tóc trắng áo xanh là một tu sĩ Toái Niết sơ kỳ dự buổi tụ họp tư nhân của Thương Tùng Tử. Bà ngồi yên, dáng vẻ lạnh lùng khi quan sát Vương Lâm bước vào.","vaiTro":"Khách đấu giá Toái Niết","tinhCach":[{"text":"Lạnh lùng"},{"text":"Trầm mặc quan sát"}],"tabs":{"diem":[{"text":"Là một trong các tu sĩ Toái Niết sơ kỳ trong phòng đấu giá tư nhân.","chuong":"@c1102"},{"text":"Ngồi yên không nhúc nhích và lạnh lùng nhìn người mới bước vào.","chuong":"@c1102"}],"kinhLich":[],"tuViMoc":[{"chuong":"@c1102","canhGioi":"Toái Niết sơ kỳ","text":"Bà lão tóc trắng áo xanh được giới thiệu là tu sĩ Toái Niết sơ kỳ trong phòng đấu giá tư nhân.","importance":"major"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1102"]},{"id":"ba-lao-ao-xanh","name":"Bà lão áo xanh","cn":"","aliases":["Bà lão từng giao dịch bản đồ tinh cầu","Triệu đạo hữu","lão bà áo xanh","Bà lão áo xanh","Triệu lão bà áo xanh","Cô gái áo xanh"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ @c1121","trangThai":"song","blurb":"Bà lão áo xanh họ Triệu là tu sĩ bí ẩn từng giao dịch bản đồ tinh cầu với Vương Lâm, âm thầm tặng hắn bản đồ thật và cảnh báo về Ngô Thanh. Về sau bà gia nhập nhóm Thương Tùng Tử tiến vào thế giới bảy màu, thể hiện sự tinh thông cấm chế và trận pháp qua nhiều lần ra tay. Bà được xác nhận là người bố trí Mai Hoa Thập Bát Cấm và cuối cùng ra tay trước Thương Tùng Tử, song bị cấm chế bao phủ khi Vương Lâm rút khỏi chiến trường.","vaiTro":"Tu sĩ bí ẩn họ Triệu — người âm thầm giúp và cảnh báo Vương Lâm","tinhCach":"Trầm ổn, ít động tâm trước bảo vật; tinh thông cấm chế và trận pháp; kín kẽ, hành sự có toan tính riêng","tabs":{"diem":[{"text":"Đổi bản đồ tinh cầu cấp sáu và mười vạn tiên ngọc lấy thú hồn, âm thầm tặng Vương Lâm bản đồ thật","chuong":"@c1103"},{"text":"Gia nhập nhóm Thương Tùng Tử tại Man Hoang đại lục, được hứa chọn trước ba vật","chuong":"@c1108"},{"text":"Thi triển huyền băng bao phủ thân thể Giao Long,ạm thời khống chế mãnh thú","chuong":"@c1113"},{"text":"Thể hiện sự tinh thông cấm chế, luôn tránh nơi có cấm chế khi thử phá kỳ trận","chuong":"@c1115"},{"text":"Được xác nhận là người bố trí Mai Hoa Thập Bát Cấm và giấu tầng trận hút sinh cơ","chuong":"@c1118"},{"text":"Ra tay trước Thương Tùng Tử, bấm quyết tạo lực hút kéo sinh cơ đối phương","chuong":"@c1121"}],"kinhLich":[{"chuong":"@c1103","importance":"normal","mucCt":"vua","tieuDe":"Tặng bản đồ thật","text":"Bà lão áo xanh dùng ngọc giản, bản đồ tinh cầu cấp sáu và mười vạn tiên ngọc mua từ Vương Lâm để đổi lấy thú hồn cấp mười hai. Sau buổi tụ hội, bà chủ động gặp Vương Lâm, nói bản đồ trước đó là giả, tặng bản thật và cảnh báo hắn chú ý Ngô Thanh rồi biến mất.","anchor":"Bản đồ tinh cầu trước đó chỉ là giả, đây mới là đồ thật"},{"mucCt":"gon","text":"Bà lão áo xanh tham gia nhóm Thương Tùng Tử tại Man Hoang đại lục và được hứa cho chọn trước ba vật sau khi chuyện thành công.","anchor":"Lão thân sẽ cố hết sức","bridge":true,"khoang":"@c1108"},{"chuong":"@c1111","importance":"bridge","mucCt":"gon","text":"Bà lão áo xanh cùng đội tiến vào thế giới bảy màu, khẽ nhíu mày suy nghĩ và chỉ liếc Vương Lâm khi chuyện Vân Hồn Tử mất tích bị nhắc tới.","anchor":"Chỉ có lão bà áo xanh khẽ nhăn lông mày, không biết đang suy nghĩ điều gì."},{"mucCt":"vua","text":"Bà lão áo xanh thoáng bị mùi Hồi đan làm mê man rồi nhanh chóng khôi phục. Trong trận vây công Giao Long hóa sương, bà bấm pháp quyết gọi gió lạnh và tuyết rơi bao phủ con đường hẹp để đánh vào thân con thú.","anchor":"Bà lão áo xanh cũng bấm pháp quyết, một luồng gió lạnh đột nhiên nổi lên","bridge":true,"khoang":"@c1112"},{"mucCt":"vua","anchor":"từng luồng hắc khí tử trên thi thể Giao Long dung nhập vào trong tay phải","text":"Lão bà áo xanh thi triển huyền băng bao phủ thân thể Giao Long, tạm thời làm mãnh thú ngừng giãy dụa và hấp thu hắc khí, sinh cơ của nó. Sau trận, bà đặt tay lên thi thể tiếp tục hút hắc khí và máu huyết, khiến xác Giao Long chỉ còn da bọc xương và bản thân mơ hồ khôi phục hơi thở thanh xuân.","bridge":true,"khoang":"@c1113"},{"mucCt":"vua","text":"Bà chứng kiến Đoan Mộc bị Mê Thất Giả mang đi rồi truy hỏi Thương Tùng Tử về bản chất nguy hiểm của nơi này. Sau khi nghe lời giải thích về động phủ Tư Mã Mặc và tỷ lệ thành công sáu phần nếu có mình cùng Vương Lâm tương trợ, bà cân nhắc rồi đồng ý tiếp tục.","anchor":"Lão bà áo xanh nhắm mắt suy nghĩ một lát rồi khẽ gật đầu","bridge":true,"khoang":"@c1114"},{"chuong":"@c1115","importance":"normal","mucCt":"ky","tieuDe":"Thử phá kỳ trận","text":"Bà lão áo xanh họ Triệu thể hiện sự tinh thông cấm chế khi trên đường luôn đặt chân vào nơi không có cấm chế hoặc cấm chế yếu. Trước vách núi, bà dùng thủ ấn cấm chế làm hiện cửa thạch động rồi tự mình tiến vào thử Cửu Bộ Phong Tiên Trận. Bà phóng bảy luồng hắc khí chứa sinh cơ, thân thể tạm cải lão hoàn đồng, nhưng đến bước thứ sáu thì phun máu bị đánh bật ra ngoài và xác nhận muốn phá trận phải tiến đủ mười bước.","anchor":"Với tu vi của ta chỉ có thể tiến được năm bước, nếu giẫm xuống một bước nữa thì sẽ không thể gắng gượng nổi"},{"mucCt":"vua","text":"Bà lão áo xanh theo lời Vương Lâm mở cấm chế trên núi đá để hắn tiến vào Cửu Bộ Phong Tiên Trận. Sau khi không nhìn ra màn giả thương của hắn, bà cùng Thương Tùng Tử nhường vật phẩm trong động phủ cũ cho Vương Lâm rồi tiếp tục đi sâu vào khu vực bên trong dãy núi.","anchor":"Lão bà áo xanh vung tay phải về phía trước, cấm chế lập tức rồi lên núi đá làm núi đá trở nên trong suốt, lại xuất hiện những con sóng gợn.","bridge":true,"khoang":"@c1116"},{"chuong":"@c1117","importance":"bridge","mucCt":"gon","tieuDe":"Rời động phủ","text":"Lão bà áo xanh cùng Thương Tùng Tử rời động phủ, khiến lão Bàng chờ họ đi xa rồi mới ra tay với Vương Lâm.","anchor":"Nhưng trước khi đi, lão bà áo xanh quét ánh mắt lên người Vương Lâm"},{"chuong":"@c1118","importance":"normal","mucCt":"ky","tieuDe":"Để lại cấm trận","text":"Lão bà áo xanh được xác nhận là người đã bố trí Mai Hoa Thập Bát Cấm tại sơn cốc và giấu tầng trận hút sinh cơ chưa hoàn thành trong đó. Sau đó bà đi cùng Thương Tùng Tử trong vùng sương mù, gặp pho tượng đá nam tử có dấu ấn tia chớp trên mi tâm khiến sắc mặt biến đổi. Khi âm thanh Minh Chí Giả vang lên và hư ảnh xuyên qua, nguyên thần của bà bị chấn động nên hỏi Thương Tùng Tử về Minh Chí Giả và Đạo Kinh.","anchor":"Lão bà áo xanh cũng hít vào một hơi thật sâu, những âm thanh quỷ dị chuyển thẳng vào trong tâm thần"},{"mucCt":"ky","text":"Bà lão áo xanh họ Triệu đi cùng Thương Tùng Tử vào sâu trong sương mù và nhận ra màn đen quanh ngọn núi là phong ấn trong Tuế Nguyệt Cấm. Bà dùng thuật cấm chế, hắc khí, máu tươi và pháp quyết để điều khiển Phá Cấm Trùy cùng các bảo vật tự hủy đánh vào cấm chế. Trong quá trình thi triển, hình dạng của bà biến đổi từ lão bà thành phụ nữ trung niên rồi cô gái hơn hai mươi tuổi, sau đó theo Thương Tùng Tử tiến vào lỗ hổng.","anchor":"Đây là một phong ấn cấm chế trong Tuế Nguyệt Cấm","bridge":true,"khoang":"@c1119"},{"mucCt":"ky","text":"Bà lão áo xanh trong thân phận Triệu đạo hữu đi cùng Thương Tùng Tử tới ngọn núi trong khe nứt, nghi ngờ lời lão nhưng vẫn vào động phủ thú hồn sau khi bố trí cấm chế bên ngoài. Sau khi bị cửa đá khép lại, nàng thoát tới không gian tấm bia dưới hình dạng người phụ nữ trung niên áo xanh, dùng cấm chế tạo vòng xoáy ngăn bốn tiểu kiếm của Thương Tùng Tử nhưng bị kim quang hóa lỏng xuyên qua phòng hộ. Cuối chương, hình bóng bà lão áo xanh lại hiện ra trước mặt Thương Tùng Tử, khiến lão nhận ra cấm thuật Dương Tụ Âm Quy.","anchor":"Sau khi suy nghĩ một lúc thì cô gái áo xanh lập tức đi vào cánh cửa động phủ","bridge":true,"khoang":"@c1120"},{"mucCt":"ky","text":"Lão bà áo xanh ra tay trước Thương Tùng Tử, bấm quyết tạo lực hút khiến đối phương có cảm giác sinh cơ bị kéo đi. Bà bị vạn phi kiếm và nguyên anh hình người kỳ dị của Thương Tùng Tử tấn công, sau đó nguyên thần của bà cùng hai người khác dung hợp với nguyên thần lão phụ nhân bên ngoài để tăng thế công.","anchor":"Hai tay bà lão bấm niệm pháp quyết rồi khẽ hút vào, một lực hút kh*ng b* đột nhiên điên cuồng bùng ra.","bridge":true,"khoang":"@c1121"},{"chuong":"@c1123","importance":"bridge","mucCt":"gon","text":"Cuối trận, lão bà áo xanh vẫn bị cấm chế bao phủ và bị Vương Lâm bỏ qua khi hắn rút khỏi chiến trường.","anchor":"cũng không thèm nhìn qua lão bà áo xanh đang bị cấm chế bao phủ"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Từng giao dịch và sau đó tặng bản đồ thật, cảnh báo nguy hiểm","ghiChu":"Gặp trong và sau buổi tụ hội @c1103"},{"ten":"Ngô Thanh","tag":"khac","quanHe":"Người bà cảnh báo Vương Lâm phải chú ý","ghiChu":"Cảnh báo sau khi tặng bản đồ thật @c1103"},{"ten":"Thương Tùng Tử","tag":"dong-minh","quanHe":"Cùng tham gia kế hoạch bí mật, được hứa quyền chọn trước ba vật.","ghiChu":"Giao ước tại Man Hoang đại lục @c1108"},{"ten":"Giao Long hóa sương cấp mười hai","tag":"doi-thu","quanHe":"Đối thủ trong trận vây công ở con đường hẹp có Hồi đan.","ghiChu":"Bà dùng gió lạnh và tuyết công kích nó."},{"ten":"Trần Thiên Quân","tag":"dong-minh","quanHe":"đồng hành tạm thời","ghiChu":"Cùng ở trong đoàn trước khi Trần Thiên Quân rút lui."},{"ten":"Minh Chí Giả","tag":"khac","quanHe":"Bị âm thanh và hư ảnh Minh Chí Giả làm chấn động nguyên thần.","ghiChu":"Qua đó bà biết thêm về Đạo Kinh từ lời Thương Tùng Tử."},{"ten":"Thương Tùng Tử","tag":"doi-thu","quanHe":"Bị Thương Tùng Tử lừa vào động phủ thú hồn và nhốt lại khi lão đi đoạt bình ngọc.","ghiChu":"Sau đó nàng liên quan trực tiếp tới màn hiện thân Dương Tụ Âm Quy trong không gian tấm bia."},{"ten":"Người phụ nữ trung niên áo xanh họ Triệu","tag":"khac","quanHe":"Cùng họ Triệu, dung mạo giống hệt và liên quan cấm thuật Dương Tụ Âm Quy.","ghiChu":"Chương chưa nói rõ quan hệ danh tính ngoài liên hệ thuật pháp nhiều đời chung thân."},{"ten":"Lão phụ nhân áo xanh","tag":"dong-minh","quanHe":"Dung hợp nguyên thần hỗ trợ","ghiChu":"Nguyên thần của bà cùng hai người khác dung hợp với nguyên thần lão phụ nhân trong cuộc chiến."}],"tuiDo":{"phapBao":[{"ten":"Thú hồn mãnh thú cấp mười hai","loai":"linh vật","trangThai":"dang-co","moTa":"Đổi được bằng ngọc giản, bản đồ tinh cầu và mười vạn tiên ngọc.","nguon":"@c1103"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1103","@c1107","@c1108","@c1109","@c1110","@c1111","@c1112","@c1113","@c1114","@c1115","@c1116","@c1117","@c1118","@c1119","@c1120","@c1121","@c1123"]},{"id":"lao-gia-hac-y-gay-kho","name":"Lão già hắc y gầy khô","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1103","trangThai":"song","blurb":"Tu sĩ gầy khô mặc hắc y đưa thú hồn mãnh thú cấp mười hai và lông vũ Chu Tước ra giao dịch trong buổi tụ hội. Lão đặt giá rất cao và cuối cùng bán được cả hai món.","vaiTro":"Chủ vật phẩm đấu giá","tinhCach":[{"text":"Thực dụng, kiên quyết với giá đưa ra","chuong":"@c1103"},{"text":"Không dễ bị các lời trả giá làm dao động","chuong":"@c1103"}],"tabs":{"diem":[{"text":"Nắm giữ thú hồn mãnh thú cấp mười hai và lông vũ Chu Tước, hai món khiến nhiều tu sĩ chú ý.","chuong":"@c1103"},{"text":"Đòi thêm mười vạn tiên ngọc ngoài vật trao đổi mới chịu bán thú hồn.","chuong":"@c1103"}],"kinhLich":[{"chuong":"@c1103","importance":"normal","mucCt":"gon","tieuDe":"Bán hai dị vật","text":"Lão già hắc y gầy khô đưa thú hồn cấp mười hai và lông vũ Chu Tước ra giao dịch, đòi thêm mười vạn tiên ngọc mới chịu bán thú hồn cho bà lão áo xanh, còn lông vũ được đấu giá công khai.","anchor":"Lão phu không cần bản đồ tinh cầu, ngươi bỏ thêm mười vạn tiên ngọc đi"}],"tuViMoc":[],"nhanMach":[{"ten":"Bà lão áo xanh","tag":"khac","quanHe":"Người mua thú hồn cấp mười hai của lão","ghiChu":"Giao dịch trong buổi tụ hội @c1103"},{"ten":"Ngô Thanh","tag":"khac","quanHe":"Người mua lông vũ Chu Tước của lão","ghiChu":"Đấu giá công khai @c1103"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1103"]},{"id":"thieu-phu-xinh-dep","name":"Thiếu phụ xinh đẹp","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"không rõ @c1103","trangThai":"song","blurb":"Nữ tu tham gia đấu giá lông vũ Chu Tước trong buổi tụ hội. Nàng trả giá cao nhưng cuối cùng bỏ cuộc khi giá bị đẩy lên quá mức.","vaiTro":"Người tham gia đấu giá","tinhCach":[{"text":"Ưa thích vẻ đẹp của lông vũ Chu Tước","chuong":"@c1103"},{"text":"Biết cân nhắc lợi hại khi giá vượt quá dự tính","chuong":"@c1103"}],"tabs":{"diem":[{"text":"Từng ra giá tám ngàn rồi hai vạn tiên ngọc cho lông vũ Chu Tước.","chuong":"@c1103"},{"text":"Nhận ra Vương Lâm có nhiều tiên ngọc và có thể có thế lực lớn sau lưng.","chuong":"@c1103"}],"kinhLich":[{"mucCt":"gon","text":"Thiếu phụ xinh đẹp tham gia tranh lông vũ Chu Tước, trả giá tới hai vạn tiên ngọc nhưng bỏ cuộc khi Vương Lâm nâng lên ba vạn.","anchor":"Vị tiểu đạo hữu kia có nhiều tiên ngọc quá, nhưng lông vũ này quả thật quá đẹp","bridge":true,"khoang":"@c1103"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người quen trong hội đấu giá","ghiChu":"Nàng từng quen biết Vương Lâm và nhận xét về núi đá do hắn đưa ra đấu giá."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1103","@c1107"]},{"id":"lao-gia-mat-day-lo-nho","name":"Lão già mặt đầy lỗ nhỏ","cn":"","aliases":["Lão già mặt đầy lỗ","Bàng đạo hữu","Bàng lão giả","Lão già mặt đầy lỗ nhỏ","Lão già họ Bàng","Bàng Đức"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ trong chương này @c1117","trangThai":"song","blurb":"Lão già mặt đầy lỗ nhỏ, tức Bàng Đức, là tu sĩ thân cận với Thương Tùng Tử, xuất hiện từ buổi đấu giá lông vũ Chu Tước rồi tham gia hành trình thám hiểm nơi hiểm địa. Lão nhiều lần va chạm và kiêng sợ Vương Lâm, từng bị thương nặng khi đánh Giao Long, và sau cùng trở mặt muốn hại Vương Lâm nhưng bị thân diệt còn nguyên thần bị giữ lại. Lão được cho là có sở trường sưu hồn.","vaiTro":"Tu sĩ thân cận Thương Tùng Tử — người tham gia đấu giá và thám hiểm động phủ","tinhCach":"Thận trọng, dễ chùn bước khi gặp đối thủ mạnh; kiêng sợ và né tránh Vương Lâm sau khi lỡ lời đắc tội; ban đầu khinh thường rồi mau chóng dè chừng; sẵn sàng trở mặt vì lợi ích","tabs":{"diem":[{"text":"Mở giá lông vũ Chu Tước lên một vạn ba ngàn tiên ngọc rồi bỏ cuộc khi bị đẩy giá","chuong":"@c1103"},{"text":"Người thân cận với Thương Tùng Tử, từng nhiều lần vào nơi hiểm địa này","chuong":"@c1111"},{"text":"Dùng lô cầu đánh Giao Long nhưng bị thương nặng, phải tựa vách núi với phần ngực máu thịt","chuong":"@c1113"},{"text":"Phối hợp quen thuộc với Thương Tùng Tử để thu nguyên tinh, nhận ra hàn khí và vật thần bí","chuong":"@c1114"},{"text":"Được giao ở lại bên Vương Lâm, sau khi lục soát động phủ liền trở mặt nhưng thân diệt còn nguyên thần bị giữ","chuong":"@c1117"},{"text":"Được Thương Tùng Tử cho là có sở trường sưu hồn","chuong":"@c1118"}],"kinhLich":[{"mucCt":"gon","text":"Lão già mặt đầy lỗ nhỏ mở giá lông vũ Chu Tước rồi nâng lên một vạn ba ngàn tiên ngọc, nhưng bỏ cuộc khi Vương Lâm đưa giá lên ba vạn.","anchor":"Năm xưa khi Chu Tước chết thì lông vũ khắp toàn thân đều bốc cháy, lông vũ trước mặt rõ ràng cũng không phải là chính phẩm","bridge":true,"khoang":"@c1103"},{"chuong":"@c1109","importance":"bridge","mucCt":"vua","tieuDe":"Quan sát trận thử sức","text":"Lão giả họ Bàng ung dung quan sát cuộc thử sức giữa Vương Lâm và Vân Hồn Tử, xoay chiếc nhẫn trên tay rồi theo nhóm xuất phát.","anchor":"Tình cảnh vừa rồi đã được lão già mặt đầy lổ nhìn thấy rất rõ ràng, nhưng vẻ mặt vẫn rất ung dung"},{"chuong":"@c1111","importance":"normal","tieuDe":"Chất vấn rồi chùn bước","mucCt":"vua","text":"Lão giả họ Bàng là người thân cận với Thương Tùng Tử và từng nhiều lần vào nơi này, nhớ lại những bạn cũ đã chết trong các lần trước. Khi Vân Hồn Tử biến mất, lão nhìn chằm chằm Vương Lâm và lên tiếng chất vấn, nhưng bị Vương Lâm cảnh cáo nên nhớ tới cái chết của Ngô Thanh mà âm thầm hối hận.","anchor":"Lão già họ Bàng nhìn chằm chằm vào Vương Lâm rồi chậm rãi nói."},{"mucCt":"vua","text":"Lão giả họ Bàng vẫn hoảng sợ trong lòng vì từng lỡ lời đắc tội Vương Lâm. Khi tới nơi có Hồi đan, lão đã sớm phong bế ngũ quan để tránh mùi thuốc quỷ dị, sau đó trong trận vây công Giao Long hóa sương thi triển lôi quang và gọi lôi cầu giáng xuống.","anchor":"lão già họ Bàng đã sớm phong bế ngũ quan","bridge":true,"khoang":"@c1112"},{"mucCt":"vua","anchor":"lão sợ nếu mình chậm chân thì sẽ bị Giao Long đập lên người","text":"Lão giả họ Bàng dùng lô cầu đánh Giao Long nhưng bị thương nặng, phải tựa vào vách núi với phần ngực máu thịt mơ hồ. Khi Vương Lâm quật Giao Long xuống con đường hẹp, lão hoảng hốt lùi tránh, sau đó nhớ lại lời uy hiếp trước đó của Vương Lâm mà cay đắng và được Thương Tùng Tử đưa đan dược hỗ trợ hồi phục.","bridge":true,"khoang":"@c1113"},{"chuong":"@c1114","importance":"normal","mucCt":"vua","tieuDe":"Phối hợp thu nguyên tinh","text":"Lão nhận ra hàn khí và vật thần bí từng khiến đoàn trước tổn thất nặng, sau đó phối hợp quen thuộc với Thương Tùng Tử vào sương mù lấy nguyên tinh rồi giao túi trữ vật cho Vương Lâm. Lão thể hiện rằng mình đã nhiều lần cùng Thương Tùng Tử xử lý các vị trí có mãnh thú hóa sương trong thế giới bảy màu.","anchor":"Lão vẫn chưa quên lần thứ hai khi đám người tiến vào thế giới bảy màu này"},{"mucCt":"vua","text":"Lão giả họ Bàng đi sát sau Thương Tùng Tử nhưng vẫn kiêng sợ Vương Lâm nên không dám lại gần hắn. Khi dao động thần thông của Trần Thiên Quân truyền tới, lão cho rằng người này không nghe lời khuyên, tự tiện đi lại trong thế giới bảy màu nên đã lành ít dữ nhiều.","anchor":"Lão già họ Bàng theo sát phía sau Thương Tùng Tử, lão không dám đi gần Vương Lâm quá","bridge":true,"khoang":"@c1115"},{"mucCt":"vua","text":"Lão giả họ Bàng ban đầu khinh thường khả năng phá trận của Vương Lâm, nhưng khi thấy hắn vượt tới những bước cuối thì trở nên ngưng trọng và thầm cho rằng đối phương sẽ mất tư cách đi tiếp. Sau khi vào động phủ cũ, lão được Thương Tùng Tử nhờ ở lại bảo hộ Vương Lâm và đồng ý với sự sắp đặt này.","anchor":"Hai mắt lão già họ Bàng chợt lóe lên, lão cười nói:","bridge":true,"khoang":"@c1116"},{"chuong":"@c1117","importance":"normal","mucCt":"ky","tieuDe":"Thân diệt nguyên thần bị giữ","text":"Lão già họ Bàng được Thương Tùng Tử giao ở lại bên Vương Lâm, nhưng sau khi lục soát động phủ liền trở mặt muốn giết người đoạt lợi. Lão bị Vương Lâm phản kích đánh nổ thân thể, nguyên thần bị Thiết kiếm chém làm hai, một nửa nguyên lực bị nuốt, phần còn lại bị ép mở không gian trữ vật và bị搜 ký ức. Vương Lâm không giết hẳn mà thu nguyên thần suy yếu của lão vào túi trữ vật để tránh Thương Tùng Tử cảnh giác.","anchor":"Lão già họ Bàng phun ra một ngụm máu tươi, trong mắt lộ ra vẻ không tin, thân thể đột nhiên nổ tung trong nháy mắt rồi hóa thành một làn sương máu."},{"chuong":"@c1118","importance":"bridge","mucCt":"vua","tieuDe":"Bị nhắc chuyện sưu hồn","text":"Bàng Đức không trực tiếp ra mặt nhưng được Thương Tùng Tử cho rằng có sở trường sưu hồn và chắc chắn sẽ có thu hoạch từ Lữ đạo hữu, đặc biệt là Dịch Linh Ấn.","anchor":"Bàng Đức có sở trường sưu hồn, chắc chắn sẽ có thu hoạch"}],"tuViMoc":[],"nhanMach":[{"ten":"Vân Hồn Tử","tag":"khac","quanHe":"Người quen cũ trong nhóm Thương Tùng Tử.","ghiChu":"Cùng xuất hiện tại Man Hoang đại lục @c1108"},{"ten":"Thương Tùng Tử","tag":"dong-minh","quanHe":"Cùng tham gia nhóm do Thương Tùng Tử chủ trì.","ghiChu":"Chất vấn việc cho Lữ đạo hữu tham gia @c1108"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Từng lỡ lời đắc tội nên còn kiêng sợ Vương Lâm.","ghiChu":"Sự e dè tiếp tục hiện rõ trong thế giới bảy màu."},{"ten":"Giao Long hóa sương cấp mười hai","tag":"doi-thu","quanHe":"Đối thủ trong trận vây công tại khu Hồi đan.","ghiChu":"Lão dùng lôi quang và lôi cầu tấn công."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1103","@c1107","@c1108","@c1109","@c1110","@c1111","@c1112","@c1113","@c1114","@c1115","@c1116","@c1117","@c1118"]},{"id":"nguoi-dan-ong-trung-nien-van-si","name":"Người đàn ông trung niên văn sĩ","cn":"","aliases":["Người đàn ông văn sĩ áo trắng"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1103","trangThai":"song @c1107","blurb":"Nam tu sĩ dáng văn sĩ trong buổi tụ hội, chú ý tới Vương Lâm từ sớm. Ông nhận ra thái độ bình tĩnh của Vương Lâm trước tu sĩ Toái Niết cho thấy đối phương có con bài tẩy.","vaiTro":"Người quan sát Vương Lâm","tinhCach":[{"text":"Quan sát tinh tế, biết kiêng dè nguy hiểm","chuong":"@c1103"},{"text":"Từng nhắc người khác không nên chọc giận Vương Lâm","chuong":"@c1103"}],"tabs":{"diem":[{"text":"Kinh ngạc khi Vương Lâm ra giá lớn và vẫn bình tĩnh trước tu sĩ Toái Niết.","chuong":"@c1103"}],"kinhLich":[{"mucCt":"gon","text":"Người đàn ông trung niên văn sĩ quan sát Vương Lâm trong buổi đấu giá và cho rằng một người có thể bình tĩnh trước tu sĩ Toái Niết tất phải có con bài tẩy.","anchor":"Người này có rất nhiều tiên ngọc","bridge":true,"khoang":"@c1103"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được ông quan sát và kiêng dè","ghiChu":"Trong buổi tụ hội @c1103"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1103","@c1107"]},{"id":"truong-ky","name":"Trương Kỳ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ma Tùng Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết trung kỳ @c1105","trangThai":"song @c1105","blurb":"Trương Kỳ là đại diện Ma Tùng Đạo ra mặt sau khi Ngô Thanh bị Vương Lâm giết. Hắn lựa chọn cầu hòa, tuyên bố cắt bỏ liên hệ với Ngô Thanh và dâng lễ bồi thường để tránh họa cho tông phái.","vaiTro":"Đại diện Ma Tùng Đạo cầu hòa","tinhCach":[{"text":"Biết nhún nhường trước thế mạnh để bảo toàn tông phái","chuong":"@c1105"},{"text":"Phẫn nộ với Ngô Thanh vì đã liên lụy Ma Tùng Đạo","chuong":"@c1105"}],"tabs":{"diem":[{"text":"Có tu vi Toái Niết trung kỳ và đứng ra đại diện Ma Tùng Đạo xử lý hậu quả vụ Ngô Thanh.","chuong":"@c1105"},{"text":"Dâng Cách Hồn Đan và bảo vật để xoa dịu Vương Lâm.","chuong":"@c1105"}],"kinhLich":[{"chuong":"@c1105","importance":"normal","mucCt":"vua","tieuDe":"Cầu hòa Thần Tông","text":"Trương Kỳ chủ động ra mắt Vương Lâm, tuyên bố Ngô Thanh đã bị trục xuất khỏi Ma Tùng Đạo và dâng nhiều đan dược cùng bảo vật để bồi thường. Sau khi Vương Lâm rời đi, hắn trách Ngô Thanh đã không nghe lời mà còn chọc vào người không nên chọc.","anchor":"Ngô Thanh, lão phu trước đó đã từng bảo người đừng nên trêu chọc người này, ngươi lại không nghe"}],"tuViMoc":[{"chuong":"@c1105","canhGioi":"Toái Niết trung kỳ","text":"Xuất hiện với tu vi Toái Niết trung kỳ trong vai đại diện Ma Tùng Đạo.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng mà Trương Kỳ phải cầu hòa và bồi thường.","ghiChu":"Gặp tại Bồng Lai đại lục @c1105"},{"ten":"Ngô Thanh","tag":"khac","quanHe":"Tu sĩ gây họa cho Ma Tùng Đạo, bị Trương Kỳ tuyên bố trục xuất.","ghiChu":"Bị trách vì không nghe lời @c1105"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Cách Hồn Đan cấp bảy","trangThai":"da-dung","moTa":"Dâng bốn mươi sáu viên cho Vương Lâm.","nguon":"@c1105"},{"ten":"Cách Hồn Đan cấp tám","trangThai":"da-dung","moTa":"Dâng chín viên cho Vương Lâm.","nguon":"@c1105"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Túi trữ vật bảo vật","trangThai":"da-dung","moTa":"Dâng cho Vương Lâm để bồi thường vụ Ngô Thanh tranh đoạt.","nguon":"@c1105"}]}},"nguon":["@c1105"]},{"id":"do-duc","name":"Đỗ Đức","cn":"","aliases":["lão già hắc y"],"gioiTinh":"nam","theLuc":[{"ten":"Tán tu tinh vực cấp sáu","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết sơ kỳ @c1105","trangThai":"song @c1105","blurb":"Đỗ Đức là tán tu Toái Niết sơ kỳ ở tinh vực cấp sáu, từng giữ lông vũ Chu Tước. Sau biến cố Bồng Lai, lão đến bái phỏng Vương Lâm để kết giao và cung cấp manh mối về Man Hoang đại lục.","vaiTro":"Tán tu cung cấp manh mối lông vũ Chu Tước","tinhCach":[{"text":"Khéo kết giao khi nhận thấy Vương Lâm có thân phận và thực lực đáng trọng","chuong":"@c1105"},{"text":"Thận trọng khi nhắc đến nguy hiểm của Man Hoang đại lục","chuong":"@c1105"}],"tabs":{"diem":[{"text":"Là chủ nhân cũ của lông vũ Chu Tước mà Vương Lâm thu được.","chuong":"@c1105"},{"text":"Biết nguồn gốc lông vũ từ Man Hoang đại lục tinh vực cấp sáu.","chuong":"@c1105"}],"kinhLich":[{"chuong":"@c1105","importance":"normal","mucCt":"vua","tieuDe":"Trao manh mối lông vũ","text":"Đỗ Đức đến khách điếm bái phỏng Vương Lâm, tự giới thiệu là tán tu tinh vực cấp sáu và muốn kết giao. Khi được hỏi về lông vũ Chu Tước, lão cho biết vật này đoạt được tại Man Hoang đại lục, nơi mãnh thú am hiểu thần thông hệ hỏa và có cả mãnh thú cấp mười một, rồi trao ngọc giản thông tin cho Vương Lâm.","anchor":"Vật này Đỗ mỗ đoạt được từ trên một Man Hoang đại lục của tinh vực cấp sáu"}],"tuViMoc":[{"chuong":"@c1105","canhGioi":"Toái Niết sơ kỳ","text":"Xuất hiện với thân phận tán tu Toái Niết sơ kỳ ở tinh vực cấp sáu.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ động kết giao và cung cấp ngọc giản về Man Hoang đại lục.","ghiChu":"Bái phỏng ở khách điếm @c1105"}],"tuiDo":{"phapBao":[{"ten":"Lông vũ Chu Tước","trangThai":"mat","moTa":"Từng là chủ nhân cũ trước khi vật rơi vào tay Vương Lâm.","nguon":"@c1105"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Ngọc giản Man Hoang đại lục","trangThai":"da-dung","moTa":"Trao cho Vương Lâm để chỉ rõ nơi có lông vũ Chu Tước.","nguon":"@c1105"}]}},"nguon":["@c1105"]},{"id":"tao-truong-lao","name":"Tào trưởng lão","cn":"","aliases":["trưởng lão họ Tào","lão già áo bào đỏ","Lão già Bảo Ngọc Tông"],"gioiTinh":"nam","theLuc":[{"ten":"Bảo Ngọc Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1106","trangThai":"song","blurb":"Trưởng lão áo bào đỏ của Bảo Ngọc Tông, đại diện tông môn tiếp đãi Vương Lâm trong buổi đấu giá trên Bồng Lai. Ông khôn khéo trong ứng xử và nhận nhiệm vụ chuyển hai bảo vật của Vương Lâm vào phiên đấu giá.","vaiTro":"Trưởng lão tiếp đón đấu giá","tinhCach":[{"text":"Khôn khéo trong ứng xử","chuong":"@c1106"},{"text":"Cẩn trọng trước nhân vật nguy hiểm","chuong":"@c1106"}],"tabs":{"diem":[{"text":"Đại diện Bảo Ngọc Tông đón tiếp Vương Lâm tại buổi đấu giá.","chuong":"@c1106"},{"text":"Từng bái phỏng Vương Lâm và báo lại cho tông chủ về sự bất phàm của hắn.","chuong":"@c1106"},{"text":"Nhận hai bảo vật bị hắc quang bao phủ để chuyển vào đấu giá.","chuong":"@c1106"}],"kinhLich":[{"chuong":"@c1106","importance":"normal","mucCt":"vua","tieuDe":"Tiếp đón Vương Lâm","text":"Tào trưởng lão đại diện Bảo Ngọc Tông tiếp đón Vương Lâm tại đấu giá và nhớ lại việc từng bái phỏng, khi đó đã thấy hắn bất phàm đến mức nhìn vào mắt có thể sinh ảo giác. Lão nhận hai bảo vật bọc hắc quang của Vương Lâm để chuyển cho phía phụ trách đấu giá, xử sự khôn khéo và cung kính.","anchor":"Lữ đạo hữu có thể đến đây tham gia đấu giá, quả thật rất vinh hạnh cho Bảo Ngọc Tông ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được tiếp đãi","ghiChu":"Tào trưởng lão tiếp đón Vương Lâm và nhận hai bảo vật của hắn để đưa vào đấu giá."},{"ten":"Tông chủ Bảo Ngọc Tông","tag":"cap-tren","quanHe":"Tông chủ","ghiChu":"Tào trưởng lão từng báo cáo với tông chủ về Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1106","@c1107"]},{"id":"tong-chu-bao-ngoc-tong","name":"Tông chủ Bảo Ngọc Tông","cn":"","aliases":[],"gioiTinh":"không rõ","theLuc":[{"ten":"Bảo Ngọc Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1106","trangThai":"song","blurb":"Người đứng đầu Bảo Ngọc Tông được Tào trưởng lão báo cáo về Vương Lâm. Sau khi cân nhắc, người này hạ lệnh đệ tử trên Bồng Lai không được đắc tội Vương Lâm.","vaiTro":"Tông chủ Bảo Ngọc Tông","tinhCach":[{"text":"Thận trọng trước cường giả lạ mặt","chuong":"@c1106"},{"text":"Quyết đoán trong việc bảo toàn tông môn","chuong":"@c1106"}],"tabs":{"diem":[{"text":"Nhận báo cáo từ Tào trưởng lão về sự bất phàm của Vương Lâm.","chuong":"@c1106"},{"text":"Ra lệnh đệ tử Bảo Ngọc Tông trên Bồng Lai không được đắc tội Vương Lâm.","chuong":"@c1106"}],"kinhLich":[{"chuong":"@c1106","importance":"normal","mucCt":"gon","tieuDe":"Lệnh tránh đắc tội","text":"Tông chủ Bảo Ngọc Tông nghe Tào trưởng lão báo cáo về Vương Lâm rồi ra lệnh cho toàn bộ đệ tử trên Bồng Lai không được đắc tội hắn, bất kể hắn có phải đệ tử Thần Tông hay không.","anchor":"Rốt cuộc người này có phải đệ tử Thần Tông hay không thì chẳng có bất kỳ điều gì liên quan đến Bảo Ngọc Tông của ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Tào trưởng lão","tag":"su-mon","quanHe":"Thuộc hạ trong tông","ghiChu":"Tào trưởng lão báo cáo với tông chủ về Vương Lâm."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng cần tránh đắc tội","ghiChu":"Tông chủ ra lệnh đệ tử không được đắc tội Vương Lâm."},{"ten":"Tào trưởng lão","tag":"cap-tren","quanHe":"Thuộc hạ trong Bảo Ngọc Tông.","ghiChu":"Tào trưởng lão báo cáo với ông về Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1106"]},{"id":"thanh-nien-ao-vang","name":"Thanh niên áo vàng","cn":"","aliases":["Thanh niên áo vàng Bí Lạc Tông cấp bảy","Thanh niên áo vàng Bí Lạc Tông"],"gioiTinh":"nam","theLuc":[{"ten":"Bí Lạc Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1108","trangThai":"song","blurb":"Tu sĩ thuộc Bí Lạc Tông cấp bảy, xuất hiện trong buổi đấu giá tại Bồng Lai. Hắn tham gia tranh đoạt Thần Ma Giáp với tài lực lớn và thái độ gay gắt.","vaiTro":"Tu sĩ Bí Lạc Tông tranh đấu giá","tinhCach":[{"text":"Cạnh tranh quyết liệt trong đấu giá","chuong":"@c1107"},{"text":"Dễ lộ sát ý khi bị thách thức","chuong":"@c1107"}],"nguon":["@c1107","@c1108"],"tabs":{"diem":[{"text":"Đại diện Bí Lạc Tông cấp bảy ra giá cao để tranh Thần Ma Giáp.","chuong":"@c1107"},{"text":"Chất vấn Âu Dương Long về nguồn gốc nguyên tinh khi cuộc đấu giá bị đẩy lên cao.","chuong":"@c1107"},{"text":"Đẩy giá bộ giáp lên rất cao trước khi bị Thương Tùng Tử ép rút lui.","chuong":"@c1108"},{"text":"Là người của Bí Lạc Tông cấp bảy, đủ tài lực ra giá hơn một vạn nguyên tinh trong hội đấu giá.","chuong":"@c1107"},{"text":"Nhận ra Âu Dương Long thuộc Bảo Ngọc Tông cấp năm trên Bồng Lai đại lục và lập tức chất vấn.","chuong":"@c1107"},{"text":"Ra giá lớn trong cuộc đấu giá Thần Ma Giáp, từ một vạn ba nghìn lên hai vạn năm nghìn nguyên tinh.","chuong":"@c1107"},{"text":"Nhận ra Âu Dương Long là người của Bảo Ngọc Tông cấp năm trên Bồng Lai đại lục và chất vấn nguồn gốc nguyên tinh của hắn.","chuong":"@c1107"}],"kinhLich":[{"chuong":"@c1107","importance":"normal","mucCt":"vua","tieuDe":"Đấu giá ma giáp","text":"Thanh niên áo vàng của Bí Lạc Tông cấp bảy tham gia tranh Thần Ma Giáp, ra giá từ một vạn ba nghìn nguyên tinh và tiếp tục đẩy giá lên cao. Khi Âu Dương Long ra tới ba vạn nguyên tinh, hắn nhận ra thân phận đối phương, chất vấn nguồn gốc nguyên tinh và lộ sát khí.","anchor":"Bí Lạc Tông cấp bảy, ra giá một vạn ba nghìn nguyên tinh"},{"mucCt":"gon","text":"Thanh niên áo vàng thuộc Bí Lạc Tông trả giá đến bảy vạn nguyên tinh để tranh bộ giáp, nhưng sau lời uy hiếp của Thương Tùng Tử thì bỏ cuộc và bay đi.","anchor":"tinh vực cấp bảy đường xá xa xôi, ngươi trở về cũng phải cẩn thận","bridge":true,"khoang":"@c1108"}],"tuViMoc":[],"nhanMach":[{"ten":"Âu Dương Long","tag":"doi-thu","quanHe":"Đối thủ đấu giá","ghiChu":"Hai bên tranh đoạt Thần Ma Giáp, thanh niên áo vàng nghi ngờ tài lực của Âu Dương Long."},{"ten":"Thương Tùng Tử","tag":"doi-thu","quanHe":"Bị Thương Tùng Tử ép rút khỏi cuộc đấu giá bộ giáp.","ghiChu":"Đối đầu công khai tại Bồng Lai @c1108"},{"ten":"Vương Lâm","tag":"khac","quanHe":"người sở hữu vật đang được hắn tranh mua","ghiChu":"Thần Ma Giáp đem ra đấu giá thuộc Vương Lâm, còn hắn là người tham gia đẩy giá vật này."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"truong-lao-dao-mon","name":"Trưởng lão đạo môn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1107","trangThai":"song","blurb":"Tu sĩ đạo môn ngồi trên bia đá phía trước trong buổi đấu giá. Ông mua được núi đá từ Tiên giới và từng tham gia tranh Thần Ma Giáp.","vaiTro":"Trưởng lão đạo môn dự đấu giá","tinhCach":[{"text":"Thận trọng với giới hạn tài lực của đạo môn","chuong":"@c1107"},{"text":"Sẵn sàng ra giá cho bảo vật có giá trị cảm ngộ","chuong":"@c1107"}],"nguon":["@c1107"],"tabs":{"diem":[{"text":"Mua được núi đá từ Tiên giới với giá một nghìn nguyên tinh.","chuong":"@c1107"},{"text":"Tham gia đấu giá Thần Ma Giáp nhưng dừng lại khi giá vượt cực hạn của đạo môn.","chuong":"@c1107"},{"text":"Tham gia đấu giá Thần Ma Giáp tới một vạn nguyên tinh rồi bỏ cuộc vì đó là cực hạn của đạo môn.","chuong":"@c1107"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người bán núi đá qua hội đấu giá","ghiChu":"Núi đá mà ông mua là vật thuộc Vương Lâm được đưa ra đấu giá."}],"tuiDo":{"phapBao":[{"ten":"Núi đá từ Tiên giới","loai":"vật phẩm","trangThai":"dang-co","moTa":"Mua được trong buổi đấu giá với giá một nghìn nguyên tinh.","nguon":"@c1107"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","trangThai":"tu-vong","nguon":["@c1107","@c1146"],"tabs":{"diem":[{"text":"Bị Song Tu Môn truy sát vì Thiên Ly đan, được Vương Lâm cứu giúp và bắt đầu đồng hành","chuong":"@c0123"},{"text":"Trong bốn năm đồng hành tại Tu Ma Hải, khắc 18.974 ngọc giản đan phương — bộ sưu tập khổng lồ thể hiện thiên phú luyện đan","chuong":"@c0135"},{"text":"Ba lần Kết Anh thất bại, tuổi thọ cạn kiệt, thân thể suy kiệt không thể cứu vãn","chuong":"@c0302"},{"text":"Thân xác hóa xương khô, nguyên anh được Vương Lâm dùng bức tranh sinh tử luân hồi đưa vào chuyển sinh thành bé gái Chu Như","chuong":"@c0313"},{"text":"Sau chín mươi năm im lặng, thức tỉnh rồi từ chối cắn nuốt hồn phách Chu Như, tự đẩy nguyên anh ra để cứu đứa trẻ","chuong":"@c0381"},{"text":"Nguyên anh được Vương Lâm giữ gìn gần bảy trăm năm, bị chẩn đoán tử vong nhưng còn tia hy vọng qua Thất Tịch Thuật","chuong":"@c0827"}],"kinhLich":[{"chuong":"@c1107","importance":"bridge","mucCt":"gon","tieuDe":"Ký ức sâu nặng","text":"Trong hồi tưởng của Vương Lâm, Lý Mộ Uyển là người đã khắc sâu vào ký ức ngàn năm và đi vào tận đáy lòng hắn.","anchor":"Lý Mộ Uyển đã dùng phương pháp này để khắc sâu vào tận ký ức của Vương Lâm ngàn năm sau, đi vào tận đáy lòng hắn, rất sâu, rất sâu"},{"chuong":"@c1146","importance":"bridge","mucCt":"gon","text":"Được nhắc để nhấn mạnh mức độ mất kiểm soát của Vương Lâm: dù Lý Mộ Uyển xuất hiện trước mặt hắn cũng ra tay giết không do dự.","anchor":"Dù Lý Mộ Uyển có xuất hiện trước mặt thì hắn cũng không do dự lập tức ra tay giết người"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"the-thiep","quanHe":"người khắc sâu trong lòng hắn sau khi chết","ghiChu":"Nàng được Vương Lâm hồi tưởng như ký ức sâu nhất trong đời tình cảm của hắn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"canhGioiCaoNhat":"không rõ","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp; kiên cường chịu đựng trước suy kiệt kéo dài và cái chết cận kề; nặng tình với Vương Lâm dù biết duyên phận mong manh; giàu lòng trắc ẩn và tự hy sinh — từ chối cắn nuốt hồn phách Chu Như dù phải đánh đổi cơ hội tái sinh","gioiTinh":"nu","vaiTro":"Nhân vật nữ chính — người yêu Vương Lâm, thiên tài luyện đan và trận pháp","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ có thiên phú luyện đan và trận pháp hiếm thấy, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu, hai người đồng hành bốn năm tại Tu Ma Hải và khắc sâu tình cảm trước khi chia cách. Hơn trăm năm sau, ba lần Kết Anh thất bại khiến tuổi thọ cạn kiệt; dù Vương Lâm tìm mọi cách điều trị, thân xác bà vẫn hóa xương khô, nguyên anh được dùng bức tranh sinh tử luân hồi đưa vào chuyển sinh thành bé gái Chu Như tại Hạnh Hoa Thôn, rồi sau chín mươi năm im lặng bà thức tỉnh và tự đẩy nguyên anh ra khỏi thân thể Chu Như để cứu đứa trẻ. Nguyên anh sau đó "},{"id":"lieu-mi","name":"Liễu Mi","trangThai":"song","nguon":["@c1107"],"tabs":{"diem":[{"text":"Phân thân lặng lẽ ném lệnh bài cho Vương Lâm không nói một tiếng, thở dài sau khi hắn rời đi — mở đầu mạch tình cảm đơn phương xuyên suốt","chuong":"@c0093"},{"text":"Cảnh báo Vương Lâm tai họa sắp tới và khuyên rời Chu Tước tinh, chấp nhận bị Độn Thiên xua đuổi dọa giết","chuong":"@c0359"},{"text":"Được xác nhận là đệ tử chân truyền Chu Tước Tử, sư muội Kiền Phong, một trong bốn người được chọn kế thừa danh hiệu","chuong":"@c0374"},{"text":"Qua Hoán huyết đại pháp của Lão tổ Huyễn gia, tu vi vọt lên Vấn Đỉnh hậu kỳ đại viên mãn","chuong":"@c0633"},{"text":"Được xác định là Mộc Băng Mi — Thánh nữ đời thứ bảy của Côn Hư chi cảnh, tu luyện Thiên Hồn","chuong":"@c0993"},{"text":"Được Vương Lâm thừa nhận là người đi vào lòng hắn bằng đau đớn, lưu lại vết thương không phai trong đạo tâm","chuong":"@c1107"}],"kinhLich":[{"chuong":"@c1107","importance":"bridge","mucCt":"gon","tieuDe":"Vết thương trong lòng","text":"Trong hồi tưởng của Vương Lâm, Liễu Mi là người đi vào lòng hắn bằng đau đớn và chiến thắng ấy khiến lòng hắn phải chết đi.","anchor":"Liễu Mi vẫn thắng, nhưng chiến thắng này lại làm lòng Vương Lâm phải chết đi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người để lại vết thương tình cảm sâu trong lòng hắn","ghiChu":"Nàng được nhắc cùng ký ức đau đớn trên La Thiên và là một trong hai người phụ nữ thật sự đi vào lòng Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"canhGioiCaoNhat":"không rõ","tinhCach":"nặng lòng với Vương Lâm nhưng cam chịu không đòi hỏi, chỉ mong lưu bóng hình trong đạo tâm hắn; kiên định phụng lệnh sư tôn dù biết bị lợi dụng; hành sự quyết liệt không nề tay khi luyện oán ảnh; chủ động cảnh báo và bảo vệ Vương Lâm bất chấp nguy hiểm bản thân","gioiTinh":"nu","vaiTro":"Thiên đạo bí ẩn — đệ tử chân truyền Chu Tước Tử, Thánh nữ đời thứ bảy Côn Hư chi cảnh, nghĩa nữ Lão tổ Huyễn gia","blurb":"Liễu Mi là thiên đạo sở hữu hàng nghìn phân thân cảm ngộ thiên đạo khắp các nước, đệ tử chân truyền của Chu Tước Tử kiêm sư muội Kiền Phong, đồng thời là Thánh nữ đời thứ bảy của Côn Hư chi cảnh với danh Mộc Băng Mi; bản thể tu luyện trong Hàn Đàm cấm địa sau Chu Tước Sơn, phân thân từng hoạt động tại Huyền Đạo Tông. Nàng nhiều lần lặng lẽ tiếp cận, cảnh báo và quan sát Vương Lâm, rồi lưu lạc tới La Thiên tinh vực được Lão tổ Huyễn gia thu làm nghĩa nữ với danh Huyễn Mi, qua Hoán huyết đại pháp đạt Vấn Đỉnh hậu kỳ đại viên mãn; tại Huyễn gia nàng trở thành tâm điểm xung đột với Vương Lâm, bị H"},{"id":"hong-diep","name":"Hồng Điệp","trangThai":"song","nguon":["@c1107"],"tabs":{"diem":[{"text":"Sở hữu Thiên Tiên Ngũ Linh thể, tiềm năng Hóa Thần hậu kỳ đỉnh phong, từng vượt tiên giới cầm Vũ Trụ Bảo Phiến rồi trở về với tu vi hao tổn","chuong":"@c0268"},{"text":"Bị Vương Lâm chém đứt cánh tay phải, sau đó từ chối dùng Đông Hải Chi Linh để mọc lại tay nhằm giữ ý chí phục thù","chuong":"@c0317"},{"text":"Đại chiến Vương Lâm trên tế đàn Chu Tước quốc: triệu Băng Thần, hy sinh Anh Hài phát động Phân Thần Biến, lĩnh ngộ Tuyệt Tình ý cảnh nhưng thua trước Sinh Tử Luân Hồi","chuong":"@c0339"},{"text":"Bị Kiền Phong hạ thủ đoạt tuyệt tình ý cảnh cùng tứ linh, biến thành con rối trống rỗng bị khống chế hoàn toàn","chuong":"@c0340"},{"text":"Bị khống chế đấu Vương Lâm, tia thần thức thật cuối cùng cầu được giết; chọn không chống cự, mỉm cười kiêu hãnh đón chiến phủ mà chết","chuong":"@c0428"},{"text":"Liễu Mi điểm mi tâm biến hoá thành Hồng Điệp chân chính, dùng hoa hồng và phù văn giao đấu Vương Lâm lần cuối sau khi đã mất","chuong":"@c0634"}],"kinhLich":[{"chuong":"@c1107","importance":"bridge","mucCt":"gon","tieuDe":"Được hồi tưởng","text":"Hồng Điệp được nhắc trong dòng hồi tưởng của Vương Lâm về những cô gái từng đi qua đời hắn.","anchor":"Dù la Hồng Điệp trên La Thiên, Tây Tử Phượng, hoặc là Liễu Mi, Lữ Yên Phi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"tinhCach":"Kiêu hãnh bất khuất, giữ khí tiết đến tận lúc chết; hiếu chiến cố chấp, nhiều lần chủ động khiêu chiến Vương Lâm dù biết bất lợi; tàn nhẫn quyết đoán, sẵn sàng hy sinh pháp bảo và Anh Hài để phát động tuyệt chiêu; cương liệt trọng tôn nghiêm, từ chối phục hồi cánh tay cụt để giữ ý chí phục thù","gioiTinh":"nu","vaiTro":"Thiên chi kiêu nữ Tuyết Vực — đối thủ định mệnh của Vương Lâm","blurb":"Hồng Điệp là nữ tu thiên tài của Tuyết Vực quốc, sở hữu Thiên Tiên Ngũ Linh thể với tiềm năng đạt Hóa Thần hậu kỳ đỉnh phong, từng vượt tiên giới rồi trở về với tu vi hao tổn nghiêm trọng. Xuyên suốt nhiều lần giao tranh với Vương Lâm — từ đánh lén trên sa mạc, đấu pháp tại tế đàn đến đại chiến quyết tử tại Chu Tước quốc — nàng lĩnh ngộ Tuyệt Tình ý cảnh nhưng vẫn bại trước Sinh Tử Luân Hồi của đối thủ, rồi bị Kiền Phong đoạt ý cảnh cùng tứ linh, biến thành con rối trống rỗng mang tên Tuyệt Tình, cuối cùng chết dưới chiến phủ của Vương Lâm trong tư thế không chống cự, không né tránh, vẫn mỉm c"},{"id":"tay-tu-phuong","name":"Tây Tử Phượng","trangThai":"song","nguon":["@c1107"],"tabs":{"diem":[{"text":"Được Vương Lâm hai lần cứu giúp giữa Lôi Tiên Giới sụp đổ, cung kính cảm tạ ân nhân","chuong":"@c0750"},{"text":"Được nam tử áo lam nhắc là biểu muội luôn nhớ mãi Hứa Mộc","chuong":"@c0812"},{"text":"Gặp lại Vương Lâm giữa những người dự tranh phong tiên, nhớ lại lần gặp ở Lôi Tiên Giới","chuong":"@c0813"},{"text":"Đưa ngọc giản phòng thân cho Vương Lâm, đỏ mặt khi thấy hắn cất giữ","chuong":"@c0817"},{"text":"Thất thần rơi lệ khi nhận ra Vương Lâm tranh Phong Tiên vì Lý Mộ Uyển","chuong":"@c0826"},{"text":"Ngăn tu sĩ kiê ngạo định phá pho tượng khổng lồ của Vương Lâm","chuong":"@c1041"}],"kinhLich":[{"chuong":"@c1107","importance":"bridge","mucCt":"gon","tieuDe":"Được hồi tưởng","text":"Tây Tử Phượng được nhắc trong dòng hồi tưởng của Vương Lâm về những cô gái từng đi qua đời hắn.","anchor":"Dù la Hồng Điệp trên La Thiên, Tây Tử Phượng, hoặc là Liễu Mi, Lữ Yên Phi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"tinhCach":"biết cảm ân, cung kính tạ ơn ân nhân; trọng tình cảm, nhiều lần rung động trước Vương Lâm; dễ xúc động, tự ti trước khoảng cách thân phận","gioiTinh":"nu","vaiTro":"Nữ tu sĩ gặp Vương Lâm ở Lôi Tiên Giới, biểu muội của nam tử áo lam","blurb":"Tây Tử Phượng, còn gọi là Tử Phượng, là nữ tu sĩ xuất hiện trong biến cố Lôi Tiên Giới sụp đổ và được Vương Lâm hai lần cứu giúp. Về sau nàng gặp lại hắn trong cuộc tranh phong tiên, nhiều lần bộc lộ tình cảm phức tạp, đặc biệt đau lòng khi biết hắn tranh vị trí số một vì Lý Mộ Uyển. Nàng còn được nhắc là biểu muội luôn nhớ mãi Hứa Mộc."},{"id":"van-hon-tu","name":"Vân Hồn Tử","cn":"云魂子","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Toái Niết trung kỳ @c1111","trangThai":"song","blurb":"Vân Hồn Tử là lão giả áo bào đen trắng đội đạo quan, tu vi Toái Niết trung kỳ, mang theo vô số âm hồn cùng mùi máu tanh, thuộc nhóm Thương Tùng Tử. Vì cho rằng Vương Lâm chỉ là tiểu bối Tịnh Niết nên vừa gặp đã tung âm hồn tấn công thử tu vi, để rồi bị truyền tống vào sơn cốc và dần nhận ra thực lực kinh hoàng của đối phương. Cuối cùng lão bị Vương Lâm đặt ấn ký thu làm nô bộc, thân thể tan vỡ trong biến cố Không Niết và nguyên thần bị thu lại làm người hầu.","vaiTro":"Cánh tay đắc lực của Thương Tùng Tử — tu sĩ điều khiển âm hồn","tinhCach":"Ngạo mạn, coi thường tiểu bối nên vừa gặp đã ra tay thử tu vi; căm hận dai dẳng khi bị áp chế; kiên nhẫn, biết ẩn nhẫn chờ thời","tabs":{"diem":[{"text":"Tu sĩ Toái Niết trung kỳ, thần thôn, mang theo âm hồn vô tận","chuong":"@c1109"},{"text":"Vừa gặp đã tung âm hồn tấn công Vương Lâm để thử tu vi vì coi thường đối phương","chuong":"@c1109"},{"text":"Bị Vương Lâm xác định là cánh tay quan trọng của Thương Tùng Tử trong đội tiến vào vết nứt","chuong":"@c1111"},{"text":"Bị Vương Lâm đặt ấn ký, ẩn trong động phủ Thất Thải Giới gần trăm năm rồi trở thành nô bộc","chuong":"@c1152"},{"text":"Triệu âm hồn vô tận, phun máu giải phong ấn cây trùy đen, theo Vương Lâm xông vào lốc xoáy","chuong":"@c154"},{"text":"Thân thể tan vỡ trong lực xung kích Không Niết, nguyên thần bị thu làm người hầu","chuong":"@c1156"}],"kinhLich":[{"mucCt":"vua","text":"Vân Hồn Tử đến muộn vì gặp kẻ thù trên đường, sau lưng mang theo nhiều âm hồn. Khi thấy Vương Lâm, lão cho rằng hắn chỉ là tiểu bối Tịnh Niết nên nghi ngờ tư cách tham gia kế hoạch. Lão lập tức vung tay sai âm hồn lao tới tấn công thử Vương Lâm.","anchor":"Tiểu bối Tịnh Niết sao? Thương Tùng Tử, ngươi để một tiểu bối Tịnh Niết tham gia vào chuyện này à","bridge":true,"khoang":"@c1108"},{"mucCt":"ky","text":"Vân Hồn Tử vừa gặp đã tung âm hồn vô tận tấn công Vương Lâm để thử tu vi, buộc đối phương đánh trả và lùi lại. Sau khi Thương Tùng Tử can thiệp, lão thu hồn về, chín ngọn lửa linh hồn ngưng tụ sau lưng, rồi nhận xét Vương Lâm là kẻ giấu đầu lòi đuôi nhưng có thần thông Toái Niết. Lão bí mật truyền thần niệm với Thương Tùng Tử, tự tin có thể giết Vương Lâm rất nhanh nếu liên thủ, đồng thời nhận ra Trần Thiên Quân thuộc Dịch Thú Tông và nhắc từng giao hỏa với Thiên Tử.","anchor":"Hạng người giấu đầu lòi đuôi, không ngờ lại có thần thông Toái Niết!","bridge":true,"khoang":"@c1109"},{"chuong":"@c1111","importance":"normal","tieuDe":"Lệch vào sơn cốc","mucCt":"ky","text":"Vân Hồn Tử bị Vương Lâm xác định là cánh tay quan trọng của Thương Tùng Tử trong đội ngũ tiến vào vết nứt bảy màu. Khi chuẩn bị truyền tống, lão bị Thiết Kiếm và Thứ Không Niết Bảo tập kích, dùng ngọn lửa linh hồn chống đỡ nhưng vẫn bị Định Thân Thuật khóa trong khoảnh khắc và bị chém đứt tay phải. Sau đó lực lượng Cổ thần làm vết nứt xiêu vẹo, khiến lão bị truyền tống lệch tới một sơn cốc sương mù đầy tiếng gầm và mùi máu tanh.","anchor":"Một tiếng rên thảm vang lên, cánh tay phải của Vân Hồn Tử bị kiếm quang chém xuống máu tuôn xối xả."},{"chuong":"@c1112","importance":"bridge","mucCt":"gon","text":"Chuyện liên quan đến Vân Hồn Tử được đoàn người gác sang một bên sau biến cố trước đó.","anchor":"Những chuyện có liên quan đến Vân Hồn Tử đã được gác sang một bên"},{"chuong":"@c1125","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc: bị truyền tống đến phương hướng khác, khó bảo toàn tính mạng.","anchor":"bên trong nó lại ẩn giấu Phá Diệt Tâm Cấm của ta"},{"chuong":"@c1143","importance":"bridge","mucCt":"gon","text":"Thoát khỏi vây khốn khi sương mù co rút, nhận ra khí tức Vương Lâm trong lực tấn công lan rộng.","anchor":"Vân Hồn Tử nhận ra khí tức của Vương Lâm"},{"mucCt":"ky","text":"Cay đắng thừa nhận Vương Lâm mạnh kinh hoàng, vẫn căm hận vì bị truyền tống vào sơn cốc. Phân tích rằng Vương Lâm sau trận chiến chắc trọng thương, quyết định lợi dụng cơ hội liều mạng tấn công, phóng thẳng về phía trước.","anchor":"lợi dụng lúc hắn trọng thương mà liều mạng chiến đấu một trận, chưa chắc đã khó phân thắng bại","bridge":true,"khoang":"@c1145"},{"chuong":"@c1147","importance":"bridge","mucCt":"gon","text":"Cố xâm nhập vùng lực lượng kỳ dị bao phủ nguyên thần Vương Lâm nhưng thất bại, tìm động phủ ngồi chờ trăm năm.","anchor":"Vân Hồn Tử cố gắng xâm nhập nhưng thất bại"},{"chuong":"@c1152","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm đặt ấn ký, trở thành nô bộc","text":"Suốt gần 100 năm ẩn trong động phủ sơn cốc Thất Thải Giới. Khi Vương Lâm tỉnh dậy, bị uy áp cực mạnh gồm ngọn lửa lam, lôi đình, chiến ý xâm nhập nguyên thần, đau đớn kêu thảm. Cảm nhận Vương Lâm so với trăm năm trước khác một trời một vực, bản thân chỉ như kiến. Không dám chống cự, để ấn ký nô dịch thao túng sinh tử rơi vào mi tâm, quỳ xưng chủ nhân. Được Vương Lâm sai đi mời Trần Thiên Quân, cung kính vâng lệnh.","anchor":"Lão nô tham kiến chủ nhân."},{"chuong":"@c1153","importance":"bridge","mucCt":"gon","text":"Ở bên ngoài sơn cốc cảm nhận được lực phá kinh thiên động địa của Vương Lâm, tâm thần chấn động, sau đó theo sát phía sau khi rời khỏi sơn cốc.","anchor":"Vân Hồn Tử ở bên ngoài sơn cốc cũng hơi có chút phát hiện được, tâm thần chấn động"},{"mucCt":"vua","text":"Triệu âm hồn vô tận, phun máu giải phong ấn cây trùy đen, theo Vương Lâm xông vào cơn lốc xoáy. Toàn bộ âm hồn tử vong, pháp bảo cây trùy đen vỡ tan, nhờ lực vỡ nhảy vào lỗ hổng thoát ra. Bị thương nặng, hoảng sợ khi nhận ra mặt đất là lòng bàn tay.","anchor":"máu tươi phun ra, toàn bộ âm hồn ở phía trước đều tử vong, ngay cả pháp bảo của hắn cũng vỡ tan","bridge":true,"khoang":"@c1154"},{"mucCt":"vua","text":"Cắn răng theo sát phía sau Vương Lâm lao về phía bàn tay. Nhờ Vương Lâm che chắn phía trước nên chịu lực ít hơn, nhưng vẫn kinh mạch đứt từng khúc, xương cốt vỡ, thành thân thể đầy máu.","anchor":"kinh mạch toàn thân đứt ra từng khúc, ngay cả xương cốt cũng vỡ thành từng mảnh","bridge":true,"khoang":"@c1155"},{"chuong":"@c1156","importance":"normal","mucCt":"vua","tieuDe":"Thân thể tan vỡ, nguyên thần bị thu","text":"Lực xung kích khi hai pháp bảo Không Niết tan vỡ khiến thân thể Vân Hồn Tử không chịu nổi, vỡ nát, máu thịt văng khắp nơi. Chỉ còn nguyên thần thoát ra trong trạng thái thê thảm mê man, gần tử vong, bị Vương Lâm thu lấy.","anchor":"nguyên thần thoát ra ngoài mang theo ánh mắt thê thảm"},{"chuong":"@c1159","importance":"bridge","mucCt":"gon","text":"Nguyên thần đã được thu làm người hầu, Vương Lâm thu lại vào khe trữ vật, chưa chữa thương.","anchor":"đem nguyên thần của Vân Hồn Tử thu lại vào trong khe trữ vật"}],"tuViMoc":[{"chuong":"@c1109","canhGioi":"Toái Niết trung kỳ","text":"Lần đầu được xác nhận là tu sĩ Toái Niết trung kỳ, thần thông dùng hồn làm chủ.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Khinh thường và sai âm hồn tấn công thử.","ghiChu":"Gặp tại Man Hoang đại lục @c1108"},{"ten":"Thương Tùng Tử","tag":"dong-minh","quanHe":"Được Thương Tùng Tử chờ tới để tham gia kế hoạch bí mật.","ghiChu":"Đến muộn vì gặp kẻ thù @c1108"},{"ten":"Lão già mặt đầy lỗ nhỏ","tag":"khac","quanHe":"Người quen cũ.","ghiChu":"Cùng có mặt trong nhóm @c1108"},{"ten":"Trần Thiên Quân","tag":"khac","quanHe":"Nhận ra đối phương thuộc Dịch Thú Tông.","ghiChu":"Nhắc từng giao hỏa với Thiên Tử của Dịch Thú Tông @c1109"},{"ten":"Thiên Tử","tag":"doi-thu","quanHe":"Từng có giao hỏa với Thiên Tử của Dịch Thú Tông.","ghiChu":"Do chính Vân Hồn Tử nhắc lại @c1109"},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ nhân (bị đặt ấn ký nô dịch)","ghiChu":"Bị Vương Lâm thu phục làm nô bộc bằng ấn ký thao túng sinh tử tại Thất Thải Giới."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Âm hồn","loai":"âm hồn","trangThai":"dang-co","moTa":"Mang theo rất nhiều âm hồn sau lưng và dùng chúng để tấn công thử Vương Lâm.","nguon":"@c1108"}]}},"nguon":["@c1108","@c1109","@c1110","@c1111","@c1112","@c1125","@c1143","@c1145","@c1147","@c1152","@c1153","@c1154","@c1155","@c1156","@c1159"]},{"id":"doan-moc-dong-tu","name":"Đoan Mộc đồng tử","cn":"","aliases":["Đoan Mộc","đồng tử Đoan Mộc","Đoan Mộc đạo hữu","Đoan Mộc đổng tử"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Toái Niết trung kỳ @c1109","trangThai":"song","blurb":"Đoan Mộc đồng tử là lão quái Toái Niết trung kỳ mang thân hình nhỏ như trẻ con, mặt xanh đáng sợ, đi cùng một thanh trường kiếm lớn. Hắn tu luyện Nhật Nguyệt Hồi Đạo nên được Thương Tùng Tử mời tham gia chuyến tìm Hồi đan để cảm ngộ chín lần, song hai bên chỉ lợi dụng lẫn nhau. Về sau hắn bị Mê Thất Giả mang đi, khiến đoàn người thiếu mất ý cảnh thần thông của hắn.","vaiTro":"Lão quái Toái Niết trung kỳ được Thương Tùng Tử mời đi tìm Hồi đan","tinhCach":"Lòng dạ độc ác, chỉ lợi dụng lẫn nhau; kiên trì tu luyện dù chịu phản chấn thổ huyết","tabs":{"diem":[{"text":"Lần đầu được xác nhận là tu sĩ Toái Niết trung kỳ trong nhóm","chuong":"@c1109"},{"text":"Cưỡi kiếm quang ác liệt xuyên sương mù đến nơi tụ hội, lộ dáng vẻ thân nhỏ như trẻ con","chuong":"@c109"},{"text":"Bị Vương Lâm đánh giá là lòng dạ độc ác, chỉ lợi dụng lẫn nhau với Thương Tùng Tử","chuong":"@c111"},{"text":"Được mời tham gia vì tu luyện Nhật Nguyệt Hồi Đạo và cần Hồi đan để cảm ngộ chín lần","chuong":"@c1112"},{"text":"Dùng dấu ấn nhật nguyệt phong ấn Giao Long nhưng liên tục chịu phản chấn, thổ huyết","chuong":"@c113"},{"text":"Bị Mê Thất Giả mang đi, khiến đoàn người thiếu ý cảnh thần thông","chuong":"@c1115"}],"kinhLich":[{"mucCt":"ky","text":"Đoan Mộc đồng tử cưỡi kiếm quang ác liệt xuyên sương mù đến nơi tụ hội, để lộ dáng vẻ thân nhỏ như trẻ con, ngũ quan vặn vẹo và mặt xanh đáng sợ. Hắn phàn nàn bản đồ tinh cầu của Thương Tùng Tử khó tìm đường, hỏi về Hồi đan rồi trầm mặc khi biết nơi đó có Giao Long hóa sương cấp mười hai canh giữ. Hắn cũng quét mắt đánh giá Vương Lâm nhưng không nói gì.","anchor":"Thương Tùng Tử, ngươi đưa ta cái bản đồ tinh cầu quỷ quái gì mà tìm mãi mới tới đây được","bridge":true,"khoang":"@c1109"},{"mucCt":"vua","text":"Đoan Mộc đồng tử được Vương Lâm đánh giá là chỉ lợi dụng lẫn nhau với Thương Tùng Tử và lòng dạ độc ác. Sau khi vào thế giới bảy màu, hắn chú ý sương mù kỳ dị rồi chen lời nói theo hướng Vân Hồn Tử có thể tự đổi hướng hoặc bị truyền tới nơi khác, khiến nghi vấn nhằm vào Vương Lâm dịu xuống.","anchor":"Thật thú vị, Thương Tùng Tử, lời nói của vị đạo hữu này rất có đạo lý.","bridge":true,"khoang":"@c1111"},{"chuong":"@c1112","importance":"normal","tieuDe":"Hồi thuật phong thú","mucCt":"ky","text":"Đoan Mộc đồng tử được Thương Tùng Tử mời tới vì tu luyện Nhật Nguyệt Hồi Đạo và cần Hồi đan để cảm ngộ chín lần quay về ký ức. Hắn nhận ra mục đích thật của Thương Tùng Tử là mượn Hồi Đại Tự Tại mở đường qua sương mù, sau đó đồng ý tham gia phân chia lợi ích và lấy thân thể Giao Long. Khi giao chiến, hắn thi triển dấu ấn nhật nguyệt cùng Hồi thuật để ảnh hưởng Giao Long hóa sương trong mười nhịp thở, tạo Hồi Phong Ấn kiềm chế con thú và phóng phi kiếm công kích.","anchor":"Hồi thuật của ta chỉ ảnh hưởng đến con thú này trong khoảng thời gian mười lần hít thở"},{"mucCt":"ky","anchor":"Đoan Mộc phun ra máu tơi và không tiếp tục phong ấn","text":"Đoan Mộc dùng dấu ấn nhật nguyệt phong ấn Giao Long nhưng liên tục chịu phản chấn, thổ huyết và cuối cùng không thể giữ nổi khi dấu ấn tan vỡ. Sau trận, hắn nhận Hồi đan từ Vương Lâm, cảm kích ôm quyền nhưng chưa lập tức nuốt mà giữ lại để thổ nạp chữa thương. Cuối chương, hắn cùng Thương Tùng Tử dừng lại khi phát hiện dị thường trên con đường hẹp.","bridge":true,"khoang":"@c1113"},{"mucCt":"ky","text":"Đoan Mộc đứng cuối đoàn và vì phản ứng khi người áo xám đi ngang nên bị đối phương quay lại nhìn. Ý cảnh Nhật Nguyệt Hồi trên thiên linh của hắn bị kéo ra rồi nhập vào người áo xám, khiến vẻ mê man trong mắt hắn tiêu tán nhưng sinh cơ cũng mất đi. Sau đó tóc hắn rụng, thân thể trở nên trong suốt và hắn bước theo Mê Thất Giả rời khỏi đoàn.","anchor":"Vẻ mê man trong mắt đồng tử Đoan Mộc lập tức tiêu tán","bridge":true,"khoang":"@c1114"},{"chuong":"@c1115","importance":"bridge","mucCt":"gon","tieuDe":"Bị Mê Thất Giả mang đi","text":"Đoan Mộc đồng tử được nhắc là đã bị Mê Thất Giả mang đi, khiến đoàn người thiếu đi ý cảnh thần thông có thể phong ấn biến hóa cấm chế.","anchor":"Đáng tiếc là Đoan Mộc đạo hữu lại bị Mê Thất Giả mang đi"}],"tuViMoc":[{"chuong":"@c1109","canhGioi":"Toái Niết trung kỳ","text":"Lần đầu được xác nhận là tu sĩ Toái Niết trung kỳ trong nhóm được Thương Tùng Tử mời.","importance":"major"}],"nhanMach":[{"ten":"Thương Tùng Tử","tag":"dong-minh","quanHe":"Nhận bản đồ tinh cầu từ Thương Tùng Tử và tới tham gia chuyến đi.","ghiChu":"Gặp tại Man Hoang đại lục @c1109"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Quét mắt đánh giá khi gặp trong nhóm sáu người.","ghiChu":"Chưa nói chuyện trực tiếp @c1109"},{"ten":"Giao Long hóa sương cấp mười hai","tag":"doi-thu","quanHe":"Đối thủ bị hắn dùng Hồi thuật và Hồi Phong Ấn kiềm chế.","ghiChu":"Hắn muốn lấy thân thể Giao Long."},{"ten":"Người áo xám","tag":"khac","quanHe":"bị mang đi","ghiChu":"Bị Mê Thất Giả hút ý cảnh Nhật Nguyệt Hồi và dẫn đi trong thế giới bảy màu."},{"ten":"Mê Thất Giả","tag":"doi-thu","quanHe":"Bị mang đi","ghiChu":"Việc bị Mê Thất Giả mang đi khiến Đoan Mộc vắng mặt khi đoàn người cần trợ lực phong ấn cấm chế."}],"tuiDo":{"phapBao":[{"ten":"Thanh trường kiếm của Đoan Mộc đồng tử","loai":"phi kiếm","trangThai":"dang-co","moTa":"Trường kiếm lớn dùng để phi hành, kiếm quang ác liệt và có hàn khí.","nguon":"@c1109"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1109","@c1110","@c1111","@c1112","@c1113","@c1114","@c1115"]},{"id":"tran-thien-quan","name":"Trần Thiên Quân","cn":"陈天权","aliases":["Dịch Thú Tông Trần Thiên Quân"],"gioiTinh":"nam","theLuc":[{"ten":"Dịch Thú Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết sơ kỳ @c1109","trangThai":"song","blurb":"Trần Thiên Quân là tu sĩ Dịch Thú Tông cảnh Toái Niết sơ kỳ, sư đệ của Thiên Tử, thân hình cao lớn mặc áo bào tím. Dù tu vi thấp nhất trong nhóm, thuật ẩn giấu và thần thông luyện hóa mãnh thú của hắn khiến các lão quái Toái Niết trung kỳ phải thận trọng. Sau gần trăm năm cô độc trong Thất Thải Giới, hắn bị thân xác tan rã, nguyên thần chỉ còn một nửa vàầu Vương Lâm đưa về tông môn.","vaiTro":"Tu sĩ Dịch Thú Tông — sư đệ Thiên Tử, chuyên luyện hóa mãnh thú","tinhCach":"Giỏi ẩn giấu, nhiều mưu tính; thận trọng, tránh mạo hiểm khi thấy hiểm nguy; kính sợ và thán phục trước cường giả","tabs":{"diem":[{"text":"Được Vương Lâm nhìn nhận là kẻ nhiều mưu tính, ẩn giấu đến mức không ai phát hiện","chuong":"@c1111"},{"text":"Ẩn mình trong đầu Giao Long suốt trận để thu linh hồn mãnh thú","chuong":"@c1113"},{"text":"Dùng thần thông Dịch Thú Tông mạo hiểm thu hoạch nguyên tinh mãnh thú hóa sương cấp mười hai","chuong":"@c1140"},{"text":"Chứng kiến Vương Lâm tiêu diệt lão già tóc trắng Toái Niết hậu kỳ, kinh hoàng thán phục","chuong":"@c145"},{"text":"Cô độc gần trăm năm trong động phủ Thất Thải Giới, tuyệt vọng nhớ sư tôn và sư huynh đệ","chuong":"@c1152"},{"text":"Thân xác tan rã, nguyên thần bị chia đôi khi uy áp hạ xuống, gần chết","chuong":"@c1154"}],"kinhLich":[{"mucCt":"ky","text":"Trần Thiên Quân đã đến từ trước nhưng ẩn giấu đến mức không ai phát hiện, rồi bước ra trong áo bào tím cùng vài trăm mãnh thú. Hắn giết sạch đám mãnh thú, luyện linh hồn của chúng thành viên đan dược đen và nuốt vào, qua đó phô bày thần thông kỳ dị của Dịch Thú Tông. Hắn tự xưng là sư đệ của Thiên Tử, nói mình bị tinh vực cấp chín kêu gọi phải nhanh quay về, nên thúc Thương Tùng Tử hành sự mau chóng.","anchor":"Tiểu Thiên Tử là sư huynh của ta, tại là là Trần Thiên Quân","bridge":true,"khoang":"@c1109"},{"chuong":"@c1111","importance":"normal","tieuDe":"Kích động trước sương mù","mucCt":"vua","text":"Trần Thiên Quân của Dịch Thú Tông được Vương Lâm xem là người có mưu tính và không thật sự thân thiết với Thương Tùng Tử. Khi vào thế giới bảy màu, hắn tỏ vẻ cực kỳ kích động và cuồng nhiệt nhìn về sương mù phương xa.","anchor":"Vẻ mặt Trần Thiên Quân Dịch Thú Tông bên cạnh cũng trở nên cực kỳ kích động."},{"chuong":"@c1112","importance":"normal","tieuDe":"Đòi hồn Giao Long","mucCt":"vua","text":"Trần Thiên Quân hỏi về tên gọi và bản chất của thế giới bảy màu, rồi chú ý tới một động phủ trong núi. Khi biết Giao Long hóa sương canh giữ Hồi đan, hắn đòi lấy hồn phách của nó, sau đó dùng u quang xuất hiện dưới đầu Giao Long rồi dung nhập vào thân thể con thú.","anchor":"Ta muốn hồn phách của con Giao Long này!"},{"mucCt":"vua","anchor":"Trần Thiên Quân từ trong cái đầu tan nát của Giao Long phóng ra ngoài","text":"Trần Thiên Quân ẩn trong đầu Giao Long suốt trận để thu linh hồn, đến khi Vương Lâm quật vỡ đầu mãnh thú mới phóng ra ngoài. Hắn thừa nhận tuy chưa hấp thu hoàn toàn linh hồn Giao Long, phần thu hoạch của mình vẫn là lớn nhất trong trận.","bridge":true,"khoang":"@c1113"},{"mucCt":"vua","text":"Trần Thiên Quân bị biến cố Mê Thất Giả làm chấn động và nghi ngờ những người mất tích trong các lần trước đều biến thành Mê Thất Giả. Sau khi cho rằng theo Thương Tùng Tử vào đây là sai lầm, hắn tuyên bố rút lui và quay lại theo đường cũ, mặc cho Thương Tùng Tử nói hắn không thể tự trở về.","anchor":"Lần này theo ngươi đến đây cũng là một sai lầm","bridge":true,"khoang":"@c1114"},{"chuong":"@c1115","importance":"bridge","mucCt":"gon","tieuDe":"Dao động từ xa","text":"Trần Thiên Quân không trực tiếp hiện thân, nhưng dao động thần thông của hắn từ xa được Thương Tùng Tử nhận ra và bị lão giả họ Bàng phán đoán là đã lành ít dữ nhiều.","anchor":"Trần Thiên Quân này chắc chắn đã lành ít dữ nhiều"},{"chuong":"@c1124","importance":"bridge","mucCt":"gon","text":"Đang chữa thương trong động phủ đỉnh núi, mặt tái nhợt, y phục nâu lấm tấm máu, mở mắt khi nghe tiếng nổ La Bàn vỡ.","anchor":"trong lúc hắn đang chữa thương thì mở rộng hai mắt ra, hai bên tai lập tức vang lên tiếng nổ vang vọng ở phương xa"},{"chuong":"@c1125","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc: bỏ đi sớm, trên đường từng cảm nhận sóng rung động thần thông nhưng rất khó chứng minh hắn đã chết.","anchor":"Tất cả đám người ở đây đều thầm tính toán lẫn nhau, không ai muốn để kẻ khác cầm bảo vật bình yên rời khỏi đây"},{"mucCt":"vua","text":"Từ động phủ trên núi gần đó chứng kiến Vương Lâm giết Thương Tùng Tử, kinh sợ vã mồ hôi. Chủ động giải thích từng gặp mãnh thú cấp mười hai bị trọng thương, khẩn cầu Vương Lâm mang theo rời thế giới bảy màu, đổi lại dùng công pháp Dịch Thiên Tông thu thập nguyên tinh từ mãnh thú hóa sương. Được đồng ý, nhận ngọc giản truyền âm.","anchor":"Tại ha có công pháp đặc biệt, hơn nữa lại khá hiểu về mãnh thú nên mới miễn cưỡng chạy thoát được","bridge":true,"khoang":"@c1132"},{"mucCt":"vua","text":"Đang mạo hiểm thu hoạch nguyên tinh mãnh thú hóa sương cấp mười hai bằng thần thông Dịch Thú Tông, nhiều lần suýt chết. Khi biển lửa bạch sắc quét qua, sóng nhiệt vượt qua bên cạnh thân mà không giết hắn, hắn chấn động khi cảm nhận khí tức Vương Lâm trong biển lửa.","anchor":"Trần Thiên Quân cảm nhận được một luồng khí tức của Vương Lâm trong biển lửa","bridge":true,"khoang":"@c1140"},{"chuong":"@c1143","importance":"bridge","mucCt":"gon","text":"Theo dõi trận chiến từ xa, kinh hãi quyết định cả đời không mạo hiểm vào nơi có bảo vật.","anchor":"cả đời sẽ không bao giờ tiến vào bất kỳ vùng đất nào có chứa bảo vật"},{"chuong":"@c1145","importance":"bridge","mucCt":"vua","text":"Chứng kiến Vương Lâm tiêu diệt lão già tóc trắng Toái Niết hậu kỳ, kinh hoàng thán phục, nhận định tên tuổi Vương Lâm sẽ hiển hách ở Vân Hải tinh vực.","anchor":"có thể đứng đây chứng kiến thần thông của hắn thì Trần Thiên Quân ta cũng quá vinh hạnh"},{"chuong":"@c1147","importance":"bridge","mucCt":"gon","text":"Ở trong thế giới bảy màu, ngồi trong bóng đêm chờ đợi suốt trăm năm.","anchor":"Trần Thiên Quân và lão phụ nhân áo xanh cũng ở trong thế giới bảy màu này"},{"mucCt":"vua","text":"Suốt gần 100 năm cô độc trong động phủ Thất Thải Giới, tuyệt vọng nhớ sư tôn và sư huynh đệ ở tầng chín tinh vực. Khi Vương Lâm tỉnh, hy vọng bùng lên. Được Vân Hồn Tử mời tới gặp Vương Lâm, kích động gọi Lữ huynh, giao túi trữ vật chứa nguyên tinh, được hứa sẽ đưa rời khỏi đây.","anchor":"Rốt cuộc cũng có thể đi ra ngoài.","bridge":true,"khoang":"@c1152"},{"chuong":"@c1153","importance":"bridge","mucCt":"gon","text":"Tận mắt nhìn Vương Lâm phá núi đá bằng một quyền, ánh mắt càng thêm kính sợ, được Vương Lâm cuốn theo rời sơn cốc.","anchor":"ánh mắt nhìn về phía Vương Lâm càng thêm phần kính sợ"},{"importance":"normal","mucCt":"ky","chuong":"@c1154","tieuDe":"Thân xác tan rã, nguyên thần bị chia đôi","text":"Tu vi yếu nhất trong bốn người, phun máu ngay khi uy áp hạ xuống. Phóng hơn mười thú hồn gồm hai hồn phách mãnh thú cấp mười hai cực suy yếu cùng chiến đấu. Không chịu nổi lực hút cơn lốc xoáy, thân xác tan rã thành đám máu thịt bị hút vào. Nguyên thần giãy giụa kêu cứu, bị chia đôi — một phần bị cơn lốc xoáy nuốt mất, phần còn lại được Vương Lâm giằng co giật về.","anchor":"Ngươi đã hứa mang ta ra ngoài! Ngươi đã hứa!"},{"chuong":"@c1159","importance":"normal","mucCt":"vua","tieuDe":"Xin Vương Lâm đưa về Dịch Thú Tông","text":"Nguyên thần chỉ còn một nửa, gần chết, lúc nào cũng có thể tiêu tán. Xin Vương Lâm đưa về Dịch Thú Tông để sư tôn cứu chữa, Vương Lâm đáp ứng và thu hồi nguyên thần.","anchor":"Sư tôn của tôi sẽ cứu tôi"}],"tuViMoc":[{"chuong":"@c1109","canhGioi":"Toái Niết sơ kỳ","text":"Lần đầu được xác nhận là tu sĩ Toái Niết sơ kỳ của Dịch Thú Tông.","importance":"major"}],"nhanMach":[{"ten":"Thiên Tử","tag":"su-mon","quanHe":"Sư huynh trong Dịch Thú Tông.","ghiChu":"Do Trần Thiên Quân tự xác nhận @c1109"},{"ten":"Vân Hồn Tử","tag":"khac","quanHe":"Được Vân Hồn Tử nhận ra là người của Dịch Thú Tông.","ghiChu":"Vân Hồn Tử từng giao hỏa với Thiên Tử @c1109"},{"ten":"Thương Tùng Tử","tag":"dong-minh","quanHe":"Tạm tham gia chuyến đi do Thương Tùng Tử tổ chức.","ghiChu":"Thúc đối phương làm nhanh @c1109"},{"ten":"Giao Long hóa sương cấp mười hai","tag":"doi-thu","quanHe":"Nhắm tới hồn phách Giao Long trong trận tranh đoạt lợi ích.","ghiChu":"Hắn dùng u quang dung nhập vào thân Giao Long."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"đồng hành tạm thời","ghiChu":"Cùng ở trong đoàn tiến vào thế giới bảy màu trước khi rút lui."},{"ten":"Bà lão áo xanh","tag":"dong-minh","quanHe":"đồng hành tạm thời","ghiChu":"Cùng ở trong đoàn tiến vào thế giới bảy màu."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Viên đan dược đen","loai":"đan dược luyện từ thú hồn","trangThai":"da-dung","moTa":"Được luyện tức thì từ linh hồn vài trăm mãnh thú rồi nuốt vào.","nguon":"@c1109"}],"congPhap":[{"ten":"Thuật ẩn dấu Dịch Thú Tông","loai":"thần thông","trangThai":"dang-co","moTa":"Che giấu khí tức khiến nhóm lão quái không phát hiện hắn đã đến từ trước.","nguon":"@c1109"},{"ten":"Thần thông luyện hóa mãnh thú Dịch Thú Tông","loai":"thần thông","trangThai":"dang-co","moTa":"Giết thú, rút linh hồn và luyện thành đan dược đen.","nguon":"@c1109"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1109","@c1110","@c1111","@c1112","@c1113","@c1114","@c1115","@c1124","@c1125","@c1132","@c1140","@c1143","@c1145","@c1147","@c1152","@c1153","@c1154","@c1159"]},{"id":"thien-tu","name":"Thiên Tử","cn":"","aliases":["Tiểu Thiên Tử"],"gioiTinh":"nam","theLuc":[{"ten":"Dịch Thú Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Thiên Tử là tu sĩ Dịch Thú Tông từng giao hỏa với Vân Hồn Tử. Trần Thiên Quân xác nhận người này là sư huynh của mình.","vaiTro":"Sư huynh Dịch Thú Tông được nhắc tới","tinhCach":[{"text":"Chưa bộc lộ trực tiếp trong chương, chỉ được nhắc qua quan hệ và quá khứ giao hỏa","chuong":"@c1109"}],"tabs":{"diem":[{"text":"Là người của Dịch Thú Tông từng giao hỏa với Vân Hồn Tử.","chuong":"@c1109"},{"text":"Được Trần Thiên Quân gọi là sư huynh.","chuong":"@c1109"}],"kinhLich":[{"chuong":"@c1109","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc bởi đồng môn","text":"Thiên Tử được Vân Hồn Tử nhắc là người của Dịch Thú Tông từng giao hỏa với lão, đồng thời được Trần Thiên Quân xác nhận là sư huynh.","anchor":"Lão phu Vân Hồn Tử từng có giao hỏa với Thiên Tử đạo hữu của quý tông"}],"tuViMoc":[],"nhanMach":[{"ten":"Trần Thiên Quân","tag":"su-mon","quanHe":"Sư huynh của Trần Thiên Quân trong Dịch Thú Tông.","ghiChu":"Được Trần Thiên Quân xác nhận @c1109"},{"ten":"Vân Hồn Tử","tag":"doi-thu","quanHe":"Từng giao hỏa với Vân Hồn Tử.","ghiChu":"Do Vân Hồn Tử nhắc lại @c1109"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1109"]},{"id":"giao-long-hoa-suong-cap-muoi-hai","name":"Giao Long hóa sương cấp mười hai","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Tương đương Toái Niết đại viên mãn @c1112","trangThai":"tu-vong","blurb":"Mãnh thú cấp mười hai canh giữ khu Hồi đan trong thế giới bảy màu. Nó lao ra từ sương mù với uy áp vượt Toái Niết và trở thành mục tiêu vây công của đoàn người.","vaiTro":"Mãnh thú canh giữ Hồi đan","tinhCach":[{"text":"Hung dữ, phản ứng bằng uy áp và công kích trực diện","chuong":"@c1112"},{"text":"Cố vùng thoát khỏi đạo cảnh phong ấn khi bị vây công","chuong":"@c1112"}],"nguon":["@c1112","@c1113"],"tabs":{"diem":[{"text":"Là mãnh thú hóa sương cấp mười hai, được mô tả tương đương tu sĩ Toái Niết đại viên mãn.","chuong":"@c1112"},{"text":"Canh giữ khu vực có Hồi đan và hài cốt trên con đường hẹp.","chuong":"@c1112"},{"text":"Khi xuất hiện, uy áp của nó còn mạnh hơn Toái Niết và khiến đoàn người phải hợp lực đối phó.","chuong":"@c1112"}],"kinhLich":[{"mucCt":"vua","text":"Giao Long hóa sương cấp mười hai canh giữ khu Hồi đan, được Thương Tùng Tử xác nhận tương đương tu sĩ Toái Niết đại viên mãn. Sau khi bị Hồi thuật kích động, nó lao ra từ sương mù với uy áp mạnh hơn Toái Niết, bị Đoan Mộc phong ảnh hưởng ngắn hạn rồi bị Trần Thiên Quân, Thương Tùng Tử, bà lão áo xanh, lão giả họ Bàng và Vương Lâm cùng vây công.","anchor":"Đây là một mãnh thú Giao Long hóa sương cấp mười hai tương đương với tu sĩ Toái Niết đại viên mãn","bridge":true,"khoang":"@c1112"},{"mucCt":"ky","anchor":"thân thể khổng lồ của Giao Long trực tiếp đập mạnh xuống con đường hẹp","text":"Giao Long hóa sương cấp mười hai bị nhóm tu sĩ vây công bằng phi kiếm, lô cầu, kiếm vũ, huyền băng và phong ấn nhật nguyệt. Sau khi phá vỡ phong ấn, nó dần hóa thành thân thể thật, dùng sừng đen hút nguyên lực thiên địa và ánh sáng bảy màu để tạo lưới điện cùng nhiều hư ảnh Giao Long. Khi sắp thăng không, nó bị Vương Lâm dùng lực Cổ Thần kéo đuôi quật xuống con đường hẹp, đầu vỡ tan, sau đó thi thể bị thu linh hồn, hắc khí và máu huyết.","bridge":true,"khoang":"@c1113"}],"tuViMoc":[],"nhanMach":[{"ten":"Đoan Mộc đồng tử","tag":"doi-thu","quanHe":"Bị Đoan Mộc dùng Hồi thuật và Hồi Phong Ấn kiềm chế.","ghiChu":"Đoan Mộc muốn lấy thân thể của nó."},{"ten":"Trần Thiên Quân","tag":"doi-thu","quanHe":"Bị Trần Thiên Quân nhắm tới hồn phách.","ghiChu":"Trần Thiên Quân dùng u quang dung nhập vào thân nó."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm áp sát đánh quyền vào thân thể.","ghiChu":"Vương Lâm đòi nguyên tinh trong sương mù trước trận đánh."},{"ten":"Thương Tùng Tử","tag":"doi-thu","quanHe":"Bị Thương Tùng Tử dùng mưa phi kiếm công kích.","ghiChu":"Thương Tùng Tử cần vượt qua khu vực nó canh giữ."},{"ten":"Bà lão áo xanh","tag":"doi-thu","quanHe":"Bị bà dùng gió tuyết công kích.","ghiChu":"Diễn ra trong trận vây công tại con đường hẹp."},{"ten":"Lão giả họ Bàng","tag":"doi-thu","quanHe":"Bị lão dùng lôi quang và lôi cầu công kích.","ghiChu":"Diễn ra trong trận vây công tại khu Hồi đan."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"nguoi-ao-xam","name":"Người áo xám","cn":"","aliases":["Mê Thất Giả"],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"không rõ @c1114","trangThai":"song @c1114","blurb":"Người áo xám là một Mê Thất Giả trong thế giới bảy màu, thân thể trong suốt, không tóc và hai mắt không còn sinh khí. Sự xuất hiện của nó khiến đoàn tu sĩ nhận ra nguy cơ người bị mang đi có thể biến thành Mê Thất Giả mới.","vaiTro":"Mê Thất Giả trong thế giới bảy màu","tinhCach":[{"text":"vô sinh khí, hành động quỷ dị","chuong":"@c1114"},{"text":"có thể đoạt ý cảnh và dẫn người khác đi theo","chuong":"@c1114"}],"tabs":{"diem":[{"text":"Thân thể trong suốt, không tóc, mắt không có sinh khí, xuất hiện cùng hàn khí sau lưng đoàn tu sĩ.","chuong":"@c1114"},{"text":"Có thể khiến thi thể Giao Long thối rữa thành máu mà không thấy ra tay rõ ràng.","chuong":"@c1114"},{"text":"Hút ý cảnh Nhật Nguyệt Hồi khỏi Đoan Mộc và khiến Đoan Mộc đi theo mình, thân thể dần trong suốt.","chuong":"@c1114"}],"kinhLich":[{"mucCt":"ky","text":"Người áo xám xuất hiện sau đoàn tu sĩ trong hàn khí, đi tới bên thi thể Giao Long và khiến xác này thối rữa thành máu. Khi Đoan Mộc động tâm niệm và nhìn thẳng nó, nó quay lại, hút hư ảnh Nhật Nguyệt Hồi trên thiên linh của Đoan Mộc nhập vào thân mình. Sau đó Đoan Mộc mất sinh cơ, tóc rụng, thân thể dần trong suốt và đi theo nó rời khỏi đoàn.","anchor":"Tên áo xám vừa rồi chính là Mê Thất Giả","bridge":true,"khoang":"@c1114"}],"tuViMoc":[],"nhanMach":[{"ten":"Đoan Mộc đồng tử","tag":"khac","quanHe":"mang đi","ghiChu":"Hút ý cảnh Nhật Nguyệt Hồi của Đoan Mộc rồi khiến hắn đi theo mình."},{"ten":"Thương Tùng Tử","tag":"khac","quanHe":"bị nhận ra lai lịch","ghiChu":"Thương Tùng Tử gọi nó là Mê Thất Giả và nói nó từng là đạo hữu bị mang đi."},{"ten":"Vương Lâm","tag":"khac","quanHe":"chạm mặt","ghiChu":"Vương Lâm nhìn thấy rõ nó xuất hiện phía sau đoàn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1114"]},{"id":"me-that-gia","name":"Mê Thất Giả","gioiTinh":"khong-ro","trangThai":"song","blurb":"Mê Thất Giả được nhắc tới qua việc mang Đoan Mộc đồng tử đi, khiến đoàn thăm dò mất một trợ lực quan trọng trong lúc phá cấm chế.","vaiTro":"Kẻ mang Đoan Mộc đi","tinhCach":[{"text":"Bí ẩn, chỉ hiện qua hậu quả để lại","chuong":"@c1115"}],"tabs":{"diem":[{"text":"Đã mang Đoan Mộc đạo hữu đi khỏi đoàn người.","chuong":"@c1115"}],"kinhLich":[{"chuong":"@c1115","importance":"bridge","mucCt":"gon","tieuDe":"Mang Đoan Mộc đi","text":"Mê Thất Giả được nhắc là đã mang Đoan Mộc đạo hữu đi, làm đoàn người không còn trợ lực phong ấn biến hóa cấm chế.","anchor":"Đoan Mộc đạo hữu lại bị Mê Thất Giả mang đi"}],"tuViMoc":[],"nhanMach":[{"ten":"Đoan Mộc đồng tử","tag":"doi-thu","quanHe":"Đã mang đi","ghiChu":"Việc này khiến Đoan Mộc vắng mặt khi đoàn người gặp Cửu Bộ Phong Tiên Trận."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1115","@c1129"]},{"id":"tan-ma","name":"Tán Ma","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1117","importance":"bridge","mucCt":"gon","tieuDe":"Khôi giáp bị truy dấu","text":"Tán Ma không xuất hiện trực tiếp, nhưng tên gắn với Tán Ma khôi giáp mà Vương Lâm cảm ứng và quyết định truy theo.","anchor":"- Tán Ma khôi giáp của Vương mỗ, người khác há có thể mặc được sao?"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1117"]},{"id":"ly-nguyen","name":"Lý Nguyên","gioiTinh":"nam","trangThai":"song","tabs":{"diem":[{"text":"Thoát khỏi nô ấn mi tâm khi tượng đá biến hóa tại Lôi Tiên Giới, lấy lại tự do sau thời gian dài bị khống chế","chuong":"@c0710"},{"text":"Truyền Mai hoa thập tam cấm, Phá Diệt cấm chế và Ẩn Nặc thuật cho Vương Lâm, tính toán bố trí 1465 điểm sụp đổ bằng cấm chế trước khi rời đi","chuong":"@c0715"},{"text":"Đồng hành cùng Vương Lâm dò phá cấm chế trong Lôi chi Tiên giới, hỗ trợ tìm kiếm tiên thuật và bảo vật tại Tàng Phẩm Các","chuong":"@c0727"},{"text":"Tin tưởng Vương Lâm, mạo hiểm thoát khỏi Lôi Tiên Giới qua Lôi Đỉnh dù thần thông chưa ổn định, bị thương nặng trong quá trình","chuong":"@c0740"},{"text":"Vì báo ân mà chia nửa Tâm cấm trong cơ thể cho Vương Lâm, khiến bản thân mệt mỏi già nua và tu vi suy giảm","chuong":"@c0805"},{"text":"Tu vi đạt Tịch Niết hậu kỳ đại viên mãn, dẫn đầu nhóm tu sĩ tiểu bối thăm dò bên ngoài Phong Tiên Giới","chuong":"@c1164"}],"kinhLich":[{"chuong":"@c1118","importance":"bridge","mucCt":"gon","tieuDe":"Lời cũ về Tứ Cấm","text":"Lý Nguyên được Vương Lâm nhớ lại qua lời giải thích cũ về nguồn gốc cấm chế, Tứ Đại Cấm Thuật và khả năng dung hợp bốn cấm để cảm ngộ Hư Thật.","anchor":"Năm xưa khi ta rời khỏi La Thiên thì Lý Nguyên từng nói"},{"mucCt":"vua","text":"Dẫn đầu nhóm hơn mười tu sĩ tiểu bối thăm dò bên ngoài khe Phong Tiên Giới, cảm nhận Vương Lâm quỷ dị khó lường, chủ động mời hợp tác nhưng bị từ chối. Khi đàn Văn Thú đỏ phun ra, hét lớn cảnh báo đồng bọn dùng Tế Thiên Hương xua đuổi. Sau cùng kinh hãi trước cảnh toàn bộ Văn Thú cung kính nghênh đón Vương Lâm vào Phong Tiên Giới.","anchor":"tu vi có vẻ đạt tới Tịnh Niết hậu kỳ đại viên mãn","bridge":true,"khoang":"@c1164"},{"chuong":"@c1165","importance":"bridge","mucCt":"gon","text":"Quan sát cảnh đàn Văn Thú đỏ nghênh đón Văn Thú Vương của Vương Lâm khi tiến vào Phong Tiên Giới.","anchor":"theo đám người Lý Nguyên Lôi nhìn, thì những Văn Thú màu đỏ này quả thật đang tiếp đón vua của chúng"}],"tuViMoc":[{"chuong":"@c1164","canhGioi":"Tịch Niết hậu kỳ đại viên mãn","text":"Được xác nhận tu vi đạt Tịch Niết hậu kỳ đại viên mãn, cao nhất nhóm tiểu bối.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người lạ mặt mà Lý Nguyên Lôi chủ động mời hợp tác, bị từ chối","ghiChu":"Cảm nhận Vương Lâm quỷ dị khó lường, sau kinh hãi trước cảnh Văn Thú nghênh đón hắn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1118","@c1164","@c1165"],"canhGioiCaoNhat":"Tịch Niết hậu kỳ đại viên mãn","vaiTro":"Tu sĩ cấm chế của Lý gia — đồng hành trọng yếu của Vương Lâm tại Lôi Tiên Giới","tinhCach":"tinh thông cấm chế, giỏi tính toán bố cục trận pháp; trọng ân nghĩa, sẵn sàng hy sinh tu vi để báo ân; dám mạo hiểm đặt tính mạng khi tin người; mưu trí thận trọng nhưng quyết đoán lúc cần","blurb":"Lý Nguyên là nam tu xuất thân Lý gia, gia tộc chuyên về cấm chế, từng bị nô ấn và mệnh hồn ràng buộc bởi thế lực khác khiến hắn mất tự do trong thời gian dài. Sau khi thoát nô ấn tại Lôi Tiên Giới nhờ biến cố liên quan đến tượng đá, hắn trở thành đồng hành đắc lực của Vương Lâm, nhiều lần dùng tạo nghệ cấm chế dò phá trận pháp, tìm bảo vật và tiên thuật trong Lôi chi Tiên giới, rồi cùng Vương Lâm thoát khỏi nơi đó qua Lôi Đỉnh. Về sau, Lý Nguyên vì báo ân mà chia nửa Tâm cấm trong cơ thể cho Vương Lâm, khiến bản thân suy kiệt, nhưng sau đó tu vi đạt tới Tịch Niết hậu kỳ đại viên mãn và dẫn đầu","aliases":["Lý Nguyên"]},{"id":"minh-chi-gia","name":"Minh Chí Giả","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Có đạo cảnh nhưng không có Đạo Kinh @c1118","trangThai":"song","blurb":"Minh Chí Giả là tồn tại được Thương Tùng Tử gọi tên trong vùng sương mù của thế giới bảy màu. Họ còn chấp niệm đạo hồn, liên quan trực tiếp tới bí mật Đạo Kinh.","vaiTro":"Tàn lưu đạo hồn truy tìm Đạo Kinh","tinhCach":[{"text":"Chấp niệm sâu nặng với Đạo Kinh","chuong":"@c1118"},{"text":"Tồn tại dưới dạng âm thanh và hư ảnh quỷ dị trong sương mù","chuong":"@c1118"}],"tabs":{"diem":[{"text":"Có đạo cảnh nhưng không có Đạo Kinh, khiến đạo tâm tan vỡ và chỉ còn chấp niệm đạo hồn.","chuong":"@c1118"},{"text":"Âm thanh và hư ảnh của họ có thể xuyên thấu tâm thần, khiến Thương Tùng Tử tái mặt và lão bà áo xanh nguyên thần chấn động.","chuong":"@c1118"}],"kinhLich":[{"chuong":"@c1118","importance":"normal","mucCt":"vua","tieuDe":"Hiện thân trong sương mù","text":"Minh Chí Giả xuất hiện qua âm thanh quỷ dị và hư ảnh trong vùng sương mù, trực tiếp xuyên qua Thương Tùng Tử cùng lão bà áo xanh. Thương Tùng Tử giải thích họ là những kẻ có đạo cảnh nhưng không có Đạo Kinh, đạo tâm tan vỡ, chỉ còn chấp niệm đạo hồn truy tìm sau nhiều vạn năm.","anchor":"Minh Chí Giả có đạo cảnh nhưng lại không có Đạo Kinh"},{"chuong":"@c1121","importance":"bridge","mucCt":"gon","tieuDe":"Bị chấn động kéo tới","text":"Các Minh Chí Giả ngoài sương mù bị vụ nổ trong vùng giao chiến kinh động và đồng loạt phóng về nơi phát ra tiếng nổ.","anchor":"tất cả những bóng hình đang vật vờ bên ngoài lập tức dừng hẳn lại, sau đó toàn bộ Minh Chí Giả đều phóng về phía địa phương phát ra tiếng nổ."}],"tuViMoc":[],"nhanMach":[{"ten":"Thương Tùng Tử","tag":"khac","quanHe":"Bị Thương Tùng Tử nhận ra và giải thích lai lịch.","ghiChu":"Sự xuất hiện của Minh Chí Giả khiến tuyến Đạo Kinh lộ diện."},{"ten":"Lão bà áo xanh","tag":"khac","quanHe":"Âm thanh và hư ảnh khiến nguyên thần lão bà áo xanh chấn động.","ghiChu":"Lão bà áo xanh hỏi Thương Tùng Tử về Minh Chí Giả và Đạo Kinh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1118","@c1121","@c1129"]},{"id":"nguoi-phu-nu-trung-nien-ao-xanh-ho-trieu","name":"Người phụ nữ trung niên áo xanh họ Triệu","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"không rõ @c1120","trangThai":"song @c1120","blurb":"Nữ tu họ Triệu hiện thân trong không gian tấm bia sau khi Thương Tùng Tử đoạt bình ngọc. Nàng có dung mạo giống hệt bà lão áo xanh và được liên hệ với cấm thuật Dương Tụ Âm Quy.","vaiTro":"Nữ tu họ Triệu ngăn Thương Tùng Tử","tinhCach":[{"text":"Phản ứng quyết liệt khi bình ngọc bị đoạt","chuong":"@c1120"},{"text":"Sử dụng cấm chế để phòng thủ và đánh chặn","chuong":"@c1120"}],"tabs":{"diem":[{"text":"Huyễn hóa trong không gian tấm bia đúng lúc Thương Tùng Tử vừa nhấc bình ngọc khỏi trận pháp.","chuong":"@c1120"},{"text":"Dùng nhiều cấm chế tạo vòng xoáy nước chống lại bốn tiểu kiếm kim quang.","chuong":"@c1120"}],"kinhLich":[{"mucCt":"vua","text":"Người phụ nữ trung niên áo xanh họ Triệu huyễn hóa trong không gian tấm bia khi Thương Tùng Tử đoạt bình ngọc. Nàng dùng nhiều cấm chế tạo vòng nước xoáy ngăn bốn tiểu kiếm, nhưng tiểu kiếm tan thành chất lỏng vàng xuyên qua phòng hộ và lao về phía nàng.","anchor":"Không trung đột nhiên trở nên vặn vẹo, người phụ nữ trung niên xinh đẹp đột nhiên huyễn hóa ra","bridge":true,"khoang":"@c1120"}],"tuViMoc":[],"nhanMach":[{"ten":"Thương Tùng Tử","tag":"doi-thu","quanHe":"Hiện thân ngăn lão rời đi sau khi lão đoạt bình ngọc.","ghiChu":"Bị bốn tiểu kiếm kim quang của lão xuyên qua vòng xoáy cấm chế."},{"ten":"Bà lão áo xanh","tag":"khac","quanHe":"Cùng họ Triệu, dung mạo giống hệt và liên quan cấm thuật Dương Tụ Âm Quy.","ghiChu":"Chương chưa xác định quan hệ cụ thể ngoài dấu hiệu thuật pháp ba đời."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Dương Tụ Âm Quy","loai":"cấm thuật","trangThai":"dang-co","moTa":"Nàng là một trong hai nữ tu họ Triệu có dung mạo giống nhau khiến Thương Tùng Tử nhận ra cấm thuật này.","nguon":"@c1120"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1120"]},{"id":"ba-lao-ao-xanh-ho-trieu","name":"Bà lão áo xanh họ Triệu","cn":"","aliases":["lão bà áo xanh"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"không rõ @c1120","trangThai":"song @c1120","blurb":"Bà lão áo xanh họ Triệu hiện ra trước mặt Thương Tùng Tử trong không gian tấm bia. Dung mạo của bà giống người phụ nữ trung niên áo xanh họ Triệu, khiến Thương Tùng Tử nhận ra cấm thuật Dương Tụ Âm Quy.","vaiTro":"Người hé lộ Dương Tụ Âm Quy","tinhCach":[{"text":"Ẩn nhẫn tới thời điểm Thương Tùng Tử định rời đi mới hiện thân","chuong":"@c1120"},{"text":"Gắn với cấm thuật nhiều đời chung thân bí hiểm","chuong":"@c1120"}],"tabs":{"diem":[{"text":"Đột nhiên hiện ra khi Thương Tùng Tử định rời khỏi không gian tấm bia.","chuong":"@c1120"},{"text":"Sự xuất hiện của bà khiến Thương Tùng Tử nhận ra đây không phải phân thân mà là Dương Tụ Âm Quy.","chuong":"@c1120"}],"kinhLich":[{"mucCt":"vua","text":"Bà lão áo xanh họ Triệu hiện ra trước mặt Thương Tùng Tử khi lão định rời khỏi không gian tấm bia. Dung mạo giống hệt người phụ nữ trung niên áo xanh họ Triệu khiến lão nhận ra Dương Tụ Âm Quy đã đạt cảnh giới ba đời.","anchor":"Hinh bóng này cũng áo xanh, không ngờ chính là lão bà áo xanh","bridge":true,"khoang":"@c1120"}],"tuViMoc":[],"nhanMach":[{"ten":"Thương Tùng Tử","tag":"doi-thu","quanHe":"Hiện thân chặn trước mặt lão trong không gian tấm bia.","ghiChu":"Sự xuất hiện của bà làm lão nhận ra cấm thuật Dương Tụ Âm Quy."},{"ten":"Người phụ nữ trung niên áo xanh họ Triệu","tag":"khac","quanHe":"Cùng họ Triệu và có dung mạo giống hệt.","ghiChu":"Liên quan tới tổ thuật mẹ con nhiều đời chung thân."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Dương Tụ Âm Quy","loai":"cấm thuật","trangThai":"dang-co","moTa":"Sự hiện thân của bà cùng người phụ nữ trung niên áo xanh là dấu hiệu khiến Thương Tùng Tử nhận ra cấm thuật này.","nguon":"@c1120"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1120"]},{"id":"lao-phu-nhan-ao-xanh","name":"Lão phụ nhân áo xanh","aliases":["Lão Bà Tử","lão bà họ Triệu","Triệu đạo hữu","lão bà áo xanh"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Tứ Tổ, Toái Niết trung kỳ đỉnh phong @c1121","trangThai":"song","blurb":"Lão phụ nhân áo xanh họ Triệu là cường giả Tứ Tổ Toái Niết trung kỳ đỉnh phong ẩn thân trong hư vô tại thế giới bảy màu. Bà phục kích Thương Tùng Tử rồi truy sát Vương Lâm bằng độc, Sinh Tử Cấm và Phá Diệt Cấm, nhưng cuối cùng bị chính trận pháp giam hãm và khiếp sợ trước thực lực đối phương. Sau khi liều mạng nghênh chiến, bà bị Vương Lâm phong ấn nguyên thần và đánh tụt tu vi xuống Tịch Niết.","vaiTro":"Đối thủ truy sát Tứ Tổ trong thế giới bảy màu","tinhCach":"Xảo quyệt, ẩn trong hư vô phục kích và giăng cấm chế; thức thời, chuyển từ oán niệm sang cầu hòa khi nhận ra thua kém; liều lĩnh, dám dâng Sinh Tử Cấm đổi mạng","tabs":{"diem":[{"text":"Cường giả Tứ Tổ Toái Niết trung kỳ đỉnh phong, khiến Thương Tùng Tử nhận ra không thể coi thường","chuong":"@c1121"},{"text":"Từ hư vô hiện thân phục kích Thương Tùng Tử rồi truy kích Vương Lâm, kích hoạt cấm chế trong sơn cốc","chuong":"@c1122"},{"text":"Bị chính Sinh Tử Cấm và Phá Diệt Cấm dung hợp giam hãm, thương nặng và đạo tâm hỗn loạn","chuong":"@c1130"},{"text":"Oán niệm với Vương Lâm tan biến thành kinh sợ, tự nhận không phải đối thủ và quyết tâm cầu hòa","chuong":"@c1145"},{"text":"Dùng Sinh Tử Cấm chế hóa sinh tử nhị khí thành rồng khí chống lại đòn tấn công","chuong":"@c1154"},{"text":"Bị Vương Lâm phong ấn nguyên thần, công pháp bị phá và tu vi tụt xuống Tịch Niết","chuong":"@c1159"}],"kinhLich":[{"mucCt":"ky","text":"Lão phụ nhân áo xanh từ hư vô hiện thân phục kích Thương Tùng Tử khi lão định rời qua sóng gợn, khiến tay trái đối phương trúng kịch độc. Bà phá mưa kiếm, phong ấn nguyên anh hình người, dung hợp ba nguyên thần, dùng Sinh Tử Cấm đối đầu Nghịch Hành Giả rồi truy sát Vương Lâm sau khi bình ngọc bị đoạt. Trong cuộc truy sát, bà hóa hư ảnh bò cạp độc khổng lồ và tiếp tục dùng ba luồng Sinh Tử Cấm đánh về phía Vương Lâm.","anchor":"Trong hư không cách đó không xa xuất hiện một bà lão rất già, giống như một lão phụ nhân từ trong quan tài đi ra.","bridge":true,"khoang":"@c1121"},{"mucCt":"ky","text":"Lão phụ nhân áo xanh truy kích Vương Lâm và kích hoạt cấm chế trong sơn cốc bằng hai tay bấm quyết, tạo vòng xoáy khói đen nhằm cuốn hắn lại. Vương Lâm xoay người điều khiển ngược vòng xoáy, mở hàng vạn cấm chế rồi dung hợp Sinh Tử Cấm với Phá Diệt Cấm để bao phủ toàn thân bà ta. Bên trong cấm chế truyền ra tiếng rên, tiếng nổ và huyết quang, khiến bà ta rơi vào tình cảnh sinh tử nhưng chưa xác nhận đã chết.","anchor":"tiếng rên nhẹ của lão phụ nhân lại rõ ràng truyền ra","bridge":true,"khoang":"@c1122"},{"chuong":"@c1124","importance":"normal","mucCt":"gon","tieuDe":"Bị giam trong cấm chế dung hợp, thương nặng","text":"Bị mắc kẹt trong sơn cốc bởi Sinh Tử Cấm và Phá Diệt Cấm dung hợp, uy lực vượt xa tưởng tượng, liên tục bấm pháp quyết chống cự nhưng thân bị thương nghiêm trọng, ngẩng đầu ngạc nhiên khi nghe tiếng nổ La Bàn vỡ.","anchor":"uy lực cấm chế nơi đây đã vượt xa sức tưởng tượng của lão bà"},{"chuong":"@c1125","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc: đang bị nhốt trong trận pháp có Phá Diệt Tâm Cấm ẩn giấu, muốn phá ra ngoài tuyệt đối không đơn giản.","anchor":"bên trong nó lại ẩn giấu Phá Diệt Tâm Cấm của ta"},{"mucCt":"vua","text":"Bị giam trong trận pháp Phá Diệt Cấm kết hợp Sinh Tử Cấm, đạo tâm hỗn loạn. Tướng mạo biến đổi liên tục giữa khô gầy, tang thương, trung niên khi tâm thần Vương Lâm nhìn xuyên qua.","anchor":"Tướng mạo của bà lão áo xanh đang nhanh chóng biến đổi, khi thì khô gầy, lúc thì tang thương, chốc chốc lại là trung niên","bridge":true,"khoang":"@c1130"},{"mucCt":"gon","text":"Trận pháp phong ấn lão bà đã bị mở, bên trong không còn bóng dáng lão bà áo xanh.","anchor":"trận pháp đã bị mở ra, bên trong đã không còn bóng dáng của lão bà áo xanh","bridge":true,"khoang":"@c1134"},{"chuong":"@c1140","importance":"bridge","mucCt":"gon","text":"Vẻ mặt trắng bệch không còn chút máu khi biển lửa bao phủ sơn cốc thế giới bảy màu.","anchor":"Lần đầu tiên sau rất nhiều năm trong dãy núi hình vòng cung đã không còn sương mù"},{"chuong":"@c1143","importance":"bridge","mucCt":"gon","text":"Cảm nhận trận chiến kinh hồn, oán niệm đối với Vương Lâm tan biến thay bằng kinh sợ, tự nhận không phải đối thủ.","anchor":"Ta cũng không phải là đối thủ nếu so sánh với hắn"},{"chuong":"@c1145","importance":"bridge","mucCt":"vua","text":"Chứng kiến trận chiến, sợ hãi sâu sắc, hạ quyết tâm phải tạo quan hệ tốt với Vương Lâm để bù đắp xung đột trước đó.","anchor":"Nhất định phải nhanh chóng tạo ra mối quan hệ tốt với người này để bù đắp xung đột trước đó"},{"chuong":"@c1147","importance":"bridge","mucCt":"gon","text":"Ở trong thế giới bảy màu cùng Trần Thiên Quân, ngồi trong bóng đêm chờ đợi.","anchor":"Trần Thiên Quân và lão phụ nhân áo xanh cũng ở trong thế giới bảy màu này"},{"mucCt":"vua","text":"Dùng Sinh Tử Cấm chế hóa sinh tử nhị khí thành rồng khí sinh tử chống cơn lốc xoáy. Toàn bộ Sinh Tử Cấm chế tan vỡ, tự bạo hai phân thân (lão bà và trung niên phu nhân) lấy lực lao qua lỗ hổng. Bị thương quá nặng, thần sắc uể oải.","anchor":"hai tay bấm quyết, điểm lên mi tâm, đột nhiên thân thể run lên, ở hai bên sườn trái phải đều xuất hiện một thân ảnh","bridge":true,"khoang":"@c1154"},{"mucCt":"vua","text":"Bị trọng thương từ trước, liều mạng bay lên cao tránh lòng bàn tay, nhận định chỉ cần Vương Lâm chết thì chưởng tiêu tan. May mắn tránh được lực nổ từ ngón tay út nhưng ngón tay trỏ từ phía sau lao tới, quay đầu đã muộn.","anchor":"chỉ cần đối phương chết, như vậy chưởng này sẽ tiêu tan","bridge":true,"khoang":"@c1155"},{"chuong":"@c1159","importance":"normal","mucCt":"vua","tieuDe":"Dâng Sinh Tử Cấm đổi mạng","text":"Nguyên thần bị Vương Lâm phong ấn mang ra khỏi Thất Thải giới. Công pháp bị phá, tu vi tụt xuống Tịch Niết trung kỳ. Dâng Sinh Tử Cấm đổi mạng sống, bị Vương Lâm lục soát thiên linh lấy cấm chế rồi dùng cuồng phong thả đi.","anchor":"Lữ đạo hữu, lão thân nguyện ý dâng ra Sinh Tử Cấm, đổi lấy một cơ hội sống"}],"tuViMoc":[{"chuong":"@c1121","canhGioi":"Tứ Tổ, Toái Niết trung kỳ đỉnh phong","text":"Thương Tùng Tử nhận ra cảnh giới của lão phụ nhân áo xanh khi bị phục kích.","importance":"major"}],"nhanMach":[{"ten":"Thương Tùng Tử","tag":"doi-thu","quanHe":"Phục kích và giao chiến","ghiChu":"Bà dùng độc làm hỏng tay trái, phong ấn nguyên anh hình người và đối kháng Nghịch Hành Giả."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Truy sát sau vụ đoạt bình","ghiChu":"Bà truy đuổi Vương Lâm bằng hư ảnh bò cạp độc và Sinh Tử Cấm."},{"ten":"Lão bà áo xanh","tag":"dong-minh","quanHe":"Cùng phe áo xanh","ghiChu":"Nguyên thần của lão bà áo xanh và hai người khác dung hợp với nguyên thần của bà."}],"tuiDo":{"phapBao":[{"ten":"Khiên tử quang của lão phụ nhân","trangThai":"dang-co","moTa":"Huyễn hóa trước người để chống bảy thanh trường kiếm của Thương Tùng Tử.","nguon":"@c1121"}],"danDuoc":[],"congPhap":[{"ten":"Sinh Tử Cấm","trangThai":"dang-co","moTa":"Ba luồng Sinh Tử Cấm của bà có thể dung hợp thành uy lực hủy thiên diệt địa.","nguon":"@c1121"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1121","@c1122","@c1124","@c1125","@c1130","@c1134","@c1140","@c1143","@c1145","@c1147","@c1154","@c1155","@c1159"]},{"id":"nghich-hanh-gia","name":"Nghịch Hành Giả","cn":"逆行者","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"không rõ @c1123","trangThai":"song","blurb":"Nghịch Hành Giả là các tồn tại hoặc hình thái công kích được Thương Tùng Tử triệu hồi bằng ba hạt châu trong trận chiến với Vương Lâm. Chúng biểu hiện thành hư ảnh kiếm uy, người đá trăm trượng và La Bàn khổng lồ.","vaiTro":"Lực lượng triệu hồi của Thương Tùng Tử","tinhCach":[{"text":"Gắn với sát chiêu triệu hồi, tạo sức ép nhiều tầng trong chiến trận","chuong":"@c1123"},{"text":"Biểu hiện không đồng nhất, gồm hư ảnh, người đá và La Bàn","chuong":"@c1123"}],"tabs":{"diem":[{"text":"Được Thương Tùng Tử triệu hồi bằng ba hạt châu để công kích Vương Lâm.","chuong":"@c1123"},{"text":"Ba biểu hiện được nêu gồm hư ảnh kiếm uy, người đá trăm trượng và La Bàn khổng lồ.","chuong":"@c1123"}],"kinhLich":[{"chuong":"@c1123","importance":"normal","mucCt":"vua","tieuDe":"Ba hạt châu triệu hồi","text":"Nghịch Hành Giả được Thương Tùng Tử triệu hồi bằng ba hạt châu trong trận chiến với Vương Lâm. Ba biểu hiện gồm hư ảnh kiếm uy, người đá trăm trượng và La Bàn khổng lồ, cùng tham gia tạo thế vây công.","anchor":"Thương Tùng Tử vung một trảo vào khe nứt không gian trữ vật, trong tay lập tức xuất hiện ba hạt châu"},{"chuong":"@c1133","importance":"normal","mucCt":"vua","tieuDe":"Bị phong ấn trong động phủ thứ bảy","text":"Lão già tóc hoa râm bị phong ấn cấm chế dày đặc trong động phủ thứ bảy, mặt không còn chút máu. Khi thấy Vương Lâm thì phát điên cuồng gào thét lao ra tấn công vách đá nhưng thần thông bị cấm chế hút sạch, cuối cùng mệt mỏi lui về ngồi tĩnh tọa. Vương Lâm nghi đây chính là Nghịch Hành Giả.","anchor":"Chẳng lẽ người này là… Nghịch Hành Giả sao?"}],"tuViMoc":[],"nhanMach":[{"ten":"Thương Tùng Tử","tag":"dong-minh","quanHe":"được triệu hồi bởi Thương Tùng Tử","ghiChu":"Xuất hiện qua ba hạt châu trong trận chiến @c1123"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"tham gia công kích Vương Lâm","ghiChu":"Các hình thái triệu hồi vây công Vương Lâm @c1123"},{"ten":"Tư Mã Mặc","tag":"dong-hanh","quanHe":"Đồng môn","ghiChu":"Bị Tư Mã Đặc đưa về phong ấn trong động phủ cố cho thức tỉnh nhưng thất bại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1123","@c1129","@c1133"]},{"id":"nam-tu-trung-nien-an-than-tien-phong","name":"Nam tử trung niên ẩn thân","cn":"","aliases":["Tu sĩ tiên phong đạo cốt"],"gioiTinh":"nam","theLuc":[{"ten":"Ma Tùng Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nam tử trung niên diện mạo tiên phong đạo cốt, ẩn thân quan sát cuộc gặp giữa Vương Lâm và trưởng lão Ma Tùng Đạo, nhận định Vương Lâm cực kỳ nguy hiểm và khuyên Ma Tùng Đạo rút lui khỏi vụ đan phương, ngọc giản.","vaiTro":"Nhân vật bí ẩn thuộc Ma Tùng Đạo, địa vị có vẻ cao hơn hai trưởng lão Toái Niết","tinhCach":[{"text":"Thận trọng, biết lượng sức, dám khuyên tổ chức rút lui khi nhận thấy nguy hiểm"}],"tabs":{"diem":[{"text":"Ẩn thân quan sát Vương Lâm suốt cuộc gặp, nhận ra hắn cực kỳ nguy hiểm và khuyên Ma Tùng Đạo rút khỏi vụ đan phương ngọc giản","chuong":"@c1101"}],"kinhLich":[{"chuong":"@c1101","importance":"normal","mucCt":"vua","tieuDe":"Ẩn thân quan sát Vương Lâm, khuyên Ma Tùng Đạo rút lui","text":"Ẩn thân tại bàn góc trong khách điếm suốt cuộc gặp giữa Vương Lâm và hai trưởng lão. Sau khi VL rời đi mới hiện hình, nhận định hắn cực kỳ nguy hiểm và khuyên Ma Tùng Đạo rút chân khỏi vụ đan phương và ngọc giản.","anchor":"đối với chuyện đan phương và ngọc giản, Ma Tùng Đạo ta nên rút chân ra thôi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng quan sát, nhận định cực kỳ nguy hiểm","ghiChu":"@c1101"},{"ten":"Đường Lệ Hải","tag":"dong-minh","quanHe":"Trưởng lão Ma Tùng Đạo, cùng bàn luận","ghiChu":"@c1101"},{"ten":"Ngô Thanh","tag":"dong-minh","quanHe":"Trưởng lão Ma Tùng Đạo, cùng bàn luận","ghiChu":"@c1101"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1101"]},{"id":"nam-tu-lung-hum-vai-gau-au-duong","name":"Nam tử lưng hùm vai gấu","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thế lực Âu Dương Long","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Đệ tử hoặc thuộc hạ của Âu Dương Long, được cử đến mời và dẫn đường Vương Lâm vào tòa thành trung tâm.","vaiTro":"Thuộc hạ Âu Dương Long, người dẫn đường","tinhCach":[{"text":"Lễ phép, xưng vãn bối với Vương Lâm"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c1101","importance":"bridge","mucCt":"gon","text":"Đến mời Vương Lâm và dẫn đường vào tòa thành trung tâm gặp Âu Dương Long.","anchor":"Tiền bối, gia sư Âu Dương Long cho mời!"}],"tuViMoc":[],"nhanMach":[{"ten":"Âu Dương Long","tag":"cap-tren","quanHe":"Gia sư, người sai đi mời Vương Lâm","ghiChu":"@c1101"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Tiền bối được gia sư sai mời","ghiChu":"@c1101"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1101"]},{"id":"dong-tu-doan-moc","name":"Đồng tử Đoan Mộc","aliases":[],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1124","importance":"bridge","mucCt":"gon","text":"Nằm trong số Mê Thất Giả đang mê man trong thế giới bảy màu, dừng chân ngẩng đầu nhìn về phía tiếng nổ La Bàn vỡ.","anchor":"trong đó cũng có đồng tử Đoan Mộc"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1124"]},{"id":"bang-duc-tai","name":"Bàng Đức Tài","cn":"庞德才","aliases":["lão già họ Bàng"],"gioiTinh":"nam","trangThai":"tu-vong","vaiTro":"Tu sĩ đã chết, ký ức bị Vương Lâm khai thác để tìm động phủ Tư Mã Mặc","tinhCach":"Không rõ","blurb":"Tu sĩ từng dẫn nhóm phát hiện động phủ Tư Mã Mặc trong thế giới bảy màu nhưng chỉ phá được tầng cấm chế hư ảo. Bị Vương Lâm giết, ký ức bị khai thác.","tabs":{"diem":[{"text":"Ký ức chứa thông tin về vị trí động phủ Tư Mã Mặc, bị Vương Lâm khai thác","chuong":"@c1126"}],"kinhLich":[{"mucCt":"vua","text":"Ký ức của Bàng Đức Tài bị Vương Lâm khai thác để biết vị trí động phủ Tư Mã Mặc và việc nhóm hắn chỉ phá được tầng cấm chế hư ảo thứ nhất.","anchor":"Trong ký ức của Bàng Đức Tài, sau khi bọn họ phát hiện ra động phủ của Tư Mã Mặc thì cũng không thể mở ra hoàn toàn","bridge":true,"khoang":"@c1126"},{"chuong":"@c1131","importance":"bridge","mucCt":"gon","text":"Thương Tùng Tử tiết lộ Bàng Đức Tài không hề biết phương pháp chính thức rời khỏi thế giới bảy màu, chỉ biết những gì Thương Tùng Tử cố ý cho biết.","anchor":"Bàng Đức Tài cũng không biết phương pháp chính thức rời khỏi nơi này, những gì hắn biết được, chẳng qua lão phu muốn cho hắn biết mà thôi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết hắn và khai thác ký ức","ghiChu":""}],"tuiDo":{"phapBao":[{"ten":"Chiếc nhẫn chín tầng phong ấn","trangThai":"mat","moTa":"Bị Vương Lâm lấy sau khi chết","nguon":"@c1126"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1126","@c1131"]},{"id":"chuong-ton","name":"Chưởng Tôn","cn":"掌尊","aliases":["bản tôn"],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","theLuc":[{"ten":"Ngoại giới","trangThai":"gan-bo"}],"vaiTro":"Lão tổ tông Nguyệt Tộc bước thứ ba — tồn tại uy hiếp Phù Tộc, cha của Thu Dao","tinhCach":"Mưu tính sâu xa, bày bố Thiên Đạo Kế xuyên suốt nhiều đời; tàn nhẫn quyết đoán, phong ấn giết Chiến Tinh Dã đoạt chiến hồn không chút do dự; giỏi dùng lợi ích lớn mua chuộc kẻ khác ra tay; quyền thế áp đảo, khiến cả Phù Tộc phải lẩn trốn vào Phong Giới","blurb":"Chưởng Tôn là lão tổ tông Nguyệt Tộc bước thứ ba, tự xưng Chưởng Tôn Thái Cổ Tinh Thần, một tồn tại uy thế bậc cao khiến Phù Tộc phải trốn vào Phong Giới để tránh bị khống chế, đồng thời là cha của Thu Dao ở thế giới bên ngoài. Sở hữu hai luồng bản nguyên đại thành nhập đạo, từng luyện 108 cây Thất Thải Thần Không Đinh chuyên giết tu sĩ bước thứ ba, liên thủ với người Viễn Cổ Tiên Vực đánh trọng thương Chủ nhân Phong Giới gần tử vong, và bị Vương Lâm suy đoán là kẻ từng nắm giữ Thiên Nghịch thật cùng chế tạo hạt châu mô phỏng. Trong cuộc đối đầu trực tiếp với Vương Lâm tại khe cổ mộ, triệu chư","tabs":{"diem":[{"text":"Được Thu Dao nhắc tới là nguyên nhân khiến Phù Tộc trốn vào Phong Giới để tránh bị khống chế","chuong":"@c0969"},{"text":"Trong ảo cảnh tự xưng bản tôn, thi triển thần thông bảy màu Thiên Địa Thái Sơ phong ấn giết Chiến Tinh Dã đoạt chiến hồn, tiết lộ Thiên Đạo Kế","chuong":"@c1134"},{"text":"Luyện thiên thạch thần bí ra 108 cây Thất Thải Thần Không Đinh, cùng người Viễn Cổ Tiên Vực liên thủ đánh trọng thương Chủ nhân Phong Giới gần tử vong","chuong":"@c1206"},{"text":"Thi triển Tứ Đại Giai Không Thuật đối kháng nguyên linh Chu Tước, xé áo giáp thái cổ chí bảo của sư tôn để chiến đấu, cuối cùng bị Cổ Thần đánh trọng thương","chuong":"@c1340"},{"text":"Triệu chưởng ấn hư ảo khổng lồ che lấp toàn bộ tinh vực, tự xưng Chưởng Tôn Thái Cổ Tinh Thần đối đầu Vương Lâm tại khe cổ mộ","chuong":"@c1382"},{"text":"Chưởng ấn tan vỡ không chút sức kháng cự, bị lực lượng từ khe xuyên vào tâm thần khiến phun máu, hai chân nổ tung, trọng thương thảm hại","chuong":"@c1383"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1127","tieuDe":"Xuất hiện trong ý thức Tư Mã Đặc","text":"Tư Mã Đặc trong thế giới bảy màu, sau vài trăm năm ý thức kéo dài đến tinh không kỳ dị, nhìn thấy một người đàn ông trung niên mặc áo bào, mi tâm có ấn ký hình trăng khuyết, tên Chưởng Tôn. Vương Lâm kinh hoàng khi đọc tên này, liên hệ Chưởng Tôn là cường giả cùng thời đại với Thanh Lâm.","anchor":"đây là một người đàn ông trung niên mặc áo bào, trên mi tâm của hắn có một ấn ký hình trăng khuyết, tên ngày này là Chưởng Tôn"},{"chuong":"@c1128","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm suy đoán có lẽ chính là kẻ chế tạo hạt châu mô phỏng Thiên Nghịch, từng nắm giữ Thiên Nghịch thật.","anchor":"Người này, có lẽ cũng là Chưởng Tôn"},{"chuong":"@c1134","importance":"normal","mucCt":"ky","tieuDe":"Tiết lộ Thiên Đạo Kế — giết Chiến Tinh Dã lấy chiến hồn","text":"Trong ảo cảnh, tự xưng bản tôn, dùng thần thông bảy màu Thiên Địa Thái Sơ chỉ một chiêu phong ấn giết chết Chiến Tinh Dã cảnh giới Không Linh Chi. Tuyên bố đã tặng Chiến Tự Thiếp cho Chiến Tinh Dã tu luyện, sau đó giết lấy chiến hồn làm dẫn tìm xương cốt sư phụ Chiến Lão Quỷ Không Kiếp, bức ra đạo tủy hai sư đồ, gọi mưu kế là Hủy Kỳ Niết bản tôn Thiên Đạo Kế. Sở hữu lực lượng thái sơ, thần thông cùng loại Tàn Dạ nhưng vượt xa.","anchor":"Hủy Kỳ Niết, bản tôn Thiên Đạo Kế"},{"chuong":"@c1146","importance":"bridge","mucCt":"gon","text":"Được người nuôi hoa nhắc đến: năm xưa khuyên người đó không đối mặt Không Kiếp, nuôi bảy cây hoa và chờ Thiên Đạo Kế hoàn thành.","anchor":"Cái ta chờ mong chính là Thiên Đạo Kế của hắn sẽ có ngày hoàn thành"},{"mucCt":"vua","text":"Được Lam Mộng Đạo Tôn nhắc lại: năm xưa lẻn vào Thất Thải giới nhưng trọng thương chạy về, bị cảnh cáo khắp Thái Cổ. Sau đó bị cấm bản thể vào, chỉ cho phân thân nuôi hoa vào được. Lam Mộng nghi ngờ hắn có mục đích khác khi nhờ Lam Mộng ra tay đối phó Vương Lâm.","anchor":"Chưởng Tôn năm đó lẻn vào bên trong giới, nhưng lại trọng thương chạy về","bridge":true,"khoang":"@c1157"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Lâm","tag":"khac","quanHe":"Cường giả cùng thời đại","ghiChu":"@c1127"},{"ten":"Tư Mã Mặc","tag":"khac","quanHe":"Tư Mã Đặc nhìn thấy Chưởng Tôn khi ý thức kéo dài trong thế giới bảy màu","ghiChu":"@c1127"},{"ten":"Chiến Tinh Dã","tag":"khac","quanHe":"Tặng Chiến Tự Thiếp rồi giết lấy chiến hồn, nạn nhân Thiên Đạo Kế","ghiChu":"@c1134"},{"ten":"Chiến Lão Quỷ","tag":"doi-thu","quanHe":"Muốn tìm xương cốt bức ra đạo tủy, rất e sợ hắn","ghiChu":"@c1134"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1127","@c1128","@c1134","@c1136","@c1146","@c1157"]},{"id":"thap-luc-su-de","name":"Thập Lục sư đệ","cn":"","aliases":["Thập Lục sư đệ (Phá Thiên Tông)"],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","theLuc":[{"ten":"Phá Thiên Tông","trangThai":"gan-bo"}],"vaiTro":"Đồng môn Phá Thiên Tông, một trong ba người sống sót cuối cùng trong thế giới bảy màu","tinhCach":"Chưa rõ","blurb":"Đồng môn Phá Thiên Tông, một trong ba người sống sót cuối cùng cùng Tư Mã Đặc trong thế giới bảy màu. Bị Tư Mã Đặc đuổi khỏi sơn cốc, mang theo lệnh bài và đan phương thú cốt rời đi, có thể là người đưa đan phương ra Vân Hải tinh vực.","tabs":{"diem":[{"text":"Người mang đan phương thú cốt và lệnh bài rời khỏi thế giới bảy màu","chuong":"@c1127"}],"kinhLich":[{"mucCt":"gon","text":"Bị Tư Mã Đặc đuổi khỏi sơn cốc khi ý niệm điên cuồng xâm nhập, được giao lệnh bài thân phận và đan phương thú cốt, dặn mười năm sau quay lại.","anchor":"ta đưa lệnh bài thân phận của mình và đan phương thú cốt cho hắn","bridge":true,"khoang":"@c1127"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Mã Mặc","tag":"su-mon","quanHe":"Đồng môn Phá Thiên Tông, đưa lệnh bài và đan phương rồi đuổi đi để bảo vệ","ghiChu":"@c1127"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Lệnh bài thân phận Tư Mã Đặc","moTa":"Được Tư Mã Đặc giao trước khi đuổi đi","nguon":"@c1127"},{"ten":"Đan phương thú cốt","moTa":"Được Tư Mã Đặc giao, có thể mang ra Vân Hải tinh vực","nguon":"@c1127"}]}},"nguon":["@c1127"]},{"id":"cuu-su-de","name":"Cửu sư đệ","cn":"","aliases":["Cửu sư đệ (Phá Thiên Tông)"],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","theLuc":[{"ten":"Phá Thiên Tông","trangThai":"gan-bo"}],"vaiTro":"Đồng môn Phá Thiên Tông, hy sinh tuổi thọ gia cố trận pháp Tuế Nguyệt Cấm","tinhCach":"Nghĩa khí, xả thân vì đồng môn","blurb":"Đồng môn Phá Thiên Tông trong thế giới bảy màu, hy sinh tuổi thọ để gia cố trận pháp Tuế Nguyệt Cấm bảo hộ sơn cốc. Trước khi chết nhờ mang hài cốt về Phá Thiên Tông.","tabs":{"diem":[{"text":"Hy sinh tuổi thọ gia cố trận pháp Tuế Nguyệt Cấm bảo hộ đồng môn","chuong":"@c1127"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1127","tieuDe":"Hy sinh tuổi thọ gia cố trận pháp","text":"Hy sinh tuổi thọ để gia cố trận pháp Tuế Nguyệt Cấm trong sơn cốc, trước khi chết nhờ mang hài cốt về Phá Thiên Tông.","anchor":"Cuối cùng ta cũng hiểu rõ được Tuế Nguyệt Cấm, lúc đó ta cùng với những đồng môn còn sót lại bố trí một đại cấm chế Tuế Nguyệt Cấm chính thức trong sơn cốc"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Mã Mặc","tag":"su-mon","quanHe":"Đồng môn Phá Thiên Tông","ghiChu":"@c1127"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1127"]},{"id":"tu-su-thuc","name":"Tứ sư thúc","cn":"","aliases":["Tứ sư thúc (Phá Thiên Tông)"],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","theLuc":[{"ten":"Phá Thiên Tông","trangThai":"gan-bo"}],"vaiTro":"Sư thúc Phá Thiên Tông, Nghịch Hành Giả đầu tiên","tinhCach":"Chưa rõ (đã trở thành Nghịch Hành Giả)","blurb":"Tứ sư thúc là một sư thúc trong Phá Thiên Tông, thuộc số ít người sống sót cuối cùng trong thế giới bảy màu. Sau một trăm năm ở nơi này, ông trở thành Nghịch Hành Giả đầu tiên xuất hiện.","tabs":{"diem":[{"text":"Trở thành Nghịch Hành Giả đầu tiên xuất hiện sau một trăm năm trong thế giới bảy màu","chuong":"@c1127"}],"kinhLich":[{"importance":"major","mucCt":"gon","chuong":"@c1127","tieuDe":"Trở thành Nghịch Hành Giả đầu tiên","text":"Sau một trăm năm trong thế giới bảy màu, trở thành Nghịch Hành Giả, là Nghịch Hành Giả đầu tiên xuất hiện. Tư Mã Đặc lần thứ tư vào vị trí sâu nhất cứu nhưng thất bại, bị cây đinh bảy màu đâm.","anchor":"Bị một cây đinh bảy màu đâm vào trong cơ thể… Cây đinh này rất quỷ dị, khi tiến vào trong cơ thể thì lập tức hòa tan"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Mã Mặc","tag":"su-mon","quanHe":"Tư Mã Đặc cố cứu Tứ sư thúc khỏi trạng thái Nghịch Hành Giả nhưng thất bại","ghiChu":"@c1127"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1127"]},{"id":"vu-ton","name":"Vũ Tôn","cn":"武尊","aliases":[],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","theLuc":[{"ten":"Ngoại giới","trangThai":"gan-bo"}],"vaiTro":"Tồn tại cực kỳ hùng mạnh ở Ngoại giới","tinhCach":"Chưa rõ","blurb":"Tồn tại cực kỳ hùng mạnh trong Ngoại giới, Vương Lâm biết từ động phủ Tiên Đế Thanh Lâm.","tabs":{"diem":[{"text":"Tồn tại cực kỳ hùng mạnh ở Ngoại giới, được nhắc đến trong động phủ Tiên Đế Thanh Lâm","chuong":"@c1127"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1127","chuong":"@c1127","text":"Được Vương Lâm nhắc lại khi liên hệ Chưởng Tôn với các cường giả Ngoại giới.","anchor":"trong đám người ở Ngoại giới có một tồn tại cực kỳ hùng mạnh, tên là Vũ Tôn"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Cùng thuộc Ngoại giới","ghiChu":"@c1127"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1127"]},{"id":"thanh-lam","name":"Thanh Lâm","gioiTinh":"nam","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1127","chuong":"@c1127","text":"Được nhắc: Chưởng Tôn và Thanh Lâm là cường giả cùng thời đại.","anchor":"người này và Thanh Lâm là cường giả cùng thời đại"},{"chuong":"@c1151","importance":"bridge","mucCt":"vua","text":"Đang tĩnh tọa khôi phục tu vi tại Vũ Tiên Giới, cảm nhận khí tức từ cửa Thiên Nghịch, bùng phát tinh quang chưa từng có, đứng lên gọi Sư tôn.","anchor":"cố gắng nhanh chóng khôi phục tu vi. Nhưng trong khoảnh khắc này, hai mắt hắn cũng bùng phát ra tinh quang chưa từng có"}],"nhanMach":[{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Cường giả cùng thời đại","ghiChu":"@c1127"}],"diem":[{"text":"Lộ thân phận Tiên Đế, đệ nhất cường giả Tiên giới và phụ thân Thanh Sương qua ngọc giản","chuong":"@c0595"},{"text":"Hiện thân tiên phong đạo cốt từ Thức Hải, đánh tan tay phải Cổ Ma và truyền thụ Quy tắc thân thể cho Vương Lâm","chuong":"@c1047"},{"text":"Thức tỉnh trong trận pháp hồi sinh, khai sinh Tân Vũ Giới, ôn hòa an ủi các đệ tử","chuong":"@c1050"},{"text":"Được xác nhận là một trong hai người duy nhất có hai luồng bản nguyên đại thành nhập đạo Đệ Tam Bộ","chuong":"@c1209"},{"text":"Tiết lộ từng bị Chưởng Tôn dụ dỗ tại Vũ giới nhiều năm trước, chịu sự hấp dẫn tương tự Vương Lâm","chuong":"@c1243"},{"text":"Đang tĩnh tọa khôi phục tu vi tại Vũ Tiên Giới, từng ngăn cản Thác Sâm và giữa hai bên dường như có hiệp ước","chuong":"@c1195"}]},"nguon":["@c1127","@c1151"],"vaiTro":"Tiên Đế — đệ nhất cường giả Tiên giới, phụ thân Thanh Sương, ân sư Vương Nguy và Hồ Quyên","tinhCach":"Ôn hòa, che chở đệ tử và người thân; mưu tính sâu xa với bố cục vượt thời gian khiến Cổ Ma kiêng dè; trọng ân nghĩa, từng cứu người kết duyên","blurb":"Thanh Lâm là Tiên Đế, đệ nhất cường giả Tiên giới, phụ thân của Thanh Sương, phu quân Hoa Phi, đồng thời là ân sư của Vương Nguy cùng Hồ Quyên và có đại ân với Lữ Vân Đạo. Sau khi Tiên giới vỡ nát, thân thể ông tồn tại trong khe không gian rồi bị Cổ Ma Tháp Già nhập thể; hiện thân của ông trong Thức Hải đã truyền thụ Quy tắc thân thể và chuyển giao khống chế Thức Hải cho Vương Lâm, sau đó thức tỉnh trong trận pháp hồi sinh và khai sinh Tân Vũ Giới. Hiện Thanh Lâm đang tĩnh tọa khôi phục tu vi tại Vũ Tiên Giới, từng ngăn cản Thác Sâm và được tiết lộ là một trong hai người duy nhất có hai luồng "},{"id":"thanh-thuy","name":"Thanh Thủy","gioiTinh":"nam","tabs":{"kinhLich":[{"mucCt":"vua","text":"Vương Lâm liên hệ: Thanh Thủy sư huynh trước khi Tiên giới tan vỡ đang bế quan thì đột nhiên điên cuồng, sau đến Liên Minh Tu Chân lại điên cuồng lần nữa. Hiện tượng này giống hệt hiệu ứng cây đinh bảy màu đâm vào Tư Mã Đặc.","anchor":"Thanh Thủy sư huynh từng nói, trước khi Tiên giới tan vỡ hắn đang ngồi bế quan tu luyện thì đột nhiên trở nên điên cuồng","bridge":true,"khoang":"@c1127"},{"chuong":"@c1146","importance":"bridge","mucCt":"gon","text":"Được nhắc đến khi so sánh: cảm giác điên cuồng của Vương Lâm khi rơi vào Sát Ngục giống cái điên cuồng của Thanh Thủy năm xưa.","anchor":"giống như cái điên cuồng của Thanh Thủy năm xưa"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Lai lịch được tiết lộ: vốn là thái tử Thanh Thủy Quốc thượng cổ, phi thăng Tiên giới rồi trở thành sát tinh, sau tỉnh ngộ tự phong ấn bản thân","chuong":"@c0746"},{"text":"Hiện thân bảo hộ truyền nhân Bạch Phàm, đối kháng Huyết Thần Tử, nuốt bảy đạo thiên kiếp khôi phục thêm Cực Cảnh","chuong":"@c0803"},{"text":"Tái xuất chiến trường vây đánh Huyền Bảo thượng nhân, thi triển Cực Cảnh và Tát Đậu Thành Binh","chuong":"@c0874"},{"text":"Phong ấn tự mở sau khi rời cõi hư vô, tu vi được khôi phục, hẹn Vương Lâm vào Sát Vực Giới","chuong":"@c0887"},{"text":"Dùng Cực Cảnh đồ diệt đại bộ phận tu sĩ Sát Vực Giới, giết Thần Ma Tử","chuong":"@c0894"},{"text":"Được xác nhận còn sống nhưng đã điên, đang ở tổng bộ Liên Minh tu chân","chuong":"@c1039"}]},"nguon":["@c1127","@c1146"],"vaiTro":"Tiên quân Cực Cảnh — sư huynh đồng môn Bạch Phàm, bảo hộ và truyền thừa cho Vương Lâm","tinhCach":"trọng tình nghĩa đồng môn, nguyện xả thân bảo hộ truyền nhân; sát phạt quyết liệt, không nương tay với kẻ địch; thận trọng đa nghi, không dễ tin người; biết tự tỉnh sau sát nghiệp, từng tự phong ấn vì hối hận","blurb":"Thanh Thủy Tiên Quân vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới, phi thăng lên Tiên giới rồi trở thành sát tinh khét tiếng tại Lôi Giới, sau đó tỉnh ngộ trước sát nghiệp của mình mà tự phong ấn tu vi. Với tư cách sư huynh cùng sư môn Bạch Phàm, ông nhiều lần hiện thân bảo hộ Vương Lâm, truyền thừa các tiên thuật Hoán Vũ, Tát Đậu Thành Binh, U Minh Dẫn Lộ cùng quy tắc, giao chiến với Huyết Thần Tử và Huyền Bảo thượng nhân, dùng Cực Cảnh đồ diệt Sát Vực Giới. Sau biến cố trong cõi hư vô, phong ấn tự mở và tu vi được khôi phục, nhưng về sau được xác nhận đang ở tổng bộ Liên Minh "},{"id":"lao-to-cam-dia-chu-tuoc","name":"Lão Tổ Cấm Địa Chu Tước","gioiTinh":"nam","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1127","chuong":"@c1127","text":"Được nhắc: từng nói về việc Thanh Thủy đến Liên Minh Tu Chân rồi điên cuồng lần nữa.","anchor":"Chu tước lão Thánh Hoàng cũng từng nói, sau khi Thanh Thủy sư huynh đi đến Liên Minh Tu Chân lại điên cuồng một lần nữa"}],"diem":[{"text":"Ra lệnh Kiền Phong nuốt tuyệt tình ý cảnh và tứ linh của Hồng Điệp, sai Liễu Mi truy tìm Vương Lâm để làm lò luyện nhằm đoạt Thiên Nghịch Châu và Tinh La Bàn","chuong":"@c0340"},{"text":"Vui mừng khi Vương Lâm hóa hư hỏa, thả Viêm Long tặng cho Vương Lâm và truyền âm về Thiên Phương Hương","chuong":"@c1324"},{"text":"Tiết lộ đã lén lưu hư hỏa lên người Tư Mặc Tử qua ba cái tát, bố cục giúp Vương Lâm chiến thắng để lấy uy danh","chuong":"@c1330"},{"text":"Kinh ngạc trước Cổ Tức Diệp khi thấy y phong ấn hương hỏa giới, đồng tử co rụt lộ vẻ không thể tin","chuong":"@c1331"},{"text":"Tiễn biệt Vương Lâm trên Đại Đế tinh, trao Cổ Hồn Cấm và giao phó nhiệm vụ","chuong":"@c1335"},{"text":"Truyền thụ thần thông Phần Giới Cổ Tán — tuyệt học mạnh nhất Chu Tước tộc — cho Vương Lâm","chuong":"@c1336"}]},"nguon":["@c1127"],"vaiTro":"Lão tổ đời thứ hai của Chu Tước tộc — thế lực bí ẩn trong cấm địa Chu Tước Sơn","tinhCach":"Thủ đoạn lạnh lùng, xem sinh linh làm mồi luyện; toan tính thâm sâu, bố cục nhiều tầng; ẩn dật bí hiểm, hành sự từ trong cấm địa; trọng nhân tài, sẵn lòng truyền thụ tuyệt học cho kẻ xứng đáng","blurb":"Lão tổ đời thứ hai của Chu Tước tộc, toàn thân phát hồng quang, ẩn cư trong cấm địa phía sau Chu Tước Sơn. Thuở đầu nuôi Hồng Điệp làm mồi cho Kiền Phong và ra lệnh truy tìm Vương Lâm để đoạt Thiên Nghịch Châu cùng Tinh La Bàn, nhưng về sau nhận ra tài năng của Vương Lâm, chuyển sang âm thầm trợ giúp, trao Cổ Hồn Cấm và đích thân truyền thụ thần thông Phần Giới Cổ Tán — tuyệt học mạnh nhất của Chu Tước tộc."},{"id":"vong-nguyet","name":"Vọng Nguyệt","gioiTinh":"nam","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1127","chuong":"@c1127","text":"Được nhắc: năm xưa Vương Lâm và Thanh Thủy vào hư vô chiến đấu với Vọng Nguyệt, hư vô tan vỡ xuất hiện hai tu sĩ Ngoại giới.","anchor":"Năm xưa khi lão già kia nhìn thấy hạt châu Thiên Nghịch thì gọi ta là Phong Tôn"}]},"nguon":["@c1127"]},{"id":"thanh-nien-ky-hieu-tia-chop","name":"Thanh niên ký hiệu tia chớp","cn":"","aliases":["Người thanh niên Thiểm Lôi Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết trung kỳ (biến thân)","trangThai":"tu-vong","blurb":"Người đàn ông đi đầu nhóm ba người xuất hiện trên tế đàn phủ sương ở sâu trong thế giới bảy màu, mi tâm mang ký hiệu hình tia chớp, y phục khác hẳn tu sĩ Vân Hải.","vaiTro":"Dẫn đầu nhóm người mang ký hiệu mi tâm xâm nhập thế giới bảy màu","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Dẫn đầu nhóm ba người mang ký hiệu mi tâm xuất hiện trên tế đàn phủ sương, y phục khác tu sĩ Vân Hải","chuong":"@c1128"},{"text":"Mi tâm có ký hiệu hình tia chớp, cảm nhận được khí tức tổ tiên Thiên Lôi Tộc trong vùng sâu thế giới bảy màu","chuong":"@c1130"},{"text":"Tu sĩ Thiểm Lôi Tộc, dùng pháp thuật biến thân từ Tịnh Niết đại viên mãn lên Toái Niết trung kỳ, sở hữu quyền năng lôi quang bộ tộc.","chuong":"@c1137"}],"kinhLich":[{"mucCt":"vua","text":"Dẫn đầu nhóm ba người y phục khác tu sĩ Vân Hải xuất hiện trên tế đàn phủ sương ở nơi rất sâu trong thế giới bảy màu. Mi tâm mang ký hiệu hình tia chớp.","anchor":"Trên mi tâm người đàn ông đi đầu có một ký hiệu hình tia chớp","bridge":true,"khoang":"@c1128"},{"mucCt":"vua","text":"Cùng hai thanh niên Hỏa Tước Tộc và trăng lưỡi liềm thám hiểm vùng sâu thế giới bảy màu, cảm nhận khí tức tổ tiên Thiên Lôi Tộc. Khi tâm thần Vương Lâm phóng qua, đột nhiên run lên, nghe tiếng sấm trong đầu, ký hiệu mi tâm lóe sáng dữ dội.","anchor":"Quỷ dị là ta có cảm giác được nơi đây có khí tức của tổ tiên Thiên Lôi Tộc","bridge":true,"khoang":"@c1130"},{"chuong":"@c1136","importance":"normal","mucCt":"vua","tieuDe":"Mở phong ấn tập kích Vương Lâm","text":"Muốn rút lui bẩm báo trưởng lão nhưng do dự. Tham lam muốn thôn phệ lực lượng sấm sét trên người Vương Lâm để tăng cấp. Vỗ mi tâm mở phong ấn, thân thể phóng lớn hơn mười trượng bao phủ ánh chớp, cùng hai đồng bạn tập kích Vương Lâm.","anchor":"Sau khi thôn phệ hắn, ta có thể tăng cấp!"},{"chuong":"@c1137","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm giết, mất quyền lôi quang","text":"Xông lên đầu tiên trong ba tu sĩ Ngoại giới, triệu hoán hình bóng hư ảo trăm trượng lôi quang dùng chiêu Thiểm Lôi Băng. Bị Vương Lâm vỗ chưởng chuyển kiếm chỉ liên tiếp bốn lần đánh nát ngực, xương cốt gãy hơn phân nửa. Dùng chiêu mượn lực tổ tiên lôi quang triệu hoán hư ảnh lần hai nhưng bị Vương Lâm bùng Chân Giả ý cảnh đạp tan trái tim. Vương Lâm dùng ký hiệu tia chớp mắt phải thu hồi tư cách điều khiển sấm sét, sấm sét quay lại thiêu hủy thân thể, nguyên thần bị lôi quang nuốt.","anchor":"xương cốt bên trong đã gãy hơn phân nửa, thân thể hơn mười trượng lui hẳn ra sau"}],"tuViMoc":[{"chuong":"@c1137","canhGioi":"Toái Niết trung kỳ (biến thân)","text":"Tu vi gốc Tịnh Niết đại viên mãn, dùng pháp thuật biến thân mượn lực thiên địa tăng lên Toái Niết trung kỳ.","importance":"major"}],"nhanMach":[{"ten":"Thanh niên ký hiệu trăng lưỡi liềm","tag":"dong-hanh","quanHe":"Đồng hành, cùng xuất hiện trên tế đàn","ghiChu":""},{"ten":"Thanh niên ký hiệu ngọn lửa","tag":"dong-hanh","quanHe":"Đồng hành, cùng xuất hiện trên tế đàn","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù — bị Vương Lâm giết","ghiChu":"Bị thu hồi quyền lôi quang @c1137"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1128","@c1130","@c1136","@c1137"]},{"id":"thanh-nien-ky-hieu-trang-luoi-liem","name":"Thanh niên ký hiệu trăng lưỡi liềm","cn":"","aliases":["Thanh niên Nguyệt Phệ tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Nguyệt Phệ tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Thanh niên Nguyệt Phệ tộc mang ký hiệu trăng lưỡi liềm nơi mi tâm, một trong nhóm ba người xuất hiện trên tế đàn phủ sương ở sâu trong thế giới bảy màu. Sau khi nhận ra Vương Lâm, hắn mở phong ấn liều mình tập kích để đoạt bảo vật, dùng thuật Lực Phản Nguyệt giao chiến. Cuối cùng bị Vương Lâm tiêu diệt hoàn toàn, thân thể hóa nước máu chỉ còn hai khúc xương lưu lại trên đinh bảy màu.","vaiTro":"Thành viên Nguyệt Phệ tộc trong nhóm ba người xâm nhập thế giới bảy màu","tinhCach":"Hưng phấn, háo hức khi mạo hiểm; liều lĩnh dám tập kích để đoạt bảo vật; dễ hoảng loạn khi thất thế; bất khuất không chịu phận nô lệ","tabs":{"diem":[{"text":"Xuất hiện đầy hưng phấn trên tế đàn phủ sương cùng nhóm ba người trong thế giới bảy màu","chuong":"@c1128"},{"text":"Nhận ra Vương Lâm, hạ quyết tâm mạo hiểm mở phong ấn tập kích để đoạt bảo vật","chuong":"@c1136"},{"text":"Chứng kiến hai đồng bạn Thiểm Lôi Tộc và Hỏa Tước Tộc bị giết trong nháy mắt","chuong":"@c1137"},{"text":"Gào lên phủ nhận thân phận nô lệ rồi dùng thuật Lực Phản Nguyệt giao chiến với Vương Lâm","chuong":"@c138"},{"text":"Bị Vương Lâm tiêu diệt hoàn toàn, thân thể hóa nước máu chỉ còn hai khúc xương trên đinh bảy màu","chuong":"@c1139"}],"kinhLich":[{"chuong":"@c1128","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện trên tế đàn thế giới bảy màu","text":"Cùng nhóm xuất hiện trên tế đàn phủ sương ở sâu trong thế giới bảy màu. Đảo mắt bốn phía đầy hưng phấn, hỏi có phải đây là khe nứt không gian đối phương phát hiện.","anchor":"Đây chính là khe nứt không gian ngươi phát hiện ra sao?"},{"mucCt":"vua","text":"Đi sau cùng cẩn thận quan sát trong vùng sâu thế giới bảy màu. Khi tâm thần Vương Lâm phóng qua, run rẩy, nhớ lại ác mộng, nghi nhận ra Vương Lâm nhưng không dám xác định.","anchor":"Chẳng lẽ… là hắn… không thể được, sao hắn lại xuất hiện ở đây","bridge":true,"khoang":"@c1130"},{"chuong":"@c1136","importance":"normal","mucCt":"vua","tieuDe":"Nhận ra Vương Lâm, mở phong ấn tập kích","text":"Hạ quyết tâm mạo hiểm lấy bảo vật. Khi nhìn thấy Vương Lâm, đồng tử co rút, nhớ ký ức cũ, thốt lên nhận ra đối phương. Vỗ mi tâm mở phong ấn, da trở nên trong suốt như ánh trăng.","anchor":"Đúng là hắn!"},{"mucCt":"vua","text":"Chứng kiến hai đồng bạn Thiểm Lôi Tộc và Hỏa Tước Tộc bị giết trong nháy mắt, hoảng sợ tái nhợt muốn bỏ chạy. Nhớ lại sư tôn từng bị Vương Lâm đánh bị thương nặng trong hư vô. Bị Vương Lâm lạnh lùng bảo nô tộc ở lại, nói tộc hắn ngày xưa dám tự xưng thiên đạo, hồn bay phách tán.","anchor":"nô tộc ở lại cho ta, ngày xưa dám đứng trước mặt ta tự xưng thiên đạo","bridge":true,"khoang":"@c1137"},{"mucCt":"ky","text":"Gào lên rằng mình không phải nô lệ rồi giao chiến với Vương Lâm. Dùng thuật Lực Phản Nguyệt tạo vầng trăng khuyết và gió lốc chống đỡ nhưng bị áp đảo. Tuyệt vọng sử dụng cấm thuật Nguyệt Cấm thần nộ, quỳ gối triệu hồi hư ảnh Cổ Thần vài trăm trượng mượn thần hồn lực, nhưng bị Vương Lâm dùng quyền vương tộc Cổ Thần xóa bỏ lực che chở. Bị đá gãy xương cốt toàn thân, ghim vào đinh bảy màu trên bộ hài cốt dưới bia đá, bị sưu hồn lấy ký ức rồi chết dần trong tra tấn. Từ điển tịch biết mình là bộc tộc phản bội Cổ Thần.","anchor":"Mượn thần hồn lực dung nhập vào người Nguyệt Phệ tộc","bridge":true,"khoang":"@c1138"},{"chuong":"@c1139","importance":"normal","mucCt":"gon","tieuDe":"Bị Vương Lâm tiêu diệt hoàn toàn","text":"Thân thể hóa nước máu, xương cốt vỡ vụn, chỉ còn hai khúc xương giữ lại trên hai cây đinh bảy màu.","anchor":"vẫn còn lại hai khúc xương dược giữ lại trên hai cây đinh bảy màu"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh niên ký hiệu tia chớp","tag":"dong-hanh","quanHe":"Đồng hành, cùng xuất hiện trên tế đàn","ghiChu":""},{"ten":"Thanh niên ký hiệu ngọn lửa","tag":"dong-hanh","quanHe":"Đồng hành, cùng xuất hiện trên tế đàn","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Từng gặp trước đây, nghi nhận ra tâm thần Vương Lâm","ghiChu":"@c1130"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1128","@c1130","@c1136","@c1137","@c1138","@c1139"]},{"id":"thanh-nien-ky-hieu-ngon-lua","name":"Thanh niên ký hiệu ngọn lửa","cn":"","aliases":["Người thanh niên Hỏa Tước Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Hỏa Tước Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (biến thân tăng tu vi)","trangThai":"tu-vong","blurb":"Thành viên cuối của nhóm ba người trên tế đàn, mi tâm mang ký hiệu ngọn lửa đồ đằng.","vaiTro":"Thành viên nhóm người mang ký hiệu mi tâm xâm nhập thế giới bảy màu","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Mi tâm mang ký hiệu ngọn lửa đồ đằng, thành viên cuối cùng của nhóm ba người trên tế đàn","chuong":"@c1128"},{"text":"Mi tâm có ký hiệu ngọn lửa, cảm nhận triệu hoán từ tổ tiên Hỏa Tước Tộc trong vùng sâu thế giới bảy màu","chuong":"@c1130"},{"text":"Tu sĩ Hỏa Tước Tộc sở hữu cánh lửa và quyền năng hỏa, khi thấy bộ giáp Chu Tước hoảng sợ kêu lên Thánh giáo.","chuong":"@c1137"}],"kinhLich":[{"chuong":"@c1128","importance":"bridge","mucCt":"gon","text":"Cùng nhóm xuất hiện trên tế đàn phủ sương ở sâu trong thế giới bảy màu, mi tâm mang ký hiệu ngọn lửa đồ đằng.","anchor":"người cuối cùng có một ký hiệu ngọn lửa đồ đằng"},{"chuong":"@c1130","importance":"normal","mucCt":"vua","tieuDe":"Phát hiện tổ tiên Hỏa Tước Tộc, đề nghị liên thủ","text":"Cảm nhận triệu hoán và nhận định nơi này có tổ tiên Hỏa Tước Tộc vì tộc đằng mi tâm phản ứng mạnh. Khi tâm thần Vương Lâm phóng qua, ký hiệu ngọn lửa bùng cháy muốn thiêu thân, đau đớn tột độ. Đề nghị hai người kia mở phong ấn liên thủ đối phó.","anchor":"Nơi đây rõ ràng có tổ tiên Hỏa Tước tộc chúng ta, lực lượng tâm thần vừa rồi rõ ràng là tổ tiên"},{"chuong":"@c1136","importance":"normal","mucCt":"vua","tieuDe":"Đề xuất mở phong ấn giết Vương Lâm","text":"Đề xuất ba người mở phong ấn dùng lực lượng đỉnh phong để giết Vương Lâm. Vỗ mi tâm mở phong ấn, sau lưng mọc đôi cánh lửa, đầu mọc sừng, toàn thân bao phủ ngọn lửa.","anchor":"Nếu ba người chúng ta mở ra phong ấn thì có thể lợi dụng thời gian lực lượng đỉnh phong để giết tên kia"},{"chuong":"@c1137","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm giết, mất quyền hỏa và Tộc linh","text":"Hoảng sợ muốn rút lui nhưng bị biển lửa từ mắt trái Vương Lâm bao phủ mấy trăm trượng. Dùng cánh lửa tạo bão lửa đánh trả nhưng thất bại, ngọn lửa do chính hắn điều khiển phản bội thiêu đốt chủ nhân, thân hóa tro bụi. Trước khi chết kêu lên Thánh giáo! Thiêu! khi thấy bộ giáp Chu Tước và triệu hoán Tộc linh — con chim lửa đen khổng lồ. Tộc linh bị Chu Tước thật của Vương Lâm khinh thường rồi thôn phệ hoàn toàn.","anchor":"Kẻ này là người Hỏa Tước tộc, cả đời làm bạn với lửa nhưng chưa bao giờ nghĩ đến chuyện có một ngày chính mình bị lửa cắn trả"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh niên ký hiệu tia chớp","tag":"dong-hanh","quanHe":"Đồng hành, cùng xuất hiện trên tế đàn","ghiChu":""},{"ten":"Thanh niên ký hiệu trăng lưỡi liềm","tag":"dong-hanh","quanHe":"Đồng hành, cùng xuất hiện trên tế đàn","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù — bị Vương Lâm giết","ghiChu":"Bị đoạt quyền hỏa, Tộc linh bị Chu Tước thôn phệ @c1137"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1128","@c1130","@c1136","@c1137"]},{"id":"thieu-nu-giong-lao-ba-ao-xanh","name":"Thiếu nữ giống lão bà áo xanh","gioiTinh":"nu","trangThai":"song","vaiTro":"Thiếu nữ bí ẩn trong động phủ ngọn núi thứ hai, tướng mạo giống lão phụ nhân áo xanh","tinhCach":"Không rõ","blurb":"Thiếu nữ có tướng mạo giống lão bà áo xanh, được tâm thần Vương Lâm phát hiện đang khoanh chân thổ nạp trong động phủ ngọn núi thứ hai bị Tuế Nguyệt Cấm bao quanh, vẻ mặt xám tro, thân thể run rẩy.","tabs":{"diem":[{"text":"Tướng mạo giống lão bà áo xanh, ẩn trong động phủ ngọn núi thứ hai bên cạnh kho thú hồn phong ấn","chuong":"@c1130"}],"kinhLich":[{"mucCt":"gon","text":"Được tâm thần Vương Lâm phát hiện đang khoanh chân thổ nạp trong động phủ ngọn núi thứ hai, vẻ mặt xám như tro tàn, thân thể run rẩy.","anchor":"một thiếu nữ tướng mạo giống như lão bà áo xanh, nàng đang khoanh chân ngồi xuống mà vẻ mặt xám như tro tàn","bridge":true,"khoang":"@c1130"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão phụ nhân áo xanh","tag":"khac","quanHe":"Tướng mạo giống nhau, mối liên hệ chưa rõ","ghiChu":"@c1130"}],"tuiDo":{}},"nguon":["@c1130"]},{"id":"lao-gia-toc-trang-ngon-nui","name":"Lão già tóc trắng (ngọn núi thế giới bảy màu)","cn":"","aliases":["Nghịch Hành giả","hậu nhân Phong Diệt tộc","Phong Diệt tộc giả mạo"],"gioiTinh":"nam","vaiTro":"Hậu nhân Phong Diệt tộc — thủ hộ giả ngọn núi sâu nhất thế giới bảy màu","tinhCach":"Cảnh giác cao, chủ động tấn công thần thức kẻ thăm dò; quyết đoán khi giao chiến nhưng biết ngừng tay trước đạo niệm mạnh; ẩn nhẫn thủ hộ bí mật đến cùng","blurb":"Lão già tóc trắng là hậu nhân Phong Diệt tộc, tu vi Toái Niết hậu kỳ, ẩn trên ngọn núi sâu nhất thế giới bảy màu để thủ hộ thứ có thể liên quan đạo tủy. Khi màn Tuế Nguyệt cấm sụp đổ và ngọn lửa lam sắc tràn vào, lão triệu tập thần thông Nghịch Hành giả cùng chín khúc xương thú giao chiến Vương Lâm, thi triển Phong Thần thuật và Dịch Linh Ấn nhưng đều bị đánh bại. Cuối cùng lão dùng đạo thuật xóa kýức, bị phản đòn khi thấy Tiên Nghịch và Cực trong ký ức Vương Lâm, trọng thương mất sinh cơ mà tử vong.","theLuc":[],"canhGioiCaoNhat":"Toái Niết hậu kỳ","trangThai":"tu-vong","tabs":{"diem":[{"text":"Phóng thần thức hóa bàn tay khổng lồ tấn công tâm thần Vương Lâm khi hắn thăm dò ngọn núi","chuong":"@c1131"},{"text":"Thủ hộ ngọn núi sâu nhất thế giới bảy màu để lấy thứ có thể liên quan đạo tủy","chuong":"@c1133"},{"text":"Bộc lộ huyết mạch Phong Diệt tộc, triệu tập Nghịch Hành giả cùng chín khối xương thú và quả cầu nguyên lực giao chiến","chuong":"@c1141"},{"text":"Thi triển Phong Thần thuật và Dịch Linh Ấn nhưng bị ngọn lửa lam sắc quét sạch, chín khúc xương thú bảo hộ vỡ vụn","chuong":"@c1142"},{"text":"Thi triển đạo thuật xóa ký ức cảm ngộ từ đạo cảnh, xuyên qua Chiến Ý Cảnh của Vương Lâm","chuong":"@c1144"},{"text":"Bại vong dưới tay Vương Lâm khi đạo thuật bị phản đòn lúc thấy Tiên Nghịch và Cực trong ký ức hắn","chuong":"@c1145"}],"kinhLich":[{"mucCt":"vua","text":"Phóng thần thức hóa bàn tay khổng lồ tấn công tâm thần Vương Lâm khi hắn thăm dò ngọn núi. Nhận xét ý cảnh Vương Lâm tinh chất hơn Minh Chí Giả gấp trăm lần. Thấy Vương Lâm triệu hồi đạo niệm tạo phòng thủ mạnh thì ngừng tay, cảnh cáo chỉ một lần duy nhất rồi thu thần thức quay về.","anchor":"Đã từ rất lâu rồi chưa thấy luồng ý cảnh nào tinh chất như vậy","bridge":true,"khoang":"@c1131"},{"chuong":"@c1132","importance":"bridge","mucCt":"gon","text":"Ngồi trên ngọn núi sâu trong thế giới bảy màu, ngẩng đầu nhìn trời rồi lặng lẽ gật đầu, dường như nhận tín hiệu từ cung điện Thái Cổ tinh vực.","anchor":"Lão già ngẩng đầu lên nhìn về phía bầu trời, một lúc lâu sau lại lặng lẽ gật đầu"},{"chuong":"@c1133","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc đến: lão đang thủ hộ ngọn núi sâu nhất để lấy thứ gì đó có thể liên quan đạo tủy, trong ký ức Thương Tùng Tử không thấy hình bóng lão.","anchor":"Những gì Thương Tùng Tử tính toán chính là cầm đạo tủy này tìm một địa phương tuyệt đối an toàn"},{"mucCt":"vua","text":"Khi tấm màn Tuế Nguyệt cấm sụp đổ và ngọn lửa bùng vào thế giới bảy màu, mở mắt tràn đầy sợ hãi nhìn về phía Vương Lâm. Giống như nhận được mệnh lệnh, hóa cầu vồng gào thét phóng về phía Vương Lâm.","anchor":"thân thể lóe lên hóa thành một luồng cầu vồng gào thét phóng về phía Vương Lâm","bridge":true,"khoang":"@c1139"},{"mucCt":"vua","text":"Đang phóng đến nơi Vương Lâm từ vùng sâu nhất thế giới bảy màu nhưng bị ngọn lửa lam sắc chặn lại. Phải dùng pháp bảo và pháp quyết mới sống sót, mồ hôi lạnh đầy trán, kinh hoàng trước loại lửa chưa từng thấy có thể đốt cháy nguyên thần và thân thể tu sĩ Toái Niết.","anchor":"Đây. đây là loại lửa gì?","bridge":true,"khoang":"@c1140"},{"importance":"normal","chuong":"@c1141","mucCt":"vua","tieuDe":"Đối chiến Vương Lâm, triệu tập toàn bộ Nghịch Hành Giả","text":"Dùng chín khối xương thú và quả cầu nguyên lực khổng lồ chiến đấu, nhận định lửa Vương Lâm đủ chiến ngang tu sĩ Toái Niết và cảm ngộ lửa lam sắc mới là thứ Tôn giả muốn. Triệu hồi Nghịch Hành Giả uy lực vượt xa Thương Tùng Tử nhưng bị Vương Lâm phá. Dùng hiệu lệnh thủ hộ thế giới bảy màu triệu tập hơn mười Nghịch Hành Giả đồng loạt tấn công, tự tin pháp bảo Tôn giả ban không bị lửa phá.","anchor":"Dưới thần thông Nghịch Hành giả của lão phu thì ngươi đừng hòng chống đỡ nổi"},{"chuong":"@c1142","importance":"normal","mucCt":"ky","tieuDe":"Bộc lộ huyết mạch Phong Diệt tộc — Phong Thần thuật — Dịch Linh Ấn đối đầu","text":"Thi triển thần thông Nghịch Hành giả nhưng bị ngọn lửa lam sắc quét sạch, chín khúc xương thú bảo hộ vỡ vụn thành tro. Tình thế nguy cấp, bộc lộ thân phận mang một phần huyết mạch Phong Diệt tộc (không phải hậu nhân thật sự), thi triển Phong Thần thuật — điểm chỉ mi tâm mở khe hở bùng hắc quang, phong ấn thành công đồ đằng ngọn lửa trên mi tâm Vương Lâm khiến biển lửa lam tiêu tán, đổi lại ngoại hình cực kỳ già nua, sinh cơ hao tổn không thể khôi phục. Kinh hãi nhận ra Vương Lâm đồng thời sở hữu lực lượng Hỏa Tước tộc và Thiểm Lôi tộc, nhận định đây là mầm họa cho bộ tộc thái cổ. Tiết lộ từng đầu nhập Thần Tông học được Dịch Linh Ấn, thi triển bàn tay khổng lồ Dịch Linh Ấn đối công Vương Lâm — hai ấn phóng thẳng vào nhau.","anchor":"Hậu nhân Phong Diệt tộc kêu gọi đại thần thông phong ấn, phong bế đồ đằng ngọn lửa của tên kia"},{"mucCt":"ky","text":"Bị phản kích từ va chạm Dịch Linh Ấn, khóe miệng chảy máu. Thi triển Phong Thần thuật lần hai phong ấn ký hiệu Thiểm Lôi trên mi tâm Vương Lâm, sinh cơ tiêu tán nghiêm trọng, thân thể gầy như xác khô. Bị Vương Lâm dùng Chiến Ý cảnh áp đảo trong cận chiến. Triệu hồi toàn bộ đạo hồn từ Mê Thất giả, Minh Chí giả và mãnh thú, thi triển cấm thuật Tán Đạo bao phủ hào quang vàng lên Vương Lâm, đánh đổi toàn bộ tuổi thọ và tu vi, chỉ duy trì được ba hơi thở.","anchor":"Thắng hay bại đều được quyết định bằng một chiêu này","bridge":true,"khoang":"@c1143"},{"chuong":"@c1144","importance":"normal","mucCt":"ky","tieuDe":"Thi triển đạo thuật xóa ký ức, sinh cơ tiêu tán","text":"Thi triển đạo thuật đã cảm ngộ từ đạo cảnh, luồng hào quang vàng bao phủ thiên địa xuyên qua Chiến Ý Cảnh của Vương Lâm, trực tiếp xâm nhập ký ức linh hồn nhằm xóa bỏ. Triết lý của lão: bản nguyên mỗi người chính là ký ức trong linh hồn, xóa bỏ ký ức thì kẻ đó sẽ chết. Khép mắt lại, sinh cơ cả đời tiêu tán, dồn toàn bộ vào ba lần hít thở.","anchor":"Ba lần hít thở cũng đã đủ!"},{"chuong":"@c1145","importance":"normal","mucCt":"ky","tieuDe":"Bại vong dưới tay Vương Lâm","text":"Đạo thuật bị phản đòn khi nhìn thấy Tiên Nghịch và Cực trong ký ức Vương Lâm, trọng thương nặng mất sinh cơ. Bị Vương Lâm chỉ kiếm đánh vỡ đầu, nổ tung thân xác. Nguyên thần bỏ chạy được hào quang bảy màu bảo hộ, liên tục kêu cứu Tôn giả nhưng không ai đáp. Cuối cùng bị lôi hỏa ngưng tụ tiêu diệt hoàn toàn. Được giọng tang thương ở Thái Cổ Tinh Thần xác nhận là Phong Diệt tộc giả mạo, không phải Phong Diệt tộc thật.","anchor":"Chết một tên Phong Diệt tộc giả mạo, ngươi không nghi ngờ nguyên nhân cái chết của hắn sao"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối đầu rồi lui bước","ghiChu":"Tấn công tâm thần Vương Lâm khi hắn thăm dò ngọn núi, thấy mạnh thì cảnh cáo rồi lui (@c1131)"},{"ten":"Minh Chí Giả","tag":"khac","quanHe":"So sánh","ghiChu":"Nhận xét ý cảnh Vương Lâm tinh chất hơn Minh Chí Giả gấp trăm lần (@c1131)"}],"tuiDo":{}},"nguon":["@c1131","@c1132","@c1133","@c1139","@c1140","@c1141","@c1142","@c1143","@c1144","@c1145"]},{"id":"giong-noi-tang-thuong-dai-dien-thai-co-tinh-than","name":"Giọng nói tang thương (đại điện Thái Cổ Tinh Thần)","aliases":["Người nuôi hoa","Chủ nhân vòng xoáy"],"gioiTinh":"khong-ro","trangThai":"song","theLuc":[],"blurb":"Thế lực bí ẩn trong cung điện cấm địa Thái Cổ tinh vực, thở dài khi ngọc giản Thương Tùng Tử vỡ, nghịch chuyển thời gian tái ngưng tụ ngọc giản đổi tên thành Vương Lâm, nhắm đến linh hồn Vương Lâm để thành đạo.","vaiTro":"Thế lực bí ẩn đứng sau, nhắm linh hồn Vương Lâm","tinhCach":"Bí ẩn; tang thương; mưu tính thâm sâu","tabs":{"diem":[{"text":"Phát ra tiếng thở dài và giọng thì thào trong cung điện Thái Cổ tinh vực, nghịch chuyển thời gian ngưng tụ lại ngọc giản đã vỡ, đổi tên mục tiêu sang Vương Lâm","chuong":"@c1132"}],"kinhLich":[{"chuong":"@c1132","importance":"normal","mucCt":"ky","tieuDe":"Ngọc giản nghịch chuyển, nhắm linh hồn Vương Lâm","text":"Khi Thương Tùng Tử chết, ngọc giản mang tên lão trong cung điện vỡ tan. Phát ra tiếng thở dài, nghịch chuyển thời gian khiến ngọc giản tái ngưng tụ đổi tên thành Vương Lâm. Thì thào rằng nếu có được linh hồn người này thì đạo chắc chắn sẽ thành, truyền âm vào tinh không.","anchor":"Ngọc giản đã vở tan lập tức xuất hiện nghịch biến, lại được ngưng tụ giống như tất cả tình cảnh xuất hiện vừa rồi chưa từng được xảy ra"},{"chuong":"@c1145","importance":"normal","mucCt":"vua","tieuDe":"Bình luận về Vương Lâm và cái chết lão già tóc trắng","text":"Ngón tay già nua thu về, nhận xét sức lửa của Vương Lâm đã đến mức nhưng chưa nung nấu hồn phách nên chưa hợp đạo. Gọi lão già tóc trắng là Phong Diệt tộc giả mạo, nói không cần nghi ngờ nguyên nhân cái chết, sau khi loại đạo sẽ biết tất cả, coi chờ đợi là hương vị tuyệt vời nhất.","anchor":"sau khi loại đạo, ta sẽ biết được tất cả các đáp án, như vậy sẽ thú vị hơn"},{"chuong":"@c1146","importance":"normal","mucCt":"ky","tieuDe":"Tiết lộ thân phận người nuôi bảy cây hoa, chờ Thiên Đạo Kế","text":"Giọng nói vang ra từ vòng xoáy đen kịt, gọi sự điên cuồng của Vương Lâm là lửa giận — ngọn lửa tuyệt vời nhất trong thiên địa, yêu cầu Vương Lâm dùng lửa giận nung nấu hồn phách loại bỏ đạo. Sau khi Đạo quả đỏ kết thành, trả lời rằng lửa giận không thể đốt cháy ngón tay. Tiết lộ năm xưa được Chưởng Tôn khuyên không nên đối mặt Không Kiếp, tình nguyện trở thành người nuôi dưỡng bảy cây hoa, chờ Thiên Đạo Kế của Chưởng Tôn hoàn thành. Cho biết sáu cây hoa còn lại cũng sắp kết quả.","anchor":"năm xưa lão phu được Chưởng Tôn nói không nên đối mặt với Không Kiếp"},{"chuong":"@c1147","importance":"bridge","mucCt":"gon","text":"Không phát hiện biến đổi kinh thiên trong Đạo quả cây bảy màu khi hạt châu Tiên Nghịch xuất hiện.","anchor":"Người nuôi hoa nói hắn sẽ không bao giờ bị ngọn lửa đốt cháy ngón tay"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu linh hồn","ghiChu":"Nhắm đến linh hồn Vương Lâm để thành đạo"},{"ten":"Chưởng Tôn","tag":"an-nhan","quanHe":"Người khuyên bảo, ban Thiên Đạo Kế","ghiChu":"Chưởng Tôn khuyên không đối mặt Không Kiếp, nuôi bảy cây hoa chờ Thiên Đạo Kế hoàn thành"}],"tuiDo":{},"tuViMoc":[]},"nguon":["@c1132","@c1145","@c1146","@c1147"]},{"id":"bon-me-that-gia","name":"Bốn Mê Thất giả (đồng môn Tư Mã Đặc)","cn":"","aliases":[],"gioiTinh":"khong-ro","canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","vaiTro":"Bốn đồng môn Tư Mã Đặc bị phong ấn trong động phủ thứ năm, trạng thái Mê Thất giả","blurb":"Bốn người quần áo hủy hoại, đầu trọc, mắt phát sáng như xác không hồn, mê man đi lại trong động phủ thứ năm ở sơn cốc thế giới bảy màu.","tinhCach":["Mất hồn, mê man đi lại như xác sống"],"tabs":{"diem":[{"text":"Xác không hồn, mắt phát sáng, mê man đi lại trong động phủ, bị trận pháp tỏa sáng dung nhập vào thân thể","chuong":"@c1133"}],"kinhLich":[{"mucCt":"gon","text":"Bốn người quần áo hủy hoại, đầu trọc, mắt phát sáng như xác không hồn, mê man đi lại trong động phủ thứ năm, bị trận pháp tỏa sáng dung nhập vào thân thể.","anchor":"Ngày trước Tư Mã Đặc đã đưa bọn họ về phong ấn trong động phủ rồi cố gắng để bọn họ thức tình","bridge":true,"khoang":"@c1133"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Mã Mặc","tag":"dong-hanh","quanHe":"Đồng môn","ghiChu":"Bị Tư Mã Đặc đưa về phong ấn cố cho thức tỉnh nhưng thất bại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1133"]},{"id":"ba-minh-chi-gia","name":"Ba Minh Chí giả (đồng môn Tư Mã Đặc)","cn":"","aliases":["Đám Minh Chí giả"],"gioiTinh":"khong-ro","canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Ba đồng môn Tư Mã Đặc bị phong ấn trong động phủ thứ sáu, trạng thái Minh Chí giả","blurb":"Ba nguyên thần không còn thân thể, bay bổng lẩm bẩm trong động phủ thứ sáu ở sơn cốc thế giới bảy màu.","tinhCach":["Chỉ còn nguyên thần, bay bổng lẩm bẩm"],"tabs":{"diem":[{"text":"Chỉ còn nguyên thần không thân thể, bay bổng lẩm bẩm trong động phủ phong ấn","chuong":"@c1133"}],"kinhLich":[{"mucCt":"gon","text":"Ba nguyên thần không còn thân thể, bay bổng lẩm bẩm trong động phủ thứ sáu bị cấm chế phong ấn.","anchor":"Ngày trước Tư Mã Đặc đã đưa bọn họ về phong ấn trong động phủ rồi cố gắng để bọn họ thức tình","bridge":true,"khoang":"@c1133"},{"chuong":"@c1140","importance":"bridge","mucCt":"gon","text":"Bay lơ lửng trong không trung khoanh chân chống lại sự xâm nhập của ngọn lửa bạch sắc.","anchor":"Đám Minh Chí giả đang ngồi khoanh chân bay bổng trong không trung để chống lại sự xâm nhập của ngọn lửa"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Mã Mặc","tag":"dong-hanh","quanHe":"Đồng môn","ghiChu":"Bị Tư Mã Đặc đưa về phong ấn cố cho thức tỉnh nhưng thất bại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1133","@c1140"]},{"id":"chien-tinh-da","name":"Chiến Tinh Dã","cn":"战星野","aliases":["lão tổ Chiến gia","Chiến mỗ"],"gioiTinh":"nam","theLuc":[{"ten":"Chiến gia","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"tu-vong","blurb":"Chiến Tinh Dã là lão tổ Chiến gia trên La Thiên, thiên tư cực cao, đạt tới cảnh giới Không Linh Chi (Đệ Tam Bộ) nhờ cảm ngộ Chiến Tự Thiếp. Ông bị Chưởng Tôn dùng thần thông phong ấn giết chết để thực hiện Thiên Đạo Kế, chỉ còn lại nửa bộ hài cốt bị đinh bảy màu ghim trên bia đá. Chiến ý cùng di ngôn của ông sau này truyền đến Vương Lâm, trở thành động lực để hắn dám đối đầu với cường địch.","vaiTro":"Lão tổ Chiến gia, truyền nhân Chiến Lão Quỷ, nạn nhân Thiên Đạo Kế","tinhCach":"Thiên tư phi phàm; kiên cường chiến đấu đến chết; ý chí bất khuất truyền qua chữ Chiến","tabs":{"diem":[{"text":"Đạt cảnh giới Không Linh Chi (Đệ Tam Bộ) nhờ cảm ngộ Chiến Tự Thiếp","chuong":"@c1134"},{"text":"Xuất hiện dưới hình dạng lão già áo trắng, thi triển chữ chiến kim sắc chống lại thần thông trong ảo cảnh","chuong":"@c1134"},{"text":"Bị Chưởng Tôn phong ấn giết chết để thực hiện Thiên Đạo Kế","chuong":"@c1134"},{"text":"Di ngôn truyền qua chữ Chiến đến Vương Lâm, nửa bộ hài cốt bị hai cây đinh bảy màu ghim trên bia đá","chuong":"@c1136"},{"text":"Chiến ý và câu nói vang vọng trong đầu Vương Lâm, trở thành động lực để hắn dám đối đầu tu sĩ mạnh","chuong":"@c1142"}],"kinhLich":[{"chuong":"@c1134","importance":"normal","mucCt":"ky","tieuDe":"Bị Chưởng Tôn phong ấn giết chết trong Thiên Đạo Kế","text":"Xuất hiện trong ảo cảnh dưới hình dạng lão già áo trắng, thi triển chữ chiến kim sắc chống lại thần thông bảy màu nhưng bị phong ấn mà chết. Trước đó đã đoạt được Chiến Tự Thiếp do Chưởng Tôn tặng và cảm ngộ ý cảnh đạt cảnh giới Không Linh Chi. Bị Chưởng Tôn dùng chiến hồn làm dẫn để tìm xương cốt sư phụ Chiến Lão Quỷ, bức ra đạo tủy hai người sư đồ trong mưu kế Thiên Đạo Kế.","anchor":"Chiến Tinh Dã, nếu không phải năm xưa lão phu tặng ngươi Chiến Tự Thiếp"},{"chuong":"@c1136","importance":"major","mucCt":"ky","tieuDe":"Di ngôn truyền qua chữ Chiến đến Vương Lâm","text":"Nửa bộ hài cốt bị hai cây đinh bảy màu ghim chặt trên bia đá khổng lồ trong không gian kỳ dị. Khi Vương Lâm đưa chữ Chiến hư ảo đến gần, kim quang từ hài cốt phóng ra dung hợp vào chữ Chiến. Di ngôn vang lên trong tâm thần Vương Lâm: tự xưng tu sĩ La Thiên, thà tan vỡ đạo niệm chứ không khuất phục Chưởng Tôn, yêu cầu người đoạt chiến ý cảm ngộ và giết sạch dân Ngoại giới tế linh hồn mình.","anchor":"Chiến mỗ là tu sĩ La Thiên, thà tan vỡ đạo niệm chứ không cấu kết với người Ngoại giới"},{"chuong":"@c1142","importance":"bridge","mucCt":"gon","text":"Chiến ý và câu nói của Chiến Tinh Dã vang vọng trong đầu Vương Lâm, trở thành động lực để hắn dám đối đầu tu sĩ Toái Niết hậu kỳ.","anchor":"Ta là tu sĩ, sợ gì một trận chiến"}],"tuViMoc":[{"chuong":"@c1134","canhGioi":"Không Linh Chi (Đệ Tam Bộ)","text":"Đạt cảnh giới Không Linh Chi nhờ cảm ngộ Chiến Tự Thiếp do Chưởng Tôn tặng","importance":"major"}],"nhanMach":[{"ten":"Chiến Lão Quỷ","tag":"su-mon","quanHe":"Sư phụ, Chiến Tự Thiếp chứa đạo niệm của Chiến Lão Quỷ","ghiChu":"@c1134"},{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Kẻ tặng Chiến Tự Thiếp rồi giết lấy chiến hồn, chủ mưu Thiên Đạo Kế","ghiChu":"@c1134"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người chứng kiến ảo cảnh bị giết và thừa hưởng Chiến Tự Thiếp hoàn chỉnh","ghiChu":"@c1134"}],"tuiDo":{"phapBao":[{"ten":"Chiến Tự Thiếp","trangThai":"mat","moTa":"Do Chưởng Tôn tặng, nhờ đó cảm ngộ đạt Không Linh Chi, sau khi chết kim quang từ hài cốt thoát ra nhập vào ba bức tranh","nguon":"@c1134"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1134","@c1136","@c1142"]},{"id":"chien-lao-quy","name":"Chiến Lão Quỷ","cn":"战老鬼","aliases":["Không Kiếp"],"gioiTinh":"nam","canhGioiCaoNhat":"Không Kiếp (Đệ Tam Bộ)","trangThai":"tu-vong","blurb":"Sư phụ Chiến Tinh Dã, cảnh giới Không Kiếp trong Đệ Tam Bộ. Chưởng Tôn rất e sợ hắn, bày mưu Thiên Đạo Kế tìm xương cốt hắn chôn giấu để bức ra đạo tủy. Chiến Tự Đồ chính là tất cả đạo niệm hắn giữ lại.","vaiTro":"Sư phụ Chiến Tinh Dã, cường giả Không Kiếp, mục tiêu Thiên Đạo Kế","tinhCach":"Mạnh mẽ đến mức Chưởng Tôn phải e sợ; để lại đạo niệm bảo vệ truyền nhân","tabs":{"diem":[{"text":"Cảnh giới Không Kiếp trong Đệ Tam Bộ, Chưởng Tôn rất e sợ phải bày mưu Thiên Đạo Kế xuyên nhiều đời để tìm xương cốt","chuong":"@c1134"},{"text":"Chiến Tự Đồ chính là tất cả đạo niệm Chiến Lão Quỷ giữ lại, bản chất là di sản bảo vệ truyền nhân","chuong":"@c1134"}],"kinhLich":[{"mucCt":"vua","text":"Được Chưởng Tôn nhắc đến qua lời tuyên bố khi giết Chiến Tinh Dã: muốn tìm xương cốt chôn giấu nơi đây để bức ra đạo tủy hai người sư đồ. Vương Lâm suy đoán lão già trong Chiến Tự Thiếp từng nói về cảnh giới Phong Không Chi chính là Chiến Lão Quỷ.","anchor":"Chiến Tự Đồ chính là tất cả đạo niệm mà Chiến Lão Quỷ giữ lại ở nơi này!","bridge":true,"khoang":"@c1134"}],"tuViMoc":[{"chuong":"@c1134","canhGioi":"Không Kiếp (Đệ Tam Bộ)","text":"Cảnh giới Không Kiếp, cao hơn Không Linh, Chưởng Tôn e sợ","importance":"major"}],"nhanMach":[{"ten":"Chiến Tinh Dã","tag":"su-mon","quanHe":"Đồ đệ, vô tình đoạt được Chiến Tự Thiếp và trở thành truyền nhân","ghiChu":"@c1134"},{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Kẻ bày Thiên Đạo Kế muốn bức ra đạo tủy từ xương cốt","ghiChu":"@c1134"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1134"]},{"id":"linh-nhi","name":"Linh Nhi","cn":"灵儿","aliases":[],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1135","importance":"bridge","mucCt":"gon","text":"Được nhắc thoáng qua: Vương Lâm từ Linh Nhi mà biết Nguyệt Phệ tộc trước đây chỉ là tôi tớ của Cổ Thần.","anchor":"Mạnh mẽ như Nguyệt Phệ tộc mà Vương Lâm cũng từ Linh Nhi mà biết dược"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Xuất hiện với tu vi Nguyên Anh kỳ, bái kiến Vương Lâm theo lời Nhất Trần Tử","chuong":"@c0906"},{"text":"Con gái Nhất Trần Tử, người có tên được dùng đặt cho Thủy Linh Tinh","chuong":"@c0921"},{"text":"Thức tỉnh ký ức Thần nô Mộc Linh khi nhìn thấy năm ngôi sao Cổ Thần trên mi tâm Vương Lâm","chuong":"@c0927"},{"text":"Bị Tư Đồ Nam nhìn ra Thủy Linh căn và cuốn đi","chuong":"@c0933"},{"text":"Quỳ trước tượng đá Vương Lâm van xin cứu tổ gia gia sắp chết","chuong":"@c1029"},{"text":"Nguồn để Vương Lâm biết Nguyệt Phệ tộc trước đây chỉ là tôi tớ của Cổ Thần","chuong":"@c1135"}]},"nguon":["@c1135"],"vaiTro":"Vãn bối Thủy Linh thể của Nhất Trần Tử, ẩn chứa Thần nô Mộc Linh","tinhCach":"hồn nhiên, chủ động thân cận cố nhân; trọng tình, tận tâm bồi bạn tổ gia gia lúc hoạn nạn; kiên trì, dám quỳ cầu xin vì người thân","blurb":"Linh Nhi là con gái Nhất Trần Tử và là người được dùng tên đặt cho Thủy Linh Tinh, trời sinh Thủy Linh thể nên luôn được che chở vì dễ bị kẻ xấu nhắm làm lô đỉnh. Ra mắt Vương Lâm với tu vi Nguyên Anh kỳ, nàng dần thức tỉnh ký ức bị phong ấn về thân phận Thần nô Mộc Linh sau khi nhìn thấy năm ngôi sao Cổ Thần trên mi tâm hắn. Về sau nàng bị Tư Đồ Nam nhận ra Thủy Linh căn và cuốn đi, rồi lặng lẽ bồi bạn bên Trần Đạo Tử trong những ngày tang thương."},{"id":"chu-tuoc","name":"Chu Tước","cn":"朱雀","gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1137","importance":"major","mucCt":"ky","tieuDe":"Thôn phệ Tộc linh Hỏa Tước, có dấu hiệu thức tỉnh lần ba","text":"Chu Tước thật (trắng) xuất hiện từ thân Vương Lâm, khinh thường con chim lửa đen (Tộc linh Hỏa Tước Tộc) rồi trực tiếp thôn phệ hoàn toàn cả ngọn lửa lẫn linh hồn nó. Sau khi thôn phệ, Chu Tước ngửa mặt hót vang trời, tinh thần cực kỳ hưng phấn, mơ hồ có dấu hiệu thức tỉnh lần thứ ba.","anchor":"tinh thần nó cực kỳ hưng phấn giống như mơ hồ có dấu hiệu thức tỉnh lần thứ ba"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1137"]},{"id":"lao-gia-tang-thuong-nguyet-phe-toc","name":"Lão già tang thương mặc nguyệt bào (Nguyệt Phệ tộc)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Nguyệt Phệ tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Nhân vật cao cấp Nguyệt Phệ tộc, phát hiện pho tượng Cổ Thần sụp đổ","tinhCach":"Quyết đoán; sợ hãi trước sức mạnh vương tộc Cổ Thần","blurb":"Nhân vật cao cấp của Nguyệt Phệ tộc, mặc nguyệt bào, phóng đến cấm địa khi chín pho tượng Cổ Thần sụp đổ. Nhận ra có vương tộc Cổ Thần xóa bỏ quy ước Thái Cổ, trong mắt lộ sợ hãi kinh hoàng.","tabs":{"diem":[{"text":"Nhận ra nguyên nhân pho tượng sụp đổ là do vương tộc Cổ Thần xóa quy ước, bùng lên sợ hãi","chuong":"@c1139"}],"kinhLich":[{"chuong":"@c1139","importance":"normal","mucCt":"vua","tieuDe":"Phát hiện pho tượng Cổ Thần sụp đổ","text":"Phóng đến cấm địa Nguyệt Phệ tộc khi chín pho tượng Cổ Thần nứt vỡ, ra lệnh toàn lực ngăn cản. Nhận ra nguyên nhân: có vương tộc Cổ Thần xóa bỏ quy ước Thái Cổ, trong mắt bùng lên sợ hãi kinh hoàng.","anchor":"Có vương tộc Cổ Thần xóa bỏ quy ước Thái Cổ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1139"]},{"id":"chin-lao-gia-cam-dia-nguyet-phe-toc","name":"Chín lão già cấm địa Nguyệt Phệ tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Nguyệt Phệ tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Chín tu sĩ thiên tư cao nhất Nguyệt Phệ tộc, cưỡng chế hấp thu lực lượng Cổ Thần","tinhCach":"Khiếp sợ khi biến cố xảy ra","blurb":"Chín tu sĩ thiên tư cực cao của Nguyệt Phệ tộc, ngồi trên chín pho tượng Cổ Thần trong cấm địa dùng pháp quyết cưỡng chế hấp thu lực lượng Cổ Thần. Bừng tỉnh khi pho tượng nứt vỡ.","tabs":{"diem":[{"text":"Ngồi trên chín pho tượng Cổ Thần cưỡng chế hấp thu lực lượng, bừng tỉnh hoảng sợ khi tượng sụp đổ","chuong":"@c1139"}],"kinhLich":[{"chuong":"@c1139","importance":"normal","mucCt":"gon","tieuDe":"Pho tượng Cổ Thần sụp đổ","text":"Chín pho tượng Cổ Thần đồng loạt nứt vỡ, chín lão già bừng tỉnh khiếp sợ mờ mịt.","anchor":"pho tương Cổ Thần đầu tiên đã sụp đổ ầm ầm, lực lượng Cổ Thần tiêu tán trong trời đất"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1139"]},{"id":"chu-nhan-ngon-tay-heo-ru","name":"Chủ nhân ngón tay héo rũ (cung điện Thái Cổ Tinh Thần)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Nhân vật bí ẩn trong cung điện bay bổng Thái Cổ Tinh Thần, quan sát Chu Tước thức tỉnh","tinhCach":"Tự tin tuyệt đối; bình thản trước lửa hủy diệt","blurb":"Ngồi trong cung điện bay bổng đen tối giữa tinh không Thái Cổ Tinh Thần. Điểm ngón tay héo rũ lên nến lửa, nhận xét ngọn lửa Chu Tước rất thích hợp thiêu đốt linh hồn, rồi đưa tay vào lửa thể hiện tự tin tuyệt đối.","tabs":{"diem":[{"text":"Đưa ngón tay vào lửa, tự tin tuyệt đối trước uy lực Chu Tước thức tỉnh lần ba","chuong":"@c1139"}],"kinhLich":[{"mucCt":"gon","text":"Ngồi trong cung điện bay bổng, điểm ngón tay lên nến, nhận xét ngọn lửa Chu Tước thích hợp thiêu đốt linh hồn rồi đưa tay vào lửa thể hiện tự tin tuyệt đối.","anchor":"Ngọn lửa thiêu đốt càng mạnh, nếu dùng để thiêu đốt linh hồn thì cực kỳ tuyệt vời","bridge":true,"khoang":"@c1139"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1139"]},{"id":"giong-noi-thu-hai-cung-dien-thai-co","name":"Giọng nói thứ hai (cung điện Thái Cổ Tinh Thần)","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Nhân vật bí ẩn thứ hai trong cung điện bay bổng, chất vấn chủ nhân ngón tay","tinhCach":"Lạnh lùng; thận trọng","blurb":"Giọng nói lạnh như băng vang lên trong cung điện bay bổng Thái Cổ Tinh Thần, chất vấn chủ nhân ngón tay héo rũ có sợ ngọn lửa mạnh lên thiêu cháy tay mình không.","tabs":{"diem":[{"text":"Chất vấn chủ nhân ngón tay về nguy cơ ngọn lửa Chu Tước mạnh lên","chuong":"@c1139"}],"kinhLich":[{"chuong":"@c1139","importance":"bridge","mucCt":"gon","text":"Giọng lạnh như băng chất vấn chủ nhân ngón tay có sợ ngọn lửa mạnh lên thiêu cháy tay mình không.","anchor":"Ngươi không sợ sau khi ngọn lửa kia trở nên mạnh mẽ thì thiêu cháy ngón tay chính mình sao?"},{"chuong":"@c1145","importance":"bridge","mucCt":"gon","text":"Hỏi giọng tang thương liệu có nghi ngờ nguyên nhân cái chết của tên Phong Diệt tộc giả mạo không.","anchor":"ngươi không nghi ngờ nguyên nhân cái chết của hắn sao"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1139","@c1145"]},{"id":"thanh-long-thanh-hoang","name":"Thanh Long Thánh Hoàng","cn":"青龙圣皇","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tứ Thánh Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thanh Long Thánh Hoàng là Thánh Hoàng hùng mạnh nhất của Tứ Thánh Tông, vừa nhậm chức liền điều tra Tiên giới sụp đổ rồi mất tích, chỉ để lại thần niệm cầu cứu trong Thanh quang thuẫn. Sau khi bị Tiên Đế Thanh Lâm phong ấn trong lòng núi tại Vũ chi Tiên giới, ông được đoàn của Vương Lâm giải cứu và thoát ra. Trở về, ông chỉnh hợp Tứ Thánh Tông thành một tông duy nhất và xưng thánh tôn, tính tình đã đổi khác vì ảnh hưởng của máu thiên đạo, rồi bế quan trấn áp nội hoạ và ra tay thu phục các thế lực.","vaiTro":"Thánh Hoàng hùng mạnh nhất Tứ Thánh Tông, sau xưng thánh tôn","tinhCach":"Năm xưa hào sảng phóng khoáng; nay âm trầm tâm cơ sâu do ảnh hưởng máu thiên đạo; giỏi bày mưu giăng bẫy","tabs":{"diem":[{"text":"Vừa nhậm chức liền đi điều tra Tiên giới sụp đổ rồi mất tích không tin tức","chuong":"@c1027"},{"text":"Bị Tiên Đế Thanh Lâm phong ấn trong lòng núi tại Vũ chi Tiên giới","chuong":"@c1043"},{"text":"Được đoàn Vương Lâm giải cứu, thoát phong ấn và tiết lộ máu thiên đạo cùng cạm bẫy","chuong":"@c1044"},{"text":"Chỉnh hợp Tứ Thánh Tông thành một tông duy nhất, xưng thánh tôn","chuong":"@c1054"},{"text":"Bế quan trấn áp nội hoạ rồi xuất quan hạ lệnh thu phục Côn Hư","chuong":"@c1141"},{"text":"Một mình tiến vào tinh vực Thi Âm Tông, giết/trọng thương nhiều trưởng lão và đánh bại tông chủ","chuong":"@c1147"}],"kinhLich":[{"importance":"normal","chuong":"@c1141","mucCt":"ky","tieuDe":"Bế quan trấn áp nội hoạ, xuất quan hạ lệnh thu phục Côn Hư","text":"Bế quan một tháng trong mật thất đại điện Thanh Long, bị tám sợi xích sắt đen khoá chặt, bốn thanh Thái Cổ Tứ Thánh Khí trấn áp thân thể. Khối thịt quái dị di chuyển dưới da gây đau đớn cực độ, trên đầu mơ hồ hiện hình Thanh Long suy yếu mọc vật huyết sắc. Lão tạm chiến thắng cơn phát tác. Cảm ứng được Chu Tước Thánh Hoàng đã dục hoả trọng sinh, thức tỉnh Chu Tước lần thứ ba — tộc nhân đầu tiên kể từ thượng cổ, cười điên kèm nước mắt xác nhận đây là người lão lựa chọn. Xuất quan, giải phóng xích sắt, thu bốn thanh thánh khí vào cơ thể. Hạ lệnh triệu tập toàn bộ tộc nhân Tứ Thánh Tông thu phục Côn Hư tinh vực — tất cả tu sĩ hoặc quy hàng hoặc chết. Thầm nói về tương lai Ngoại giới.","anchor":"Lão phu lại chiến thắng một lần nữa"},{"mucCt":"vua","text":"Một mình tiến vào tinh vực Thi Âm Tông, giết/trọng thương nhiều trưởng lão, đánh bại tông chủ Đệ Nhất Vương nhưng không giết. Sau đó bị Thác Sâm dùng lực lượng Cổ Thần phối hợp tinh điểm mi tâm đánh trọng thương nặng.","anchor":"dùng một thức thần thông đánh Thanh Long Thánh Hoàng bị thương nặng","bridge":true,"khoang":"@c1147"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1141","@c1147"]},{"id":"chu-tuoc-thanh-hoang","name":"Chu Tước Thánh Hoàng","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Chu Tước Thánh Hoàng là lão tổ giữ danh vị trọng yếu của Chu Tước mạch thuộc Tứ Thánh Tông, ngự tại tinh vực lửa nơi Cấm Địa Chu Tước. Cận kề tử vong, ông vẫn ba năm không ngừng truyền nguyên lực cho Vương Lâm, đích thân áp chế phong ấn và trao lại toàn bộ truyền thừa Thánh Hoàng cho hắn. Cuối cùng ông qua đời sau khi để lại trăn trối, được Vương Lâm nhớ tới với ân nghĩa sâu nặng, và về sau được xác nhận đã dục hỏa trọng sinh — thức tỉnh Chu Tước lần thứ ba.","vaiTro":"Lão tổ Cấm Địa Chu Tước — người truyền thừa danh vị Thánh Hoàng cho Vương Lâm","tinhCach":"Tận tâm dẫn dắt, hi sinh bản thân vì hậu bối; kiên định bảo hộ đệ tử, sẵn sàng xuất thủ cứu khi nguy; trânọng và kỳ vọng ở người kế tục","tabs":{"diem":[{"text":"Phát thần niệm cực mạnh từ sâu trong tinh vực lửa để cứu Vương Lâm khi Chu Tước Chi Biến","chuong":"@c0967"},{"text":"Xuất hiện dưới dạng nguyên thần từ tinh không, đứng ra bảo hộ Vương Lâm cùng các nhánh Tứ Thánh","chuong":"@c1012"},{"text":"Mở đệ tam trọng Chu Tước Thánh khí, thi triển Thái cổ Tứ Thánh khí và phong ấn Cổ Ma","chuong":"@c1014"},{"text":"Ba năm cường hành truyền nguyên lực, bốn lần đích thân áp chế phong ấn nguyên lực cho Vương Lâm dù cận kề tử vong","chuong":"@c1017"},{"text":"Trao cho Vương Lâm ba vật phẩm truyền thừa của tân Thánh Hoàng: áo choàng, Chu Tước Thánh khí và toàn bộ truyền thừa","chuong":"@c1020"},{"text":"Để lại trăn trối bằng thần niệm đặc biệt rồi qua đời, về sau dục hỏa trọng sinh thức tỉnh Chu Tước lần thứ ba","chuong":"@c1039"}],"kinhLich":[{"importance":"bridge","chuong":"@c1141","mucCt":"gon","text":"Được Thanh Long Thánh Hoàng xác nhận đã dục hoả trọng sinh, thức tỉnh Chu Tước lần thứ ba — tộc nhân đầu tiên kể từ thượng cổ.","anchor":"không ngờ có thể dục hỏa trọng sinh"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1141"]},{"id":"de-nhat-vuong","name":"Đệ Nhất Vương","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thi Âm Tông","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Tông chủ Thi Âm Tông, bế quan nhiều năm","tinhCach":"Thận trọng; ẩn mình bế quan","blurb":"Tông chủ Thi Âm Tông, bế quan nhiều năm. Bị ép xuất quan giao chiến với Thanh Long Thánh Hoàng nhưng hoàn toàn bại trận.","tabs":{"diem":[{"text":"Tông chủ Thi Âm Tông nhưng hoàn toàn bại dưới tay Thanh Long Thánh Hoàng","chuong":"@c1147"}],"kinhLich":[{"chuong":"@c1147","importance":"normal","mucCt":"vua","tieuDe":"Bại trận trước Thanh Long Thánh Hoàng","text":"Bế quan nhiều năm phải xuất quan giao chiến với Thanh Long Thánh Hoàng nhưng hoàn toàn suy bại. Thanh Long Thánh Hoàng vì có mục đích khác nên không giết.","anchor":"Đệ Nhất Vương Thi Âm Tông đã hoàn toàn suy bại"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Long Thánh Hoàng","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Bị đánh bại nhưng được tha mạng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1147"]},{"id":"moc-bang-mi","name":"Mộc Băng Mi","cn":"木冰弥","aliases":["Liễu Mi"],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1147","importance":"normal","mucCt":"vua","tieuDe":"Bị Thác Sâm đánh tan thân, trốn đến Man Hoang","text":"Chiến đấu với Thác Sâm, thân thể tan vỡ, nguyên thần trọng thương, bị lưu ký hiệu. Dùng bí thuật Côn Hư phá ranh giới chạy đến Man Hoang đại lục trên Vân Hải tinh vực, ngưng tụ thân thể trong động phủ, ý niệm duy nhất là muốn gặp Vương Lâm.","anchor":"Vương Lâm, không biết giờ đây ngươi như thế nào, có khỏe không?"},{"mucCt":"ky","text":"Ẩn trong động phủ trên đỉnh núi ở đại lục hoang dã trong Vân Hải tinh vực, thương thế nặng chưa hồi phục. Đợi ngọc giản truyền thừa Côn Hư lão tổ mà nàng đã ném ra khi đến Vân Hải. Hồi tưởng cuộc đời, đặc biệt về phân thân Liễu Mi — phân thân đặc biệt nhất khiến nàng đôi khi không phân biệt được mình là Liễu Mi hay Mộc Băng Mi, nước mắt nguyên thần chảy xuống. Nữ tử hoàng sam Vương San San đến nói gia sư có việc ngoài ý muốn nên sai nàng đón Mộc Băng Mi về Thần Tông. Nghe họ Vương, Mộc Băng Mi lộ vẻ cô đơn. Đồng ý cùng Vương San San về Thần Tông và ghé xem cuộc so tài tông phái.","anchor":"Liễu Mi là phân thân đặc biệt nhất, cũng chính bởi vì sự đặc biệt đó mà có lúc khiến cho Mộc Băng Mi có chút không thể phân biệt rõ mình là Liễu Mi hay là Mộc Băng Mi","bridge":true,"khoang":"@c1163"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương San San","tag":"ban-be","quanHe":"Người đến đón Mộc Băng Mi về Thần Tông theo lệnh gia sư","ghiChu":"Tự xưng muội muội, mang đan dược, đề nghị cùng đi xem cuộc so tài"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Cứu Vương Lâm cận tử, hóa cầu vồng lao đỡ khi hắn rơi, đối đầu Thiên Vận Tử","chuong":"@c1010"},{"text":"Tuyên bố mọi thần thông và nguyên lực thiên địa trong Côn Hư Tinh vực đều nằm trong tay nàng","chuong":"@c1011"},{"text":"Khẩn cầu Vương Lâm cho nhìn con một lần, khẳng định Vương Bình là con của mình nhưng bị cự tuyệt","chuong":"@c1014"},{"text":"Bị Thác Sâm đánh tan thân, nguyên thần trọng thương, dùng bí thuật Côn Hư trốn đến Man Hoang ẩn tu","chuong":"@c1147"},{"text":"Thoát chết khỏi Côn Hư cảnh bị Thác Sâm hủy diệt hoàn toàn, tái ngộ Vương Lâm","chuong":"@c1195"},{"text":"Xác nhận danh tính Liễu Mi, đạo tâm viên mãn, từ biệt Vương Lâm","chuong":"@c1196"}]},"nguon":["@c1147","@c1163"],"vaiTro":"Côn Hư Thánh Nữ — chủ nhân tối cao của Côn Hư Tinh vực, mẹ của Vương Bình","tinhCach":"Lạnh lùng băng giá, quyền uy tuyệt đối; ẩn giấu tình cảm sâu nặng dưới vẻ ngoài lãh đạm; giằng xé giữa tình thân và đạo tâm; kiên định, chấp niệm với Vương Lâm và người con","blurb":"Mộc Băng Mi, bí danh Côn Hư Thánh Nữ, nắm giữ mọi thần thông và nguyên lực thiên địa trong Côn Hư Tinh vực. Nàng ra tay cứu Vương Lâm lúc cận tử, để lộ mối quan hệ phức tạp với hắn cùng người con Vương Bình, rồi lặng lẽ chia tay sau nhiều lần khẩn cầu bất thành. Bị Thác Sâm đánh tan thân, nàng trốn đến Man Hoang ẩn tu; sau khi Côn Hư cảnh bị hủy diệt, nàng tái ngộ Vương Lâm, tự nhận là Liễu Mi rồi bị Thần Tông hạn chế tự do và vây khốn."},{"id":"lo-phu-tu","name":"Lỗ Phu Tử","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"La Thiên","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Nhân vật ẩn giấu trong phe La Thiên","tinhCach":"Thận trọng, ẩn mình","blurb":"Luôn ẩn giấu trong phe La Thiên. Khi Thác Sâm xuất hiện thì hoảng sợ trốn chạy thật xa khỏi Liên Minh tinh vực.","tabs":{"diem":[{"text":"Ẩn giấu cực tốt trong phe La Thiên, hoảng sợ bỏ chạy khi Thác Sâm xuất hiện","chuong":"@c1147"}],"kinhLich":[{"chuong":"@c1147","importance":"bridge","mucCt":"gon","text":"Khi Thác Sâm xuất hiện, hoảng sợ trốn chạy thật xa khỏi Liên Minh tinh vực.","anchor":"Lỗ Phu Tử luôn ẩn giấu cực tốt cũng càng hoảng sợ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1147"]},{"id":"thanh-nong","name":"Thanh Nông","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"song","vaiTro":"Nhân vật bí ẩn, xuất hiện ngoài Vũ Tiên giới thuyết phục Thác Sâm","tinhCach":"Bí ẩn, có uy vọng đủ để Thác Sâm lắng nghe","blurb":"Xuất hiện ngoài Vũ Tiên giới khi Thác Sâm định phá phong ấn, nói điều gì đó khiến Thác Sâm trầm tư rồi gật đầu bỏ đi.","tabs":{"diem":[{"text":"Thuyết phục được Thác Sâm không phá phong ấn Vũ Tiên giới","chuong":"@c1147"}],"kinhLich":[{"chuong":"@c1147","importance":"normal","mucCt":"gon","tieuDe":"Thuyết phục Thác Sâm rời đi","text":"Xuất hiện ngoài Vũ Tiên giới khi Thác Sâm định phá phong ấn, nói điều gì đó khiến Thác Sâm trầm tư rồi gật đầu bỏ đi.","anchor":"Thanh Nông xuất hiện ngoài Vũ Tiên giới, hai người này không biết đã nói với nhau điều gì"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"khac","quanHe":"Đối thoại","ghiChu":"Thuyết phục Thác Sâm không phá phong ấn Vũ Tiên giới"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1147"]},{"id":"lao-gia-hac-bao-tinh-vuc-hoa","name":"Lão già hắc bào (tinh vực hoa bảy màu)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Người canh giữ khu vực trồng hoa bảy màu trong tinh vực trận pháp. Phát hiện Đạo quả khô héo bất thường, lao tới can thiệp nhưng bị Thiên Nghịch cản lại bất lực.","vaiTro":"Người canh giữ khu vực hoa bảy màu, thuộc hạ Chưởng Tôn","tinhCach":["Tận trách với nhiệm vụ canh giữ; kinh hoàng khi mất Đạo quả"],"tabs":{"diem":[{"text":"Bất lực trước Thiên Nghịch — bị cản ngoài mười trượng, chỉ trơ mắt nhìn cây hoa đỏ máu do Chưởng Tôn tâm huyết nuôi trồng bị hấp thu sạch.","chuong":"@c1150"}],"kinhLich":[{"chuong":"@c1150","importance":"normal","mucCt":"vua","tieuDe":"Phát hiện Đạo quả khô héo, bị Thiên Nghịch cản trở","text":"Phát hiện Đạo quả sắp xuất hiện lại khô héo bất thường, kinh hoàng la lên. Phóng thần niệm tới nhưng bị Thiên Nghịch bắn ngược, huyễn hóa ra lao tới tấn công nhưng bị cản ngoài mười trượng, bất lực nhìn cây hoa đỏ máu bị hấp thu sạch.","anchor":"trơ mắt nhìn cây hoa bảy màu đỏ máu trong đám hoa bảy màu được chính Chưởng Tôn bỏ ra rất nhiều tâm huyết để nuôi trồng"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"cap-tren","quanHe":"Chủ nhân/cấp trên","ghiChu":"Canh giữ khu hoa bảy màu do Chưởng Tôn bỏ tâm huyết nuôi trồng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1150"]},{"id":"dong-tu-toc-hoa-ram","name":"Đồng tử tóc hoa râm (Thần Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thần Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đồng tử tóc hoa râm ngồi trong mật thất Thần Tông hàng vạn năm bất động, cảm nhận được khí tức chủ nhân Phong Giới khi cửa Thiên Nghịch mở ra.","vaiTro":"Nhân vật bí ẩn trong Thần Tông, liên quan tới chủ nhân Phong Giới","tinhCach":"Bí ẩn; trầm mặc","tabs":{"diem":[{"text":"Hình dáng đồng tử nhưng tóc hoa râm, ngồi bất động hàng vạn năm trong mật thất Thần Tông.","chuong":"@c1151"}],"kinhLich":[{"chuong":"@c1151","importance":"normal","mucCt":"gon","tieuDe":"Cảm nhận khí tức chủ nhân Phong Giới","text":"Ngồi trong mật thất Thần Tông hàng vạn năm bất động, cảm nhận khí tức chủ nhân Phong Giới liền mở mắt.","anchor":"Người này hình dáng như một đồng tử, nhưng tóc lại hoa râm"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1151"]},{"id":"lao-gia-hoa-da-phong-tien-gioi","name":"Lão già hóa đá (Phong Tiên Giới)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Lão già khoanh chân ngồi trên đường lớn ở Phong Tiên Giới giữa đàn Văn Thú, toàn thân đã hóa đá. Cảm nhận khí tức của lão gia khi cửa Thiên Nghịch mở.","vaiTro":"Nhân vật bí ẩn tại Phong Tiên Giới, liên quan tới chủ nhân Phong Giới","tinhCach":"Bí ẩn; trung thành","tabs":{"diem":[{"text":"Toàn thân hóa đá, ngồi giữa đàn Văn Thú ở Phong Tiên Giới, mở mắt khi cảm nhận khí tức rồi lại hóa tượng đá.","chuong":"@c1151"}],"kinhLich":[{"chuong":"@c1151","importance":"normal","mucCt":"gon","tieuDe":"Cảm nhận khí tức của lão gia","text":"Cảm nhận khí tức của lão gia, mở mắt, ký ức tràn về rồi lại nhắm mắt trở thành tượng đá.","anchor":"Khí tức của lão gia… Ánh mắt lão già lộ ra vẻ kỳ dị"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1151"]},{"id":"nu-tu-dinh-nui-phong-gioi","name":"Nữ tử trên đỉnh núi (Phong Giới)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử đứng trên đỉnh núi một tu chân tinh bên trong Phong Giới, cảm nhận khí tức quen thuộc từ cửa Thiên Nghịch nhưng không nhớ ra là ai.","vaiTro":"Nhân vật bí ẩn trong Phong Giới","tinhCach":"Mê man hồi tưởng","tabs":{"diem":[{"text":"Cảm nhận khí tức rất quen thuộc nhưng không thể nhớ ra là ai.","chuong":"@c1151"}],"kinhLich":[{"chuong":"@c1151","importance":"bridge","mucCt":"gon","text":"Đứng trên đỉnh núi tu chân tinh trong Phong Giới, cảm nhận khí tức quen thuộc nhưng không nhớ ra là ai.","anchor":"Nghĩ không ra khí tức này rốt cuộc là của ai… rất quen, rất quen thuộc…"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1151"]},{"id":"thanh-nien-ngu-ngay-phong-gioi","name":"Thanh niên ngủ ngáy (Phong Giới)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thanh niên nằm ngủ trên ngọn núi ở tu chân tinh trong Phong Giới, chính là người từ trong khe chạy ra khi Vương Lâm vượt Thiên Kiếp.","vaiTro":"Nhân vật bí ẩn trong Phong Giới, liên quan tới Vương Lâm vượt Thiên Kiếp","tinhCach":"Ngơ ngác; thoải mái","tabs":{"diem":[{"text":"Chính là người từ trong khe xuất hiện chạy ra khi Vương Lâm vượt Thiên Kiếp, giật mình tỉnh dậy khi cảm nhận khí tức quen thuộc.","chuong":"@c1151"}],"kinhLich":[{"chuong":"@c1151","importance":"bridge","mucCt":"gon","text":"Nằm ngủ trên ngọn núi trong Phong Giới, giật mình tỉnh dậy khi cảm nhận khí tức quen thuộc, gãi đầu ngơ ngác.","anchor":"Hù dọa lão tử giật mình, còn tưởng mấy lão già từ Tiên Vực xuống đây bắt lão tử"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1151"]},{"id":"lao-phu-nhan-ao-xanh-that-thai-gioi","name":"Lão phụ nhân áo xanh (Thất Thải Giới)","gioiTinh":"nu","trangThai":"song","blurb":"Một lão phụ nhân mặc áo xanh xuất hiện khi đoàn Vương Lâm rời sơn cốc trong Thất Thải Giới, rất do dự không dám tới gần, chỉ đi theo phía sau rất xa.","vaiTro":"Nhân vật phụ, xuất hiện thoáng qua tại Thất Thải Giới","tinhCach":["Do dự, e ngại"],"tabs":{"diem":[{"text":"Xuất hiện khi đoàn Vương Lâm rời sơn cốc, rất do dự không dám tới gần","chuong":"@c1153"}],"kinhLich":[{"mucCt":"gon","text":"Chạy tới khi đoàn Vương Lâm rời sơn cốc, rất do dự, không dám tới gần, chỉ đi theo phía sau rất xa.","anchor":"một lão phụ nhân mặc áo xanh chạy tới, dường như rất do dự, không dám tới gần","bridge":true,"khoang":"@c1153"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1153"]},{"id":"ton-tai-than-bi-loc-xoay","name":"Tồn tại thần bí trong cơn lốc xoáy","gioiTinh":"khong-ro","trangThai":"khong-ro","blurb":"Tồn tại thần bí xuất hiện tại biên giới Thất Thải Giới dưới dạng cơn lốc xoáy khổng lồ khuấy động bầu trời, bên trong ẩn hai ánh mắt vô tình chứa nỗi tang thương xa xưa. Hắn nói đạo quả của mình bị nuốt và ngăn không cho Vương Lâm rời đi. Lai lịch cùng cảnh giới đều chưa rõ.","vaiTro":"Tồn tại thần bí chặn Vương Lâm tại biên giới Thất Thải Giới","tinhCach":"Vô tình; mang thương xa xưa","tabs":{"diem":[{"text":"Xuất hiện dưới dạng cơn lốc xoáy khổng lồ khuấy động bầu trời tối đen tan vỡ, bên trong có hai ánh mắt vô tình","chuong":"@c1153"},{"text":"Chặn Vương Lâm tại biên giới Thất Thải Giới, ngăn không cho rời đi","chuong":"@c1153"}],"kinhLich":[{"chuong":"@c1153","importance":"major","mucCt":"ky","tieuDe":"Xuất hiện chặn Vương Lâm tại biên giới Thất Thải Giới","text":"Xuất hiện dưới dạng cơn lốc xoáy khổng lồ khuấy động bầu trời tối đen tan vỡ, bên trong có hai ánh mắt vô tình chứa sự tang thương xa xưa. Nói đạo quả của hắn bị nuốt, ngăn Vương Lâm rời khỏi Thất Thải Giới.","anchor":"Nuốt lấy đạo quả của bổn tôn, chẳng lẽ cứ như vậy mà rời khỏi sao?"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Chặn Vương Lâm rời Thất Thải Giới, đòi đạo quả","ghiChu":"@c1153"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1153"]},{"id":"ke-bi-phong-an-trong-con-loc-xoay-ngu-sac","name":"Kẻ bị phong ấn trong cơn lốc xoáy ngũ sắc","aliases":["Lam Mộng Đạo Tôn","Kẻ bị phong ấn trong cơn lốc xoáy ngũ sắc"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1154","tieuDe":"Biến Thất Thải giới thành lòng bàn tay, thử thách một chưởng","text":"Phát ra lời thách thức: chịu được một chưởng thì cho cơ hội trưởng thành. Biến toàn bộ Thất Thải giới thành lòng bàn tay khổng lồ — năm ngọn núi là năm ngón tay, vết nứt mặt đất là vân tay. Bàn tay bắt đầu nắm lại muốn nghiền nát mọi thứ bên trong, uy áp vượt xa cơn lốc xoáy.","anchor":"Bổn tôn không lừa ngươi, nếu có thể dưới một chưởng mà không chết, bổn tôn sẽ cho ngươi cơ hội tiếp tục trưởng thành"},{"chuong":"@c1156","importance":"normal","mucCt":"ky","tieuDe":"Lộ danh tính, hứa không giết Vương Lâm","text":"Bàn tay năm ngón đã bị Vương Lâm phá hai ngón (trỏ và giữa) nhưng ngón trỏ tự khôi phục với tốc độ cực nhanh. Lần đầu tiên động dung trước ý chí chiến đấu bất khuất của Vương Lâm. Tuyên bố nếu Vương Lâm sống sót dưới một chưởng này sẽ không giết. Tự xưng là Lam Mộng Đạo Tôn của Thái Cổ Tinh Thần Lam Ti Tộc, tiết lộ danh tính ngoại giới chưởng tôn.","anchor":"Lão phu là Lam Mộng Đạo Tôn của Thái Cổ Tinh Thần Lam Ti Tộc!"},{"chuong":"@c1157","importance":"normal","mucCt":"ky","tieuDe":"Nhận ra phúc hữu, buông tha Vương Lâm","text":"Bàn tay trong Thất Thải giới giao chiến với Vương Lâm, ngón cái — đòn mạnh nhất — đang giáng xuống thì nhận ra lam quang từ vòng tay trên cổ tay Vương Lâm chứa phúc hữu của con gái Nguyệt nhi. Lập tức giơ ngón cái lên, hất Vương Lâm bay ra, buông tha. Cất tiếng tang thương nói với con gái đã đầu thai. Sau đó trở về Lam Sơn trong tinh vực Lam Ti tộc, đánh giá Vương Lâm là người mạnh nhất trong đám tiểu bối kể cả Thái Cổ Tinh Thần, thề bảo hộ người mang phúc hữu chống cả Chưởng Tôn. Bất mãn Chưởng Tôn có mục đích khác khi nhờ mình ra tay.","anchor":"Một trong Thái Cổ ngũ tôn, Lam Mộng Đạo Tôn không ngờ đột nhiên lại có một khoảnh khắc không khống chế được tâm thần"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ sinh tử tại Thất Thải giới, nhưng động dung trước ý chí của Vương Lâm và hứa không giết nếu sống sót","ghiChu":""},{"ten":"Nguyệt nhi","tag":"cha-me","quanHe":"Con gái, đã đầu thai","ghiChu":"Kiếp trước tặng vòng tay lam cho Vương Lâm"},{"ten":"Vân Mộng","tag":"the-thiep","quanHe":"Vợ","ghiChu":"Phúc hữu trên vòng tay truyền thừa từ bà"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Tiểu bối được bảo hộ","ghiChu":"Mang phúc hữu của con gái, thề bảo hộ"},{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Đồng đẳng sức mạnh nhưng bất mãn","ghiChu":"Nghi Chưởng Tôn có mục đích khác khi nhờ ra tay"}],"tuiDo":{},"diem":[{"text":"Phá phong ấn thứ chín, lấy lại con mắt phải chứa Cực Cảnh","chuong":"@c0739"},{"text":"Giao chiến trực diện với Vương Lâm, nhận ra Hô Phong, Tiêu Dao Tử Mẫu Khô và kiếm kỹ đối phương","chuong":"@c0741"},{"text":"Thoát khỏi pho tượng, trẻ hóa thành thanh niên và biến tượng vỡ thành trường thương để thôn phệ phục hồi","chuong":"@c0743"},{"text":"Biến toàn bộ Thất Thải giới thành lòng bàn tay, thách Vương Lâm chịu được một chưởng để cho cơ hội trưởng thành","chuong":"@c1154"},{"text":"Lộ danh tính và hứa không giết Vương Lâm dù bị phá hai ngón tay","chuong":"@c1156"},{"text":"Nhận ra phúc hữu nên thu lại đòn ngón cái mạnh nhất, buông tha Vương Lâm","chuong":"@c1157"}]},"trangThai":"song","nguon":["@c1154","@c1156","@c1157"],"canhGioiCaoNhat":"Thái Cổ Ngũ Tôn","vaiTro":"Tồn tại bí ẩn bị phong ấn tại Lôi Tiên Giới","tinhCach":"chủ động phá phong ấn, thôn phệ để phục hồi; am hiểu, nhận ra nhiều thần thông và pháp bảo; hành sự tà dị nhưng biết buông tha khi nhận ra phúc duyên","blurb":"Kẻ bị phong ấn trong cơn lốc xoáy ngũ sắc là một tồn tại bí ẩn tại Lôi Tiên Giới, từng bị chia cắt và phong ấn. Sau khi phá phong ấn thứ chín, hắn lấy lại con mắt phải chứa Cực Cảnh, thoát khỏi pho tượng, trẻ hóa thành thanh niên và thôn phệ liên tục để phục hồi. Về sau hắn giao chiến với Vương Lâm qua bàn tay khống chế Thất Thải giới, nhưng cuối cùng nhận ra phúc hữu mà buông tha.","cn":"蓝梦道尊","gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần Lam Ti Tộc","trangThai":"gan-bo"}]},{"id":"nguyet-nhi","name":"Nguyệt nhi","gioiTinh":"nu","trangThai":"mat-tich","theLuc":[{"ten":"Thái Cổ Tinh Thần Lam Ti Tộc","trangThai":"da-roi"}],"vaiTro":"Con gái Lam Mộng Đạo Tôn và Vân Mộng, đã đầu thai","tinhCach":["Chưa rõ (chỉ được nhắc tên)"],"blurb":"Con gái của Lam Mộng Đạo Tôn và Vân Mộng. Đã đầu thai, kiếp trước từng tặng vòng tay lam chứa phúc hữu cho Vương Lâm.","tabs":{"diem":[{"text":"Kiếp trước tự tay tặng vòng tay lam chứa phúc hữu truyền thừa từ mẹ Vân Mộng cho Vương Lâm — chỉ khi tự tay đưa phúc hữu mới phát huy.","chuong":"@c1157"}],"kinhLich":[{"chuong":"@c1157","importance":"normal","mucCt":"gon","tieuDe":"Được cha nhắc tên, phúc hữu cứu Vương Lâm","text":"Lam Mộng Đạo Tôn nhận ra phúc hữu trên vòng tay lam do Nguyệt nhi kiếp trước tự tay tặng cho Vương Lâm, gọi tên hai lần trong đau thương.","anchor":"con gái chúng ta đã đầu thai rồi"}],"tuViMoc":[],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"cha-me","quanHe":"Cha","ghiChu":""},{"ten":"Vân Mộng","tag":"cha-me","quanHe":"Mẹ","ghiChu":"Phúc hữu truyền thừa từ mẹ"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được tặng vòng tay lam","ghiChu":"Kiếp trước tự tay tặng"}],"tuiDo":{}},"nguon":["@c1157"]},{"id":"van-mong","name":"Vân Mộng","cn":"云梦","gioiTinh":"nu","trangThai":"khong-ro","theLuc":[{"ten":"Thái Cổ Tinh Thần Lam Ti Tộc","trangThai":"gan-bo"}],"vaiTro":"Vợ Lam Mộng Đạo Tôn, mẹ Nguyệt nhi","tinhCach":["Chưa rõ (chỉ được nhắc tên)"],"blurb":"Vợ của Lam Mộng Đạo Tôn. Phúc hữu trên vòng tay lam truyền thừa từ bà.","tabs":{"diem":[{"text":"Phúc hữu trên vòng tay lam được truyền thừa từ Vân Mộng.","chuong":"@c1157"}],"kinhLich":[{"chuong":"@c1157","importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1157–@c1157","text":"Được Lam Mộng Đạo Tôn nhắc tên khi nói về phúc hữu truyền thừa trên vòng tay lam.","anchor":"phúc hữu được truyền thừa từ Vân Mộng nàng"}],"tuViMoc":[],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"the-thiep","quanHe":"Chồng","ghiChu":""},{"ten":"Nguyệt nhi","tag":"cha-me","quanHe":"Con gái, đã đầu thai","ghiChu":""}],"tuiDo":{}},"nguon":["@c1157"]},{"id":"lao-gia-ao-trang-de-tu-chuong-ton","name":"Lão già áo trắng","gioiTinh":"nam","trangThai":"song","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"vaiTro":"Đệ tử Chưởng Tôn, sứ giả liên lạc","tinhCach":["Cung kính, không dám đắc tội Thái Cổ Ngũ Tôn"],"blurb":"Lão già áo trắng, đệ tử của Chưởng Tôn. Xuất hiện trước mặt Lam Mộng Đạo Tôn trên Lam Sơn nhưng bị quát đuổi ngay lập tức.","tabs":{"diem":[{"text":"Là đệ tử Chưởng Tôn nhưng đối mặt Thái Cổ Ngũ Tôn không dám đắc tội.","chuong":"@c1157"}],"kinhLich":[{"chuong":"@c1157","importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1157–@c1157","text":"Xuất hiện trước mặt Lam Mộng Đạo Tôn trên Lam Sơn xưng gia sư, bị quát đuổi ngay lập tức.","anchor":"Hắn tuy là đệ tử Chưởng Tôn, nhưng đối mặt với một trong Thái Cổ Ngũ Tôn sức mạnh tương đương với sư phụ của mình cũng không chút nào dám đắc tội"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"su-mon","quanHe":"Sư phụ","ghiChu":""},{"ten":"Lam Mộng Đạo Tôn","tag":"khac","quanHe":"Thái Cổ Ngũ Tôn, bị quát đuổi","ghiChu":""}],"tuiDo":{}},"nguon":["@c1157"]},{"id":"tu-do-nam","name":"Tư Đồ Nam","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1157","importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1157–@c1157","text":"Được Vương Lâm nhắc tên trong lời trối trăng trước cái chết.","anchor":"dựa theo ấn quyết trong ký ức của Thương Tùng Tử nhanh chóng ở phía trước người mở ra một cái khe quay về Vân Hải"}],"diem":[{"text":"Tiết lộ danh tính cường giả lục cấp Chu Tước Quốc, tinh hoa Nguyên Anh ẩn trong Thiên Nghịch Châu sau khi bị kẻ địch thất cấp truy sát thân hủy","chuong":"@c0047"},{"text":"Đoạt xá thành công thân xác đồng tử áo đỏ, nuốt tứ tổ Tiên Di Tộc, bản lãnh đạt Vấn Đỉnh Kỳ","chuong":"@c0411"},{"text":"Cướp sạch chín thành Giao Dịch Tinh trong ba ngày, đánh bại năm Vấn Đỉnh tu sĩ liên thủ","chuong":"@c0447"},{"text":"Tu vi đạt Tịnh Niết sơ kỳ, nổi danh tinh vực với thân phận cung chủ Hồng Phấn Cung trên Thiên Vận Tinh","chuong":"@c0932"},{"text":"Được Thanh Lâm thu nhận làm đệ tử tại Vũ Tiên Giới, với điều kiện không bị hạn chế tự do","chuong":"@c1050"},{"text":"Được Vương Lâm hồi tưởng là ân nhân lớn nhất, người đã bỏ qua Thiên Nghịch Châu và theo sát hắn mấy trăm năm từ thuở nhỏ","chuong":"@c1341"}]},"nguon":["@c1157"],"vaiTro":"Thế lực ẩn — cường giả lục cấp Chu Tước Quốc, huynh trưởng và ân nhân lớn nhất của Vương Lâm","tinhCach":"Kiêu ngạo bất kính, hành xử ngang tàng không kiêng nể; tàn độc quyết đoán, chủ trương diệt địch tận gốc; trọng tình nghĩa với Vương Lâm, sẵn sàng xả thân tương trợ; thận trọng toan tính lâu dài nhưng dễ mất kiên nhẫn","blurb":"Tư Đồ Nam vốn là đệ nhất cao thủ tinh cầu lục cấp tu chân quốc Chu Tước, bị kẻ địch từ thất cấp tu chân quốc truy sát đến thân hủy, chỉ còn tinh hoa Nguyên Anh ẩn náu trong Thiên Nghịch Châu của Vương Lâm suốt hàng trăm năm. Sau khi được lửa Chu Tước đánh thức, ông đoạt xá thành công thân xác đồng tử áo đỏ, nuốt tứ tổ Tiên Di Tộc đạt Vấn Đỉnh Kỳ rồi dần tu luyện tới Tịnh Niết sơ kỳ, gây họa khắp tinh vực và bị Loan Phượng tinh truy nã, nhưng luôn quay về bên Vương Lâm trong những lúc nguy cấp. Tại Vũ Tiên Giới, ông được Thanh Lâm thu nhận làm đệ tử với điều kiện không bị hạn chế tự do, và được"},{"id":"luu-kim-buu","name":"Lưu Kim Bưu","cn":"刘金彪","aliases":["Kim Bưu Tử"],"gioiTinh":"nam","theLuc":[{"ten":"Không thuộc tông phái cố định","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết","trangThai":"song","blurb":"Lưu Kim Bưu, đạo hiệu Kim Bưu Tử, là tên lừa đảo lão luyện chuyên đổi tên mỗi kỳ đại hội ngàn năm, nhắm vào các phân tông suy yếu sắp giải tán để tống tiền bằng ngọc giản phát khí tức giả Toái Niết dù tu vi thực chỉ ở tầng Âm Hư. Sau khi lừa gạt Quy Nguyên Tông, lão bị Vương Lâm truy kích, bảo vật ngọc bội chứa rết ngàn trượng mất hết linh khí, rồi sa vào tay Hứa Lập Quốc bị tra tấn đến tiều tụy và tự thú đạo lừa đảo đã ăn mòn cả ký ức lẫn nguyên thần. Về sau lão bị buộc giả dạng Chu Tước đời thứ sáu lừa lão tổ Hỏa Tước tộc, rơi vào hiểm cảnh trong thánh địa và được Vương Lâm cứu thoát.","vaiTro":"Kẻ lừa đảo kỳ cựu chuyên tống tiền phân tông yếu, sau trở thành tốt thí của Vương Lâm và Hứa Lập Quốc","tinhCach":"Xảo quyệt, mỗi ngàn năm đổi tên một lần để tránh bị truy cứu; Tính toán kỹ lưỡng, điều tra kỹ tiểu sử nạn nhân trước khi hành động; Giả mạo thực lực, dùng ngọc giản khí tức Toái Niết che giấu tu vi thật chỉ Âm Hư; Đạo lừa đảo ăn sâu đến mức tự lừa gạt bản thân, ký ức và nguyên thần đều bị ảnh hưởng","tabs":{"diem":[{"text":"Dùng ngọc giản chứa khí tức Toái Niết phá tan hộ sơn đại trận Thiên Cương Tông, tống tiền công khai","chuong":"@c1158"},{"text":"Lừa gạt Quy Nguyên Tông bằng kim quang giả Toái Niết, bị Vương Lâm truy kích và lộ tu vi thật chỉ tầng Âm Hư","chuong":"@c1198"},{"text":"Ngọc bội thả rết ngàn trượng thất bại, tám con rết chết sạch khiến bảo vật mất hoàn toàn linh khí","chuong":"@c1199"},{"text":"Bị Hứa Lập Quốc tra tấn đến tiều tụy, tự thú đạo lừa đảo đã ăn mòn ký ức và nguyên thần","chuong":"@c1302"},{"text":"Giả dạng Chu Tước đời thứ sáu lừa lão tổ Hỏa Tước tộc, bị đưa vào thánh địa trên Hỏa Tước tinh","chuong":"@c1335"},{"text":"Bị sợi tơ quấn quanh trong thánh địa Hỏa Tước tộc, được Vương Lâm cứu thoát","chuong":"@c1338"}],"kinhLich":[{"chuong":"@c1158","importance":"normal","mucCt":"ky","tieuDe":"Tống tiền Thiên Cương Tông","text":"Dùng ngọc giản chứa khí tức Toái Niết phá tan hộ sơn đại trận Thiên Cương Tông, xuyên thấu nóc đại điện. Kể vanh vách tiểu sử ba lão già (Chúc Duẫn Minh, La Tòng Cương, Chu Thần), uy hiếp đòi sáu vạn nguyên tinh hoặc vật tương đương trong nửa nén hương, hứa sẽ giúp giải mối nguy giải tán nếu nộp tiền.","anchor":"Lão phu Lưu Kim Bưu! Đạo hiệu Kim Bưu Tử!"}],"tuViMoc":[{"chuong":"@c1158","canhGioi":"Toái Niết","text":"Ngọc giản tỏa khí tức Toái Niết cực mạnh, cho thấy tu vi ít nhất ở cảnh giới Toái Niết","importance":"major"}],"nhanMach":[{"ten":"Chúc Duẫn Minh","tag":"khac","quanHe":"Nạn nhân tống tiền","ghiChu":"Tống tiền tông chủ Thiên Cương Tông"},{"ten":"La Tòng Cương","tag":"khac","quanHe":"Nạn nhân tống tiền","ghiChu":"Tống tiền"},{"ten":"Chu Thần","tag":"khac","quanHe":"Nạn nhân tống tiền","ghiChu":"Tống tiền"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Vương Lâm tuyên bố sẽ hành hạ Lưu Kim Bưu"}],"tuiDo":{"phapBao":[{"ten":"Ngọc giản chứa khí tức Toái Niết","trangThai":"dang-co","moTa":"Ngọc giản phá tan hộ sơn đại trận, dùng để truyền âm và uy hiếp","nguon":"@c1158"}]}},"nguon":["@c1158"]},{"id":"chuc-duan-minh","name":"Chúc Duẫn Minh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Cương Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Khuy Niết sơ kỳ","trangThai":"song","blurb":"Tông chủ Thiên Cương Tông, sinh ở Thiên Hải đại lục, bảy tuổi tu đạo, hiện ở Khuy Niết sơ kỳ. Lo lắng trước nguy cơ tông phái bị giải tán.","vaiTro":"Tông chủ Thiên Cương Tông, phân tông nhỏ yếu ngũ giai","tinhCach":["Lo lắng cho tông phái; biết rõ tình thế yếu kém nhưng bất lực"],"tabs":{"diem":[{"text":"Tông chủ phân tông nhỏ yếu, bảy tuổi tu đạo, kết đan hơn hai trăm năm, Nguyên Anh hơn sáu trăm năm, hiện Khuy Niết sơ kỳ","chuong":"@c1158"},{"text":"Tông chủ Thiên Cương Tông, bảy tuổi tu đạo, kết đan hơn hai trăm năm, Nguyên Anh hơn sáu trăm năm, hiện Khuy Niết sơ kỳ.","chuong":"@c1158"}],"kinhLich":[{"chuong":"@c1158","importance":"normal","mucCt":"vua","tieuDe":"Bị Lưu Kim Bưu tống tiền","text":"Cùng La Tòng Cương và Chu Thần ngồi trong đại điện lo lắng trước đại hội ngàn năm. Ngọc giản của Lưu Kim Bưu phá hộ sơn đại trận, kể vanh vách tiểu sử, đòi sáu vạn nguyên tinh.","anchor":"Chúc Duẫn Minh, sinh ra ở Thiên hải đại lục, bảy tuổi tu đạo, bái nhập Thiên Cương Tông"}],"tuViMoc":[{"chuong":"@c1158","canhGioi":"Khuy Niết sơ kỳ","text":"Hiện ở Khuy Niết sơ kỳ, bảy tuổi tu đạo, kết đan hơn hai trăm năm, Nguyên Anh hơn sáu trăm năm","importance":"minor"}],"nhanMach":[{"ten":"Lưu Kim Bưu","tag":"doi-thu","quanHe":"Bị tống tiền bởi Lưu Kim Bưu","ghiChu":""},{"ten":"La Tòng Cương","tag":"dong-minh","quanHe":"Đồng liêu Thiên Cương Tông","ghiChu":""},{"ten":"Chu Thần","tag":"dong-minh","quanHe":"Đồng liêu Thiên Cương Tông","ghiChu":""}],"tuiDo":{}},"nguon":["@c1158"]},{"id":"la-tong-cuong","name":"La Tòng Cương","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Cương Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Khuy Niết sơ kỳ","trangThai":"song","blurb":"Một trong ba lão già Thiên Cương Tông, sinh tại Thiên Hải đại lục, dùng đan dược tăng tu vi, dừng ở Khuy Niết sơ kỳ.","vaiTro":"Trưởng lão Thiên Cương Tông","tinhCach":["Lo lắng cho tông phái"],"tabs":{"diem":[{"text":"Sinh tại Thiên Hải đại lục, dùng đan dược tăng tu vi, dừng ở Khuy Niết sơ kỳ","chuong":"@c1158"},{"text":"Dùng đan dược tăng tu vi, dừng ở Khuy Niết sơ kỳ, sinh tại Thiên Hải đại lục.","chuong":"@c1158"}],"kinhLich":[{"chuong":"@c1158","importance":"normal","mucCt":"gon","tieuDe":"Bị Lưu Kim Bưu tống tiền","text":"Cùng Chúc Duẫn Minh và Chu Thần bị Lưu Kim Bưu uy hiếp tống tiền sáu vạn nguyên tinh.","anchor":"La Tòng Cương, sinh tại Thiên Hải đại lục, ở bên cạnh La Hải"}],"tuViMoc":[{"chuong":"@c1158","canhGioi":"Khuy Niết sơ kỳ","text":"Dùng đan dược tăng tu vi, dừng ở Khuy Niết sơ kỳ","importance":"minor"}],"nhanMach":[{"ten":"Chúc Duẫn Minh","tag":"dong-minh","quanHe":"Đồng liêu Thiên Cương Tông","ghiChu":""},{"ten":"Chu Thần","tag":"dong-minh","quanHe":"Đồng liêu Thiên Cương Tông","ghiChu":""},{"ten":"Lưu Kim Bưu","tag":"doi-thu","quanHe":"Bị tống tiền","ghiChu":""}],"tuiDo":{}},"nguon":["@c1158"]},{"id":"chu-than","name":"Chu Thần","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Cương Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Dương Thực","trangThai":"song","blurb":"Một trong ba lão già Thiên Cương Tông, sinh ở Chu Vĩ đại lục, nửa đường gia nhập Thiên Cương Tông, đình trệ tại Dương Thực bảy trăm ba mươi lăm năm.","vaiTro":"Trưởng lão Thiên Cương Tông","tinhCach":["Lo lắng cho tông phái"],"tabs":{"diem":[{"text":"Sinh ở Chu Vĩ đại lục, nửa đường gia nhập Thiên Cương Tông, đình trệ tại Dương Thực bảy trăm ba mươi lăm năm","chuong":"@c1158"}],"kinhLich":[{"chuong":"@c1158","importance":"normal","mucCt":"gon","tieuDe":"Bị Lưu Kim Bưu tống tiền","text":"Cùng Chúc Duẫn Minh và La Tòng Cương bị Lưu Kim Bưu uy hiếp tống tiền sáu vạn nguyên tinh.","anchor":"Chu Thần, cũng không phải là người của Thiên Hải đại lục mà sinh ra ở Chu Vĩ đại lục"}],"tuViMoc":[{"chuong":"@c1158","canhGioi":"Dương Thực","text":"Đình trệ tại Dương Thực bảy trăm ba mươi lăm năm, chưa đột phá","importance":"minor"}],"nhanMach":[{"ten":"Chúc Duẫn Minh","tag":"dong-minh","quanHe":"Đồng liêu Thiên Cương Tông","ghiChu":""},{"ten":"La Tòng Cương","tag":"dong-minh","quanHe":"Đồng liêu Thiên Cương Tông","ghiChu":""},{"ten":"Lưu Kim Bưu","tag":"doi-thu","quanHe":"Bị tống tiền","ghiChu":""}],"tuiDo":{}},"nguon":["@c1158"]},{"id":"lao-gia-vo-cuc-tong","name":"Lão giả Vô Cực Tông (Loạn Thú Vụ Giới)","aliases":["sư tôn Loạn Thú Vụ Giới"],"gioiTinh":"nam","theLuc":[{"ten":"Vô Cực Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết đại viên mãn","trangThai":"song","blurb":"Lão giả mặc đạo bào trắng đen, tóc hoa râm, tu vi Toái Niết đại viên mãn thuộc Vô Cực Tông. Dẫn ba đệ tử chủ chốt vào Loạn Thú Vụ Giới luyện tập chiến đấu mãnh thú để cảm ngộ thiên đạo.","vaiTro":"Trưởng bối Vô Cực Tông dẫn đệ tử luyện tập trong Loạn Thú Vụ Giới","tinhCach":"Nghiêm khắc với đệ tử; coi trọng thực chiến hơn đan dược; quan tâm an nguy học trò","tabs":{"diem":[{"text":"Tu vi Toái Niết đại viên mãn, nhận xét đệ tử dựa đan dược đề cao tu vi, cảm ngộ thiên đạo không sâu, nên đẩy họ vào sinh tử để lĩnh ngộ.","chuong":"@c1161"}],"kinhLich":[{"mucCt":"vua","text":"Dẫn ba đệ tử Tịch Niết trên con đường thứ ba trong Loạn Thú Vụ Giới, vung tay áo dùng cuồng phong đẩy cả ba vào sương mù chiến đấu mãnh thú để cảm ngộ thiên đạo trong sinh tử. Khi nghe tiếng gầm rết lửa cấp mười hai, kinh ngạc lo lắng đệ tử gặp nguy, lập tức tiến vào sương mù cứu họ.","anchor":"phương pháp hiểu được thiên đạo tốt nhất chính là trong nguy cơ sinh tử","bridge":true,"khoang":"@c1161"},{"mucCt":"vua","text":"Ẩn trong sương mù quan sát Vương Lâm chiến đấu, kinh sợ nhận xét ngọn lửa của hắn hơn cả Hỏa Ngô Linh, nếu không bị thương thì ngay cả lão cũng không chắc đánh nổi. Nhận ra thứ Vương Lâm thi triển tương tự nhưng không phải Dịch Linh Ấn thật và Vương Lâm không phải người Thần Tông. Khi khí tức cấp 13 quét ra, biến sắc cuốn ba đệ tử rời đi theo con đường thứ ba, chấm dứt tập luyện ở Loạn Thú Vụ Giới.","anchor":"Tu vi của người này quá mạnh, nếu không phải đang bị thương, sợ là ngay cả ta cũng không thể nắm chắc có thể cũng hắn đánh một trận","bridge":true,"khoang":"@c1162"}],"tuViMoc":[{"chuong":"@c1161","canhGioi":"Toái Niết đại viên mãn","text":"Được giới thiệu với tu vi Toái Niết đại viên mãn.","importance":"major"}],"nhanMach":[{"ten":"Nữ đệ tử Vô Cực Tông","tag":"su-mon","quanHe":"Đệ tử","ghiChu":"Một trong ba đệ tử chủ chốt được dẫn vào Loạn Thú Vụ Giới luyện tập"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1161","@c1162"]},{"id":"nu-de-tu-vo-cuc-tong-loan-thu","name":"Nữ đệ tử Vô Cực Tông (Loạn Thú Vụ Giới)","gioiTinh":"nu","theLuc":[{"ten":"Vô Cực Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịch Niết","trangThai":"song","blurb":"Nữ tử mặc đạo bào, tướng mạo thanh khiết, phong thái mê người, tu vi Tịch Niết. Đệ tử chủ chốt Vô Cực Tông, bị sư tôn đẩy vào sương mù Loạn Thú Vụ Giới luyện tập.","vaiTro":"Đệ tử chủ chốt Vô Cực Tông trong Loạn Thú Vụ Giới","tinhCach":"Thanh khiết; phong thái mê người","tabs":{"diem":[{"text":"Tướng mạo thanh khiết, phong thái mê người, khiến hai nam đệ tử cùng nhóm lộ vẻ cuồng nhiệt khi liếc nhìn.","chuong":"@c1161"}],"kinhLich":[{"chuong":"@c1161","importance":"bridge","mucCt":"gon","text":"Bị sư tôn vung tay áo đẩy vào sương mù Loạn Thú Vụ Giới cùng hai nam đệ tử để chiến đấu mãnh thú lĩnh ngộ thiên đạo.","anchor":"Các ngươi là những đệ tử chủ chốt của Vô Cực Tông ta, nhưng lại dựa vào đan dược mà đề cao tu vi"},{"chuong":"@c1162","importance":"bridge","mucCt":"gon","text":"Cùng hai sư huynh hoảng sợ chứng kiến Vương Lâm chiến đấu, nhìn theo hắn rời đi với ánh mắt khó hiểu, rồi bị sư phụ cuốn đi rời Loạn Thú Vụ Giới.","anchor":"Nhất là nữ tu xinh đẹp kia, hai mắt lóe lên, nhìn về phía Vương Lâm rời khỏi"}],"tuViMoc":[{"chuong":"@c1161","canhGioi":"Tịch Niết","text":"Được giới thiệu với tu vi Tịch Niết.","importance":"minor"}],"nhanMach":[{"ten":"Lão giả Vô Cực Tông (Loạn Thú Vụ Giới)","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Dẫn vào Loạn Thú Vụ Giới luyện tập"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1161","@c1162"]},{"id":"than-anh-dai-dien-yeu-tong","name":"Thân ảnh mơ hồ trong đại điện Yêu Tông","gioiTinh":"khong-ro","theLuc":[{"ten":"Yêu Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thân ảnh mơ hồ ngồi khoanh chân sâu trong đại điện sơn môn Yêu Tông ở tầng thứ chín. Có ánh mắt đoạt hồn, thanh âm phiêu diêu khiến trời đất âm hàn.","vaiTro":"Nhân vật phụ trấn thủ đại điện Yêu Tông, cấp trên của Lý Thiến Mai tại chiến trường","tinhCach":"Nghiêm khắc nhưng có lòng thương; kiên quyết giữ kỷ luật song biết nhượng bộ khi cần","tabs":{"diem":[{"text":"Ánh mắt đoạt hồn, thanh âm phiêu diêu khiến trời đất âm hàn, trấn giữ đại điện Yêu Tông","chuong":"@c1163"}],"kinhLich":[{"mucCt":"vua","text":"Từ chối cho Lý Thiến Mai rời đi, cảnh cáo nàng sẽ bị coi là đào ngũ và sỉ nhục Phá Thiên Tông vì thú triều quy mô lớn sắp tới. Cuối cùng thở dài nhượng bộ, đưa ngọc bội cho nàng dùng truyền tống trận.","anchor":"Nếu ngươi rời khỏi nửa bước, sẽ bị coi như là kẻ đào ngũ!","bridge":true,"khoang":"@c1163"}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Thiến Mai","tag":"dong-minh","quanHe":"Tu sĩ Phá Thiên Tông dưới quyền tại chiến trường Yêu Tông","ghiChu":"Cảnh cáo nàng nhưng cuối cùng nhượng bộ cho rời đi"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1163"]},{"id":"vuong-san-san","name":"Vương San San","gioiTinh":"nu","theLuc":[{"ten":"Thần Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Vương San San là nữ tử hoàng sam, tướng mạo thanh tú, đệ tử Thần Tông được sư tôn phái đến đại lục hoang dã trong Vân Hải tinh vực đón Mộc Băng Mi. Nàng tự xưng muội muội, mang theo đan dược, đồng hành cùng Mộc Băng Mi qua đại hội phân tông rồi đưa nàng trở về Thần Tông. Trong quá trình đó, nàng bí mật ghi lại tình cảnh trận chiến của Vương Lâm và truyền hình ảnh về tông môn.","vaiTro":"Đệ tử Thần Tông, người đón Mộc Băng Mi về tông môn","tinhCach":"Dịu dàng, thân thiện; chu đáo, hay giới thiệu người quen; kín đáo, làm việc theo lệnh sư tôn","tabs":{"diem":[{"text":"Nhận lệnh gia sư đến đại lục hoang dã Vân Hải tinh vực đón Mộc Băng Mi, mang theo đan dược và đề nghị cùng đi","chuong":"@c1163"},{"text":"Tại đại hội phân tông cấp năm, giới thiệu Lý Thiến Mai — thiên chi kiêu nữ — cho Mộc Băng Mi làm quen","chuong":"@c1181"},{"text":"Giải thích nguồn gốc thần thông rút hồn thuộc Đệ Tam Bộ theo lời sư tôn","chuong":"@c1188"},{"text":"Bí mật khắc toàn bộ tình cảnh trận chiến của Vương Lâm vào ngọc giản rồi truyền hình ảnh về Thần Tông","chuong":"@c1191"},{"text":"Nhận lệnh sư tôn đưa Mộc Băng Mi rời Vô Cực Tông trở về Thần Tông","chuong":"@c1196"},{"text":"Ở bên Mộc Băng Mi trong Thần Tông, sắc mặt tái nhợt nhìn thiên không khi thiên kiếp bùng nổ","chuong":"@c1230"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1163","tieuDe":"Đón Mộc Băng Mi về Thần Tông","text":"Đến đại lục hoang dã trong Vân Hải tinh vực đón Mộc Băng Mi theo lệnh gia sư. Mang đan dược, đề nghị cùng đi xem cuộc so tài tông phái trong tám tầng Vân Hải.","anchor":"tiểu muội là Vương San San"}],"tuViMoc":[],"nhanMach":[{"ten":"Mộc Băng Mi","tag":"ban-be","quanHe":"Người được gia sư giao đón về Thần Tông","ghiChu":"Khen xinh đẹp, mang đan dược, đề nghị cùng xem cuộc so tài"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1163"]},{"id":"tong-lac-hai","name":"Tống Lạc Hải","cn":"宋洛海","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tịch Hồn Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết trung kỳ","trangThai":"song","blurb":"Trưởng lão Tịch Hồn Đạo, tu vi Toái Niết trung kỳ. Tự nhận rất hiểu Văn Thú, ẩn nấp ba tháng trong vùng Văn Thú ở tầng thứ tám tinh vực nhằm bắt Văn Thú Vương để kiểm chứng một suy đoán bí ẩn trong lòng.","vaiTro":"Trưởng lão Tịch Hồn Đạo, nghiên cứu Văn Thú","tinhCach":"Tham vọng lớn; kiên nhẫn (ẩn nấp ba tháng); tự phụ về kiến thức Văn Thú; tham lam trước cơ hội","tabs":{"diem":[{"text":"Ẩn nấp ba tháng trong vùng Văn Thú để bắt Văn Thú Vương kiểm chứng suy đoán bí ẩn, tin rằng nếu thành công sẽ danh chấn tầng thứ tám, thậm chí tầng thứ chín tinh vực cũng coi trọng.","chuong":"@c1168"}],"kinhLich":[{"mucCt":"ky","text":"Trưởng lão Tịch Hồn Đạo, tu vi Toái Niết trung kỳ, đã ẩn nấp ba tháng trong vùng Văn Thú ở tầng thứ tám tinh vực với mục đích bắt Văn Thú Vương để kiểm chứng suy đoán bí ẩn. Nửa tháng trước bị hai con Văn Thú màu trắng (khí tức tương đương Toái Niết) xuất hiện khiến tiến thoái lưỡng nan. Khi chứng kiến Văn Thú Vương (Vương Lâm) hạ sát bốn Văn Thú lam, tâm thần chấn động, cảm thấy cơ hội đã tới. Sau đó Văn Thú Vương màu tím xuất hiện, hắn nhìn nó với vẻ tham lam.","anchor":"Tống Lạc Hải đối với Văn Thú tự nhận là rất hiểu rõ, mục đích của hắn lần này chính là muốn bắt lấy một Văn Thú Vương để kiểm chứng suy đoán trong lòng","bridge":true,"khoang":"@c1168"},{"mucCt":"vua","text":"Ẩn mình sau tảng đá chứng kiến toàn bộ trận chiến Vương Lâm hạ sát Văn Thú Vương màu tím, tâm thần chấn động. Nhận ra nguyên thần tu sĩ ẩn trên thân Văn Thú Vương, ánh mắt lóe lên dõi theo đầy toan tính.","anchor":"Tống Lạc Hải ánh mắt lóe lên, nhìn chằm chằm Văn Thú Vương, tim đập thình thịch.","bridge":true,"khoang":"@c1169"}],"tuViMoc":[{"chuong":"@c1168","canhGioi":"Toái Niết trung kỳ","text":"Được giới thiệu với tu vi Toái Niết trung kỳ.","importance":"minor"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1168","@c1169"]}]};
